def _pvp_stats_init(pair, a, d):
    """Start fresh damage accounting for a fight."""
    _pvp_stats[pair] = {
        "turns": 0, "start": time.time(),
        a["user_id"]: {"dmg": 0, "biggest": 0, "hits": 0, "name": a.get("username", "?")},
        d["user_id"]: {"dmg": 0, "biggest": 0, "hits": 0, "name": d.get("username", "?")},
    }

def _pvp_stats_record(pair, attacker_uid, dmg):
    """Accumulate one action's damage for the post-fight recap."""
    st = _pvp_stats.get(pair)
    if not st:
        return
    st["turns"] = st.get("turns", 0) + 1
    ps = st.get(attacker_uid)
    if ps is None:
        return
    dmg = max(0, safe_int(dmg))
    ps["dmg"] += dmg
    if dmg > 0:
        ps["hits"] += 1
    if dmg > ps["biggest"]:
        ps["biggest"] = dmg

def _pvp_summary_text(pair, winner_id):
    """Build the end-of-fight group recap: damage totals, biggest hit, MVP."""
    st = _pvp_stats.get(pair)
    if not st or len(pair) != 2:
        return ""
    u1, u2 = pair
    s1, s2 = st.get(u1), st.get(u2)
    if not s1 or not s2:
        return ""
    dur = int(time.time() - st.get("start", time.time()))
    dur_str = f"{dur // 60}m {dur % 60}s" if dur >= 60 else f"{dur}s"
    def _line(uid, s):
        crown = "👑 " if uid == winner_id else ""
        return (f"{crown}*{s['name']}* — {fmt_num(s['dmg'])} dmg "
                f"({s['hits']} hits, biggest {fmt_num(s['biggest'])})")
    top = max((s1, s2), key=lambda s: s["dmg"])
    lines = [
        "📊 *FIGHT RECAP*",
        _line(u1, s1),
        _line(u2, s2),
        f"⏱️ {st.get('turns', 0)} actions · {dur_str}",
        f"🏅 Most damage: *{top['name']}* ({fmt_num(top['dmg'])})",
    ]
    return "\n".join(lines)

def _pvp_series_key(au, du):
    return frozenset((au, du))

def _pvp_series_bump(au, du, winner_id, a_name, d_name):
    """Record a fight result in the best-of-3 series. Returns (score_str,
    series_over, series_winner_name) or (None, False, None) if no winner."""
    if winner_id is None:
        return None, False, None
    key = _pvp_series_key(au, du)
    ser = _pvp_series.get(key)
    if not ser:
        ser = {"score": {au: 0, du: 0}, "name": {au: a_name, du: d_name}}
        _pvp_series[key] = ser
    ser["name"][au] = a_name
    ser["name"][du] = d_name
    ser["score"][winner_id] = ser["score"].get(winner_id, 0) + 1
    sa, sd = ser["score"].get(au, 0), ser["score"].get(du, 0)
    score_str = f"{ser['name'][au]} *{sa}* — *{sd}* {ser['name'][du]}"
    if max(sa, sd) >= _PVP_SERIES_TARGET:
        win_name = ser["name"][winner_id]
        _pvp_series.pop(key, None)
        return score_str, True, win_name
    return score_str, False, None

# ── PVP RATING (ELO-STYLE) ────────────────────────────────────────────────────
_PVP_RATING_BASE = 1000
def _pvp_rating(p):
    return safe_int(p.get("pvp_rating"), _PVP_RATING_BASE) or _PVP_RATING_BASE

def _pvp_rank_name(rating):
    if rating >= 1600: return "🔱 Grandmaster"
    if rating >= 1450: return "💎 Master"
    if rating >= 1300: return "🥇 Diamond"
    if rating >= 1180: return "🥈 Platinum"
    if rating >= 1080: return "🥉 Gold"
    if rating >= 980:  return "⚔️ Silver"
    if rating >= 880:  return "🛡️ Bronze"
    return "🔰 Unranked"

def _apply_pvp_rating(winner_id, loser_id):
    """Symmetric ELO update on a decisive PvP finish. K-factor 32, floored so a
    win always nets at least +5 and a loss never drops you below 100. Updates
    peak. Returns (winner_delta, loser_delta, new_w_rating, new_l_rating) or
    None if either side isn't a real distinct player."""
    if not winner_id or not loser_id or winner_id == loser_id:
        return None
    wp = get_player(winner_id); lp = get_player(loser_id)
    if not wp or not lp:
        return None
    rw, rl = _pvp_rating(wp), _pvp_rating(lp)
    exp_w = 1.0 / (1.0 + 10 ** ((rl - rw) / 400.0))
    K = 32
    dw = max(5, round(K * (1.0 - exp_w)))
    dl = max(5, round(K * exp_w))
    new_w = rw + dw
    new_l = max(100, rl - dl)
    wp["pvp_rating"] = new_w
    wp["pvp_peak_rating"] = max(safe_int(wp.get("pvp_peak_rating"), new_w), new_w)
    lp["pvp_rating"] = new_l
    save_player(wp); save_player(lp)
    return dw, -(rl - new_l), new_w, new_l

async def _auto_delete_pvp_card(bot, uid, chat_id, msg_id, delay=300):
    """Delete a PvP battle card after `delay` seconds if it hasn't been replaced."""
    await asyncio.sleep(delay)
    stored = _pvp_dm_last_msg.get(uid)
    if stored and stored[1] == msg_id:
        _pvp_dm_last_msg.pop(uid, None)
        try:
            await bot.delete_message(chat_id=chat_id, message_id=msg_id)
        except Exception:
            pass

def _pvp_pair_key(a, b):
    """Return whichever direction of (a,b)/(b,a) exists in _pvp_cards, or (a,b)."""
    if (a, b) in _pvp_cards: return (a, b)
    if (b, a) in _pvp_cards: return (b, a)
    return (a, b)


def _class_companion_strike(attacker, deal_dmg_fn, apply_to_defender_fn=None):
    """
    Fire the class-specific built-in companion auto-proc on every attack.
    deal_dmg_fn(raw) -> actual_dealt  (caller handles defense for PvP; direct for enc/boss)
    apply_to_defender_fn(effect, val) -> apply status to defender (optional, PvP only)
    Returns list of text lines to append to the combat action message.
    """
    line = get_class_line(attacker)
    pks  = get_all_passive_keys(attacker)
    path = attacker.get("class_path")
    lvl  = attacker.get("level", 1)
    lines = []

    # ── WARRIOR — Blade Wraith 👻 ────────────────────────────────────────────
    if line == "warrior":
        raw = round(get_stat(attacker, "STR") * 0.6 + lvl * 3)
        if "iron_bulwark" in pks or "einherjar_will" in pks: raw = round(raw * 1.4)
        elif "iron_will" in pks or "celestial_wrath" in pks: raw = round(raw * 1.2)
        dealt = deal_dmg_fn(raw)
        lines.append(f"👻 *Blade Wraith* echoes the strike for *{dealt} dmg*!")
        if path == "A" and random.random() < 0.30 and apply_to_defender_fn:
            apply_to_defender_fn("burn", 2)
            lines.append("🔥 Wraith ignites the target! *Burn ×2*")
        elif path == "B" and random.random() < 0.25 and apply_to_defender_fn:
            apply_to_defender_fn("def_reflect_hits", 1)
            lines.append("🛡️ Wraith's echo reinforces your guard!")

    # ── SERPENT — Snake Companion 🐍 ─────────────────────────────────────────
    elif line == "serpent":
        raw = round((get_stat(attacker,"STR") + get_stat(attacker,"AGI")) * 0.5 + lvl * 3)
        if "serpentine_mastery" in pks or "immortal_coils" in pks: raw = round(raw * 1.2)
        elif "death_venom" in pks or "coiling_stance" in pks: raw = round(raw * 1.1)
        dealt = deal_dmg_fn(raw)
        lines.append(f"🐍 *Serpent Companion* strikes for *{dealt} dmg*!")
        if path == "A" and apply_to_defender_fn:
            apply_to_defender_fn("poison_stacks", 1)
        elif path == "B" and random.random() < 0.35 and apply_to_defender_fn:
            apply_to_defender_fn("distract_turns", 1)
            lines.append("🐍 *Serpent coils around the target!* Distracted ×1 (30% miss chance)!")

    # ── MAGE — Arcane Familiar 🔮 ────────────────────────────────────────────
    elif line == "mage":
        raw = round(get_stat(attacker, "INT") * 0.7 + lvl * 2.5)
        if "eternal_arcanum" in pks or "void_throne" in pks: raw = round(raw * 1.4)
        elif "arcane_mind" in pks or "arcane_shield" in pks: raw = round(raw * 1.2)
        dealt = deal_dmg_fn(raw)
        lines.append(f"🔮 *Arcane Familiar* fires an arcane bolt for *{dealt} dmg*!")
        if path == "A" and random.random() < 0.35:
            bonus = deal_dmg_fn(round(raw * 0.6))
            lines.append(f"✨ *Double Blast!* Familiar fires again for *{bonus} dmg*!")
        elif path == "B" and random.random() < 0.20 and apply_to_defender_fn:
            apply_to_defender_fn("silence_turns", 1)
            lines.append("🔇 *Arcane Silence!* Target silenced for 1 turn!")

    # ── THIEF — Shadow Clone 🌑 ──────────────────────────────────────────────
    elif line == "thief":
        raw = round((get_stat(attacker,"DEX") + get_stat(attacker,"LUK")) * 0.45 + lvl * 2.5)
        if "final_cut" in pks or "soul_ripper" in pks: raw = round(raw * 1.4)
        elif "death_whirl" in pks or "adrenaline" in pks: raw = round(raw * 1.2)
        dealt = deal_dmg_fn(raw)
        lines.append(f"🌑 *Shadow Clone* lunges from darkness for *{dealt} dmg*!")
        if path == "A" and random.random() < 0.35 and apply_to_defender_fn:
            apply_to_defender_fn("distract_turns", 2)
            lines.append("💨 *Smoke Bomb!* Target distracted ×2 (30% miss chance)!")
        elif path == "B" and random.random() < 0.30:
            crit_bonus = deal_dmg_fn(round(raw * 0.8))
            lines.append(f"⚡ *Shadow Crit!* Clone follows up for *{crit_bonus} dmg*!")

    # ── ARCHER — Trap System 🪤 ──────────────────────────────────────────────
    elif line == "archer":
        raw = round(get_stat(attacker, "DEX") * 0.65 + lvl * 3)
        if "dead_or_alive" in pks or "headshot" in pks: raw = round(raw * 1.4)
        elif "steady_aim" in pks or "railfinder" in pks: raw = round(raw * 1.2)
        dealt = deal_dmg_fn(raw)
        if path == "A" and random.random() < 0.40 and apply_to_defender_fn:
            lines.append(f"💨 *Smoke Screen!* Target blinded for *{dealt} dmg*!")
            apply_to_defender_fn("distract_turns", 3)
        elif path == "B" and random.random() < 0.35 and apply_to_defender_fn:
            lines.append(f"🪤 *Bear Trap* snaps for *{dealt} dmg*!")
            apply_to_defender_fn("stun_turns", 1)
        else:
            lines.append(f"🪤 *Trap* triggers for *{dealt} dmg*!")

    # ── PRIEST — Guardian Spirit 🕊️ ──────────────────────────────────────────
    elif line == "priest":
        raw = round(get_stat(attacker, "WIS") * 0.55 + lvl * 2.5)
        if "divine_rosary" in pks or "eternal_verdict" in pks: raw = round(raw * 1.4)
        elif "divine_presence" in pks or "resurrection" in pks: raw = round(raw * 1.2)
        dealt = deal_dmg_fn(raw)
        lines.append(f"🕊️ *Guardian Spirit* smites for *{dealt} holy dmg*!")
        if path == "A":
            heal = round(calc_max_hp(attacker) * 0.05)
            attacker["hp"] = min(calc_max_hp(attacker), attacker["hp"] + heal)
            lines.append(f"💚 Spirit restores *{heal} HP* to you!")
        elif path == "B" and random.random() < 0.25 and apply_to_defender_fn:
            apply_to_defender_fn("branded_hits", 2)
            lines.append("✨ *Holy Brand!* Target branded ×2 (takes +30% dmg)!")

    # ── BOTANIST — Thorned Vine 🌿 ───────────────────────────────────────────
    elif line == "botanist":
        raw = round(get_stat(attacker, "WIS") * 0.60 + lvl * 2.5)
        if "primordial_root" in pks or "root_of_worlds" in pks: raw = round(raw * 1.4)
        elif "eternal_bloom" in pks or "primal_fury" in pks: raw = round(raw * 1.2)
        dealt = deal_dmg_fn(raw)
        lines.append(f"🌿 *Thorned Vine* whips for *{dealt} nature dmg*!")
        if path == "A" and apply_to_defender_fn:
            apply_to_defender_fn("bleed_stacks", 1)
            lines.append("🩸 Vine cuts deep — *Bleed* applied!")
        elif path == "B":
            heal = round(dealt * 0.40)
            attacker["hp"] = min(calc_max_hp(attacker), attacker["hp"] + heal)
            lines.append(f"🌸 Vine siphons life — *+{heal} HP*!")

    # ── ENCHANTRESS — Cursed Puppet 🎭 ──────────────────────────────────────
    elif line == "enchantress":
        raw = round(get_stat(attacker, "INT") * 0.55 + lvl * 2.5)
        if "dooms_conduit" in pks or "aria_eternal" in pks: raw = round(raw * 1.4)
        elif "empress_dread" in pks or "misery_aura" in pks: raw = round(raw * 1.2)
        dealt = deal_dmg_fn(raw)
        lines.append(f"🎭 *Cursed Puppet* corrupts for *{dealt} dmg*!")
        if random.random() < 0.40 and apply_to_defender_fn:
            apply_to_defender_fn("hex_turns", 2)
            lines.append("💜 *Puppet Hex!* Target hexed ×2 (25% less dmg for 2 hits)!")

    # ── VALKYRIE — Shield Maiden ⚡ ───────────────────────────────────────────
    elif line == "valkyrie":
        raw = round((get_stat(attacker,"STR") + get_stat(attacker,"DEF")) * 0.4 + lvl * 3)
        if "choosers_aegis" in pks or "mjolnirs_rage" in pks: raw = round(raw * 1.4)
        elif "celestial_wrath" in pks or "iron_bulwark" in pks: raw = round(raw * 1.2)
        dealt = deal_dmg_fn(raw)
        lines.append(f"⚡ *Shield Maiden* strikes with thunder for *{dealt} dmg*!")
        hp_pct = attacker["hp"] / max(1, calc_max_hp(attacker))
        if hp_pct < 0.40:
            rally = round(calc_max_hp(attacker) * 0.06)
            attacker["hp"] = min(calc_max_hp(attacker), attacker["hp"] + rally)
            lines.append(f"🔱 *Valkyrie's Will!* +{rally} HP — refuse to fall!")

    # ── PHANTOM DANCER — Phantom Echo 💃 ────────────────────────────────────
    elif line == "phantom_dancer":
        raw = round((get_stat(attacker,"AGI") + get_stat(attacker,"DEX")) * 0.45 + lvl * 2.5)
        if "ethereal_sovereign" in pks or "eternal_waltz" in pks: raw = round(raw * 1.4)
        elif "final_performance" in pks or "flourish" in pks: raw = round(raw * 1.2)
        dealt = deal_dmg_fn(raw)
        lines.append(f"💃 *Phantom Echo* dances through for *{dealt} dmg*!")
        if random.random() < 0.30 and apply_to_defender_fn:
            apply_to_defender_fn("distract_turns", 2)
            lines.append("🌀 *Phantom Blur!* Target confused ×2 (30% miss chance)!")

    return lines


def _pvp_fight_card(viewer_p, opp_p, action_text, pair=None):
    def _bar(hp, mx, w=14):
        f = round(max(0, min(int(hp), int(mx))) / max(1, int(mx)) * w)
        return "█" * f + "░" * (w - f)
    v_hp = max(0, int(viewer_p.get("hp", 0)))
    v_mx = max(1, int(viewer_p.get("max_hp", 100)))
    o_hp = max(0, int(opp_p.get("hp", 0)))
    o_mx = max(1, int(opp_p.get("max_hp", 100)))
    vn = str(viewer_p.get("username", "You"))[:16]
    on = str(opp_p.get("username", "Foe"))[:16]
    _k = _get_king()
    if _k:
        if _k.get("uid") == viewer_p.get("user_id"): vn = "👑" + vn
        if _k.get("uid") == opp_p.get("user_id"):    on = "👑" + on
    v_lvl = viewer_p.get("level", 1)
    o_lvl = opp_p.get("level", 1)
    v_pct = round(v_hp / v_mx * 100)
    o_pct = round(o_hp / o_mx * 100)
    v_status = _compact_status_emojis(viewer_p)
    o_status = _compact_status_emojis(opp_p)
    v_shield = safe_int(viewer_p.get("shield_hp"))
    o_shield = safe_int(opp_p.get("shield_hp"))
    v_sh_str = f"  🛡️{v_shield}" if v_shield > 0 else ""
    o_sh_str = f"  🛡️{o_shield}" if o_shield > 0 else ""
    v_mp = safe_int(viewer_p.get("mp")); v_mxmp = safe_int(viewer_p.get("max_mp")) or calc_max_mp(viewer_p)
    o_mp = safe_int(opp_p.get("mp"));   o_mxmp = safe_int(opp_p.get("max_mp")) or calc_max_mp(opp_p)
    lines = []
    # Best-of-3 series header (only if a series is in progress between these two)
    _vu, _ou = viewer_p.get("user_id"), opp_p.get("user_id")
    _ser = _pvp_series.get(_pvp_series_key(_vu, _ou)) if (_vu and _ou) else None
    if _ser:
        _vs = _ser["score"].get(_vu, 0); _os = _ser["score"].get(_ou, 0)
        lines.append(f"🎯 Series *{_vs}—{_os}* _(first to {_PVP_SERIES_TARGET})_")
    lines += [
        f"👤 *{vn}*  Lv{v_lvl}",
        f"`{_bar(v_hp, v_mx)}`  {v_pct}%{v_sh_str}",
        f"💙 {v_mp}/{v_mxmp} MP",
    ]
    if v_status:
        lines.append(f"↳ {v_status}")
    lines.append("──────────────────")
    lines.append(f"👾 *{on}*  Lv{o_lvl}")
    lines.append(f"`{_bar(o_hp, o_mx)}`  {o_pct}%{o_sh_str}")
    lines.append(f"💙 {o_mp}/{o_mxmp} MP")
    if o_status:
        lines.append(f"↳ {o_status}")
    # Live damage tally
    if pair is not None:
        _dst = _pvp_stats.get(pair)
        if _dst and _vu in _dst and _ou in _dst:
            lines.append(f"⚔️ Dmg: you *{fmt_num(_dst[_vu]['dmg'])}* · them *{fmt_num(_dst[_ou]['dmg'])}*")
    # On-card battle log (replaces the separate log message — halves API calls)
    if pair is not None:
        logs = _pvp_battle_logs.get(pair, [])
        if logs:
            lines.append("──────────────────")
            for entry in logs[-2:]:
                e_lines = [l.strip() for l in entry.split("\n") if l.strip()]
                if e_lines:
                    lines.append("▸ " + e_lines[0][:120])
                    for extra in e_lines[1:3]:
                        lines.append(f"  ↳ {extra[:90]}")
    return "\n".join(lines)


_pvp_card_ts = {}     # uid -> last card send time (per-player pacing)
_pvp_render_seq = {}  # uid -> latest render sequence (stale renders are dropped)
_pvp_card_locks = {}  # uid -> asyncio.Lock serializing card delivery per viewer
_pvp_last_action = {} # pair -> time.time() of last combat action (idle-draw watchdog)

async def _pvp_notify_both(pair, a, d, au_id, du_id, action_text, bot):
    """Deliver a PvP turn as a FRESH card to each player (send new → delete
    old), same mechanic as the dungeon revamp. The battle log rides on the
    card itself, so one send per player replaces what used to be four inline
    edits per action. Falls back to editing the old card if the send is
    throttled, so one path always lands.

    Deliveries are SEQUENCED per viewer: rapid actions produce overlapping
    renders, and without ordering an older render (with pre-hit HP) could
    land after a newer one and become the visible card — making damage look
    like it never applied. Each render takes a sequence number; superseded
    renders are dropped instead of sent."""
    _pvp_cards.setdefault(pair, {})
    _pvp_last_action[pair] = time.time()  # fight is alive — reset idle-draw clock
    async def _upd_card(viewer_uid, viewer_p, opp_uid, opp_p):
        try:
            card = _pvp_fight_card(viewer_p, opp_p, action_text, pair=pair)
        except Exception:
            card = action_text
        try:
            markup = _build_pvp_card_markup(viewer_uid, opp_uid, viewer_p, opp_p)
        except Exception:
            markup = None

        my_seq = _pvp_render_seq.get(viewer_uid, 0) + 1
        _pvp_render_seq[viewer_uid] = my_seq
        dlock = _pvp_card_locks.setdefault(viewer_uid, asyncio.Lock())
        async with dlock:
            if _pvp_render_seq.get(viewer_uid) != my_seq:
                return  # a newer turn already rendered — don't send stale HP

            # Pace card sends per player (~1/sec — Telegram's DM send budget)
            _since = time.time() - _pvp_card_ts.get(viewer_uid, 0)
            if _since < 1.0:
                await asyncio.sleep(1.0 - _since)
            if _pvp_render_seq.get(viewer_uid) != my_seq:
                return  # superseded while pacing — the newer render delivers

            await _upd_card_locked(viewer_uid, card, markup)

    async def _upd_card_locked(viewer_uid, card, markup):
        stored = _pvp_dm_last_msg.get(viewer_uid)

        async def _edit_old():
            if not stored:
                raise ValueError("no card to edit")
            await asyncio.wait_for(bot.edit_message_text(
                chat_id=stored[0], message_id=stored[1],
                text=card, parse_mode="Markdown", reply_markup=markup), timeout=8)

        # Primary: fresh card, then remove the old one
        try:
            msg = await asyncio.wait_for(bot.send_message(
                chat_id=viewer_uid, text=card,
                parse_mode="Markdown", reply_markup=markup), timeout=8)
            _pvp_dm_last_msg[viewer_uid] = (viewer_uid, msg.message_id)
            _pvp_card_ts[viewer_uid] = time.time()
            if stored and stored[1] != msg.message_id:
                async def _rm_old(cid=stored[0], mid=stored[1]):
                    try:
                        await bot.delete_message(chat_id=cid, message_id=mid)
                    except Exception:
                        # Can't delete (permissions/age) — at least strip the
                        # old card's buttons so it can't be tapped
                        try:
                            await bot.edit_message_reply_markup(
                                chat_id=cid, message_id=mid, reply_markup=None)
                        except Exception:
                            pass
                _t = asyncio.create_task(_rm_old())
                _bg_tasks.add(_t); _t.add_done_callback(_bg_tasks.discard)
            _t2 = asyncio.create_task(_auto_delete_pvp_card(bot, viewer_uid, viewer_uid, msg.message_id))
            _bg_tasks.add(_t2); _t2.add_done_callback(_bg_tasks.discard)
            return
        except RetryAfter as e:
            # Send throttled — update the old card in place instead
            try:
                await _edit_old()
                _pvp_card_ts[viewer_uid] = time.time()
                return
            except Exception:
                pass
            try:
                await asyncio.sleep(min(6, float(getattr(e, "retry_after", 3)) + 0.5))
                msg = await asyncio.wait_for(bot.send_message(
                    chat_id=viewer_uid, text=card,
                    parse_mode="Markdown", reply_markup=markup), timeout=8)
                _pvp_dm_last_msg[viewer_uid] = (viewer_uid, msg.message_id)
                _pvp_card_ts[viewer_uid] = time.time()
                return
            except Exception:
                return
        except Exception:
            pass  # blocked bot / network — try the in-place edit as last resort
        try:
            await _edit_old()
            _pvp_card_ts[viewer_uid] = time.time()
        except Exception:
            pass
    await asyncio.gather(_upd_card(au_id, a, du_id, d), _upd_card(du_id, d, au_id, a))


# (the separate live battle-log message was removed — the log now rides on
#  the fight card itself, halving API calls per action)

async def _finalize_pvp(pair, result_text, bot, winner_id=None):
    # Settle spectator bets first (refunds if no winner known)
    try:
        await _resolve_fight_bets(bot, pair, winner_id, result_text)
    except Exception:
        pass
    # ── RATING: ELO update on a decisive finish (before recap, so we can show it)
    _rating_line = ""
    if winner_id and len(pair) == 2:
        try:
            _loser_id = pair[0] if pair[1] == winner_id else pair[1]
            _elo = _apply_pvp_rating(winner_id, _loser_id)
            if _elo:
                _dw, _dl, _nw, _nl = _elo
                _wp = get_player(winner_id)
                _rating_line = (f"📈 *{(_wp or {}).get('username','?')}* +{_dw} rating "
                                f"→ {_nw} ({_pvp_rank_name(_nw)})")
        except Exception:
            logger.error("elo update failed", exc_info=True)
    # ── FIGHT CARD 2.0: group recap + best-of-3 series ──────────────────────
    _grp_recap = _pvp_origin_chat.get(pair)
    if _grp_recap and len(pair) == 2:
        try:
            _recap = _pvp_summary_text(pair, winner_id)
            _u1, _u2 = pair
            _n1 = _pvp_stats.get(pair, {}).get(_u1, {}).get("name", "?")
            _n2 = _pvp_stats.get(pair, {}).get(_u2, {}).get("name", "?")
            _score_str, _series_over, _series_win = _pvp_series_bump(
                _u1, _u2, winner_id, _n1, _n2)
            _extra = []
            if _rating_line:
                _extra.append(_rating_line)
            if _score_str:
                if _series_over:
                    _extra.append(f"🏆 *SERIES WON by {_series_win}!*  ({_score_str})")
                else:
                    _extra.append(f"🎯 *Series:* {_score_str}  _(first to {_PVP_SERIES_TARGET})_")
            _full_recap = _recap + (("\n\n" + "\n".join(_extra)) if _extra else "")
            if _full_recap.strip():
                asyncio.create_task(announce(bot, _grp_recap, _full_recap, delay=45))
        except Exception:
            logger.error("fight recap failed", exc_info=True)
    _pvp_stats.pop(pair, None)
    _pvp_cards.pop(pair, None)
    _pvp_battle_logs.pop(pair, None)
    _pvp_cur_page.pop(pair, None)
    _pvp_origin_chat.pop(pair, None)
    _pvp_last_action.pop(pair, None)
    _cancel_card_timer(pair)  # cancel, don't just drop — or the pending
                              # auto-delete later removes the final result card
    if len(pair) == 2:
        _f_au, _f_du = pair
        _f_a = get_player(_f_au)
        _f_d = get_player(_f_du)
        async def _fin_card(viewer_uid, vp, op):
            if not vp or not op:
                # At minimum send the defeat text as a plain DM
                try:
                    await bot.send_message(chat_id=viewer_uid, text=result_text[:4096],
                                           parse_mode="Markdown")
                except Exception:
                    pass
                return
            try:
                card = _pvp_fight_card(vp, op, result_text)
            except Exception:
                card = ""
            # Append the full result text below the HP card so defeat/win is visible
            full_text = (card + "\n\n" + result_text)[:4096] if card else result_text[:4096]
            stored = _pvp_dm_last_msg.get(viewer_uid)
            _opp_uid = _f_du if viewer_uid == _f_au else _f_au
            _rematch = InlineKeyboardMarkup([[InlineKeyboardButton(
                "⚔️ Rematch", callback_data=f"pvprematch_{viewer_uid}_{_opp_uid}")]])
            # Fresh final card, then remove the old combat card (same mechanic
            # as mid-fight turns); falls back to editing the old card in place
            try:
                await bot.send_message(chat_id=viewer_uid, text=full_text,
                                       parse_mode="Markdown", reply_markup=_rematch)
                if stored:
                    try: await bot.delete_message(chat_id=stored[0], message_id=stored[1])
                    except Exception: pass
                return
            except Exception:
                pass
            if stored:
                try:
                    await bot.edit_message_text(chat_id=stored[0], message_id=stored[1],
                                                text=full_text, parse_mode="Markdown",
                                                reply_markup=_rematch)
                except Exception:
                    pass
        await asyncio.gather(_fin_card(_f_au, _f_a, _f_d), _fin_card(_f_du, _f_d, _f_a))
        # (final result is on the fight card itself — no separate log message)
        # Clear all combat status effects for both players so they don't bleed into the next fight
        _status_fields = (
            "poison_stacks","poison_pct","poison_damage",
            "burn_stacks","burn_pct","burn_damage",
            "bleed_stacks","bleed_pct","bleed_damage",
            "ward_charges","shield_charges","exposed_hits","marked_hits","branded_hits","weakened_hits",
            "vanish_turns","regen_charges","regen_amt",
            "heal_blocked_turns","revive_blocked_turns","silence_turns","hex_turns",
            "stun_turns","freeze_turns","entangle_turns","distract_turns",
            "dodge_momentum",
        )
        # Legacy timestamp-based status effects (separate mechanism from the turn/stack
        # fields above) — these must also be cleared or they bleed into the next PvP fight.
        # defeated_until/invincible_until are intentionally excluded: those represent
        # post-fight cooldown/grace states, not in-combat buffs.
        _status_until_fields = (
            "ward_until","holy_field_until","hexed_until","blessed_until","weakened_until",
            "distracted_until","entangled_until","frozen_until","stunned_until","vanish_until",
            "bleed_until","poison_until","burn_until","exposed_until","branded_until","marked_until",
            "silenced_until","healing_blocked_until","revival_blocked_until","temp_hp_until",
            "def_reflect_until","cursed_until",
        )
        for _sp in (_f_a, _f_d):
            if _sp:
                for _sf in _status_fields:
                    _sp[_sf] = 0
                for _suf in _status_until_fields:
                    _sp[_suf] = None
                save_player(_sp)
        # Clear per-fight item state (Abyssal Plate, Crystal Golem, Cryptwalker, etc.)
        for _uid in pair:
            _pvp_battle_state.pop(_uid, None)
    for _uid in pair:
        _pvp_dm_last_msg.pop(_uid, None)
        _pvp_log_msg.pop(_uid, None)
        _pvp_card_ts.pop(_uid, None)
        _pvp_render_seq.pop(_uid, None)
        _pvp_card_locks.pop(_uid, None)
    if len(pair) == 2:
        _pvp_miss_streaks.pop((pair[0], pair[1]), None)
        _pvp_miss_streaks.pop((pair[1], pair[0]), None)


async def _pvp_idle_watch_loop(bot):
    """Fights with no action for 5 minutes end in a DRAW: statuses cleared,
    spectator bets refunded, cards closed. Before this, abandoned fights just
    lingered forever with live buttons and sticky status effects."""
    while True:
        await asyncio.sleep(60)
        try:
            now = time.time()
            for pair in list(_pvp_origin_chat.keys()):
                last = _pvp_last_action.get(pair)
                if last and now - last > 300:
                    try:
                        await _finalize_pvp(pair,
                            "🏳️ *DRAW* — the fight fizzled out (no actions for 5 minutes).\n"
                            "_Status effects cleared; spectator bets refunded._",
                            bot, winner_id=None)
                    except Exception:
                        logger.error("idle-draw finalize failed for %s", pair, exc_info=True)
                        _pvp_last_action.pop(pair, None)
        except Exception:
            logger.error("pvp idle watch error", exc_info=True)

def _pvp_attack_allowed(a, d):
    """Gate for STARTING a PvP attack. Returns (True, '') or (False, reason).
    Counterattacks inside an existing fight are always allowed."""
    auid, duid = safe_int(a.get("user_id")), safe_int(d.get("user_id"))
    pair = _pvp_pair_key(auid, duid)
    in_fight = pair in _pvp_origin_chat
    if not in_fight and safe_int(d.get("level"), 1) < 10 and safe_int(a.get("level"), 1) >= 10:
        return (False, f"🐣 *{d.get('username','?')}* is under *Newbie Protection* (below level 10) — "
                       "they can't be attacked unless they strike first.")
    if duid in active_dungeons:
        return (False, f"🏚️ *{d.get('username','?')}* is deep in a dungeon — you can't reach them.")
    if duid in active_encounters:
        return (False, f"⚔️ *{d.get('username','?')}* is mid-encounter — you can't reach them.")
    if auid in active_dungeons:
        return (False, "🏚️ You're in a dungeon — finish or flee before starting PvP.")
    if auid in active_encounters:
        return (False, "⚔️ You're mid-encounter — finish it before starting PvP.")
    return (True, "")

def _reset_card_timer(pair, bot, chat_id, mid, seconds=20):
    """Cancel any existing auto-delete task for this card and schedule a fresh one."""
    old = _pvp_card_tasks.pop(pair, None)
    if old and not old.done():
        old.cancel()
    task = asyncio.create_task(_auto_delete(bot, chat_id, mid, seconds))
    _pvp_card_tasks[pair] = task
    _bg_tasks.add(task)
    task.add_done_callback(_bg_tasks.discard)

def _cancel_card_timer(pair):
    old = _pvp_card_tasks.pop(pair, None)
    if old and not old.done():
        old.cancel()

# ── RATE LIMITER ──────────────────────────────────────────────────────────────
# Commands and ordinary chat messages get SEPARATE buckets. They used to share
# _cmd_timestamps, so an active chatter (8 messages in 6s) filled the bucket
# with plain conversation and their next command was silently swallowed by the
# pre-filter — "certain commands randomly do nothing" until a few quiet seconds
# passed. Chatting must never consume command budget.
_cmd_timestamps    = {}   # user_id -> [float timestamps]  (commands only)
_chat_timestamps   = {}   # user_id -> [float timestamps]  (non-command messages)
_rate_warn_ts      = {}   # user_id -> last "slow down" warning time
_processing_users  = {}  # user_id -> lock acquire time; users inside a state-changing callback
_CB_LOCK_STALE_SECS = 30  # a leaked lock (unhandled exception) self-heals after this long

def _rate_ok(uid: int, max_cmds: int = 8, window: float = 6.0, _store=None) -> bool:
    """Return True if the user is within the rate limit, False if they're spamming."""
    store = _cmd_timestamps if _store is None else _store
    now = time.time()
    times = store.get(uid, [])
    times = [t for t in times if now - t < window]
    if len(uid_times := times) >= max_cmds:
        store[uid] = uid_times
        return False
    times.append(now)
    store[uid] = times
    return True

def _chat_rate_ok(uid: int) -> bool:
    """Rate limit for ordinary chat messages (EXP ticks etc.) — its own bucket,
    higher ceiling: fast group conversation is normal, not abuse."""
    return _rate_ok(uid, max_cmds=15, window=6.0, _store=_chat_timestamps)

def _cb_lock(uid: int):
    """Acquire a processing lock for a callback. Returns a truthy token on
    success, None if already held. Locks older than _CB_LOCK_STALE_SECS are
    treated as leaked (an exception skipped the unlock) and are re-acquirable,
    so a player can never be frozen out of buttons until restart."""
    now = time.time()
    ts = _processing_users.get(uid)
    if ts is not None and now - ts < _CB_LOCK_STALE_SECS:
        return None
    _processing_users[uid] = now
    return now

def _cb_unlock(uid: int, token=None):
    """Release the lock. With a token, only releases if the lock is still the
    one that token was issued for — so a handler that already unlocked early
    (and whose lock was then re-acquired by a newer tap) can't accidentally
    release the newer tap's lock from its finally block."""
    if token is None or _processing_users.get(uid) == token:
        _processing_users.pop(uid, None)

# ── SEND HELPERS ──────────────────────────────────────────────────────────────
async def _q_edit(query, *args, **kwargs):
    """query.edit_message_text that tolerates Telegram's 'Message is not
    modified' refusal — re-rendering an identical card (e.g. feeding an
    already-full pet) is a no-op, not an error worth crashing the handler."""
    try:
        return await query.edit_message_text(*args, **kwargs)
    except BadRequest as e:
        _el = str(e).lower()
        if "not modified" in _el:
            return None
        if "to edit not found" in _el or "be edited" in _el:
            # The card was auto-deleted (or cleaned up) but the button lived on
            # in the client — tell the tapper instead of crashing the handler.
            try:
                await query.answer("⌛ That card has expired — run the command again.")
            except Exception:
                pass
            return None
        if "parse entities" in _el or "can't find end of the entity" in _el:
            # Dynamic content (an item name, username, etc.) contained a stray
            # markdown character. Retry WITHOUT parse_mode so the edit lands as
            # plain text instead of crashing the handler.
            _kw = dict(kwargs); _kw.pop("parse_mode", None)
            try:
                return await query.edit_message_text(*args, **_kw)
            except Exception:
                return None
        raise

async def _auto_delete(bot, chat_id, msg_id, delay):
    await asyncio.sleep(delay)
    try:
        await bot.delete_message(chat_id=chat_id, message_id=msg_id)
    except Exception:
        pass

def _md_escape(s):
    """Escape Telegram-Markdown special chars in dynamic text (usernames, item
    names) so a stray * _ ` [ can't break the whole message's parsing."""
    return re.sub(r"([_*`\[])", r"\\\1", str(s))

async def send_group(update: Update, text: str, parse_mode="Markdown",
                     permanent=False, delay=9, reply_markup=None):
    chat_id = update.effective_chat.id
    user_id = update.effective_user.id
    # Escape the display name — Telegram names can contain * _ ` [ which would
    # otherwise break Markdown parsing for the entire message.
    name_hdr = f"👤 *{_md_escape(update.effective_user.first_name)}*\n"
    text = name_hdr + text
    key     = (chat_id, user_id)
    old_id  = last_bot_message.get(key)
    results = await asyncio.gather(
        update.get_bot().send_message(
            chat_id=chat_id, text=text[:4096],
            parse_mode=parse_mode, reply_markup=reply_markup),
        update.get_bot().delete_message(chat_id=chat_id, message_id=old_id)
            if old_id else asyncio.sleep(0),
        update.message.delete() if update.message else asyncio.sleep(0),
        return_exceptions=True
    )
    new_msg = results[0]
    if isinstance(new_msg, Exception):
        # Retry — and if it was a Markdown parse failure, drop parse_mode so the
        # message lands as plain text instead of vanishing.
        _pm = None if "parse entities" in str(new_msg).lower() else parse_mode
        try:
            new_msg = await update.get_bot().send_message(
                chat_id=chat_id, text=text[:4096],
                parse_mode=_pm, reply_markup=reply_markup)
        except Exception:
            try:
                new_msg = await update.get_bot().send_message(
                    chat_id=chat_id, text=text[:4096], reply_markup=reply_markup)
            except Exception:
                return None
    if not permanent:
        last_bot_message[key] = new_msg.message_id
        asyncio.create_task(_auto_delete(
            update.get_bot(), chat_id, new_msg.message_id, delay))
    return new_msg

async def announce(bot, chat_id: int, text: str,
                   parse_mode="Markdown", permanent=False, delay=9):
    try:
        msg = await bot.send_message(
            chat_id=chat_id, text=text[:4096], parse_mode=parse_mode)
    except BadRequest as e:
        if "parse entities" in str(e).lower():
            try:
                msg = await bot.send_message(chat_id=chat_id, text=text[:4096])  # plain
            except Exception:
                return None
        else:
            return None
    except Exception:
        return None
    if not permanent:
        asyncio.create_task(_auto_delete(bot, chat_id, msg.message_id, delay))
    return msg

async def reply_to_dm(update, context, text: str, parse_mode="Markdown"):
    """Send text to the user's DM. If in a group, delete command and post brief notice."""
    user = update.effective_user
    chat = update.effective_chat
    is_group = chat.type in ("group", "supergroup")
    # Always try to delete the user's command (works in groups with admin perm
    # and in private chats within 48h per Telegram API)
    try: await update.message.delete()
    except Exception: pass
    try:
        await context.bot.send_message(chat_id=user.id, text=text[:4096], parse_mode=parse_mode)
        if is_group:
            try:
                notice = await context.bot.send_message(chat_id=chat.id, text="📬 Sent to your DM!", parse_mode="Markdown")
                asyncio.create_task(_auto_delete(context.bot, chat.id, notice.message_id, 5))
            except Exception: pass
    except Exception:
        # Bot not started in DM — fall back to group with auto-delete
        try:
            msg = await context.bot.send_message(chat_id=chat.id, text=text[:4096], parse_mode=parse_mode)
            asyncio.create_task(_auto_delete(context.bot, chat.id, msg.message_id, 30))
        except Exception: pass

async def send_dm_or_group(bot, user_id: int, chat_id: int, text: str,
                            parse_mode="Markdown", group_delay: int = 20):
    """Try to DM the player; fall back to group with auto-delete."""
    try:
        return await bot.send_message(chat_id=user_id, text=text[:4096], parse_mode=parse_mode)
    except Exception:
        msg = await bot.send_message(chat_id=chat_id, text=text[:4096], parse_mode=parse_mode)
        if group_delay > 0:
            asyncio.create_task(_auto_delete(bot, chat_id, msg.message_id, group_delay))
        return msg

# ── SAFE HELPERS ──────────────────────────────────────────────────────────────
def sjl(v, d):
    if v is None: return d
    try: return json.loads(v)
    except: return d

def safe_inv(p):    return sjl(p.get("inventory"), [])
def safe_stats(p):
    return sjl(p.get("stats"),
               {"STR":5,"DEF":0,"AGI":5,"INT":5,"WIS":5,"DEX":5,"LUK":5})
def safe_titles(p): return sjl(p.get("titles"), ["Adventurer"])  # default is Adventurer
def safe_cds(p):    return sjl(p.get("passive_cooldowns"), {})
def safe_int(v, d=0):
    try: return int(v or d)
    except: return d

def resolve_item_ci(typed, collection):
    """Return the canonical item name from collection that matches typed (case-insensitive), or None."""
    typed_l = typed.strip().lower()
    for item in collection:
        if item.lower() == typed_l:
            return item
    return None

