_weather_cache = {"weather":None,"set_at":None}
def get_weather():
    now = datetime.now()
    if not _weather_cache["set_at"] or (now-_weather_cache["set_at"]).seconds > 3600:
        _weather_cache["weather"] = random.choice(WEATHER_TABLE)
        _weather_cache["set_at"]  = now
    return _weather_cache["weather"]

# ── EXP CURVE ─────────────────────────────────────────────────────────────────
# SQLite INTEGER tops out at 2^63-1 (~9.2e18). The old curve blew past that
# around level 180 (lifetime total_exp) and produced per-level requirements in
# the 10^21+ range near the cap — every save for such a player crashed with
# OverflowError. Requirements now flatten at _EXP_REQ_CEIL, and stored EXP/gold
# clamp to _INT_SAFE_MAX at save time, keeping every number storable forever.
_EXP_REQ_CEIL = 10_000_000_000_000_000       # 1e16 — max EXP needed for one level
_INT_SAFE_MAX = 8_000_000_000_000_000_000    # 8e18 — hard cap for stored counters

def exp_for_level(level):
    if level <= 10:   req = level * 20000
    elif level <= 20: req = level * 100000
    elif level <= 30: req = level * 500000
    elif level <= 40: req = level * 3000000
    elif level <= 50: req = level * 10000000
    elif level <= 60: req = level * 40000000
    elif level <= 70: req = level * 150000000
    # ── POST-70: every 10 levels multiplies requirement by ~4-6× ──
    elif level <= 80: req = level * 800000000
    elif level <= 90: req = level * 4000000000
    elif level <= 100: req = level * 20000000000
    elif level <= 110: req = level * 100000000000
    elif level <= 120: req = level * 500000000000
    elif level <= 130: req = level * 2500000000000
    elif level <= 140: req = level * 12000000000000
    elif level <= 150: req = level * 60000000000000
    else:             req = level * 300000000000000
    return min(req, _EXP_REQ_CEIL)

def exp_share(level, pct):
    """EXP equal to `pct` (0.10 = 10%) of the EXP required for `level`.
    Keeps every reward meaningful at any level instead of a flat number
    that is huge at level 1 and irrelevant at level 50."""
    return max(1, round(exp_for_level(max(1, min(250, safe_int(level, 1)))) * pct))

def fmt_num(n):
    """Compact display for big numbers: 12.5K, 3.4M, 2.1B, 3.77T, 1.2Q.
    Values under 10,000 show in full. Display only — stored values unchanged."""
    try:
        n = int(n)
    except (TypeError, ValueError):
        return str(n)
    neg = "-" if n < 0 else ""
    a = abs(n)
    if a < 10000:
        return f"{neg}{a:,}"
    for div, suf in ((10**15, "Q"), (10**12, "T"), (10**9, "B"), (10**6, "M"), (10**3, "K")):
        if a >= div:
            v = a / div
            s = f"{v:.2f}".rstrip("0").rstrip(".") if v < 100 else f"{round(v):,}"
            return f"{neg}{s}{suf}"
    return f"{neg}{a:,}"

def gold_floor(level, amount):
    """Floor for a NONZERO gold reward — no award is ever pocket lint.
    Zero stays zero (a miss is a miss, not an insult)."""
    amount = safe_int(amount)
    if amount <= 0:
        return amount
    return max(25 + max(1, safe_int(level, 1)) * 5, amount)

def scaled_gold(level, base):
    """Level-scaled gold from a legacy flat base: ~+12% per level (the /pool
    curve), then floored via gold_floor. 0 stays 0."""
    base = safe_int(base)
    if base <= 0:
        return 0
    lvl = max(1, safe_int(level, 1))
    return gold_floor(lvl, round(base * (1.0 + (lvl - 1) * 0.12)))

def _scaled_raid_exp(level, flat):
    """Solo-raid completion: legacy flat tier values (280..8000) map to
    15%-30% of the player's current level requirement."""
    pct = 0.15 + 0.15 * min(1.0, flat / 8000)
    return exp_share(level, pct)

def _scaled_boss_exp(level, flat):
    """Group-boss kill share: legacy flat boss values (1600..40000) map to
    6%-35% of each participant's current level requirement."""
    pct = min(0.35, 0.05 + 0.10 * (flat / 16000))
    return exp_share(level, pct)

def _scaled_shot_exp(level, shot_exp):
    """Pool-shot EXP (3s cooldown, spammable): table values (18..4000) map to
    ~0.005%-1% of a level, so rare shots feel great without shots out-earning
    real activities."""
    return exp_share(level, min(0.01, shot_exp / 4000 * 0.01))

def max_hp_for_level(level): return 300 + (level - 1) * 250

