# Defensive ability definitions
PET_DEF_ABILITIES = {
    "intercept":  {"name":"Intercept",     "emoji":"🛡️","desc":"Jumps in front of the attack, absorbing most of the damage for you.", "proc_base":0.28},
    "counter":    {"name":"Counter Strike","emoji":"⚔️","desc":"Retaliates instantly with a fierce counter attack.",           "proc_base":0.26},
    "poison":     {"name":"Venom Bite",    "emoji":"🐍","desc":"Sinks fangs into the attacker, applying stacking poison.",     "proc_base":0.24},
    "stun":       {"name":"Stunning Blow", "emoji":"⚡","desc":"Delivers a blow that stuns the attacker (miss next attack).", "proc_base":0.22},
    "lifesteal":  {"name":"Life Drain",    "emoji":"💜","desc":"Drains 30–45% of incoming damage as HP for you (scales with pet level).", "proc_base":0.24},
    "shield":     {"name":"Aura Shield",   "emoji":"✨","desc":"Projects a protective aura that heavily reduces incoming damage.",    "proc_base":0.30},
}

PERSONALITY_DEFEND = {
    "playful":    "leaps in front of you with a gleeful yip!",
    "fierce":     "snarls and throws itself between you and the attacker!",
    "calm":       "steps forward with quiet, unshakable resolve.",
    "mischievous":"appears from nowhere and intercepts the hit!",
    "loyal":      "refuses to let you take that hit alone.",
    "lazy":       "manages to drag itself over just in time.",
    "greedy":     "protects you — but will expect a snack for this.",
    "timid":      "trembles but holds the line for you.",
}

# EXP needed per pet level
def pet_exp_for_level(lvl): return lvl * 50 + (lvl * lvl * 5)

# Passive bonus unlocks by pet level
PET_LEVEL_PASSIVES = {
    5:   {"atk_flat": 4},
    10:  {"atk_flat": 9},
    15:  {"atk_flat": 12, "crit_bonus": 0.04},
    20:  {"atk_flat": 16, "crit_bonus": 0.06},
    25:  {"atk_flat": 22, "crit_bonus": 0.07, "dodge_bonus": 0.04},
    30:  {"atk_flat": 28, "crit_bonus": 0.10, "dodge_bonus": 0.06},
    40:  {"atk_flat": 36, "crit_bonus": 0.13, "dodge_bonus": 0.07, "lifesteal_flat": 8},
    50:  {"atk_flat": 48, "crit_bonus": 0.16, "dodge_bonus": 0.10, "lifesteal_flat": 16},
    60:  {"atk_flat": 62, "crit_bonus": 0.19, "dodge_bonus": 0.13, "lifesteal_flat": 22},
    75:  {"atk_flat": 80, "crit_bonus": 0.23, "dodge_bonus": 0.17, "lifesteal_flat": 30},
    100: {"atk_flat": 105, "crit_bonus": 0.28, "dodge_bonus": 0.22, "lifesteal_flat": 40},
}

def get_pet_passives(pet_level):
    bonus = {}
    for threshold in sorted(PET_LEVEL_PASSIVES.keys()):
        if pet_level >= threshold:
            bonus = dict(PET_LEVEL_PASSIVES[threshold])
    return bonus

def get_pet_def_proc_chance(pet):
    """Chance that pet's defensive ability triggers when owner is attacked."""
    sp = PET_SPECIES.get(pet.get("species"), {})
    da = sp.get("def_ability")
    if not da: return 0.0
    lvl = pet.get("level", 1)
    if lvl < 10: return 0.0          # ability not yet unlocked
    base = PET_DEF_ABILITIES[da]["proc_base"]
    level_bonus = min(0.30, lvl * 0.004)   # up to +30% at L75
    hunger_ok = pet.get("hunger", 100) >= 20
    mood_ok   = pet.get("mood", 100)   >= 30
    if not hunger_ok or not mood_ok: return 0.0
    bond_bonus = _get_bond_proc_bonus(pet)
    return round(min(0.80, base + level_bonus + bond_bonus), 3)

def apply_pet_defense(pet, attacker, dmg_after_def, extra_notes, owner_max_hp=0):
    """
    Check if the defender's pet triggers its defensive ability.
    Mutates dmg_after_def (returns new value) and appends to extra_notes.
    Also returns any status to apply to attacker: ("poison"|"stun"|None, value).
    """
    if dmg_after_def <= 0:
        return dmg_after_def, None, None
    chance = get_pet_def_proc_chance(pet)
    if chance <= 0 or random.random() > chance:
        return dmg_after_def, None, None
    sp     = PET_SPECIES.get(pet.get("species"), {})
    da     = sp.get("def_ability", "shield")
    lvl    = pet.get("level", 1)
    pers   = sp.get("personality", "calm")
    emoji  = sp.get("emoji", "🐾")
    pname  = pet.get("nickname") or sp.get("name", "Your Pet")
    defend_flavor = PERSONALITY_DEFEND.get(pers, "steps in to defend you!")
    ability_info  = PET_DEF_ABILITIES.get(da, {})
    ab_emoji = ability_info.get("emoji", "🐾")
    status_type = None
    status_val  = None

    if da == "intercept":
        absorb_pct = min(0.60, 0.20 + lvl * 0.005)
        absorbed   = round(dmg_after_def * absorb_pct)
        dmg_after_def = max(0, dmg_after_def - absorbed)
        extra_notes.append(f"{emoji} *{pname}* {defend_flavor}\n{ab_emoji} *Intercept!* Absorbed *{absorbed} dmg*!")

    elif da == "counter":
        counter_dmg = round(5 + lvl * 1.2)
        if attacker:
            attacker["hp"] = max(0, attacker.get("hp", 0) - counter_dmg)
        extra_notes.append(f"{emoji} *{pname}* {defend_flavor}\n{ab_emoji} *Counter Strike!* Deals *{counter_dmg} dmg* back!")

    elif da == "poison":
        poison_dmg = round(4 + lvl * 0.5)
        status_type = "poison"
        status_val  = poison_dmg
        extra_notes.append(f"{emoji} *{pname}* {defend_flavor}\n{ab_emoji} *Venom Bite!* Attacker is *poisoned* ({poison_dmg} dmg/30s)!")

    elif da == "stun":
        status_type = "stun"
        status_val  = 1
        extra_notes.append(f"{emoji} *{pname}* {defend_flavor}\n{ab_emoji} *Stunning Blow!* Attacker is *stunned* — misses next attack!")

    elif da == "lifesteal":
        heal_amt = round(owner_max_hp * 0.10) if owner_max_hp > 0 else round(max(30, dmg_after_def * (0.06 + lvl * 0.001)))
        status_type = "lifesteal_to_owner"
        status_val  = heal_amt
        extra_notes.append(f"{emoji} *{pname}* {defend_flavor}\n{ab_emoji} *Life Drain!* Drained *{heal_amt} HP* from attacker!")

    elif da == "shield":
        shield_pct = min(0.40, 0.10 + lvl * 0.003)
        absorbed   = round(dmg_after_def * shield_pct)
        dmg_after_def = max(0, dmg_after_def - absorbed)
        extra_notes.append(f"{emoji} *{pname}* {defend_flavor}\n{ab_emoji} *Aura Shield!* Shielded *{absorbed} dmg*!")

    return dmg_after_def, status_type, status_val

# Eggs and their hatch pools by rarity weight
PET_EGG_POOLS = {
    "Common Egg":   {"common":0.65,"uncommon":0.30,"rare":0.05},
    "Rare Egg":     {"uncommon":0.40,"rare":0.45,"epic":0.15},
    "Dragon Egg":   {"rare":0.35,"epic":0.50,"legendary":0.15},
    "Mythic Egg":   {"epic":0.40,"legendary":0.45,"mythic":0.15},
}

# Elemental advantage table: strong_against → bonus; weak_against → penalty
ELEMENT_MATCHUPS = {
    "fire":      {"strong": "nature",    "weak": "water"},
    "water":     {"strong": "fire",      "weak": "lightning"},
    "lightning": {"strong": "water",     "weak": "earth"},
    "earth":     {"strong": "lightning", "weak": "nature"},
    "nature":    {"strong": "earth",     "weak": "fire"},
    "shadow":    {"strong": "holy",      "weak": "void"},
    "void":      {"strong": "shadow",    "weak": "holy"},
    "holy":      {"strong": "void",      "weak": "shadow"},
    "wind":      {"strong": "earth",     "weak": "lightning"},
}

# Personality → ATK multiplier in combat
PERSONALITY_ATK_MOD = {
    "fierce":      1.15,  # +15% — aggressive striker
    "mischievous": 1.08,  # +8%  — sneaky hits land harder
    "loyal":       1.05,  # +5%  — steady and reliable
    "lazy":        0.90,  # -10% — doesn't put in full effort
    "calm":        1.00,
    "playful":     1.00,
    "timid":       1.00,
    "greedy":      1.00,
}

def _hatch_species(egg_name):
    """Pick a random species from egg pool, weighted by rarity."""
    pool = PET_EGG_POOLS.get(egg_name)
    if not pool: return None
    roll = random.random()
    cumulative = 0.0
    target_rarity = None
    for rarity, weight in pool.items():
        cumulative += weight
        if roll <= cumulative:
            target_rarity = rarity; break
    if not target_rarity:
        target_rarity = list(pool.keys())[-1]
    candidates = [sid for sid, sd in PET_SPECIES.items() if sd["rarity"] == target_rarity]
    return random.choice(candidates) if candidates else None

def get_pet_atk_bonus(pet):
    """Raw ATK a pet contributes per attack. Bonus when well-fed and happy;
    penalty when neglected. This is the pet's POTENTIAL — in combat it's
    additionally bounded to a fraction of the owner's own hit (see
    _pet_combat_atk) so a pet supplements the player instead of replacing them.
    Scaling is deliberately gentler than the player's (level×2 vs the player's
    level×4) so pet quality/investment scales UP toward the cap without ever
    dwarfing the owner's build."""
    sp = PET_SPECIES.get(pet.get("species"), {})
    base = sp.get("base_atk", 0) * 1.0 + pet.get("level", 1) * 2.0
    passives = get_pet_passives(pet.get("level", 1))
    base += passives.get("atk_flat", 0) * 0.5
    base += _get_bond_atk_bonus(pet)
    evo = pet.get("evolution_stage", 0)
    if evo > 0: base += evo * 15
    # Personality modifier
    pers = sp.get("personality", "calm")
    base = round(base * PERSONALITY_ATK_MOD.get(pers, 1.0))
    # Shiny bonus: +15% ATK
    if pet.get("is_shiny"): base = round(base * 1.15)
    hunger = pet.get("hunger", 100)
    mood   = pet.get("mood", 100)
    # Well-fed AND happy: +25% bonus (reward for good care)
    if hunger >= 70 and mood >= 70:
        base = round(base * 1.25)
    # Very hungry: severely reduced damage
    elif hunger < 20:
        base = round(base * 0.30)
    # Hungry: reduced damage
    elif hunger < 40:
        base = round(base * 0.60)
    # Sad (but not hungry): reduced damage
    elif mood < 20:
        base = round(base * 0.30)
    elif mood < 40:
        base = round(base * 0.60)
    # Collector's Bond — owning more of the bestiary makes your active pet fiercer
    _owner = pet.get("owner_id")
    if _owner:
        base = round(base * (1.0 + _collector_atk_pct(_owner)))
    return max(1, round(base))

_PET_DMG_CAP = 0.65   # a pet strike may not exceed this fraction of the owner's own hit

def _pet_combat_atk(pet, owner):
    """Pet damage for a real combat strike: the pet's potential (get_pet_atk_bonus)
    bounded to _PET_DMG_CAP of the owner's own attack. Weak pets fall under the
    cap (so leveling/collecting them scales toward it — investment matters),
    while a maxed pet/collector tops out at ~65% of your hit. The player's own
    build always remains the majority of a turn's output. Skill procs and
    elemental multipliers still apply ON TOP of this at the call site, so a
    proc can still burst above the cap as a rewarded moment."""
    raw = get_pet_atk_bonus(pet)
    if not owner:
        return raw
    try:
        owner_hit = calc_attack_damage(owner)
    except Exception:
        return raw
    return max(1, min(raw, round(owner_hit * _PET_DMG_CAP)))

# ── BESTIARY / COLLECTOR SYSTEM ───────────────────────────────────────────────
_ALL_SPECIES_COUNT = len(PET_SPECIES)
# Milestones: unique species owned -> (permanent global reward, one-time claim reward)
_BESTIARY_MILESTONES = [
    (10, "+3% gold from all sources",      {"gold": 5000}),
    (25, "+5% gold, +2 stat points",       {"gold": 15000, "stat_points": 2, "item": "Rare Egg"}),
    (45, "+8% gold, +5% EXP",              {"gold": 50000, "stat_points": 3, "item": "Dragon Egg"}),
    (65, "+12% gold, +8% EXP, +3 stats",   {"gold": 150000, "stat_points": 5, "item": "Mythic Egg"}),
    (85, "MASTER COLLECTOR — +20% gold, +12% EXP", {"gold": 500000, "stat_points": 10, "item": "Mythic Egg"}),
]

def _pet_dex(p):
    """Set of species keys this player has EVER owned (persists after selling).
    Seeds from currently-owned pets so pre-feature players get credit."""
    dex = set(sjl(p.get("pet_dex"), []))
    for pt in get_all_pets(p.get("user_id")):
        if pt.get("species"): dex.add(pt["species"])
    return {s for s in dex if s in PET_SPECIES}

def _record_dex(p, species):
    """Add a species to the player's permanent bestiary. Returns True if new."""
    if species not in PET_SPECIES: return False
    dex = sjl(p.get("pet_dex"), [])
    if species in dex: return False
    dex.append(species)
    p["pet_dex"] = json.dumps(dex)
    return True

def _dex_count(owner_id):
    p = get_player(owner_id)
    return len(_pet_dex(p)) if p else 0

def _collector_atk_pct(owner_id):
    """+3% pet ATK per unique species collected (capped +150%) — the core
    reason to catch them all. Full 85-species dex hits the cap comfortably."""
    return min(1.50, _dex_count(owner_id) * 0.03)

def _collector_global(p):
    """Permanent global bonuses unlocked by bestiary milestones reached."""
    n = len(_pet_dex(p))
    gold_pct = exp_pct = 0.0
    if n >= 10: gold_pct = 0.03
    if n >= 25: gold_pct = 0.05
    if n >= 45: gold_pct, exp_pct = 0.08, 0.05
    if n >= 65: gold_pct, exp_pct = 0.12, 0.08
    if n >= 85: gold_pct, exp_pct = 0.20, 0.12
    return {"gold_pct": gold_pct, "exp_pct": exp_pct}

def pet_status_tag(pet):
    """Short status summary for a pet."""
    hunger = pet.get("hunger", 100)
    mood   = pet.get("mood", 100)
    if hunger < 20:   return "😫 Starving"
    if hunger < 50:   return "😕 Hungry"
    if mood < 40:     return "😢 Sad"
    if mood < 70:     return "😐 Okay"
    if mood >= 90:    return "😄 Thrilled"
    return "🙂 Happy"

def _decay_pet(pet):
    """Apply hunger/mood decay based on elapsed time. Mutates in place."""
    now = datetime.now()
    last_fed_str = pet.get("last_fed")
    if last_fed_str:
        try:
            hours_since = (now - datetime.fromisoformat(last_fed_str)).total_seconds() / 3600
            decay = round(hours_since * 5)  # -5 hunger per hour
            pet["hunger"] = max(0, pet.get("hunger", 100) - decay)
        except Exception: pass
    # Mood drops when hungry
    if pet.get("hunger", 100) < 30:
        mood_decay = round((30 - pet["hunger"]) * 0.5)
        pet["mood"] = max(0, pet.get("mood", 100) - mood_decay)

def get_active_pet_record(owner_id):
    """Fetch the active pet for a player from the DB."""
    conn = _connect_db(); conn.row_factory = sqlite3.Row; c = conn.cursor()
    c.execute("SELECT * FROM pets WHERE owner_id=? AND is_active=1", (owner_id,))
    row = c.fetchone(); conn.close()
    if row:
        pet = dict(row)
        _decay_pet(pet)
        return pet
    return None

def get_all_pets(owner_id):
    conn = _connect_db(); conn.row_factory = sqlite3.Row; c = conn.cursor()
    c.execute("SELECT * FROM pets WHERE owner_id=? ORDER BY is_active DESC, level DESC", (owner_id,))
    rows = [dict(r) for r in c.fetchall()]; conn.close()
    for p in rows: _decay_pet(p)
    return rows

def save_pet(pet):
    # First time this pet is written (creation) — stamp its species into the
    # owner's permanent bestiary so it counts forever, even if sold/released.
    if pet.get("pet_id") is None and pet.get("species") in PET_SPECIES:
        _dex_owner = get_player(pet.get("owner_id"))
        if _dex_owner and _record_dex(_dex_owner, pet["species"]):
            save_player(_dex_owner)
    conn = _connect_db(); c = conn.cursor()
    c.execute("""INSERT OR REPLACE INTO pets
        (pet_id,owner_id,species,nickname,level,exp,hunger,mood,last_fed,last_trained,
         is_active,created_at,bond_score,adventure_ends_at,last_battle,evolution_stage,
         is_shiny,job_ends_at,daycare_until)
        VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)""",
        (pet.get("pet_id"), pet["owner_id"], pet["species"],
         pet.get("nickname"), pet.get("level",1), pet.get("exp",0),
         pet.get("hunger",100), pet.get("mood",100),
         pet.get("last_fed"), pet.get("last_trained"),
         pet.get("is_active",0), pet.get("created_at", datetime.now().isoformat()),
         pet.get("bond_score",0), pet.get("adventure_ends_at"),
         pet.get("last_battle"), pet.get("evolution_stage",0),
         pet.get("is_shiny",0), pet.get("job_ends_at"),
         pet.get("daycare_until")))
    conn.commit(); conn.close()

def get_retired_pet_atk_bonus(p):
    return safe_int(p.get("pet_retire_atk"))

def get_retired_pet_hp_bonus(p):
    return safe_int(p.get("pet_retire_hp"))

def _get_pet_element_mult(atk_pet, def_pet):
    """Element matchup multiplier between two pets: 1.25 strong, 0.75 weak, 1.0 neutral."""
    if not atk_pet or not def_pet:
        return 1.0
    atk_elem = PET_SPECIES.get(atk_pet.get("species",""), {}).get("element","")
    def_elem = PET_SPECIES.get(def_pet.get("species",""), {}).get("element","")
    if not atk_elem or not def_elem:
        return 1.0
    matchup = ELEMENT_MATCHUPS.get(atk_elem, {})
    if matchup.get("strong") == def_elem:
        return 1.25
    if matchup.get("weak") == def_elem:
        return 0.75
    return 1.0

def _pet_skill_check(pet):
    """Returns (triggered: bool, skill: dict|None). Skills unlock at lv 10."""
    lvl  = pet.get("level", 1)
    if lvl < 10:
        return False, None
    elem  = PET_SPECIES.get(pet.get("species",""), {}).get("element","")
    skill = PET_COMBAT_SKILLS.get(elem)
    if not skill:
        return False, None
    chance = 0.25 + (0.08 if lvl >= 25 else 0) + (0.07 if lvl >= 40 else 0)  # max 40% (was 25%)
    return random.random() < chance, skill

def _pet_display_name(pet):
    sp   = PET_SPECIES.get(pet.get("species"), {})
    nick = pet.get("nickname")
    base = sp.get("name", pet.get("species", "Unknown"))
    evo  = pet.get("evolution_stage", 0)
    if evo > 0:
        elem  = sp.get("element", "")
        title = EVO_STAGE_TITLES.get(evo, {}).get(elem, "")
        if title:
            base = f"{title} {base}"
    shiny   = "✨ " if pet.get("is_shiny") else ""
    display = f"{nick} ({base})" if nick else base
    return f"{shiny}{display}"

def _build_pet_card(pet):
    """Build full status card text for a pet."""
    sp      = PET_SPECIES.get(pet.get("species"), {})
    dname   = _pet_display_name(pet)
    lvl     = pet.get("level", 1)
    exp     = pet.get("exp", 0)
    exp_needed = pet_exp_for_level(lvl)
    hunger  = pet.get("hunger", 100)
    mood    = pet.get("mood", 100)
    elem    = sp.get("element","?")
    rar     = sp.get("rarity","common")
    pers    = sp.get("personality","calm")
    emoji   = sp.get("emoji","🐾")
    elem_e  = ELEMENT_EMOJI.get(elem,"")
    pers_e  = PERSONALITY_EMOJI.get(pers,"")
    rar_e   = RARITY_EMOJI.get(rar,"")
    status  = pet_status_tag(pet)
    atk_bon = get_pet_atk_bonus(pet)
    passives = get_pet_passives(lvl)

    hunger_bar = "█" * round(hunger/10) + "░" * (10 - round(hunger/10))
    mood_bar   = "█" * round(mood/10)   + "░" * (10 - round(mood/10))
    exp_bar_pct = min(1.0, exp / max(1, exp_needed))
    exp_bar     = "█" * int(exp_bar_pct * 8) + "░" * (8 - int(exp_bar_pct * 8))

    shiny_badge = " ✨ *SHINY*" if pet.get("is_shiny") else ""
    pers_mod = PERSONALITY_ATK_MOD.get(pers, 1.0)
    pers_note = (" _(+ATK)_" if pers_mod > 1.0 else " _(-ATK)_" if pers_mod < 1.0 else "")
    lines = [
        f"{emoji} *{dname}*{shiny_badge}  {rar_e} {rar.capitalize()}",
        f"{elem_e} {elem.capitalize()}  |  {pers_e} {pers.capitalize()}{pers_note}",
        f"_{sp.get('desc','')}_",
        "",
        f"*Level {lvl}*",
        f"✨ EXP: `{exp}/{exp_needed}` [{exp_bar}]",
        f"🍖 Hunger: {hunger}/100  [{hunger_bar}]",
        f"💛 Mood:   {mood}/100  [{mood_bar}]",
        f"Status: {status}",
        "",
        f"⚔️ Combat ATK: +*{atk_bon}* per attack",
    ]
    if passives:
        plines = []
        if passives.get("crit_bonus"):  plines.append(f"+{round(passives['crit_bonus']*100)}% crit")
        if passives.get("dodge_bonus"): plines.append(f"+{round(passives['dodge_bonus']*100)}% dodge")
        if passives.get("lifesteal_flat"): plines.append(f"+{passives['lifesteal_flat']}% lifesteal/hit")
        if plines: lines.append("✨ Passives: " + "  |  ".join(plines))
    next_unlock = next((t for t in sorted(PET_LEVEL_PASSIVES) if t > lvl), None)
    if next_unlock:
        lines.append(f"🔒 Next unlock: Level {next_unlock}")
    # Defensive ability
    sp_def = sp.get("def_ability")
    if sp_def and lvl >= 10:
        ab_info = PET_DEF_ABILITIES.get(sp_def, {})
        chance  = round(get_pet_def_proc_chance(pet) * 100)
        lines.append(f"{ab_info.get('emoji','🐾')} *{ab_info.get('name','Ability')}* ({chance}% proc)")
    elif sp_def:
        ab_info = PET_DEF_ABILITIES.get(sp_def, {})
        lines.append(f"🔒 *{ab_info.get('name','Ability')}* unlocks at Level 10")
    # Bond status
    bond = pet.get("bond_score", 0)
    bond_tier, bond_label = _get_bond_tier(bond)
    bond_bar = "❤️" * min(10, bond // 20) + "🖤" * max(0, 10 - bond // 20)
    lines.append(f"\n💞 *Bond:* {bond_label}  `{bond}/200`\n{bond_bar}")
    if bond_tier == 1: lines.append("✨ _Trusted: +5% ability proc chance_")
    elif bond_tier == 2: lines.append("💫 _Devoted: +10% proc, +2 ATK_")
    elif bond_tier == 3: lines.append("🌟 _Soul Bond: +15% proc, +3 ATK, +5% crit_")
    # Evolution stage
    evo = pet.get("evolution_stage", 0)
    if evo > 0:
        lines.append(f"🔮 *Evolution Stage {evo}*")
    elif lvl >= 15:
        lines.append(f"🔮 _Ready to evolve! Use the Evolve button._")
    # Adventure status
    adv_end = pet.get("adventure_ends_at")
    if adv_end:
        try:
            rem = (datetime.fromisoformat(adv_end) - datetime.now()).total_seconds()
            if rem > 0:
                rm = f"{int(rem//3600)}h {int((rem%3600)//60)}m" if rem >= 3600 else f"{int(rem//60)}m"
                lines.append(f"\n🗺️ *On Adventure* — returns in {rm}")
        except Exception:
            pass
    # Collector's Bond — shown on the active pet since it's what's boosting ATK
    _own = pet.get("owner_id")
    if _own:
        _cpct = _collector_atk_pct(_own)
        if _cpct > 0:
            lines.append(f"📖 _Collector's Bond: +{round(_cpct*100)}% ATK from your bestiary_")
    return "\n".join(lines)

def _get_bond_tier(bond_score):
    """Returns (tier 0-3, label string)."""
    if bond_score >= 200: return 3, "Soul Bond 🌟"
    if bond_score >= 150: return 2, "Devoted 💫"
    if bond_score >= 100: return 1, "Trusted ✨"
    return 0, "Acquaintance 🤝"

def _get_bond_proc_bonus(pet):
    tier, _ = _get_bond_tier(pet.get("bond_score", 0))
    return [0.0, 0.05, 0.10, 0.15][tier]

def _get_bond_atk_bonus(pet):
    tier, _ = _get_bond_tier(pet.get("bond_score", 0))
    return [0, 0, 2, 3][tier]

def _pet_is_on_adventure(pet):
    adv = pet.get("adventure_ends_at")
    if not adv: return False
    try: return datetime.fromisoformat(adv) > datetime.now()
    except Exception: return False

def _pet_list_markup(pets, page=0, page_size=5, uid=0):
    start = page * page_size
    chunk = pets[start:start+page_size]
    rows = []
    for pet in chunk:
        sp = PET_SPECIES.get(pet.get("species"),{})
        emoji = sp.get("emoji","🐾")
        dname = _pet_display_name(pet)
        active_tag = " ✅" if pet.get("is_active") else ""
        rows.append([InlineKeyboardButton(
            f"{emoji} {dname} Lv{pet.get('level',1)}{active_tag}",
            callback_data=f"petview_{pet['pet_id']}")])
    nav = []
    if page > 0:    nav.append(InlineKeyboardButton("◀️ Prev", callback_data=f"petlist_{page-1}"))
    if start+page_size < len(pets): nav.append(InlineKeyboardButton("Next ▶️", callback_data=f"petlist_{page+1}"))
    if nav: rows.append(nav)
    rows.append([InlineKeyboardButton("📖 Bestiary", callback_data="bestiary_0"),
                 InlineKeyboardButton("💰 Bulk Sell", callback_data="petbulk_menu")])
    close_cb = f"close_msg_{uid}" if uid else "close_msg"
    rows.append([InlineKeyboardButton("🔙 Back", callback_data="petmain"),
                 InlineKeyboardButton("❌ Close", callback_data=close_cb)])
    return InlineKeyboardMarkup(rows)

def _pet_view_markup(pet_id, is_active, uid=0, pet=None):
    rows = []
    if not is_active:
        rows.append([InlineKeyboardButton("✅ Make Active", callback_data=f"petactivate_{pet_id}")])
    rows.append([
        InlineKeyboardButton("🍖 Feed",  callback_data=f"petfeed_{pet_id}"),
        InlineKeyboardButton("🏋️ Train", callback_data=f"pettrain_{pet_id}"),
        InlineKeyboardButton("🎮 Play",  callback_data=f"petplay_{pet_id}"),
    ])
    # Adventure button — show remaining time if on adventure
    if pet and _pet_is_on_adventure(pet):
        try:
            rem = (datetime.fromisoformat(pet["adventure_ends_at"]) - datetime.now()).total_seconds()
            rm = f"{int(rem//3600)}h {int((rem%3600)//60)}m" if rem >= 3600 else f"{int(rem//60)}m"
            rows.append([InlineKeyboardButton(f"🗺️ On Adventure ({rm})", callback_data=f"petadv_status_{pet_id}")])
        except Exception:
            rows.append([InlineKeyboardButton("🗺️ Adventure", callback_data=f"petadv_pick_{pet_id}")])
    else:
        rows.append([InlineKeyboardButton("🗺️ Adventure", callback_data=f"petadv_pick_{pet_id}")])
    # Evolve button if eligible
    if pet:
        lvl = pet.get("level", 1)
        evo = pet.get("evolution_stage", 0)
        evo_thresholds = [15, 30, 50]
        next_evo = next((t for t in evo_thresholds if lvl >= t and evo < evo_thresholds.index(t) + 1), None)
        if next_evo is not None:
            rows.append([InlineKeyboardButton("🔮 Evolve!", callback_data=f"petevolve_{pet_id}")])
    rows.append([InlineKeyboardButton("📝 Rename", callback_data=f"petrename_{pet_id}")])
    rows.append([
        InlineKeyboardButton("💰 Sell Pet",  callback_data=f"petsell_{pet_id}"),
        InlineKeyboardButton("❌ Release",   callback_data=f"petrelease_{pet_id}"),
    ])
    rows.append([InlineKeyboardButton("🔙 All Pets", callback_data="petlist_0")])
    close_cb = f"close_msg_{uid}" if uid else "close_msg"
    rows.append([InlineKeyboardButton("❌ Close", callback_data=close_cb)])
    return InlineKeyboardMarkup(rows)

_PET_SELL_BASE    = {"common":500,"uncommon":1000,"rare":2500,"epic":5000,"legendary":15000,"mythic":50000}
_PET_SELL_PER_LVL = {"common":100,"uncommon":150,"rare":200,"epic":300,"legendary":500,"mythic":1000}

def _pet_sell_price(pet):
    sp = PET_SPECIES.get(pet.get("species"), {})
    rar = sp.get("rarity", "common")
    price = _PET_SELL_BASE.get(rar, 500) + safe_int(pet.get("level"), 1) * _PET_SELL_PER_LVL.get(rar, 100)
    if pet.get("is_shiny"):
        price = round(price * 2.5)   # shinies are worth far more
    return price

def _pet_main_markup():
    return InlineKeyboardMarkup([
        [InlineKeyboardButton("📋 My Pets",  callback_data="petlist_0"),
         InlineKeyboardButton("🛒 Pet Shop", callback_data="petshop")],
        [InlineKeyboardButton("📖 Bestiary", callback_data="bestiary_0"),
         InlineKeyboardButton("🥚 Hatch Egg", callback_data="hatch_egg")],
        [InlineKeyboardButton("❌ Close",     callback_data="close_msg")],
    ])

