ELEMENT_EMOJI = {
    "fire":"🔥","water":"💧","earth":"🪨","wind":"🌪️","lightning":"⚡",
    "dark":"🌑","holy":"✨","void":"🌀","physical":"💪","ice":"❄️","poison":"☠️",
}

def _enc_hp_bar(current, maximum, length=10):
    filled = max(0, round((current / max(1, maximum)) * length))
    return "█" * filled + "░" * (length - filled)

def _mon_level_stats(base_hp, base_atk, level):
    hp  = int(base_hp  * (1 + 0.06 * (level - 1)))
    atk = int(base_atk * (1 + 0.05 * (level - 1)))
    return hp, atk

def _npc_level_stats(base_hp, base_dmg, level, player_max_hp=0):
    hp  = int(base_hp  * (1 + 0.10 * (level - 1)))
    atk = int(base_dmg * (1 + 0.10 * (level - 1)))
    if player_max_hp > 0:
        # HP: between 70% and 130% of player max HP
        hp  = max(int(player_max_hp * 0.70), min(hp, int(player_max_hp * 1.30)))
        # ATK: floor 6%, ceiling 14% of player max HP (raw before DEF mitigation)
        atk = max(int(player_max_hp * 0.06), min(atk, int(player_max_hp * 0.14)))
    return hp, atk

# ── PARTY SYSTEM ──────────────────────────────────────────────────────────────

def _are_allies(a, b):
    """True if a and b are the same player or bound as allies (guild, party,
    marriage, holding hands). Support skills use this so a heal/revive/buff
    aimed at a NON-ally self-casts instead of aiding an enemy."""
    if not a or not b:
        return False
    au, bu = a.get("user_id"), b.get("user_id")
    if au == bu:
        return True
    # guild
    ag = a.get("guild_id")
    if ag and str(ag) != "None" and str(ag) == str(b.get("guild_id")):
        return True
    # party
    pa = _get_party_of(au)
    if pa and bu in _get_party_members(pa["id"]):
        return True
    # marriage
    ms = sjl(a.get("marriages"), []) or ([{"id": a.get("married_to_id")}] if a.get("married_to_id") else [])
    if any(str(m.get("id")) == str(bu) for m in ms):
        return True
    if str(a.get("married_to_id")) == str(bu):
        return True
    # holding hands
    hh = sjl(a.get("holding_hands_list"), [])
    if any(str(h.get("id") if isinstance(h, dict) else h) == str(bu) for h in hh):
        return True
    if str(a.get("holding_hands_with_id")) == str(bu):
        return True
    return False

def _get_party_of(uid):
    c = _db().cursor()
    c.execute("SELECT p.id, p.leader_id, p.name FROM parties p "
              "JOIN party_members pm ON p.id=pm.party_id WHERE pm.user_id=?", (uid,))
    row = c.fetchone()
    return {"id": row[0], "leader_id": row[1], "name": row[2]} if row else None

def _get_party_members(party_id):
    c = _db().cursor()
    c.execute("SELECT user_id FROM party_members WHERE party_id=? ORDER BY joined_at", (party_id,))
    return [r[0] for r in c.fetchall()]

def _create_party(leader_uid):
    conn = _db(); c = conn.cursor()
    c.execute("INSERT INTO parties (leader_id, created_at) VALUES (?, ?)",
              (leader_uid, datetime.now().isoformat()))
    party_id = c.lastrowid
    c.execute("INSERT OR IGNORE INTO party_members (party_id, user_id, joined_at) VALUES (?, ?, ?)",
              (party_id, leader_uid, datetime.now().isoformat()))
    conn.commit()
    return party_id

def _join_party(party_id, uid):
    conn = _db(); c = conn.cursor()
    c.execute("INSERT OR IGNORE INTO party_members (party_id, user_id, joined_at) VALUES (?, ?, ?)",
              (party_id, uid, datetime.now().isoformat()))
    conn.commit()

def _leave_party(uid):
    party = _get_party_of(uid)
    if not party: return
    conn = _db(); c = conn.cursor()
    c.execute("DELETE FROM party_members WHERE party_id=? AND user_id=?", (party["id"], uid))
    remaining = _get_party_members(party["id"])
    if not remaining:
        c.execute("DELETE FROM parties WHERE id=?", (party["id"],))
    elif party["leader_id"] == uid and remaining:
        c.execute("UPDATE parties SET leader_id=? WHERE id=?", (remaining[0], party["id"]))
    conn.commit()

async def _party_exp_bonus(bot, active_uid, exp_gained, source_name):
    party = _get_party_of(active_uid)
    if not party: return
    members = _get_party_members(party["id"])
    bonus = max(1, round(exp_gained * 0.25))
    active_p = get_player(active_uid)
    active_name = active_p.get("username", "A teammate") if active_p else "A teammate"
    for mid in members:
        if mid == active_uid: continue
        mp = get_player(mid)
        if not mp: continue
        add_exp(mp, bonus)
        save_player(mp)
        try:
            await bot.send_message(
                mid,
                f"⚔️ *{active_name}* fought {source_name} — "
                f"you earned *+{fmt_num(bonus)} EXP* as a party bonus!",
                parse_mode="Markdown")
        except Exception:
            pass

def _party_display_name(party):
    return f"*{party['name']}*" if party.get("name") else "Unnamed Party"

# ─────────────────────────────────────────────────────────────────────────────

def _encounter_battle_card(enc):
    """Pokémon-style battle card: enemy block at top, player block below, battle log at bottom."""
    mode   = enc["mode"]
    p_name = enc["p_name"]
    p_hp   = enc["p_hp"]
    p_mhp  = enc["p_max_hp"]
    e_name = enc["e_name"]
    e_hp   = enc["e_hp"]
    e_mhp  = enc["e_max_hp"]
    e_lv   = enc["e_level"]
    elem   = enc.get("element","")
    elem_e = ELEMENT_EMOJI.get(elem,"")
    p_bar  = _enc_hp_bar(p_hp, p_mhp)
    e_bar  = _enc_hp_bar(e_hp, e_mhp)
    lines  = []
    # Header
    lines.append(f"{'⚔️ NPC BATTLE' if mode=='battle' else '🌿 HUNT'}")
    lines.append("")
    # Enemy block
    if mode == "battle":
        cls_name = CLASS_TREE.get(enc.get("e_class",""), {}).get("name", enc.get("e_class","NPC").replace("_"," ").title())
        lines.append(f"👾 *{e_name}*  Lv.{e_lv}  [{cls_name}]")
    else:
        lines.append(f"{elem_e} *{e_name}*  Lv.{e_lv}")
    e_status = []
    if enc.get("e_burning"):        e_status.append("🔥")
    if enc.get("e_poisoned"):       e_status.append("☠️")
    if enc.get("e_stunned_turns"):  e_status.append("⚡")
    if enc.get("e_weakened"):       e_status.append("⬇️")
    e_s = "  " + " ".join(e_status) if e_status else ""
    lines.append(f"`{e_bar}`  {e_hp}/{e_mhp} HP{e_s}")
    lines.append("")
    # Player block
    p_status = []
    if enc.get("p_stunned") or enc.get("p_skip"): p_status.append("⚡")
    if enc.get("p_weakened"):  p_status.append("⬇️")
    if enc.get("p_guarding"):  p_status.append("🛡️")
    if enc.get("p_bleed"):     p_status.append("🩸")
    if enc.get("p_burn"):      p_status.append("🔥")
    if enc.get("p_poison"):    p_status.append("☠️")
    if enc.get("p_blind"):     p_status.append("👁️")
    if enc.get("p_slow"):      p_status.append("🐢")
    if enc.get("p_hexed"):     p_status.append("💜")
    p_s = "  " + " ".join(p_status) if p_status else ""
    pet_info = enc.get("pet_info")
    pet_str = f"  🐾 {pet_info['name']} +{pet_info['atk']}" if pet_info else ""
    p_mp = enc.get("p_mp", 0); p_mxmp = enc.get("p_max_mp", 10)
    lines.append(f"👤 *{p_name}*{p_s}")
    lines.append(f"`{p_bar}`  {p_hp}/{p_mhp} HP  💙{p_mp}/{p_mxmp} MP{pet_str}")
    # Battle log
    action_log = enc.get("action_log", [])
    if action_log:
        lines.append("")
        lines.append("─────────────")
        for act in action_log[-3:]:
            lines.append(act)
    return "\n".join(lines)

def _encounter_battle_markup(enc, p=None):
    uid  = enc["uid"]
    mode = enc["mode"]
    p_mp = enc.get("p_mp", 0)
    rows = []
    rows.append([
        InlineKeyboardButton("⚔️ Attack", callback_data=f"enc_atk_{uid}"),
        InlineKeyboardButton("🛡️ Guard",  callback_data=f"enc_guard_{uid}"),
        InlineKeyboardButton("🧪 Potion", callback_data=f"enc_heal_{uid}"),
    ])
    # Skill buttons with MP cost indicator
    if p:
        _p_skills = get_combat_skills(p)
        for _i, _sk in enumerate(_p_skills):
            _cost = _dng_skill_mp_cost(_sk)
            _can  = p_mp >= _cost
            _icon = "✅" if _can else "❌"
            if _can:
                rows.append([InlineKeyboardButton(
                    f"{_icon} {_sk.get('name','Skill')} ({_cost}MP)",
                    callback_data=f"enc_skl_{uid}_{_i}")])
    if mode == "hunt":
        bottom = []
        if enc["e_hp"] / max(1, enc["e_max_hp"]) <= 0.5:
            bottom.append(InlineKeyboardButton("🎯 Catch", callback_data=f"enc_catch_{uid}"))
        bottom.append(InlineKeyboardButton("🏃 Flee", callback_data=f"enc_flee_{uid}"))
        rows.append(bottom)
    else:
        rows.append([InlineKeyboardButton("🏃 Flee", callback_data=f"enc_flee_{uid}")])
    return InlineKeyboardMarkup(rows)

_CHEST_TIERS = {
    "wooden": {"emoji": "🪵", "gold": (1000, 2000), "gear_chance": 0.70, "curse_chance": 0.0, "exp": (150, 350)},
    "iron":   {"emoji": "⛏️",  "gold": (2000, 3500), "gear_chance": 0.90, "curse_chance": 0.0, "exp": (350, 700)},
    "golden": {"emoji": "✨",  "gold": (3500, 5000), "gear_chance": 1.00, "curse_chance": 0.0, "exp": (700, 1200)},
}

_RANDOM_EVENTS = {
    "merchant": {
        "title": "🛒 Wandering Merchant",
        "desc": "A mysterious merchant appears, offering to trade for a deal that's too good to pass up.",
        "choices": [("🛒 Browse Wares", "buy"), ("🚶 Keep Walking", "skip")],
    },
    "shrine": {
        "title": "🗿 Ancient Shrine",
        "desc": "You stumble upon an ancient shrine radiating quiet power. Pray and something may happen...",
        "choices": [("🙏 Pray at the Shrine", "pray"), ("🚶 Leave it Alone", "skip")],
    },
    "fallen": {
        "title": "💀 Fallen Adventurer",
        "desc": "You find the remains of an adventurer who didn't make it. Their pack still has some items...",
        "choices": [("🎒 Search the Pack", "loot"), ("🕯️ Leave in Peace", "skip")],
    },
    "ambush": {
        "title": "⚠️ Ambush!",
        "desc": "Bandits leap from the shadows! You can fight back or attempt to flee.",
        "choices": [("⚔️ Fight Back", "fight"), ("🏃 Attempt Escape", "flee")],
    },
}

def _enc_level_stats(enc_level, p_level):
    """Return (hp, atk, reward_mult, num_gear, num_pots, gear_rarities) scaled from enc_level."""
    hp  = max(50, round(max_hp_for_level(enc_level) * random.uniform(0.80, 1.20)))
    atk = max(1, enc_level * 9 + random.randint(10, 30))
    diff = enc_level - p_level
    # tier_bonus: each 20 levels adds 0.3× (level 20=+0.3, 40=+0.6, 60=+0.9, 80=+1.2, 100=+1.5)
    tier_bonus = (enc_level // 20) * 0.3
    reward_mult = max(0.5, round(1.0 + tier_bonus + max(0, diff) * 0.10, 2))
    num_gear = max(1, min(4, 1 + enc_level // 20))
    num_pots = max(0, min(2, enc_level // 35))
    if enc_level <= 10:
        rarities = ["common", "uncommon", "uncommon"]
    elif enc_level <= 20:
        rarities = ["uncommon", "uncommon", "rare"]
    elif enc_level <= 35:
        rarities = ["uncommon", "rare", "rare"]
    elif enc_level <= 50:
        rarities = ["rare", "rare", "epic"]
    elif enc_level <= 65:
        rarities = ["rare", "epic", "epic"]
    elif enc_level <= 80:
        rarities = ["epic", "epic", "legendary"]
    elif enc_level <= 95:
        rarities = ["epic", "legendary", "legendary"]
    else:
        rarities = ["legendary", "legendary", "mythic"]
    return hp, atk, reward_mult, num_gear, num_pots, rarities

def _treasure_card(enc):
    tier = enc.get("chest_tier", "wooden")
    td   = _CHEST_TIERS[tier]
    lines = [f"💰 *TREASURE*\n"]
    lines.append(f"{td['emoji']} A *{tier.title()} Chest* sits before you.")
    lines.append("")
    lines.append("_What do you do?_")
    log = enc.get("action_log", [])
    if log:
        lines.append("─────────────")
        for entry in log[-2:]:
            lines.append(entry)
    return "\n".join(lines)

def _treasure_markup(enc):
    uid = enc["uid"]
    return InlineKeyboardMarkup([
        [InlineKeyboardButton("🎁 Open the Chest", callback_data=f"enc_open_{uid}"),
         InlineKeyboardButton("🚪 Leave it", callback_data=f"enc_leave_{uid}")],
    ])

def _event_card(enc):
    etype = enc.get("event_type", "shrine")
    ev = _RANDOM_EVENTS.get(etype, _RANDOM_EVENTS["shrine"])
    lines = [f"*{ev['title']}*\n", ev["desc"], ""]
    log = enc.get("action_log", [])
    if log:
        lines.append("─────────────")
        for entry in log[-2:]:
            lines.append(entry)
    return "\n".join(lines)

def _event_markup(enc):
    uid   = enc["uid"]
    etype = enc.get("event_type", "shrine")
    ev    = _RANDOM_EVENTS.get(etype, _RANDOM_EVENTS["shrine"])
    rows  = [[InlineKeyboardButton(label, callback_data=f"enc_event_{uid}_{key}")
              for label, key in ev["choices"]]]
    return InlineKeyboardMarkup(rows)

def _pick_random_npc(p_level):
    lo, hi = max(1, p_level - 5), p_level + 5
    eligible = [n for n in ENCOUNTER_NPCS if n[2] <= hi and n[3] >= lo]
    if not eligible:
        eligible = sorted(ENCOUNTER_NPCS, key=lambda n: abs(n[2] - p_level))[:5]
    return random.choice(eligible)

def _pick_random_monster(p_level):
    lo, hi = max(1, p_level - 5), p_level + 5
    eligible = [m for m in ENCOUNTER_MONSTERS if m[3][0] <= hi and m[3][1] >= lo]
    if not eligible:
        eligible = sorted(ENCOUNTER_MONSTERS, key=lambda m: abs(m[3][0] - p_level))[:5]
    return random.choice(eligible)

def _enc_process_skill(enc, p, sk):
    """Process a skill use in encounter/hunt.
    Returns (action_txt, dmg, is_support).
    is_support=True means the skill healed/buffed the player (caller handles NPC turn separately).
    Modifies enc in-place (e_hp, p_hp, status flags).
    """
    sk_name = sk.get("name", "Skill")
    stype   = sk.get("type", "damage")
    w       = get_weather()
    base    = calc_attack_damage(p, w)
    # MP cost — deduct from enc state and sync to player
    _sk_cost = _dng_skill_mp_cost(sk)
    enc["p_mp"] = max(0, enc.get("p_mp", 0) - _sk_cost)
    p["mp"]     = enc["p_mp"]

    # ── Healing / support skills ─────────────────────────────────────────────
    _heal_types = {"self_heal", "self_heal_buff", "group_heal", "revive_heal",
                   "regen", "heal_shield", "mass_cleanse", "dmg_reduction_buff",
                   "party_atk_buff", "party_def_buff", "party_full_buff",
                   "ultimate_buff", "aoe_heal_dmg", "full_revive", "strip_debuff"}
    if stype in _heal_types or stype.endswith("heal"):
        wis  = get_stat(p, "WIS")
        # Support heal_pct for skills that restore % of max HP
        if sk.get("heal_pct"):
            heal = max(1, round(enc["p_max_hp"] * sk["heal_pct"]))
        else:
            heal = max(1, round(wis * sk.get("mult", sk.get("wis_mult", 50))))
        # Hexed: reduce healing by 50%
        if enc.pop("p_hexed", False):
            heal = max(1, heal // 2)
            sk_name = sk_name + " *(Hexed — half heal)*"
        if stype == "aoe_heal_dmg":
            heal = max(1, round(wis * sk.get("mult", 50)))
            enemy_hit = max(1, round(wis * 3))
            enc["e_hp"] = max(0, enc["e_hp"] - enemy_hit)
        elif stype == "full_revive":
            enc["p_hp"] = enc["p_max_hp"]
            return f"✨ *{sk_name}*! Fully restored! ({enc['p_hp']}/{enc['p_max_hp']})", 0, True
        elif stype == "strip_debuff":
            enc.pop("p_stunned", None); enc.pop("p_weakened", None)
            enc.pop("p_bleed", None);   enc.pop("p_burn", None)
            enc.pop("p_poison", None);  enc.pop("p_blind", None)
            enc.pop("p_slow", None);    enc.pop("p_hexed", None)
            return f"✨ *{sk_name}*! All debuffs cleared!", 0, True
        enc["p_hp"] = min(enc["p_max_hp"], enc["p_hp"] + heal)
        txt = f"💚 *{sk_name}*! Healed *{heal} HP*! ({enc['p_hp']}/{enc['p_max_hp']})"
        return txt, 0, True

    # ── Pure defence/buff skills (no damage) ─────────────────────────────────
    if stype == "def_buff":
        sk_active = sk.get("active", sk.get("name", ""))
        if sk_active == "Aegis Wall":
            enc["enc_shield_charges"] = enc.get("enc_shield_charges", 0) + 3
            return "🛡️ *Aegis Wall*! 3 shield charges — next 3 hits completely negated!", 0, False
        elif sk_active == "Shield Wall":
            enc["enc_shield_charges"] = enc.get("enc_shield_charges", 0) + 2
            return "🛡️ *Shield Wall*! 2 shield charges — next 2 hits completely negated!", 0, False
        else:
            enc["p_guard_hits"] = enc.get("p_guard_hits", 0) + 3
            return f"🛡️ *{sk_name}*! +30 flat damage reduction for 3 hits!", 0, False
    if stype in ("self_atk_buff",):
        ps   = get_stat(p, get_primary_stat(p))
        heal = max(1, round(ps * 15))
        enc["p_hp"] = min(enc["p_max_hp"], enc["p_hp"] + heal)
        return f"💪 *{sk_name}*! Attack power surges! +{heal} HP recovery!", 0, True
    if stype == "acc_debuff_only":
        enc["e_weakened"] = True
        return f"🌀 *{sk_name}*! Enemy disoriented — attack weakened!", 0, True
    if stype in ("dodge_buff", "vanish"):
        enc["enc_dodge_turns"] = enc.get("enc_dodge_turns", 0) + (2 if stype == "vanish" else 1)
        return f"💨 *{sk_name}*! You slip into the shadows — next hit{'s' if stype=='vanish' else ''} dodged!", 0, True
    if stype == "def_reflect":
        def_v = get_stat(p, "DEF")
        enc["enc_reflect_dmg"] = enc.get("enc_reflect_dmg", 0) + max(1, round(def_v * 1.5))
        enc["p_guarding"] = True
        return f"🛡️ *{sk_name}*! Thorns raised — reflects *{enc['enc_reflect_dmg']}* on next hit!", 0, True

    # ── Pet joins every skill use ─────────────────────────────────────────────
    pet_extra = ""
    pet_info = enc.get("pet_info")
    if pet_info and pet_info.get("atk", 0) > 0:
        pet_dmg = max(1, int(pet_info["atk"] * random.uniform(0.8, 1.2)))
        enc["e_hp"] = max(0, enc["e_hp"] - pet_dmg)
        pet_extra = f"\n🐾 *{pet_info['name']}* strikes for *{pet_dmg}*!"

    # ── Damage skills ─────────────────────────────────────────────────────────
    # Consume player status debuffs that affect damage
    if enc.pop("p_weakened", False):
        base = int(base * 0.65)
    if enc.pop("p_blind", False) and random.random() < 0.40:
        return f"👁️ *{sk_name}*! You're blinded and miss!", 0, False
    if enc.pop("p_slow", False):
        base = int(base * 0.80)
    dmg = 0
    txt = ""
    if stype == "multihit":
        mults_list = sk.get("mults") or [sk.get("mult", 0.8)] * sk.get("hits", 2)
        dmg  = sum(max(1, round(calc_attack_damage(p, w) * m)) for m in mults_list)
        txt  = f"⚡ *{sk_name}*! {len(mults_list)}-hit combo for *{dmg}* damage!{pet_extra}"
    elif stype == "aoe_bleed_multihit":
        hits = sk.get("hits", 4)
        dmg  = sum(max(1, round(base * sk.get("mult", 0.6))) for _ in range(hits))
        enc["e_poisoned"] = True; enc["e_poison_pct"] = 15
        txt  = f"🌀 *{sk_name}*! {hits}-hit combo (*{dmg}* total)! Enemy bleeding (15%/action)!{pet_extra}"
    elif stype == "multihit_crit":
        mults_list = sk.get("mults") or [sk.get("mult", 0.7)] * sk.get("hits", 3)
        crit_hits = 0
        dmg = 0
        for m in mults_list:
            h = max(1, round(calc_attack_damage(p, w) * m))
            if check_crit(p): h = apply_crit(p, h); crit_hits += 1
            dmg += h
        crit_note = f" 💥 *{crit_hits} CRIT{'s' if crit_hits > 1 else ''}!*" if crit_hits else ""
        txt  = f"⚡ *{sk_name}*! {len(mults_list)}-hit combo for *{dmg}* damage!{crit_note}{pet_extra}"
    elif stype == "execute_multihit":
        hits   = sk.get("hits", 8)
        hp_pct = enc["e_hp"] / max(1, enc["e_max_hp"])
        _em_stat = sk.get("stat", "AGI")
        _em_base = get_stat(p, _em_stat)
        # Low HP execute bonus: normal mult vs boosted mult
        normal_mult  = sk.get("mult", 0.5)
        execute_mult = sk.get("execute_mult", normal_mult * 1.5)
        mult   = execute_mult if hp_pct <= 0.50 else normal_mult
        dmg    = sum(max(1, round(_em_base * mult)) for _ in range(hits))
        prefix = "💀 *EXECUTE!* " if hp_pct <= 0.50 else ""
        txt    = f"{prefix}🌀 *{sk_name}*! {hits} hits = *{dmg}* total!{pet_extra}"
    elif stype == "crit_dmg":
        dmg = max(1, round(base * sk.get("mult", 1.8) * 2))
        txt = f"💥 *{sk_name}*! Guaranteed Critical for *{dmg}* damage!{pet_extra}"
    elif stype == "bleed_crit":
        dmg = max(1, round(base * sk.get("mult", 2.0) * 2))
        enc["e_poisoned"] = True
        txt = f"🩸 *{sk_name}*! *{dmg}* damage! Enemy bleeding!{pet_extra}"
    elif stype == "pierce_dmg":
        _pd_stat = sk.get("stat", "AGI")
        _pd_mult = sk.get("mult", 3)
        dmg = max(1, round(get_stat(p, _pd_stat) * _pd_mult))
        txt = f"🌑 *{sk_name}*! {_pd_stat}×{_pd_mult} = *{dmg}* piercing damage! _(ignores dodge)_{pet_extra}"
    elif stype == "pierce_all":
        stat = "DEX" if sk.get("dex_mult") else "STR"
        mult = sk.get("dex_mult", sk.get("str_mult", 2))
        dmg  = max(1, round(get_stat(p, stat) * mult))
        txt  = f"🏹 *{sk_name}*! Piercing for *{dmg}* damage!{pet_extra}"
    elif stype in ("pierce_dodge", "charged_shot", "execution_shot"):
        dmg = max(1, round(get_stat(p, "DEX") * sk.get("mult", 2.0)))
        txt = f"🎯 *{sk_name}*! *{dmg}* damage!{pet_extra}"
    elif stype == "stun":
        dmg = max(1, round(base * sk.get("mult", 1.0)))
        if random.random() < 0.50:
            enc["e_stunned_turns"] = enc.get("e_stunned_turns", 0) + 1
            txt = f"⚡ *{sk_name}*! *{dmg}* damage! Enemy stunned 1 turn!{pet_extra}"
        else:
            txt = f"⚡ *{sk_name}*! *{dmg}* damage!{pet_extra}"
    elif stype == "stun_def_dmg":
        str_v = get_stat(p, "STR"); def_v = get_stat(p, "DEF")
        dmg = max(1, round((str_v + def_v) * sk.get("mult", 1.0)))
        if random.random() < 0.40:
            enc["e_stunned_turns"] = enc.get("e_stunned_turns", 0) + 1
            txt = f"🛡️ *{sk_name}*! *{dmg}* (STR+DEF) damage! Enemy stunned!{pet_extra}"
        else:
            txt = f"🛡️ *{sk_name}*! *{dmg}* damage!{pet_extra}"
    elif stype == "holy_warrior_nuke":
        str_v = get_stat(p, "STR"); def_v = get_stat(p, "DEF")
        dmg   = max(1, round(str_v * 4 + def_v * 4))
        enc["e_stunned_turns"] = enc.get("e_stunned_turns", 0) + 2
        txt = f"⚡ *{sk_name}*! STR×4+DEF×4 = *{dmg}* holy damage! Enemy stunned 2 turns!{pet_extra}"
    elif stype == "godlike_lightning":
        str_v = get_stat(p, "STR")
        dmg   = max(1, round(str_v * 8))
        enc["e_weakened"] = True
        txt = f"⚡ *{sk_name}*! STR×8 = *{dmg}* divine lightning! Enemy weakened!{pet_extra}"
    elif stype == "freeze_nuke":
        int_v = get_stat(p, "INT")
        dmg   = max(1, round(int_v * 5))
        enc["e_stunned_turns"] = enc.get("e_stunned_turns", 0) + 2
        txt = f"🧊 *{sk_name}*! INT×5 = *{dmg}* damage! Enemy stunned 2 turns!{pet_extra}"
    elif stype == "void_nuke":
        dmg = max(1, enc["e_hp"] // 2)
        txt = f"🌑 *{sk_name}*! Enemy loses 50% HP! *{dmg}* damage!{pet_extra}"
    elif stype in ("drain", "drain_kill", "drain_debuff"):
        steal = round(enc["e_hp"] * sk.get("drain_pct", 0.30 if stype == "drain" else 0.40))
        dmg   = max(1, round(base * sk.get("mult", 1.0)))
        enc["p_hp"] = min(enc["p_max_hp"], enc["p_hp"] + steal)
        if stype == "drain_debuff": enc["e_weakened"] = True
        txt = f"🩸 *{sk_name}*! *{dmg}* damage! Drained *{steal} HP* from enemy!{pet_extra}"
    elif stype in ("aoe_poison_strong", "nature_nuke"):
        wis = get_stat(p, "WIS")
        mult = 7 if stype == "nature_nuke" else 1.5
        dmg = max(1, round(wis * mult))
        enc["e_poisoned"] = True
        txt = f"☠️ *{sk_name}*! *{dmg}* damage! Enemy poisoned!{pet_extra}"
    elif stype == "spell":
        int_v = get_stat(p, "INT")
        dmg   = max(1, round(int_v * sk.get("mult", 2.0)))
        enc["e_burning"] = True
        txt = f"🔥 *{sk_name}*! INT×{sk.get('mult',2)} = *{dmg}* damage! Enemy burning!{pet_extra}"
    elif stype == "bounce_spell":
        str_v = get_stat(p, "STR")
        dmg   = max(1, round(str_v * sk.get("mult", 2.0)))
        txt = f"⚡ *{sk_name}*! STR×{sk.get('mult',2)} = *{dmg}* chain lightning!{pet_extra}"
    elif stype == "holy_dmg":
        wis = get_stat(p, "WIS")
        _hmult = sk.get("mult", 3)
        dmg = max(1, wis * _hmult)
        if sk.get("active", sk.get("name", "")) == "Radiant Strike":
            _hheal = wis * 2
            enc["p_hp"] = min(enc["p_max_hp"], enc["p_hp"] + _hheal)
            txt = f"✨ *{sk_name}*! WIS×{_hmult} = *{dmg}* holy damage! +{_hheal} HP!{pet_extra}"
        else:
            txt = f"✨ *{sk_name}*! WIS×{_hmult} = *{dmg}* holy damage!{pet_extra}"
    elif stype == "condemn":
        wis = get_stat(p, "WIS")
        dmg = max(1, wis * 8)
        enc["e_weakened"] = True
        txt = f"☠️ *{sk_name}*! WIS×8 = *{dmg}* damage! Enemy condemned!{pet_extra}"
    elif stype == "curse_chain":
        int_v = get_stat(p, "INT")
        dmg   = max(1, round(int_v * 1.5))
        enc["e_weakened"] = True
        txt = f"💜 *{sk_name}*! INT×1.5 = *{dmg}* damage! Curses applied!{pet_extra}"
    elif stype == "mass_debuff":
        int_v = get_stat(p, "INT")
        dmg   = max(1, round(int_v * 2.5))
        enc["e_weakened"] = True; enc["e_stunned_turns"] = enc.get("e_stunned_turns", 0) + 1
        txt = f"💜 *{sk_name}*! INT×2.5 = *{dmg}* damage! Enemy stunned + weakened!{pet_extra}"
    elif stype == "vanish_dmg":
        agi = get_stat(p, "AGI")
        dmg = max(1, round(agi * 4))
        txt = f"👻 *{sk_name}*! AGI×4 = *{dmg}* burst damage!{pet_extra}"
    elif stype == "phantom_aoe":
        agi = get_stat(p, "AGI")
        dmg = max(1, round(agi * 2.5))
        txt = f"🌀 *{sk_name}*! AGI×2.5 = *{dmg}* phantom damage!{pet_extra}"
    elif stype == "intercept_aoe":
        def_v = get_stat(p, "DEF")
        dmg   = max(1, round(def_v * 2))
        enc["p_guarding"] = True
        txt = f"🛡️ *{sk_name}*! DEF×2 = *{dmg}* damage! Guard active!{pet_extra}"
    elif stype == "silence":
        dmg = max(1, round(base * 1.5))
        enc["e_stunned_turns"] = enc.get("e_stunned_turns", 0) + 1
        txt = f"⚡ *{sk_name}*! *{dmg}* damage! Enemy stunned — loses next turn!{pet_extra}"
    elif stype == "debuff":
        dmg = max(1, round(base * 0.8))
        enc["e_weakened"] = True
        txt = f"💀 *{sk_name}*! *{dmg}* damage! Enemy hexed + weakened!{pet_extra}"
    elif stype == "combo_dmg":
        str_v = get_stat(p, "STR"); wis_v = get_stat(p, "WIS")
        dmg = max(1, round((str_v + wis_v) * sk.get("mult", 1.5)))
        txt = f"⚔️ *{sk_name}*! (STR+WIS)×{sk.get('mult',1.5)} = *{dmg}* damage!{pet_extra}"
    elif stype == "holy_nuke":
        str_v = get_stat(p, "STR"); wis_v = get_stat(p, "WIS")
        dmg = max(1, round(str_v * 4 + wis_v * 4))
        enc["e_stunned_turns"] = enc.get("e_stunned_turns", 0) + 2
        txt = f"✨ *{sk_name}*! STR×4+WIS×4 = *{dmg}* holy damage! Enemy stunned 2 turns!{pet_extra}"
    elif stype == "dmg_field":
        int_v = get_stat(p, "INT")
        dmg = max(1, round(int_v * sk.get("mult", 3.0)))
        enc["e_burning"] = True
        txt = f"🔥 *{sk_name}*! INT×{sk.get('mult',3)} = *{dmg}* damage! Field set ablaze!{pet_extra}"
    elif stype == "guaranteed_hit":
        dmg = max(1, round(base * sk.get("mult", 1.2)))
        txt = f"⚡ *{sk_name}*! *{dmg}* guaranteed damage! _(cannot miss)_{pet_extra}"
    elif stype == "aoe_recent_attackers":
        hits = sk.get("hits", 3)
        dmg = sum(max(1, round(base * sk.get("mult", 0.7))) for _ in range(hits))
        txt = f"🌀 *{sk_name}*! {hits}-hit sweep for *{dmg}* total damage!{pet_extra}"
    elif stype == "raid_aoe":
        int_v = get_stat(p, "INT")
        _rm = sk.get("mult", 5)
        dmg = max(1, round(int_v * _rm))
        enc["e_burning"] = True; enc["e_weakened"] = True
        txt = f"💥 *{sk_name}*! INT×{_rm} = *{dmg}* massive damage! Enemy burning + weakened!{pet_extra}"
    elif stype == "execute_nuke":
        hp_pct = enc["e_hp"] / max(1, enc["e_max_hp"])
        if hp_pct <= 0.35:
            dmg = enc["e_hp"]
            txt = f"💀 *{sk_name}*! *EXECUTION!* *{dmg}* lethal damage!{pet_extra}"
        else:
            dmg = max(1, round(base * sk.get("mult", 1.5)))
            txt = f"⚔️ *{sk_name}*! *{dmg}* damage! _(execute triggers below 35% HP)_{pet_extra}"
    elif stype in ("bounty_mark", "bind_attacker"):
        dmg = max(1, round(base * sk.get("mult", 0.8)))
        enc["e_stunned_turns"] = enc.get("e_stunned_turns", 0) + 1
        enc["e_weakened"] = True
        txt = f"🎯 *{sk_name}*! *{dmg}* damage! Enemy marked + stunned 1 turn!{pet_extra}"
    elif stype in ("dmg_acc_debuff", "miss_debuff"):
        dmg = max(1, round(base * sk.get("mult", 0.8)))
        enc["e_weakened"] = True
        txt = f"🎯 *{sk_name}*! *{dmg}* damage! Enemy accuracy lowered!{pet_extra}"
    elif stype == "root":
        dmg = max(1, round(get_stat(p, "AGI") * sk.get("mult", 1.5)))
        enc["e_stunned_turns"] = enc.get("e_stunned_turns", 0) + 2
        txt = f"🌿 *{sk_name}*! *{dmg}* damage! Enemy rooted 2 turns!{pet_extra}"
    elif stype == "random_aoe":
        hits = random.randint(3, 6)
        _ra_stat = sk.get("stat", "DEX")
        _ra_mult = sk.get("mult", 1.0)
        dmg = sum(max(1, round(get_stat(p, _ra_stat) * _ra_mult)) for _ in range(hits))
        txt = f"🏹 *{sk_name}*! {hits} shots = *{dmg}* total damage! _(ignores dodge)_{pet_extra}"
    elif stype == "bounty":
        agi = get_stat(p, "AGI"); dex = get_stat(p, "DEX")
        dmg = max(1, round((agi + dex) * sk.get("mult", 2.0)))
        txt = f"🎯 *{sk_name}*! AGI+DEX = *{dmg}* execution damage!{pet_extra}"
    elif stype == "fear_kill":
        agi = get_stat(p, "AGI")
        dmg = max(1, round(agi * sk.get("mult", 5.0)))
        txt = f"💀 *{sk_name}*! AGI×5 = *{dmg}* terrifying damage!{pet_extra}"
    else:
        # Generic fallback: use stat/mult from skill def, primary stat scaling
        stat_key = sk.get("stat", get_primary_stat(p))
        dmg = max(1, round(get_stat(p, stat_key) * sk.get("mult", 1.5)))
        txt = f"💥 *{sk_name}*! *{dmg}* damage!{pet_extra}"

    # Crit check (skip for types that already guarantee a crit or are % of HP)
    if dmg > 0 and stype not in ("crit_dmg", "void_nuke", "execute_multihit") and check_crit(p):
        dmg = apply_crit(p, dmg)
        txt += " 💥 *CRITICAL HIT!*"

    # Per-skill balance scalar (default 1.0). One knob per skill in CLASS_TREE;
    # not applied to %-of-HP nukes which are already target-scaled.
    if dmg > 0 and stype not in ("void_nuke",):
        dmg = max(1, round(dmg * sk.get("power", 1.0)))

    enc["e_hp"] = max(0, enc["e_hp"] - dmg)
    return txt, dmg, False

def _enc_monster_level(monster, base_level):
    lo, hi = monster[3]
    band_lo = max(lo, max(1, base_level - 5))
    band_hi = min(hi, base_level + 5)
    if band_lo > band_hi: band_lo, band_hi = lo, hi
    return random.randint(band_lo, band_hi)

def _enc_npc_level(npc, p_level):
    lo, hi = npc[2], npc[3]
    band_lo = max(lo, max(1, p_level - 5))
    band_hi = min(hi, p_level + 5)
    if band_lo > band_hi: band_lo, band_hi = lo, hi
    return random.randint(band_lo, band_hi)

def _apply_move_effect(enc, move_key, target="player"):
    """Apply a move effect to the encounter state; return flavour string."""
    mv = MONSTER_MOVES.get(move_key, {})
    effect = mv.get("effect")
    flavour = ""
    if effect == "bleed":
        enc["p_bleed"] = enc.get("p_bleed", 0) + 1
        flavour = " Target is bleeding!"
    elif effect == "burn":
        enc["p_burn"] = enc.get("p_burn", 0) + 1
        flavour = " Target is burned!"
    elif effect == "stun":
        enc["p_stunned"] = True
        flavour = " Target is stunned!"
    elif effect == "poison":
        enc["p_poison"] = enc.get("p_poison", 0) + 1
        flavour = " Target is poisoned!"
    elif effect == "weaken":
        enc["p_weakened"] = True
        flavour = " Target is weakened!"
    elif effect == "expose":
        enc["p_exposed"] = True
        flavour = " Target's defense is lowered!"
    elif effect == "fear":
        enc["p_skip"] = True
        flavour = " Target is terrified and skips their turn!"
    elif effect == "heal_self":
        flavour = f" {enc['e_name']} tries to recover but fails!"
    elif effect == "hex":
        enc["p_hexed"] = True
        flavour = " Target is hexed!"
    elif effect == "lifesteal":
        flavour = f" {enc['e_name']} attempts to drain but nothing happens!"
    elif effect == "paralyze":
        enc["p_skip"] = True
        flavour = " Target is paralyzed and loses their turn!"
    elif effect == "blind":
        enc["p_blind"] = True
        flavour = " Target is blinded, accuracy reduced!"
    elif effect == "freeze":
        enc["p_skip"] = True
        flavour = " Target is frozen solid!"
    elif effect == "slow":
        enc["p_slow"] = True
        flavour = " Target is slowed!"
    return flavour

def _apply_dot_tick(enc):
    """Apply bleed/burn/poison ticks each turn; return combined damage text."""
    msgs = []
    # ── Player DOTs (decrement so they expire) ────────────────────────────
    if enc.get("p_bleed", 0) > 0:
        d = max(3, enc["p_max_hp"] // 20)
        enc["p_hp"] = max(0, enc["p_hp"] - d)
        enc["p_bleed"] -= 1
        msgs.append(f"🩸 Bleed -{d}" + (" *(faded)*" if not enc["p_bleed"] else ""))
    if enc.get("p_burn", 0) > 0:
        d = max(3, enc["p_max_hp"] // 18)
        enc["p_hp"] = max(0, enc["p_hp"] - d)
        enc["p_burn"] -= 1
        msgs.append(f"🔥 Burn -{d}" + (" *(faded)*" if not enc["p_burn"] else ""))
    if enc.get("p_poison", 0) > 0:
        d = max(2, enc["p_max_hp"] // 22)
        enc["p_hp"] = max(0, enc["p_hp"] - d)
        enc["p_poison"] -= 1
        msgs.append(f"☠️ Poison -{d}" + (" *(faded)*" if not enc["p_poison"] else ""))
    # ── Enemy DOTs (tick each turn, expire after set duration) ───────────
    if enc.get("e_burning"):
        d = max(3, enc["e_max_hp"] // 18)
        enc["e_hp"] = max(0, enc["e_hp"] - d)
        enc["e_burn_turns"] = enc.get("e_burn_turns", 4) - 1
        if enc["e_burn_turns"] <= 0:
            enc.pop("e_burning", None); enc.pop("e_burn_turns", None)
            msgs.append(f"🔥 {enc['e_name']} burns -{d} *(faded)*")
        else:
            msgs.append(f"🔥 {enc['e_name']} burns -{d}")
    if enc.get("e_poisoned"):
        _pct = enc.get("e_poison_pct", 5)
        d = max(2, enc["e_max_hp"] * _pct // 100)
        enc["e_hp"] = max(0, enc["e_hp"] - d)
        enc["e_poison_turns"] = enc.get("e_poison_turns", 4) - 1
        if enc["e_poison_turns"] <= 0:
            enc.pop("e_poisoned", None); enc.pop("e_poison_turns", None); enc.pop("e_poison_pct", None)
            msgs.append(f"☠️ {enc['e_name']} poisoned -{d} *(faded)*")
        else:
            msgs.append(f"☠️ {enc['e_name']} poisoned -{d}")
    return "\n".join(msgs)

def _enc_npc_attack(enc, p):
    """NPC takes their RPG combat turn; returns action description."""
    # ── Enemy stun: skip attack and decrement counter ─────────────────────────
    if safe_int(enc.get("e_stunned_turns")) > 0:
        enc["e_stunned_turns"] -= 1
        rem = enc["e_stunned_turns"]
        return (f"⚡ *{enc['e_name']}* is stunned — loses their attack!"
                + (f" ({rem} left)" if rem else " *(stun cleared!)*"))

    attacks = NPC_CLASS_ATTACKS.get(enc.get("e_class", "fighter"), _NPC_DEFAULT_ATTACKS)
    atk_name, base_mult, effect = random.choice(attacks)

    # ── Strategy tier: varies each turn so NPC isn't always hitting max ───────
    _NPC_HEALER_CLASSES = {"priest","cleric","bishop","high_priest","saint","paladin","wildflower","nature_chosen"}
    _can_self_heal = enc.get("e_class", "fighter") in _NPC_HEALER_CLASSES
    strategy = random.choices(
        ["rest",  "light", "normal", "heavy"],
        weights=[10 if _can_self_heal else 0, 25, 50, 15]
    )[0]

    if strategy == "rest":
        # Healer-class NPCs fall back to a light attack instead of healing
        strategy = "light"

    if strategy == "light":
        dmg_mult  = base_mult * random.uniform(0.28, 0.52)
        # Light attacks reliably apply a debuff
        if not effect:
            effect = random.choice(["stun","weaken","weaken"])
        effect_chance = 0.75
        label = ""
    elif strategy == "heavy":
        dmg_mult  = base_mult * random.uniform(1.20, 1.55)
        effect        = None   # heavy swings skip debuffs
        effect_chance = 0.0
        label         = "💢 "
    else:  # normal
        dmg_mult  = base_mult
        effect_chance = 0.22
        label         = ""

    # Wide variance so repeated hits feel different
    raw     = int(enc["e_atk"] * dmg_mult * random.uniform(0.70, 1.50))
    def_red = int(get_stat(p, "DEF") * 0.25)
    dmg     = max(1, raw - def_red)
    # Cap single hit at 40% of player max HP
    dmg     = min(dmg, max(1, int(enc["p_max_hp"] * 0.40)))

    _enc_cls = get_player_class(p)
    _enc_pk  = _enc_cls.get("passive_key", "") if _enc_cls else ""
    if _enc_pk == "iron_will":
        dmg = max(1, int(dmg * 0.50))
    if _enc_pk == "defensive_stance":
        if enc["p_hp"] > enc["p_max_hp"] * 0.50:
            dmg = max(1, dmg - 30)
    if _enc_pk == "battle_cry":
        add_charges(p, "battle_cry_str_hits", 5)
    if enc.get("p_exposed"):
        dmg = int(dmg * 1.2); enc["p_exposed"] = False
    if enc.pop("e_weakened", False):
        dmg = max(1, int(dmg * 0.75))

    extra = ""
    if effect and random.random() < effect_chance:
        if effect == "heal_self":
            if _can_self_heal:
                heal = enc["e_max_hp"] // 8
                enc["e_hp"] = min(enc["e_max_hp"], enc["e_hp"] + heal)
                extra = f" (+{heal} HP restored)"
                dmg = max(1, dmg // 2)
            else:
                effect = None  # non-healer NPCs don't get heal_self
        elif effect == "stun":
            enc["p_stunned"] = True
            extra = " ⚡ You are stunned next turn!"
        elif effect == "weaken":
            enc["p_weakened"] = True
            extra = " ⬇️ Your attacks are weakened!"
        elif effect == "lifesteal":
            ls = int(dmg * 0.3)
            enc["e_hp"] = min(enc["e_max_hp"], enc["e_hp"] + ls)
            extra = f" (+{ls} HP drained)"

    # Dodge turns (Vanish / dodge_buff skills)
    if enc.get("enc_dodge_turns", 0) > 0:
        enc["enc_dodge_turns"] -= 1
        return f"*{enc['e_name']}* used *{label}{atk_name}* — 💨 *Dodged!* You slipped away unscathed!"
    # Shield charge: full negate (Shield Wall / Aegis Wall)
    if enc.get("enc_shield_charges", 0) > 0:
        enc["enc_shield_charges"] -= 1
        rem = enc["enc_shield_charges"]
        dmg = 0
        extra += " 🛡️ *Shield negated the hit!*" + (f" ({rem} left)" if rem else " (shield broken!)")
    # Guard: flat reduction per hit (Brace)
    if enc.get("p_guard_hits", 0) > 0:
        enc["p_guard_hits"] -= 1
        if enc["p_guard_hits"] == 0:
            extra += " 🛡️ *(Guard exhausted)*"
        dmg = max(1, int(dmg * 0.60))
    # Reflect damage
    if enc.get("enc_reflect_dmg") and dmg > 0:
        enc["e_hp"] = max(0, enc["e_hp"] - enc["enc_reflect_dmg"])
        extra += f" 🔄 *Reflected {enc['enc_reflect_dmg']} back!*"
        enc.pop("enc_reflect_dmg"); enc.pop("p_guarding", None)
    # Player guarding (Brace skill)
    if enc.pop("p_guarding", False) and not enc.get("enc_reflect_dmg"):
        dmg = max(1, int(dmg * 0.60))
        extra += " 🛡️ *(Guarding!)*"

    enc["p_hp"] = max(0, enc["p_hp"] - dmg)
    return f"*{enc['e_name']}* used *{label}{atk_name}* — *{dmg}* damage!{extra}"

def _enc_monster_attack(enc):
    """Wild monster takes its turn; returns action description."""
    # ── Enemy stun: skip attack and decrement counter ─────────────────────────
    if safe_int(enc.get("e_stunned_turns")) > 0:
        enc["e_stunned_turns"] -= 1
        rem = enc["e_stunned_turns"]
        return (f"⚡ *{enc['e_name']}* is stunned — loses their attack!"
                + (f" ({rem} left)" if rem else " *(stun cleared!)*"))

    moves = enc.get("e_moves", ["tackle"])
    move_key = random.choice(moves)
    mv = MONSTER_MOVES.get(move_key, {"name":"Attack","dmg_mult":1.0,"effect":None})
    dmg_mult = mv.get("dmg_mult", 1.0)
    if dmg_mult == 0.0:
        eff = _apply_move_effect(enc, move_key) if mv.get("effect") else ""
        return f"*{enc['e_name']}* used *{mv['name']}*!{eff}"
    raw = int(enc["e_atk"] * dmg_mult * random.uniform(0.85, 1.15))
    # Fighter in squad? use squad fighter's def
    fighter = enc.get("active_fighter")
    if fighter and fighter.get("type") == "monster":
        f_hp = fighter["hp"]
        f_mhp = fighter["max_hp"]
        def_val = int(f_mhp * 0.1)
        dmg = max(1, raw - def_val)
        enc["p_hp"] = max(0, enc["p_hp"] - dmg)
        eff = _apply_move_effect(enc, move_key) if mv.get("effect") else ""
        return f"*{enc['e_name']}* used *{mv['name']}* on *{fighter.get('nickname') or enc['e_name']}* — {dmg} dmg!{eff}"
    else:
        p = get_player(enc.get("uid"))
        _mon_cls = get_player_class(p) if p else None
        _mon_pk  = _mon_cls.get("passive_key", "") if _mon_cls else ""

        # Strategy tier — monsters also vary their attacks
        _mstrategy = random.choices(
            ["rest",  "light", "normal", "heavy"],
            weights=[8,       22,      55,      15]
        )[0]
        if _mstrategy == "rest":
            heal = enc["e_max_hp"] // 10
            enc["e_hp"] = min(enc["e_max_hp"], enc["e_hp"] + heal)
            return f"*{enc['e_name']}* recuperates and restores *{heal} HP*!"
        elif _mstrategy == "light":
            dmg_mult = dmg_mult * random.uniform(0.28, 0.52)
        elif _mstrategy == "heavy":
            dmg_mult = dmg_mult * random.uniform(1.20, 1.55)
        # normal: use dmg_mult as-is

        raw     = int(enc["e_atk"] * dmg_mult * random.uniform(0.70, 1.50))
        def_red = int(get_stat(p, "DEF") * 0.25) if p else 0
        dmg     = max(1, raw - def_red)
        if _mon_pk == "iron_will":
            dmg = max(1, int(dmg * 0.50))
        if _mon_pk == "defensive_stance":
            if enc["p_hp"] > enc["p_max_hp"] * 0.50:
                dmg = max(1, dmg - 30)
        if enc.pop("e_weakened", False):
            dmg = max(1, int(dmg * 0.75))
        # Cap single hit at 40% of player max HP
        dmg = min(dmg, max(1, int(enc["p_max_hp"] * 0.40)))
        enc["p_hp"] = max(0, enc["p_hp"] - dmg)
        eff = _apply_move_effect(enc, move_key) if mv.get("effect") else ""
        return f"*{enc['e_name']}* used *{mv['name']}* — {dmg} damage!{eff}"

