# ── STATUS EFFECT CHECKERS ────────────────────────────────────────────────────
def _ts_active(p, key):
    ts = p.get(key)
    if not ts: return False
    try: return datetime.now() < datetime.fromisoformat(ts)
    except: return False

def is_defeated(p):
    if p.get("hp", 1) > 0: return False
    return _ts_active(p, "defeated_until")

def is_invincible(p):    return _ts_active(p, "invincible_until")
def is_distracted(p):    return _ts_active(p, "distracted_until") or safe_int(p.get("distract_turns")) > 0
def is_entangled(p):     return _ts_active(p, "entangled_until")  or safe_int(p.get("entangle_turns")) > 0
def is_frozen(p):        return _ts_active(p, "frozen_until")     or safe_int(p.get("freeze_turns")) > 0
def is_stunned(p):       return _ts_active(p, "stunned_until")    or safe_int(p.get("stun_turns")) > 0
def is_vanished(p):      return _ts_active(p, "vanish_until")     or safe_int(p.get("vanish_turns")) > 0
def is_bleeding(p):      return _ts_active(p, "bleed_until")      or safe_int(p.get("bleed_stacks")) > 0
def is_hexed(p):         return _ts_active(p, "hexed_until")      or safe_int(p.get("hex_turns")) > 0
def is_blessed(p):       return _ts_active(p, "blessed_until")    or safe_int(p.get("blessed_turns")) > 0
def is_weakened(p):      return _ts_active(p, "weakened_until")   or safe_int(p.get("weakened_hits")) > 0
def is_healing_blocked(p): return _ts_active(p, "healing_blocked_until") or safe_int(p.get("heal_blocked_turns")) > 0
def is_revival_blocked(p): return _ts_active(p, "revival_blocked_until") or safe_int(p.get("revive_blocked_turns")) > 0
def is_silenced(p):      return _ts_active(p, "silenced_until")   or safe_int(p.get("silence_turns")) > 0
def is_rooted(p):        return is_entangled(p) or is_frozen(p)
def cannot_attack(p):    return is_stunned(p) or is_rooted(p) or is_vanished(p)

def _consume_cc(p) -> str | None:
    """Consume one charge-based CC turn and return the block message, or None if free to act."""
    if safe_int(p.get("stun_turns")) > 0:
        p["stun_turns"] -= 1; save_player(p)
        rem = p["stun_turns"]
        return "⚡ Stunned — lost your action." + (f" ({rem} left)" if rem else " (cleared!)")
    if safe_int(p.get("freeze_turns")) > 0:
        p["freeze_turns"] -= 1; save_player(p)
        rem = p["freeze_turns"]
        return "🧊 Frozen — cannot act." + (f" ({rem} left)" if rem else " (cleared!)")
    if safe_int(p.get("entangle_turns")) > 0:
        p["entangle_turns"] -= 1; save_player(p)
        rem = p["entangle_turns"]
        return "🌿 Entangled — cannot move." + (f" ({rem} left)" if rem else " (cleared!)")
    if _ts_active(p, "stunned_until") or _ts_active(p, "frozen_until") or _ts_active(p, "entangled_until"):
        return "⚡ Status effect active — can't act right now."
    return None
def is_poisoned(p): return _ts_active(p, "poison_until") or safe_int(p.get("poison_stacks")) > 0
def is_burning(p):  return _ts_active(p, "burn_until")   or safe_int(p.get("burn_stacks")) > 0
def has_ward(p):    return _ts_active(p, "ward_until")    or safe_int(p.get("ward_charges")) > 0
def is_exposed(p):  return _ts_active(p, "exposed_until") or safe_int(p.get("exposed_hits")) > 0
def is_branded(p):  return _ts_active(p, "branded_until") or safe_int(p.get("branded_hits")) > 0
def is_marked(p):   return _ts_active(p, "marked_until")  or safe_int(p.get("marked_hits")) > 0

def check_cooldown(ts, secs):
    if not ts: return True
    try: return datetime.now() > datetime.fromisoformat(ts) + timedelta(seconds=secs)
    except: return True

def time_remaining(ts, secs):
    if not ts: return "Ready!"
    try:
        end  = datetime.fromisoformat(ts) + timedelta(seconds=secs)
        diff = end - datetime.now()
        if diff.total_seconds() <= 0: return "Ready!"
        m, s = divmod(int(diff.total_seconds()), 60)
        h, m = divmod(m, 60)
        if h > 0: return f"{h}h {m}m"
        if m > 0: return f"{m}m {s}s"
        return f"{s}s"
    except: return "Ready!"

def time_until(ts):
    """Format time remaining until a target timestamp (e.g. defeated_until)."""
    if not ts: return None
    try:
        diff = datetime.fromisoformat(ts) - datetime.now()
        if diff.total_seconds() <= 0: return None
        m, s = divmod(int(diff.total_seconds()), 60)
        h, m = divmod(m, 60)
        if h > 0: return f"{h}h {m}m"
        if m > 0: return f"{m}m {s}s"
        return f"{s}s"
    except: return None

def set_status(p, key, duration_seconds):
    p[key] = (datetime.now() + timedelta(seconds=duration_seconds)).isoformat()

def set_charges(p, key, count):
    """Set an integer-based charge/turn counter for a status effect."""
    p[key] = max(0, int(count))

def add_charges(p, key, count):
    """Add to an existing integer charge counter (stacks)."""
    p[key] = safe_int(p.get(key)) + max(0, int(count))

def consume_charge(p, key):
    """Decrement a charge counter by 1. Returns True if it was consumed."""
    n = safe_int(p.get(key))
    if n > 0:
        p[key] = n - 1
        return True
    return False

def get_active_statuses(p):
    statuses = []
    # Action-prevention (charge-based)
    _st = safe_int(p.get("stun_turns"))
    if _st > 0:    statuses.append(f"⚡ Stunned ×{_st} (lose next {_st} attack{'s' if _st>1 else ''})")
    elif is_stunned(p): statuses.append("⚡ Stunned (miss next attack)")
    _fr = safe_int(p.get("freeze_turns"))
    if _fr > 0:    statuses.append(f"🧊 Frozen ×{_fr} (cannot act {_fr} turn{'s' if _fr>1 else ''})")
    elif is_frozen(p):  statuses.append("🧊 Frozen Solid (can't attack)")
    _en = safe_int(p.get("entangle_turns"))
    if _en > 0:    statuses.append(f"🌿 Rooted ×{_en} (cannot move {_en} turn{'s' if _en>1 else ''})")
    elif is_entangled(p): statuses.append("🌿 Rooted (can't attack)")
    _si = safe_int(p.get("silence_turns"))
    if _si > 0:    statuses.append(f"🤐 Silenced ×{_si} (no skills next {_si} use{'s' if _si>1 else ''})")
    elif is_silenced(p):  statuses.append("🤐 Silenced (no skills)")
    _di = safe_int(p.get("distract_turns"))
    if _di > 0:    statuses.append(f"😵 Disoriented ×{_di} (30% miss next {_di} attack{'s' if _di>1 else ''})")
    elif is_distracted(p): statuses.append("😵 Disoriented (30% miss)")
    _va = safe_int(p.get("vanish_turns"))
    if _va > 0:    statuses.append(f"👻 Vanished ×{_va} (untargetable {_va} hit{'s' if _va>1 else ''})")
    elif is_vanished(p):   statuses.append("👻 Vanished (untargetable)")
    # DOT effects (charge-based, percentage or flat)
    _ps = safe_int(p.get("poison_stacks"))
    if _ps > 0:
        _pp = safe_int(p.get("poison_pct"))
        _pdesc = f"{_pp}% max HP/action" if _pp else f"{p.get('poison_damage',6)} dmg/action"
        statuses.append(f"🐍 Poison ×{_ps} ({_pdesc})")
    elif is_poisoned(p): statuses.append(f"🐍 Poisoned ({p.get('poison_damage',6)} dmg/30s)")
    _bs = safe_int(p.get("burn_stacks"))
    if _bs > 0:
        _bp = safe_int(p.get("burn_pct"))
        _bdesc = f"{_bp}% max HP/action" if _bp else f"{p.get('burn_damage',8)} dmg/action"
        statuses.append(f"🔥 Burn ×{_bs} ({_bdesc})")
    elif is_burning(p):  statuses.append(f"🔥 Burning ({p.get('burn_damage',8)} dmg/20s)")
    _bl = safe_int(p.get("bleed_stacks"))
    if _bl > 0:
        _blp = safe_int(p.get("bleed_pct"))
        _bldesc = f"{_blp}% max HP/action" if _blp else f"{p.get('bleed_damage',10)} dmg/action"
        statuses.append(f"🩸 Bleed ×{_bl} ({_bldesc})")
    elif is_bleeding(p): statuses.append(f"🩸 Bleeding ({p.get('bleed_damage',10)} dmg/30s)")
    # Incoming-hit modifiers (charge-based)
    _wc = safe_int(p.get("ward_charges"))
    if _wc > 0:    statuses.append(f"✨ Ward ×{_wc} (next {_wc} hit{'s' if _wc>1 else ''} -40% dmg)")
    elif has_ward(p):    statuses.append("✨ Warded (next hit -40%)")
    _sc = safe_int(p.get("shield_charges"))
    if _sc > 0:    statuses.append(f"🛡️ Shield ×{_sc} (negate next {_sc} hit{'s' if _sc>1 else ''})")
    _ex = safe_int(p.get("exposed_hits"))
    if _ex > 0:    statuses.append(f"🗡️ Exposed ×{_ex} (+15% dmg taken {_ex} hit{'s' if _ex>1 else ''})")
    elif is_exposed(p):  statuses.append("🗡️ Exposed (+15% dmg taken)")
    _mk = safe_int(p.get("marked_hits"))
    if _mk > 0:    statuses.append(f"🎯 Marked ×{_mk} (+20% dmg taken {_mk} hit{'s' if _mk>1 else ''})")
    elif is_marked(p):   statuses.append("🎯 Marked for Death (+20% dmg taken)")
    _br = safe_int(p.get("branded_hits"))
    if _br > 0:    statuses.append(f"🔥 Branded ×{_br} (attacker -30% dmg next {_br} hit{'s' if _br>1 else ''})")
    elif is_branded(p):  statuses.append("🔥 Branded (next attack -30%)")
    _wh = safe_int(p.get("weakened_hits"))
    if _wh > 0:    statuses.append(f"💔 Weakened ×{_wh} (+25% dmg taken {_wh} hit{'s' if _wh>1 else ''})")
    elif is_weakened(p): statuses.append("💔 Weakened (+25% dmg taken)")
    # Damage output modifiers
    _hx = safe_int(p.get("hex_turns"))
    if _hx > 0:    statuses.append(f"💀 Hexed ×{_hx} (-25% dmg next {_hx} attack{'s' if _hx>1 else ''})")
    elif is_hexed(p):    statuses.append("💀 Hexed (-25% damage)")
    _bl2 = safe_int(p.get("blessed_turns"))
    if _bl2 > 0:   statuses.append(f"✨ Blessed ×{_bl2} (+10% all stats {_bl2} attack{'s' if _bl2>1 else ''})")
    elif is_blessed(p):  statuses.append("✨ Blessed (+10% all stats)")
    # Regen
    _rg = safe_int(p.get("regen_charges"))
    if _rg > 0:    statuses.append(f"💚 Regen ×{_rg} (+{p.get('regen_amt',0)} HP/trigger)")
    _dr = safe_int(p.get("def_reflect_hits"))
    if _dr > 0:    statuses.append(f"🌿 Thorn Reflect ×{_dr} (40% dmg reduction + reflect next {_dr} hit{'s' if _dr>1 else ''})")
    # Attacker output buffs
    _bc = safe_int(p.get("battle_cry_str_hits"))
    if _bc > 0:    statuses.append(f"💪 Battle Cry (+80 STR next {_bc} attack{'s' if _bc>1 else ''})")
    # Attacker output debuffs
    _ch = safe_int(p.get("cursed_hits"))
    if _ch > 0:    statuses.append(f"💜 Cursed ×{_ch} (-10% dmg next {_ch} attack{'s' if _ch>1 else ''})")
    elif _ts_active(p, "cursed_until"): statuses.append("💜 Cursed (-10% damage)")
    # Misc (with counts)
    _hbt = safe_int(p.get("heal_blocked_turns"))
    if _hbt > 0:   statuses.append(f"🚫 Healing Blocked ×{_hbt} ({_hbt} hit{'s' if _hbt>1 else ''} remaining)")
    elif is_healing_blocked(p): statuses.append("🚫 Healing Blocked")
    _rbt = safe_int(p.get("revive_blocked_turns"))
    if _rbt > 0:   statuses.append(f"☠️ Condemned ×{_rbt} (revival blocked {_rbt} hit{'s' if _rbt>1 else ''})")
    elif is_revival_blocked(p): statuses.append("☠️ Condemned (Verdict's Call)")
    if is_invincible(p):      statuses.append("🛡️ Still Recovering (Invincible)")
    return statuses

def _compact_status_emojis(p):
    """Compact emoji row of active statuses for display next to a player's name on battle cards."""
    out = []
    if safe_int(p.get("stun_turns")) > 0 or is_stunned(p):       out.append("⚡")
    if safe_int(p.get("freeze_turns")) > 0 or is_frozen(p):      out.append("🧊")
    if safe_int(p.get("entangle_turns")) > 0 or is_entangled(p): out.append("🌿")
    if safe_int(p.get("silence_turns")) > 0 or is_silenced(p):   out.append("🤐")
    if safe_int(p.get("distract_turns")) > 0 or is_distracted(p):out.append("😵")
    if safe_int(p.get("vanish_turns")) > 0 or is_vanished(p):    out.append("👻")
    if safe_int(p.get("poison_stacks")) > 0 or is_poisoned(p):   out.append("🐍")
    if safe_int(p.get("burn_stacks")) > 0 or is_burning(p):      out.append("🔥")
    if safe_int(p.get("bleed_stacks")) > 0 or is_bleeding(p):    out.append("🩸")
    if safe_int(p.get("hex_turns")) > 0 or is_hexed(p):          out.append("💀")
    if safe_int(p.get("weakened_hits")) > 0 or is_weakened(p):   out.append("💔")
    if safe_int(p.get("marked_hits")) > 0 or is_marked(p):       out.append("🎯")
    if safe_int(p.get("shield_charges")) > 0:                     out.append("🛡️")
    if safe_int(p.get("ward_charges")) > 0 or has_ward(p):       out.append("✨")
    if safe_int(p.get("blessed_turns")) > 0 or is_blessed(p):    out.append("🌟")
    if safe_int(p.get("battle_cry_str_hits")) > 0:                out.append("💪")
    if safe_int(p.get("regen_charges")) > 0:                      out.append("💚")
    if safe_int(p.get("cursed_hits")) > 0 or _ts_active(p, "cursed_until"): out.append("💜")
    if is_healing_blocked(p):                                      out.append("🚫")
    if is_invincible(p):                                           out.append("🔰")
    if is_revival_blocked(p):                                      out.append("☠️")
    return " ".join(out)

# ── GEAR HELPERS ──────────────────────────────────────────────────────────────
def get_equipped_weapon(p):
    name = p.get("equipped_weapon")
    if not name: return None
    return WEAPONS.get(name)

def get_equipped_armor(p):
    name = p.get("equipped_armor")
    if not name: return None
    return ARMORS.get(name)

def get_equipped_shield(p):
    name = p.get("equipped_shield")
    if not name: return None
    return SHIELDS.get(name)

def get_equipped_accessory(p):
    name = p.get("equipped_accessory")
    if not name: return None
    return ACCESSORIES.get(name)

def get_all_equipped_accessories(p):
    """Return list of all equipped accessory names (non-None only)."""
    names = []
    for slot in ("equipped_accessory","equipped_accessory_2","equipped_accessory_3","equipped_accessory_4"):
        n = p.get(slot)
        if n: names.append(n)
    return names

def _first_free_acc_slot(p):
    """Return the key of the first empty accessory slot, or 'equipped_accessory' if all full."""
    for slot in ("equipped_accessory","equipped_accessory_2","equipped_accessory_3","equipped_accessory_4"):
        if not p.get(slot): return slot
    return "equipped_accessory"  # all full — replace slot 1

def get_enchant(p, item_name):
    raw = sjl(p.get("enchants"), {}).get(item_name)
    if raw is None: return []
    if isinstance(raw, dict): return [raw]
    if isinstance(raw, list): return raw
    return []

def get_all_enchants(p, item_name):
    return get_enchant(p, item_name)

def set_enchant(p, item_name, effect):
    enchants = sjl(p.get("enchants"), {})
    current = enchants.get(item_name, [])
    if isinstance(current, dict):
        current = [current]
    current = [e for e in current if e.get("id") != effect.get("id")]
    current.append(effect)
    if len(current) > 3:
        current = current[-3:]
    enchants[item_name] = current
    p["enchants"] = json.dumps(enchants)

def get_enchant_bonus(p, stat):
    total = 0
    for slot_key in ["equipped_weapon","equipped_armor","equipped_shield",
                     "equipped_accessory","equipped_accessory_2","equipped_accessory_3","equipped_accessory_4",
                     "equipped_hat","equipped_gloves","equipped_boots","equipped_mask"]:
        name = p.get(slot_key)
        if not name: continue
        # Slot-keyed enchants take priority (fixes duplicate-accessory bug); fall back to item-name for old data
        slot_encs = get_enchant(p, slot_key)
        encs = slot_encs if slot_encs else get_enchant(p, name)
        for enchant in encs:
            if enchant.get("type") == stat:
                total += enchant.get("val", 0)
    return total

def get_enhancement(p, item_name):
    return sjl(p.get("enhancements"), {}).get(item_name, 0)

def set_enhancement(p, item_name, level):
    enh = sjl(p.get("enhancements"), {})
    enh[item_name] = level
    p["enhancements"] = json.dumps(enh)

def get_enhance_bonus(p, item_name):
    return get_enhancement(p, item_name) * 6  # was *2

# ── REINFORCE HELPERS ─────────────────────────────────────────────────────────
def get_reinforce_data(p):
    return json.loads(p.get("item_reinforce_data") or "{}")

def set_reinforce_data(p, data):
    p["item_reinforce_data"] = json.dumps(data)

def get_item_reinforce(p, item_name):
    if not item_name: return {"r": 0, "s": 0}
    return get_reinforce_data(p).get(item_name, {"r": 0, "s": 0})

def star_str(s):
    return ("★" * s + "☆" * (3 - s)) if s < 3 else "★★★"

def reinforce_atk_bonus(p, item_name):
    if not item_name: return 0
    d = get_item_reinforce(p, item_name)
    return d["r"] * 3 + d["s"] * 15  # tripled (was r + s*5)

# ── ITEM SET HELPERS ───────────────────────────────────────────────────────────
def get_active_set_bonuses(p):
    equipped = {p.get("equipped_weapon"), p.get("equipped_armor"),
                p.get("equipped_shield"), p.get("equipped_accessory"),
                p.get("equipped_hat"), p.get("equipped_gloves"),
                p.get("equipped_boots"), p.get("equipped_mask")}
    equipped.discard(None)
    bonuses = {}; active_sets = []
    for set_name, data in ITEM_SETS.items():
        if set(data["pieces"]).issubset(equipped):
            active_sets.append(set_name)
            for stat, val in data["bonus"].items():
                bonuses[stat] = bonuses.get(stat, 0) + val
    return bonuses, active_sets

# ── DAILY OBJECTIVE HELPERS ────────────────────────────────────────────────────
def refresh_daily_objectives(p):
    today = datetime.now().strftime("%Y-%m-%d")
    if p.get("daily_obj_date") == today:
        return
    selected = random.sample(DAILY_QUEST_POOL, min(3, len(DAILY_QUEST_POOL)))
    objs = []
    for q in selected:
        tier = random.randint(0, 2)
        target = q["targets"][tier]
        objs.append({
            "id":          q["id"],
            "desc":        q["desc"].format(n=target),
            "progress":    0,
            "target":      target,
            "reward_exp":  q["exp"][tier],
            "reward_gold": scaled_gold(p.get("level", 1), q["gold"][tier]),
            "done":        False,
        })
    p["daily_objectives"] = json.dumps(objs)
    p["daily_obj_date"]   = today

def track_objective(p, obj_id, amount=1):
    """Increment objective progress. Returns list of (desc, exp, gold) for newly completed ones."""
    _goal_bump(p, obj_id, amount)  # weekly group goal counts qualifying actions
    refresh_daily_objectives(p)
    objs = json.loads(p.get("daily_objectives") or "[]")
    completed = []
    for obj in objs:
        if obj["id"] == obj_id and not obj.get("done"):
            obj["progress"] = min(obj["progress"] + amount, obj["target"])
            if obj["progress"] >= obj["target"]:
                obj["done"] = True
                # Scale the table's flat EXP (300..1500) to 1.6%-8% of a level
                _obj_exp = exp_share(p.get("level", 1), min(0.08, obj["reward_exp"] / 1500 * 0.08))
                completed.append((obj["desc"], _obj_exp, obj["reward_gold"]))
    p["daily_objectives"] = json.dumps(objs)
    if completed:
        p["total_obj_completed"] = safe_int(p.get("total_obj_completed")) + len(completed)
    return completed

def get_weapon_atk(p):
    w = get_equipped_weapon(p)
    if not w: return 0
    name = p.get("equipped_weapon")
    ok, _ = can_equip_weapon(p, name)
    if not ok: return 0
    base = w["atk"] + get_enhance_bonus(p, name) + reinforce_atk_bonus(p, name)
    for enchant in get_enchant(p, name):
        if enchant.get("type") == "flat_dmg":
            base += enchant["val"]
        if enchant.get("type") == "atk":
            base += enchant["val"]
    return base

def get_armor_def(p):
    a = get_equipped_armor(p); s = get_equipped_shield(p)
    a_name = p.get("equipped_armor"); s_name = p.get("equipped_shield")
    a_ok, _ = can_equip_armor(p, a_name) if a_name else (True, "")
    s_ok = True
    if s_name:
        s_data = SHIELDS.get(s_name, {})
        cls_line = get_class_line(p); path = p.get("class_path")
        if s_data.get("type") == "claw":
            s_ok = cls_line == "thief" and path == "B"
        else:
            s_ok = cls_line == "warrior" and path == "A"
    a_val = (a.get("def", 0) + get_enhance_bonus(p, a_name) + reinforce_atk_bonus(p, a_name)) if (a and a_ok) else 0
    s_val = (s.get("def", 0) + get_enhance_bonus(p, s_name) + reinforce_atk_bonus(p, s_name)) if (s and s_ok) else 0
    for enc in (get_enchant(p, a_name) if a_name else []):
        if enc.get("type") == "armor_def": a_val += enc["val"]
    for enc in (get_enchant(p, s_name) if s_name else []):
        if enc.get("type") == "armor_def": s_val += enc["val"]
    bonus = 0
    for slot_key, pool in [("equipped_hat", HATS), ("equipped_gloves", GLOVES),
                            ("equipped_boots", BOOTS), ("equipped_mask", MASKS)]:
        name = p.get(slot_key)
        if not name: continue
        item = pool.get(name)
        if not item: continue
        val = item["def"] + get_enhance_bonus(p, name) + reinforce_atk_bonus(p, name)
        for enc in get_enchant(p, name):
            if enc.get("type") == "armor_def": val += enc["val"]
        bonus += val
    return a_val + s_val + bonus

def _get_secondary_armor_def(p):
    """DEF from hat/gloves/boots/mask only — used to apply a separate DR cap."""
    bonus = 0
    for slot_key, pool in [("equipped_hat", HATS), ("equipped_gloves", GLOVES),
                            ("equipped_boots", BOOTS), ("equipped_mask", MASKS)]:
        name = p.get(slot_key)
        if not name: continue
        item = pool.get(name)
        if not item: continue
        val = item["def"] + get_enhance_bonus(p, name) + reinforce_atk_bonus(p, name)
        for enc in get_enchant(p, name):
            if enc.get("type") == "armor_def": val += enc["val"]
        bonus += val
    return bonus

def gear_line(p, slot_key):
    """Return a display string for an equipped item slot with reinforce, +enh and ✨enchant tags."""
    name = p.get(slot_key)
    if not name:
        return "None"
    enh   = get_enhancement(p, name)
    encs  = get_enchant(p, name)
    rd    = get_item_reinforce(p, name)
    parts = [name]
    if rd["s"] > 0 or rd["r"] > 0:
        parts.append(star_str(rd["s"]))
        if rd["r"] > 0: parts.append(f"[{rd['r']}/20]")
    if enh:
        parts.append(f"+{enh}")
    if encs:
        parts.append(f"✨×{len(encs)}")
    return " ".join(parts)

def get_accessory_bonus(p, stat):
    total = 0
    _bool_stats = ("revive_once","priest_aoe","spell_double_chance","revive_heal_bonus")
    for slot in ("equipped_accessory","equipped_accessory_2","equipped_accessory_3","equipped_accessory_4"):
        name = p.get(slot)
        if not name: continue
        acc = ACCESSORIES.get(name)
        if not acc: continue
        effect = acc.get("effect", {})
        # Direct stat
        if stat in effect:
            if stat in _bool_stats: return effect[stat]  # any one gives the effect
            total += effect[stat]
        # all_stats
        elif stat in ("STR","DEF","AGI","INT","WIS","DEX","LUK") and "all_stats" in effect:
            total += effect["all_stats"]
        # primary_stat / any_stat both boost the class's primary stat
        elif "primary_stat" in effect:
            primary = get_primary_stat(p)
            if stat == primary:
                total += effect["primary_stat"]
        elif "any_stat" in effect:
            primary = get_primary_stat(p)
            if stat == primary:
                total += effect["any_stat"]
    return total

# Maps new class lines → existing gear category so they can use shared weapon/armor pools
_GEAR_LINE_MAP = {
    "botanist":       "mage",
    "enchantress":    "mage",
    "valkyrie":       "warrior",
    "phantom_dancer": "thief",
    "serpent":        "warrior",   # serpent can wear warrior armors + their own scales
}

def _weapon_class_tag(item_name):
    """Return a display tag like '⚔️ Warrior (A)' for a weapon, or '' for non-weapons."""
    w = WEAPONS.get(item_name)
    if not w: return ""
    line  = w.get("line") or w.get("class", "")
    wtype = w.get("type", "")
    emoji = _LINE_EMOJI.get(line, "")
    arch  = LINE_ARCHETYPE.get(line, line.capitalize())
    path  = _WEAPON_TYPE_PATH.get(wtype, "")
    return f"{emoji} {arch}{(' (' + path + ')') if path else ''}".strip()


def can_equip_weapon(p, weapon_name):
    w = WEAPONS.get(weapon_name)
    if not w: return False, "Unknown weapon."
    cls_id = p.get("class_id")
    if not cls_id: return False, "Choose a class first."
    cls_data = CLASS_TREE.get(cls_id, {})
    raw_line   = cls_data.get("line", "")
    gear_line  = _GEAR_LINE_MAP.get(raw_line, raw_line)
    weapon_class = w.get("class")
    if weapon_class != gear_line and weapon_class != raw_line:
        return False, f"Only {weapon_class.replace('_',' ').capitalize()} classes can use this."
    weapon_type = w.get("type")
    allowed = cls_data.get("weapon_types", [])
    if weapon_type not in allowed:
        nice = " or ".join(t.replace("_", " ") for t in allowed)
        return False, (f"Your current class ({cls_data['name']}) cannot use "
                       f"{weapon_type.replace('_', ' ')} weapons. "
                       f"This class uses: {nice}.")
    return True, ""

def can_equip_armor(p, armor_name):
    a = ARMORS.get(armor_name)
    if not a: return False, "Unknown armor."
    cls_id   = get_player_class_id(p)
    cls_data = CLASS_TREE.get(cls_id, {})
    raw_line  = cls_data.get("line", "")
    gear_line = _GEAR_LINE_MAP.get(raw_line, raw_line)
    armor_class = a.get("class")
    if armor_class and armor_class != gear_line and armor_class != raw_line:
        return False, f"Only {armor_class.replace('_',' ').capitalize()} classes can wear this."
    return True, ""

def get_player_class_id(p):
    return p.get("class_id")

def get_player_class(p):
    cid = p.get("class_id")
    if not cid: return None
    return CLASS_TREE.get(cid)

def get_class_line(p):
    cls = get_player_class(p)
    if not cls: return None
    return cls.get("line")

def get_primary_stat(p):
    cls = get_player_class(p)
    if not cls: return "STR"
    return cls.get("primary_stat", "STR")

def get_all_skills(p):
    """Return all skills unlocked by player across all class tiers."""
    return sjl(p.get("all_skills"), [])

def get_class_path(p):
    return p.get("class_path")  # "A" or "B" or None

def get_combat_skills(p, skip_types=None):
    """Return skills for the player's current class path only.

    - No class_path set (still base class): return base class skills only.
    - class_path set: return ONLY path chain skills up to current class
      (base class skills are superseded once a path is chosen).
    """
    class_id   = p.get("class_id")
    class_path = p.get("class_path")  # "A" or "B"
    if not class_id:
        return []
    cls  = CLASS_TREE.get(class_id, {})
    line = cls.get("line")
    if not line:
        return []
    skills = []
    seen   = set()
    def _add(sk):
        if sk["name"] not in seen:
            seen.add(sk["name"]); skills.append(sk)

    if not class_path:
        # Pre-path: show base class skills only
        for cid, cdef in CLASS_TREE.items():
            if cdef.get("line") == line and not cdef.get("path"):
                for sk in cdef.get("skills", []):
                    _add(sk)
    else:
        # Post-path: show path chain skills only (base class skills superseded).
        # Guard: only iterate if class_id is actually in the chain.
        path_chain = CLASS_PATHS.get(line, {}).get(class_path, [])
        if class_id in path_chain:
            for path_cid in path_chain:
                for sk in CLASS_TREE.get(path_cid, {}).get("skills", []):
                    _add(sk)
                if path_cid == class_id:
                    break

    if skip_types:
        skills = [sk for sk in skills if sk.get("type") not in skip_types]
    return skills


def get_all_passive_keys(p):
    """Return all passive_keys inherited by this player: base class + full path chain up to current class.
    Used by calc_attack_damage so every tier's passive bonuses stack correctly."""
    class_id   = p.get("class_id")
    class_path = p.get("class_path")
    if not class_id:
        return set()
    cls  = CLASS_TREE.get(class_id, {})
    line = cls.get("line")
    if not line:
        return set()
    pks = set()
    # Base class passives always inherited
    for cid, cdef in CLASS_TREE.items():
        if cdef.get("line") == line and not cdef.get("path"):
            for sk in cdef.get("skills", []):
                if sk.get("passive_key"):
                    pks.add(sk["passive_key"])
    # Path chain passives up to current class
    if class_path:
        path_chain = CLASS_PATHS.get(line, {}).get(class_path, [])
        if class_id in path_chain:
            for path_cid in path_chain:
                for sk in CLASS_TREE.get(path_cid, {}).get("skills", []):
                    if sk.get("passive_key"):
                        pks.add(sk["passive_key"])
                if path_cid == class_id:
                    break
    return pks


def get_stat(p, stat):
    defaults = {"STR":5,"DEF":0,"AGI":5,"INT":5,"WIS":5,"DEX":5,"LUK":5}
    base  = safe_stats(p).get(stat, defaults.get(stat, 5))
    acc   = get_accessory_bonus(p, stat)
    all_s = get_accessory_bonus(p, "all_stats")
    blessed_bonus = 1 if is_blessed(p) else 0
    # Active title bonus
    active_title = p.get("active_title", "")
    title_bonus_dict = TITLE_BONUSES.get(active_title, {})
    title_bonus = title_bonus_dict.get(stat, 0)
    all_title = title_bonus_dict.get("all_stats", 0)
    # Item set bonus
    set_bonuses, _ = get_active_set_bonuses(p)
    set_stat  = set_bonuses.get(stat, 0)
    set_all   = set_bonuses.get("all_stats", 0)
    battle_cry_bonus = 80 if stat == "STR" and safe_int(p.get("battle_cry_str_hits")) > 0 else 0
    guild_bonus = safe_int(p.get("guild_stat_bonus", 0)) if stat in ("STR","AGI","INT","WIS","DEX","LUK") else 0
    weapon_bonus = WEAPONS.get(p.get("equipped_weapon") or "", {}).get("stat_bonus", {}).get(stat, 0)
    empire_sb = _empire_stat_bonuses(p)
    empire_stat = empire_sb.get(stat, 0) + empire_sb.get("all_stats", 0)
    if stat in ("STR","AGI","INT","WIS","DEX","LUK"):
        return base + acc + all_s + blessed_bonus + title_bonus + all_title + set_stat + set_all + battle_cry_bonus + guild_bonus + weapon_bonus + empire_stat
    return base + acc + all_s + blessed_bonus

def calc_max_hp(p):
    base   = max_hp_for_level(p["level"])
    # Apply class-line HP multiplier (warrior tankiest, mage squishiest)
    cls_line = CLASS_TREE.get(p.get("class_id") or "", {}).get("line", "")
    mult = _CLASS_LINE_HP_MULT.get(cls_line, 1.0)
    base = int(base * mult)
    acc_hp = get_accessory_bonus(p, "hp")
    enc_hp = get_enchant_bonus(p, "max_hp")
    temp   = safe_int(p.get("temp_hp_bonus")) if _ts_active(p, "temp_hp_until") else 0
    set_bonuses, _ = get_active_set_bonuses(p)
    set_hp = set_bonuses.get("hp", 0)
    def_hp = round(get_stat(p, "DEF") * 10)
    str_hp = round(get_stat(p, "STR") * 2)   # secondary: physical constitution
    wis_hp = round(get_stat(p, "WIS") * 3)   # wisdom: mental fortitude / resilience
    retire_hp = safe_int(p.get("pet_retire_hp"))
    empire_hp = _empire_stat_bonuses(p).get("max_hp", 0)
    title_hp  = TITLE_BONUSES.get(p.get("active_title", ""), {}).get("max_hp", 0)
    return base + acc_hp + enc_hp + temp + set_hp + def_hp + str_hp + wis_hp + retire_hp + empire_hp + title_hp

TIER_THRESHOLDS = {1: 5, 2: 10, 3: 30, 4: 60, 5: 100}
 
def get_class_tier(p):
    """Return current class tier 1-5 based on unlock level."""
    cls = get_player_class(p)
    if not cls: return 0
    unlock = cls.get("skills", [{}])[0].get("unlock", 5)
    for tier, lvl in sorted(TIER_THRESHOLDS.items(), reverse=True):
        if unlock >= lvl: return tier
    return 1
 
def get_proc_chance(base_pct, p):
    """Return proc chance scaled by class tier."""
    tier = get_class_tier(p)
    return base_pct + (tier * 0.03)
 
def _apply_weapon_on_hit(attacker, defender, dmg):
    """Check equipped weapon's on_hit effect. Returns (triggered, msg, extra_dmg)."""
    weap = WEAPONS.get(attacker.get("equipped_weapon") or "", {})
    oh = weap.get("on_hit")
    if not oh: return False, "", 0
    effect = oh.get("effect"); val = oh.get("val", 0)
    if random.random() >= 0.30: return False, "", 0  # 30% proc chance for all on_hit weapons
    if effect == "double_hit":
        extra = max(1, round(dmg * val))
        extra = calc_defense(defender, extra)
        defender["hp"] = max(0, defender["hp"] - extra)
        return True, f"⚡ *Double Strike!* Weapon lashes out again for *{extra}* dmg!", extra
    elif effect == "poison":
        stacks = int(val)
        add_charges(defender, "poison_stacks", stacks)
        defender["poison_pct"] = max(safe_int(defender.get("poison_pct", 0)), 25)
        return True, f"☠️ *Venom Proc!* Poison ×{stacks} seeps in — 25% max HP/action!", 0
    elif effect == "burn":
        stacks = int(val)
        add_charges(defender, "burn_stacks", stacks)
        defender["burn_pct"] = 10
        return True, f"🔥 *Ignite!* Weapon scorches — Burn ×{stacks} (10% max HP/action)!", 0
    elif effect == "lifesteal":
        steal = max(1, round(dmg * val))
        attacker["hp"] = min(calc_max_hp(attacker), attacker["hp"] + steal)
        return True, f"💜 *Lifesteal!* Drained *{steal}* HP from the wound!", 0
    elif effect == "exposed":
        hits = int(val)
        add_charges(defender, "exposed_hits", hits)
        return True, f"🗡️ *Rend!* Exposed ×{hits} — +15% dmg taken for {hits} hits!", 0
    return False, "", 0


def calc_proc_effect(attacker, defender, dmg):
    """
    Roll for class-specific proc on normal /attack.
    Returns (proc_triggered, proc_message, extra_dmg).
    Mutates attacker/defender state if proc fires.
    """
    cls = get_player_class(attacker)
    if not cls: return False, "", 0
 
    line = cls.get("line")
    path = attacker.get("class_path")
    now  = datetime.now()
 
    # ── WARRIOR PATH A  -  Blessed Strike ──────────────────────
    if line == "warrior" and path == "A":
        chance = get_proc_chance(0.10, attacker)
        if random.random() < chance:
            add_charges(defender, "burn_stacks", 3)
            defender["burn_pct"] = 10
            return True, "⚔️ *Blessed Strike!* Holy fire ignites — Burn ×3 (10% max HP/action)!", 0

    # ── WARRIOR PATH B  -  Double Strike ───────────────────────
    elif line == "warrior" and path == "B":
        chance = get_proc_chance(0.15, attacker)
        if random.random() < chance:
            extra = round(dmg * 0.60)
            extra = calc_defense(defender, extra)
            defender["hp"] = max(0, defender["hp"] - extra)
            return True, f"⚔️ *Double Strike!* A second blow lands for {extra} dmg!", extra

    # ── MAGE PATH A  -  Arcane Burn ─────────────────────────────
    elif line == "mage" and path == "A":
        chance = get_proc_chance(0.12, attacker)
        if random.random() < chance:
            add_charges(defender, "burn_stacks", 2)
            defender["burn_pct"] = 10
            return True, "🔥 *Arcane Burn!* Magical fire clings — Burn ×2 (10% max HP/action)!", 0

    # ── MAGE PATH B  -  Soul Drain ──────────────────────────────
    elif line == "mage" and path == "B":
        chance = get_proc_chance(0.12, attacker)
        if random.random() < chance:
            steal = round(dmg * 0.50)
            attacker["hp"] = min(calc_max_hp(attacker), attacker["hp"] + steal)
            return True, f"🌑 *Soul Drain!* Stole {steal} HP from the wound!", 0

    # ── THIEF PATH A  -  Poison Strike ─────────────────────────
    elif line == "thief" and path == "A":
        chance = get_proc_chance(0.15, attacker)
        if random.random() < chance:
            add_charges(defender, "poison_stacks", 4)
            defender["poison_pct"] = 30
            return True, "🐍 *Poison Strike!* Poison ×4 — 30% max HP each action!", 0

    # ── THIEF PATH B  -  Exposed ────────────────────────────────
    elif line == "thief" and path == "B":
        chance = get_proc_chance(0.15, attacker)
        if random.random() < chance:
            add_charges(defender, "exposed_hits", 3)
            return True, "🗡️ *Exposed!* Exposed ×3 — +15% dmg taken next 3 hits!", 0

    # ── ARCHER PATH A  -  Pin Down ──────────────────────────────
    elif line == "archer" and path == "A":
        chance = get_proc_chance(0.20, attacker)
        if random.random() < chance and safe_int(defender.get("distract_turns", 0)) < 3:
            add_charges(defender, "distract_turns", 3)
            return True, "🏹 *Pin Down!* Distracted ×3 — 30% miss chance next 3 attacks!", 0

    # ── ARCHER PATH B  -  Headshot ──────────────────────────────
    elif line == "archer" and path == "B":
        chance = get_proc_chance(0.20, attacker)
        if random.random() < chance:
            extra = round(dmg * 1.50)
            extra = calc_defense(defender, extra)
            defender["hp"] = max(0, defender["hp"] - extra)
            return True, f"🎯 *Headshot!* Clean hit for {extra} bonus dmg!", extra

    # ── PRIEST PATH A  -  Holy Ward (on attack) ────────────────
    elif line == "priest" and path == "A":
        chance = get_proc_chance(0.20, attacker)
        if random.random() < chance:
            add_charges(attacker, "ward_charges", 2)
            return True, "✨ *Holy Ward!* Ward ×2 — next 2 incoming hits -40% damage!", 0

    # ── PRIEST PATH B  -  Holy Brand ────────────────────────────
    elif line == "priest" and path == "B":
        chance = get_proc_chance(0.15, attacker)
        if random.random() < chance:
            add_charges(defender, "branded_hits", 2)
            return True, "🔥 *Holy Brand!* Branded ×2 — attacker's next 2 strikes -30%!", 0

    # ── SERPENT PATH A  -  Venom Coil ───────────────────────────
    elif line == "serpent" and path == "A":
        chance = get_proc_chance(0.22, attacker)
        if random.random() < chance and safe_int(defender.get("poison_stacks", 0)) < 12:
            add_charges(defender, "poison_stacks", 3)
            _a_pks_proc = get_all_passive_keys(attacker)
            _vpct = (50 if "serpentine_mastery" in _a_pks_proc else
                     40 if "death_venom"        in _a_pks_proc else
                     35 if "toxic_fangs"         in _a_pks_proc else 25)
            defender["poison_pct"] = max(safe_int(defender.get("poison_pct", 0)), _vpct)
            return True, f"🐍 *Venom Coil!* Venom ×3 seeps in — {_vpct}% max HP/action!", 0

    # ── SERPENT PATH B  -  Crushing Coils ───────────────────────
    elif line == "serpent" and path == "B":
        chance = get_proc_chance(0.22, attacker)
        if random.random() < chance:
            _cc_dist = safe_int(defender.get("distract_turns", 0))
            _cc_weak = safe_int(defender.get("weakened_hits", 0))
            if _cc_dist < 4: add_charges(defender, "distract_turns", min(3, 4 - _cc_dist))
            if _cc_weak < 5: add_charges(defender, "weakened_hits", 2)
            return True, f"🐍 *Crushing Coils!* {defender['username']} coiled — Distract ×2 + Weakened ×1!", 0

    return False, "", 0

def calc_attack_damage(attacker, weather=None):
    base      = random.randint(1, 10)
    weapon    = get_weapon_atk(attacker)
    perm      = safe_int(attacker.get("perm_dmg_bonus"))
    acc_atk   = get_accessory_bonus(attacker, "atk")
    acc_atk  += get_enchant_bonus(attacker, "atk")
    acc_atk  += get_enchant_bonus(attacker, "flat_dmg")
    stats     = safe_stats(attacker)
    primary   = get_primary_stat(attacker)
    stat_val  = get_stat(attacker, primary)
    # All classes scale 1.0× their primary stat
    stat_bonus = round(stat_val * 1.0)
    # Universal off-stat bleed: every non-primary stat contributes 0.20× damage
    # so investing in any stat always has a real effect regardless of class
    for _os in ("STR", "AGI", "INT", "WIS", "DEX", "LUK"):
        if _os != primary:
            stat_bonus += round(get_stat(attacker, _os) * 0.20)
    # Level matters — 4 damage per level so level 30 = +120 (was +15)
    level_bonus = attacker["level"] * 4

    retire_atk = safe_int(attacker.get("pet_retire_atk"))
    empire_atk = _empire_stat_bonuses(attacker).get("atk_flat", 0)
    raw = base + weapon + perm + acc_atk + stat_bonus + level_bonus + retire_atk + empire_atk

    # Weather
    if weather: raw = round(raw * weather.get("dmg_mod", 1.0))

    # Buffs
    buff_mod = 1.0
    if is_blessed(attacker):  buff_mod += 0.10
    if is_hexed(attacker):    buff_mod -= 0.25
    # Legacy: old weakened_until still reduces attacker damage for backward compat
    if _ts_active(attacker, "weakened_until") and not safe_int(attacker.get("weakened_hits")):
        buff_mod -= 0.25

    # Passive class bonuses that add to damage.
    # active_pks collects all passive_keys from base class + full path chain,
    # fixing the old bug where cls.get("passive_key","") always returned "".
    active_pks = get_all_passive_keys(attacker)
    cls = get_player_class(attacker)
    if cls:
        pk = ""  # legacy; all checks now use active_pks
        if "warcry" in active_pks:
            recent = sjl(attacker.get("recent_attackers"), [])
            now = datetime.now()
            recent_30 = [r for r in recent
                         if (now - datetime.fromisoformat(r["ts"])).total_seconds() < 1800]
            if len(recent_30) > 1: buff_mod += 0.20
        if "arcane_mind" in active_pks:  buff_mod += 0.20  # was raw+=INT (double-dip on primary)
        if "marked" in active_pks:
            if attacker.get("mark_first_hit"):
                buff_mod += 0.25
        if "steady_aim" in active_pks:
            stacks = safe_int(attacker.get("steady_aim_stacks"))
            buff_mod += min(1.00, stacks * 0.15)  # was 0.50 cap at 0.10/stack
        if "dead_or_alive" in active_pks:
            extra = safe_int(attacker.get("deadeye_kill_bonus"))
            raw += extra
        # Botanist
        if "natural_growth" in active_pks:  raw += get_stat(attacker, "WIS") * 0.15
        if "thorn_aura" in active_pks:      raw += get_stat(attacker, "WIS") * 0.20
        if "venomous_growth" in active_pks: buff_mod += 0.15
        if "primal_fury" in active_pks:
            raw += get_stat(attacker, "WIS") * 0.25; buff_mod += 0.10
        if "blossoming" in active_pks:      buff_mod += 0.05
        if "eternal_bloom" in active_pks:   buff_mod += 0.10
        # Enchantress
        if "hexmark" in active_pks:         buff_mod += 0.12
        if "stacking_curses" in active_pks: buff_mod += 0.15
        if "misery_aura" in active_pks:     raw += get_stat(attacker, "INT") * 0.10
        if "empress_dread" in active_pks:   buff_mod += 0.20
        if "harmonize" in active_pks:
            buff_mod += min(0.12, safe_int(attacker.get("harmony_stacks", 0)) * 0.04)
        if "battle_hymn" in active_pks:     buff_mod += 0.05
        if "muses_grace" in active_pks:     buff_mod += 0.20
        if "lorekeeping" in active_pks:     buff_mod += 0.05
        # Valkyrie
        if "iron_will" in active_pks:
            _iw_hp_pct = attacker["hp"] / max(1, attacker.get("max_hp", attacker["hp"]))
            if _iw_hp_pct < 0.40: buff_mod += 0.10
        if "einherjar_will" in active_pks:
            _hp_pct = attacker["hp"] / max(1, attacker.get("max_hp", attacker["hp"]))
            if _hp_pct < 0.30: buff_mod += 0.20
        if "thunder_step" in active_pks:
            if attacker.get("thunder_dodge_ready"):
                buff_mod += 0.40; attacker["thunder_dodge_ready"] = 0
        if "storms_eye" in active_pks:      buff_mod += 0.05
        if "celestial_wrath" in active_pks: buff_mod += 0.25
        if "defenders_oath" in active_pks:
            buff_mod += min(0.30, safe_int(attacker.get("oath_stacks", 0)) * 0.10)
        if "iron_bulwark" in active_pks:    buff_mod += 0.05
        # Phantom Dancer
        if "waltz" in active_pks:
            if attacker.get("waltz_dodge_ready"):
                buff_mod += 0.60; attacker["waltz_dodge_ready"] = 0
        if "rhythm" in active_pks:
            buff_mod += min(0.16, safe_int(attacker.get("rhythm_stacks", 0)) * 0.04)
        if "flourish" in active_pks:
            buff_mod += min(0.15, safe_int(attacker.get("flourish_stacks", 0)) * 0.05)
        if "adrenaline" in active_pks:
            _hp_pct = attacker["hp"] / max(1, attacker.get("max_hp", attacker["hp"]))
            if _hp_pct < 0.30: buff_mod += 0.30
        if "death_whirl" in active_pks:
            _hp_pct = attacker["hp"] / max(1, attacker.get("max_hp", attacker["hp"]))
            if _hp_pct < 0.40: buff_mod += 0.30
        if "final_performance" in active_pks:
            _hp_pct = attacker["hp"] / max(1, attacker.get("max_hp", attacker["hp"]))
            if _hp_pct < 0.25: buff_mod += 0.50
        # Mage offensive passives
        if "arcane_pulse" in active_pks:  raw += get_stat(attacker, "INT") * 0.50  # up from 0.10
        if "arcane_mastery" in active_pks:
            attacker["arcane_mastery_count"] = safe_int(attacker.get("arcane_mastery_count")) + 1
            if attacker["arcane_mastery_count"] >= 3:
                buff_mod += 2.0; attacker["arcane_mastery_count"] = 0
        if "eternal_wisdom" in active_pks: buff_mod += 0.20
        if "spell_surge" in active_pks:
            if random.random() < 0.20: buff_mod += 1.0
        # Priest offensive passives
        if "holy_fervor" in active_pks:   raw += get_stat(attacker, "WIS") * 0.50  # up from 0.10
        if "wrath_of_the_righteous" in active_pks: buff_mod += 0.15
        # dark_sense: +15% vs debuffed targets handled post-hit (needs defender reference)
        # Archer offensive passives
        if "keen_sight" in active_pks:    raw += get_stat(attacker, "DEX") * 0.50
        if "tracker" in active_pks:       buff_mod += 0.15  # precision tracking
        if "marked_for_death" in active_pks: pass  # handled post-hit (needs defender reference)
        # Warrior passives — shield_wall is now a block passive (handled in calc_defense)
        if "divine_judgment" in active_pks: buff_mod += 0.25
        # Thief — nimble: AGI bonus damage
        if "nimble" in active_pks:        raw += get_stat(attacker, "AGI") * 0.50
        # Valkyrie
        if "thunderstrike" in active_pks:
            attacker["thunderstrike_count"] = safe_int(attacker.get("thunderstrike_count")) + 1
            if attacker["thunderstrike_count"] >= 5:
                buff_mod += 0.60; attacker["thunderstrike_count"] = 0
        # Phantom Dancer
        if "whirlwind" in active_pks:
            if random.random() < 0.15: buff_mod += 0.30
        # Thief — shadowstep: after dodging, next attack +50%
        if "shadowstep" in active_pks and attacker.get("shadowstep_ready"):
            buff_mod += 0.50; attacker["shadowstep_ready"] = 0
        # Charmsong — melody resonance stacks (+5% per stack, up to 15%)
        if "melody" in active_pks:
            buff_mod += min(0.15, safe_int(attacker.get("melody_stacks", 0)) * 0.05)
        # Cursed debuff on attacker: attacker has been cursed, deals 10% less
        if safe_int(attacker.get("cursed_hits")) > 0:
            buff_mod -= 0.10

    # Accessory low HP bonus
    if get_accessory_bonus(attacker, "low_hp_dmg_bonus"):
        hp_pct = attacker["hp"] / max(1, attacker["max_hp"])
        if hp_pct < 0.30:
            buff_mod += get_accessory_bonus(attacker, "low_hp_dmg_bonus")

    # Evasive Momentum: stacks earned by dodging, spent on the next attack
    _dm_stacks = safe_int(attacker.get("dodge_momentum"))
    if _dm_stacks > 0:
        buff_mod += 0.08 * _dm_stacks
        attacker["dodge_momentum"] = 0

    # King of the Table: +5% damage while holding the crown
    if _is_king(attacker):
        buff_mod += 0.05

    # Combat Power multiplier: higher CP = higher damage
    # +30% base, +3% per 300 CP tier, no cap
    try:
        _cp = calc_combat_power(attacker)
        cp_mult = 1.30 + (_cp // 300) * 0.03
    except Exception:
        cp_mult = 1.30

    return max(1, round(raw * buff_mod * cp_mult))

def calc_defense(defender, dmg):
    stats      = safe_stats(defender)
    def_val    = get_stat(defender, "DEF")
    armor_def  = get_armor_def(defender)

    # Base reduction from DEF stat (softcap at DEF 72 = 50%)
    def_reduction  = min(0.50, (def_val / 10) * 0.07)
    # Excess DEF above cap converts to flat HP absorb per hit
    excess_def_absorb = max(0, (def_val - 72) * 5) if def_val > 72 else 0

    # Primary armor (chest+shield) and secondary slots (hat/gloves/boots/mask) have separate caps
    secondary_armor_def = _get_secondary_armor_def(defender)
    primary_armor_def   = armor_def - secondary_armor_def
    armor_reduction = min(0.20, primary_armor_def / 300) + min(0.10, secondary_armor_def / 300)

    # Universal stat bonuses: WIS → DR, AGI → dodge (all classes benefit regardless of primary)
    wis_dr = min(0.10, get_stat(defender, "WIS") * 0.005)   # 0.5% per WIS, cap 10%
    agi_dodge = min(0.08, get_stat(defender, "AGI") * 0.0015)  # 0.15% per AGI, cap 8%
    if random.random() < agi_dodge:
        return 0
    def_reduction += wis_dr

    # Serpent class: built-in snake companion absorbs a portion of damage
    _defender_line = get_class_line(defender)
    if _defender_line == "serpent":
        _def_pks_serp = get_all_passive_keys(defender)
        # Higher-tier serpents get more absorption
        if "immortal_coils" in _def_pks_serp or "coiling_stance" in _def_pks_serp:
            _snake_absorb = 0.30  # Ancient Serpent / Serpent Warlord: 30% absorbed
        elif "armored_scales" in _def_pks_serp or "serpents_resolve" in _def_pks_serp:
            _snake_absorb = 0.25  # Serpent Guard / Knight: 25% absorbed
        else:
            _snake_absorb = 0.20  # Base serpent: 20% absorbed by companion
        dmg = round(dmg * (1.0 - _snake_absorb))

    # Passive class bonuses — use get_all_passive_keys so inherited passives apply
    def_pks = get_all_passive_keys(defender)
    cls = get_player_class(defender)
    if cls:
        if "iron_will" in def_pks:      def_reduction += 0.15
        if "holy_stance" in def_pks:
            hp_pct = defender["hp"] / max(1, defender["max_hp"])
            if hp_pct < 0.50:
                if random.random() < 0.20: return 0  # 20% block when low HP
                def_reduction += 0.15
            else:
                def_reduction += 0.10  # 10% DR when above 50% HP
        if "natures_bond" in def_pks:   def_reduction += 0.10
        if "guardian_stance" in def_pks: def_reduction += 0.05
        if "thorn_skin" in def_pks:     def_reduction += 0.10
        if "eternal_bloom" in def_pks:  def_reduction += 0.15
        if "lorekeeping" in def_pks:    def_reduction += 0.15
        if "fog_of_war" in def_pks:     def_reduction += 0.10
        if "iron_bulwark" in def_pks:   def_reduction += 0.20
        if "einherjar_will" in def_pks and not defender.get("einherjar_used"):
            if defender["hp"] - dmg <= 0:
                defender["einherjar_used"] = True
                dmg = max(0, defender["hp"] - 1)
        if "shield_maiden" in def_pks:
            dmg = max(1, dmg - 15)
        if "defenders_oath" in def_pks:
            if defender["hp"] < defender.get("max_hp", defender["hp"]) * 0.50:
                def_reduction += 0.10
        if "immortal_aegis" in def_pks: def_reduction += 0.05
        if "stalwart" in def_pks:
            if random.random() < 0.15: return 0
        if "ancient_bark" in def_pks:
            if random.random() < 0.15: return 0
        if "empress_dread" in def_pks:  def_reduction += 0.10
        if "defensive_stance" in def_pks:
            if random.random() < 0.10: return 0
        if "arcane_shield" in def_pks:
            if random.random() < 0.10: return 0
        if "mana_overload" in def_pks:
            if random.random() < 0.15:
                defender["mana_overload_reflect"] = max(1, int(get_stat(defender, "INT") * 0.50))
        if "undying" in def_pks:
            today = datetime.now().strftime("%Y-%m-%d")
            if defender.get("undying_used") != today:
                test_hp = defender["hp"] - dmg
                if test_hp <= 0:
                    defender["undying_used"] = today
                    dmg = max(0, defender["hp"] - 1)
        if "resurrection" in def_pks:
            today = datetime.now().strftime("%Y-%m-%d")
            if defender.get("resurrection_used") != today:
                test_hp = defender["hp"] - dmg
                if test_hp <= 0:
                    defender["resurrection_used"] = today
                    max_hp = calc_max_hp(defender)
                    dmg = max(0, defender["hp"] - int(max_hp * 0.30))
        if "sacred_ground" in def_pks:  def_reduction += 0.10
        if "divine_presence" in def_pks: def_reduction += 0.05
        if "shield_wall" in def_pks:
            if random.random() < 0.25: return 0  # 25% block chance (up from equipment-gated 15% DR)
        if "divine_grace" in def_pks:
            if random.random() < 0.15: return 0  # 15% block chance (divine protection)
        # beguile reflect handled in apply_reflect, not here
    # def_reflect — charge-based (new) or legacy timestamp
    if safe_int(defender.get("def_reflect_hits")) > 0:
        def_reduction += 0.40
        defender["def_reflect_hits"] -= 1
    elif _ts_active(defender, "def_reflect_until"):
        def_reduction += 0.40

    # Accessory block chance (handled separately, this is just flat reduction)
    if get_accessory_bonus(defender, "block_chance"):
        if random.random() < get_accessory_bonus(defender, "block_chance"):
            return 0  # blocked entirely
    enc_block = get_enchant_bonus(defender, "block_chance")
    if enc_block and random.random() < enc_block:
        return 0

    total = min(0.80, def_reduction + armor_reduction)
    final = max(1, round(dmg * (1 - total)) - excess_def_absorb)

    # Exposed debuff (+15% dmg taken, consume one charge)
    if safe_int(defender.get("exposed_hits")) > 0:
        final = round(final * 1.15)
        defender["exposed_hits"] -= 1

    # Marked (+20% dmg taken, consume one charge)
    if safe_int(defender.get("marked_hits")) > 0:
        final = round(final * 1.20)
        defender["marked_hits"] -= 1

    # Weakened (+25% dmg taken, consume one charge)
    if safe_int(defender.get("weakened_hits")) > 0:
        final = round(final * 1.25)
        defender["weakened_hits"] -= 1

    # Branded — attacker deals 30% less (consume one charge)
    if safe_int(defender.get("branded_hits")) > 0:
        final = round(final * 0.70)
        defender["branded_hits"] -= 1

    # Runic Ward — absorbs first 20 damage of every hit
    cls_def = get_player_class(defender)
    if cls_def and cls_def.get("passive_key") == "runic_ward":
        final = max(0, final - 20)

    return final

def apply_pvp_death(p, killer_name="the enemy", cause="PvP", killer_id=None):
    """Apply full PvP-style death: 6min defeat, 10% EXP loss, losses++"""
    exp_loss = round(p.get("exp", 0) * 0.10)
    p["exp"]             = max(0, p.get("exp", 0) - exp_loss)
    p["hp"]              = 0
    p["mp"]              = 0  # drain MP on death; restored on revive
    p["losses"]          = p.get("losses", 0) + 1
    p["defeated_until"]  = (datetime.now() + timedelta(minutes=6)).isoformat()
    p["last_defeated_by"] = f"{killer_name} ({cause})"
    p["kill_streak"]     = 0  # reset streak on death
    p["shield_hp"]       = 0
    p["shield_used"]     = 0
    if killer_id:
        p["revenge_target"]  = killer_id
        p["revenge_expires"] = (datetime.now() + timedelta(hours=24)).isoformat()
    return exp_loss

def _defeated_msg(p):
    """Build a consistent 'you are defeated' message with countdown."""
    countdown = time_until(p.get("defeated_until"))
    cause     = p.get("last_defeated_by")
    msg = "💀 You're defeated!"
    if cause:  msg += f"\n☠️ Defeated by: _{cause}_"
    if countdown: msg += f"\n⏳ Back in: *{countdown}*"
    msg += "\n_Ask a Priest to revive you, or wait it out._"
    return msg

async def _notify_defeat(bot, p, cause_str):
    """DM the player letting them know what defeated them."""
    try:
        countdown = time_until(p.get("defeated_until")) or "6m"
        await bot.send_message(
            chat_id=p["user_id"],
            text=f"💀 You were defeated by *{cause_str}*!\n⏳ Back in: *{countdown}*\n_Use /heal or ask a Priest to get back sooner._",
            parse_mode="Markdown")
    except Exception:
        pass

async def _notify_attack(bot, victim, attacker_name, dmg):
    """DM the victim when attacked but not defeated. Auto-deletes after 5m."""
    try:
        hp_pct = round(victim["hp"] / max(1, victim.get("max_hp", victim["hp"])) * 100)
        msg = await bot.send_message(
            chat_id=victim["user_id"],
            text=f"⚠️ *{attacker_name}* attacked you for *{dmg} damage!*\n"
                 f"❤️ HP: *{victim['hp']}/{victim.get('max_hp', victim['hp'])}* ({hp_pct}%)\n"
                 f"_Respond in the group chat!_",
            parse_mode="Markdown")
        asyncio.create_task(_auto_delete(bot, victim["user_id"], msg.message_id, 300))
    except Exception:
        pass

def _fire(coro):
    """Schedule a coroutine as a tracked background task (prevents GC before completion)."""
    t = asyncio.create_task(coro)
    _bg_tasks.add(t)
    t.add_done_callback(_bg_tasks.discard)
    return t


async def check_and_claim_bounty(bot, attacker, target, chat_id=None):
    """Claim ALL active bounties on target (stacked from multiple players)."""
    try:
        attacker_uid = int(attacker["user_id"])
        target_uid   = int(target["user_id"])
    except (KeyError, TypeError, ValueError):
        return 0
    # King of the Table: every PvP kill path funnels through here
    try:
        await _update_king_on_kill(bot, attacker, target, chat_id)
    except Exception:
        pass

    conn = _db(); bc = conn.cursor()
    bc.execute("SELECT * FROM bounties WHERE target_id=? AND claimed_by IS NULL AND expires_at > ?",
               (target_uid, datetime.now().isoformat()))
    bounties = bc.fetchall()
    if not bounties:
        return 0

    total_reward = 0
    claimed_count = 0

    _refund_dms = []
    for bounty in bounties:
        self_placed = (int(bounty["placer_id"]) == attacker_uid)
        if self_placed:
            continue  # Bounty hunters cannot claim their own bounties
        bc.execute("UPDATE bounties SET claimed_by=? WHERE bounty_id=?",
                   (attacker_uid, bounty["bounty_id"]))
        reward = bounty["reward"]
        total_reward += reward
        claimed_count += 1
        placer_p = get_player(bounty["placer_id"])
        if placer_p:
            refund = round(reward * 0.25)
            placer_p["gold"] = placer_p.get("gold", 0) + refund
            save_player(placer_p)
            _refund_dms.append((placer_p["user_id"], reward, refund))

    conn.commit()
    # DM placers only AFTER the commit — awaiting the network while holding an
    # open write transaction stalls every other DB writer in the bot.
    for _dm_uid, _dm_reward, _dm_refund in _refund_dms:
        try:
            await bot.send_message(
                chat_id=_dm_uid,
                text=f"💰 Your *{_dm_reward}g* bounty on *{target['username']}* was claimed!\n"
                     f"You received *{_dm_refund}g* back.",
                parse_mode="Markdown")
        except Exception: pass

    if claimed_count == 0:
        return 0

    # Re-fetch attacker from DB to avoid stale dict / race with other saves
    fresh = get_player(attacker_uid)
    if fresh:
        fresh["gold"] = fresh.get("gold", 0) + total_reward
        save_player(fresh)
    else:
        attacker["gold"] = attacker.get("gold", 0) + total_reward
        save_player(attacker)

    stack_note = f" _(×{claimed_count} bounties stacked!)_" if claimed_count > 1 else ""
    try:
        if chat_id:
            await bot.send_message(
                chat_id=chat_id,
                text=f"💰 *BOUNTY CLAIMED!* *{attacker['username']}* defeated *{target['username']}*!\n"
                     f"*+{total_reward}g* collected!{stack_note} 🎯",
                parse_mode="Markdown")
    except Exception: pass
    try:
        await bot.send_message(
            chat_id=target_uid,
            text=f"🎯 The bounty on your head was collected by *{attacker['username']}*! Total: *{total_reward}g*",
            parse_mode="Markdown")
    except Exception: pass
    return total_reward

def in_active_raid(user_id, chat_id=None):
    """Returns (raid_dict, kind) where kind is 'solo', 'group', or None."""
    if user_id in active_soloraids:
        return active_soloraids[user_id], "solo"
    if chat_id is not None:
        raid = active_raids.get(chat_id)
        if raid and raid.get("in_progress"):
            if user_id in [u["id"] for u in raid["party"]]:
                return raid, "group"
    # Also search all group raids if no chat_id
    if chat_id is None:
        for cid, raid in active_raids.items():
            if raid.get("in_progress") and user_id in [u["id"] for u in raid["party"]]:
                return raid, "group"
    return None, None

def in_active_boss(user_id, chat_id=None):
    """Returns (boss_dict, chat_id) if player is in a boss fight, else (None, None)."""
    if chat_id is not None:
        bd = active_bosses.get(chat_id) or secret_boss_active.get(chat_id)
        if bd and user_id in [u["id"] for u in bd["participants"]]:
            return bd, chat_id
    for cid, bd in list(active_bosses.items()):
        if user_id in [u["id"] for u in bd["participants"]]:
            return bd, cid
    for cid, bd in list(secret_boss_active.items()):
        if user_id in [u["id"] for u in bd["participants"]]:
            return bd, cid
    return None, None

def enemy_status_active(raid_state, key):
    ts = raid_state.get("enemy_statuses", {}).get(key)
    if not ts: return False
    try: return datetime.now() < datetime.fromisoformat(ts)
    except: return False

def set_enemy_status(raid_state, key, seconds):
    if "enemy_statuses" not in raid_state:
        raid_state["enemy_statuses"] = {}
    raid_state["enemy_statuses"][key] = (datetime.now() + timedelta(seconds=seconds)).isoformat()

def tick_enemy_bleed(raid_state):
    """Returns bleed damage dealt this tick, 0 if no tick yet."""
    es = raid_state.get("enemy_statuses", {})
    if not enemy_status_active(raid_state, "bleed_until"): return 0
    last = es.get("bleed_last_tick")
    now  = datetime.now()
    if last and (now - datetime.fromisoformat(last)).total_seconds() < 30: return 0
    dmg = safe_int(es.get("bleed_damage"), 10)
    raid_state["enemy_hp"] = max(0, raid_state["enemy_hp"] - dmg)
    raid_state["enemy_statuses"]["bleed_last_tick"] = now.isoformat()
    return dmg

def apply_skill_to_raid_enemy(p, sk, raid_state, w):
    """
    Apply a skill to the current raid enemy.
    Returns (lines_list, dmg_dealt).
    Handles all skill types that make sense vs an NPC enemy.
    """
    stype   = sk.get("type", "damage")
    base    = calc_attack_damage(p, w)
    dmg     = 0
    lines   = []
    enemy   = raid_state["enemy"]

    if stype == "damage":
        dmg = round(base * sk.get("mult", 1.0))
    elif stype == "multihit":
        mults_list = sk.get("mults") or [sk.get("mult", 0.8)] * sk.get("hits", 2)
        hit_parts = []
        dmg = 0
        for _m in mults_list:
            _h = round(calc_attack_damage(p, w) * _m)
            if check_crit(p): _h = apply_crit(p, _h); hit_parts.append(f"💥{_h}")
            else: hit_parts.append(str(_h))
            dmg += _h
        lines.append(f"⚡ {len(mults_list)}-hit combo! " + " + ".join(hit_parts) + f" = *{dmg}*")
    elif stype == "crit_dmg":
        dmg = round(base * sk.get("mult", 1.8) * 2)
        lines.append("💥 *Guaranteed Critical!*")
    elif stype == "pierce_dmg":
        dmg = round(get_stat(p, "AGI") * 3)
        lines.append("🌑 *Pierce!* Full damage  -  no defense.")
    elif stype == "pierce_all":
        if sk.get("dex_mult"):
            dmg = round(get_stat(p, "DEX") * sk["dex_mult"])
        else:
            dmg = round(get_stat(p, "STR") * sk.get("str_mult", 2))
        lines.append("🏹 *Piercing Shot!* Ignores all defense.")
    elif stype == "charged_shot":
        p["charging_killshot"] = 1
        lines.append("🎯 *Charging Killshot!* Next /solostrike or /raidstrike fires it!")
        return lines, 0
    elif stype == "stun":
        dmg = round(base * 1.0)
        if random.random() < 0.45:
            set_enemy_status(raid_state, "stunned_until", 60)
            lines.append(f"⚡ *{enemy['name']}* is *Stunned!* Skips next counter-attack!")
    elif stype == "root":
        set_enemy_status(raid_state, "frozen_until", 90)
        lines.append(f"🌿 *{enemy['name']}* is *Rooted!* Cannot attack for 90 seconds!")
        dmg = round(base * 0.5)
    elif stype == "miss_debuff":
        set_enemy_status(raid_state, "weakened_until", 180)
        lines.append(f"😵 *{enemy['name']}* is *Weakened!* Deals 25% less damage for 3m.")
    elif stype == "bleed_crit":
        dmg = round(base * sk.get("mult", 2.0) * 2)
        set_enemy_status(raid_state, "bleed_until", 300)
        if "enemy_statuses" not in raid_state:
            raid_state["enemy_statuses"] = {}
        raid_state["enemy_statuses"]["bleed_damage"] = 10
        raid_state["enemy_statuses"]["bleed_last_tick"] = datetime.now().isoformat()
        lines.append(f"🩸 *{enemy['name']}* is *Bleeding!* Takes 10 dmg every 30s!")
    elif stype == "drain":
        steal = round(raid_state["enemy_hp"] * min(sk.get("drain_pct", 0.25), 0.25))
        dmg   = round(base * sk.get("mult", 1.0))
        p["hp"] = min(calc_max_hp(p), p["hp"] + steal)
        lines.append(f"🩸 Drained *{steal} HP* from {enemy['name']}! You healed {steal}.")
    elif stype == "drain_kill":
        steal = round(raid_state["enemy_hp"] * min(sk.get("drain_pct", 0.25), 0.25))
        dmg   = round(base * sk.get("mult", 1.5))
        p["hp"] = min(calc_max_hp(p), p["hp"] + steal)
        lines.append(f"🩸 *Drain Soul!* Stole {steal} HP!")
    elif stype == "debuff":
        set_enemy_status(raid_state, "hexed_until", 120)
        lines.append(f"💀 *Hexed!* {enemy['name']} deals 25% less damage for 2m!")
        dmg = round(base * 0.8)
    elif stype in ("vanish", "holy_shield", "blessing"):
        # Self-buff  -  apply to player, no damage
        if stype == "vanish":
            set_status(p, "vanish_until", 60)
            lines.append("👻 *Vanished!* (No effect in raids  -  treated as stealth stance)")
        elif stype == "blessing":
            add_charges(p, "blessed_turns", 5)
            lines.append("✨ *Blessed!* +10% all stats for next 5 attacks.")
        return lines, 0
    elif stype == "silence":
        set_enemy_status(raid_state, "silenced_until", 60)
        dmg = round(base * 1.5)
        lines.append(f"🤐 *Silenced!* {enemy['name']} is dazed  -  reduced damage next hit!")
        set_enemy_status(raid_state, "weakened_until", 60)
    elif stype in ("holy_dmg", "strip_debuff", "condemn"):
        wis = get_stat(p, "WIS")
        if stype == "holy_dmg":
            dmg = wis * sk.get("mult", 3)
            if sk.get("active") == "Radiant Strike" or sk.get("name") == "Radiant Strike":
                p["hp"] = min(calc_max_hp(p), p["hp"] + wis * 2)
        elif stype == "strip_debuff": dmg = wis * 4
        elif stype == "condemn":
            dmg = wis * 8
            set_enemy_status(raid_state, "hexed_until", 300)
            set_enemy_status(raid_state, "weakened_until", 3600)
            lines.append(f"⚡ *CONDEMNED!* {enemy['name']} is hexed and weakened!")
    elif stype == "void_nuke":
        dmg = raid_state["enemy_hp"] // 2
        lines.append(f"🌑 *Void Nuke!* Half HP obliterated!")
    elif stype == "freeze_nuke":
        int_v = get_stat(p, "INT")
        dmg   = int_v * 5
        set_enemy_status(raid_state, "frozen_until", 60)
        lines.append(f"❄️ *Frozen!* {enemy['name']} is frozen  -  skips next counter-attack!")
    # ── New class skill types ──────────────────────────────────────────────────
    elif stype == "aoe_heal_dmg":
        wis = get_stat(p, "WIS")
        heal = round(wis * sk.get("mult", 50))
        p["hp"] = min(calc_max_hp(p), p["hp"] + heal)
        lines.append(f"🌸 *Blossom Nova!* Healed self *+{heal} HP*!")
        if raid_state.get("enemy_statuses", {}).get("poisoned_until") or raid_state.get("enemy_statuses", {}).get("poison_damage"):
            dmg = wis * 6
            lines.append("☠️ Poisoned target takes WIS×6 burst nature damage!")
        else:
            dmg = wis * 3
    elif stype == "aoe_poison_strong":
        wis = get_stat(p, "WIS")
        dmg = round(wis * 1.5)
        set_enemy_status(raid_state, "poisoned_until", 600)
        if "enemy_statuses" not in raid_state:
            raid_state["enemy_statuses"] = {}
        raid_state["enemy_statuses"]["poison_damage"] = max(wis, 10)
        raid_state["enemy_statuses"]["poison_last_tick"] = datetime.now().isoformat()
        lines.append(f"☠️ *Toxic Bloom!* WIS-scaling poison applied for 10m!")
    elif stype == "def_reflect":
        add_charges(p, "def_reflect_hits", 3)
        lines.append("🌿 *Thorn Fortress!* 40% dmg reduction + reflect active next *3 hits*!")
        return lines, 0
    elif stype == "nature_nuke":
        wis = get_stat(p, "WIS")
        dmg = wis * 7
        set_enemy_status(raid_state, "poisoned_until", 300)
        if "enemy_statuses" not in raid_state:
            raid_state["enemy_statuses"] = {}
        raid_state["enemy_statuses"]["poison_damage"] = max(wis * 2, 20)
        raid_state["enemy_statuses"]["poison_last_tick"] = datetime.now().isoformat()
        set_enemy_status(raid_state, "weakened_until", 1800)
        lines.append(f"🌿 *Wrath of the Wild!* WIS×7 = {dmg} nature damage! Poisoned + weakened!")
    elif stype == "drain_debuff":
        steal = round(raid_state["enemy_hp"] * 0.25)
        p["hp"] = min(calc_max_hp(p), p["hp"] + steal)
        dmg = steal
        set_enemy_status(raid_state, "hexed_until", 180)
        set_enemy_status(raid_state, "weakened_until", 180)
        lines.append(f"💀 *Doom Curse!* Drained *{steal} HP*! Hex + Weak applied for 3m!")
    elif stype == "curse_chain":
        int_v = get_stat(p, "INT")
        dmg = round(int_v * 1.5)
        set_enemy_status(raid_state, "hexed_until", 300)
        set_enemy_status(raid_state, "weakened_until", 300)
        lines.append(f"💜 *Vex Chain!* {enemy['name']} cursed: -25% ATK/DEF for 5m!")
    elif stype == "mass_debuff":
        int_v = get_stat(p, "INT")
        dmg = round(int_v * 2.5)
        set_enemy_status(raid_state, "hexed_until", 3600)
        set_enemy_status(raid_state, "weakened_until", 3600)
        set_enemy_status(raid_state, "stunned_until", 60)
        lines.append(f"💜 *Dread Proclamation!* Max curses! Stunned + hexed + weakened for 1 hour!")
    elif stype == "party_atk_buff":
        add_charges(p, "blessed_turns", 5)
        lines.append("🎵 *War Song!* +10% all stats for next 5 attacks!")
        return lines, 0
    elif stype == "party_full_buff":
        add_charges(p, "blessed_turns", 8)
        for field in ["hex_turns", "weakened_hits"]:
            p[field] = 0
        lines.append("🎶 *Ancient Aria!* Blessed ×8 — +10% all stats next 8 attacks! Debuffs cleared.")
        return lines, 0
    elif stype == "ultimate_buff":
        p["hp"] = calc_max_hp(p)
        add_charges(p, "blessed_turns", 10)
        lines.append("✨ *Magnum Opus!* Full HP restored! Blessed ×10 — +10% all stats next 10 attacks!")
        return lines, 0
    elif stype == "self_atk_buff":
        add_charges(p, "blessed_turns", 3)
        lines.append("⚔️ *War Cry!* +10% all stats for next 3 attacks!")
        return lines, 0
    elif stype == "stun_def_dmg":
        str_v = get_stat(p, "STR"); def_v = get_stat(p, "DEF")
        dmg = round((str_v + def_v) * sk.get("mult", 1.0))
        if random.random() < 0.40:
            set_enemy_status(raid_state, "stunned_until", 30)
            lines.append(f"🛡️ *Shield Slam!* {dmg} damage! {enemy['name']} stunned!")
        else:
            lines.append(f"🛡️ *Shield Slam!* (STR+DEF) = {dmg} damage!")
    elif stype == "party_def_buff":
        add_charges(p, "blessed_turns", 5)
        lines.append("🛡️ *Rune Barrier!* +10% all stats for next 5 attacks!")
        return lines, 0
    elif stype == "intercept_aoe":
        def_v = get_stat(p, "DEF")
        dmg = round(def_v * 2)
        add_charges(p, "def_reflect_hits", 3)
        lines.append(f"🛡️ *Vanguard's Presence!* DEF×2 = {dmg} damage! Reflect active next 3 hits!")
    elif stype == "holy_warrior_nuke":
        str_v = get_stat(p, "STR"); def_v = get_stat(p, "DEF")
        dmg = round(str_v * 4 + def_v * 4)
        set_enemy_status(raid_state, "stunned_until", 60)
        lines.append(f"⚡ *Bifrost Descent!* STR×4+DEF×4 = {dmg} holy damage! {enemy['name']} stunned 60s!")
    elif stype == "godlike_lightning":
        str_v = get_stat(p, "STR")
        dmg = round(str_v * 8)
        set_enemy_status(raid_state, "hexed_until", 180)
        set_enemy_status(raid_state, "weakened_until", 180)
        lines.append(f"⚡ *Valhalla's Thunder!* STR×8 = {dmg} divine lightning!")
    elif stype == "aoe_bleed_multihit":
        hits = sk.get("hits", 4)
        dmg = sum(round(base * sk.get("mult", 0.6)) for _ in range(hits))
        set_enemy_status(raid_state, "bleed_until", 300)
        if "enemy_statuses" not in raid_state:
            raid_state["enemy_statuses"] = {}
        raid_state["enemy_statuses"]["bleed_damage"] = 15
        raid_state["enemy_statuses"]["bleed_last_tick"] = datetime.now().isoformat()
        lines.append(f"🌀 *Blade Storm!* {hits}-hit combo ({dmg} total)! *Bleeding* 15/30s!")
    elif stype == "execute_multihit":
        hits = sk.get("hits", 8)
        hp_pct = raid_state["enemy_hp"] / max(1, raid_state["enemy_max_hp"])
        mult = 0.75 if hp_pct <= 0.50 else sk.get("mult", 0.5)
        if hp_pct <= 0.50:
            lines.append(f"💀 *Execute!* Enemy below 50% HP — full power!")
        dmg = sum(round(base * mult) for _ in range(hits))
        lines.append(f"🌀 *Thousand Cuts!* {hits} hits = *{dmg} total damage!*")
    elif stype == "vanish_dmg":
        agi = get_stat(p, "AGI")
        dmg = round(agi * 4)
        set_status(p, "vanish_until", 30)
        lines.append(f"👻 *Phase Step!* Vanished + burst: AGI×4 = {dmg}!")
    elif stype == "phantom_aoe":
        agi = get_stat(p, "AGI")
        dmg = round(agi * 2.5)
        lines.append(f"🌀 *Ethereal Storm!* Phantom wave: AGI×2.5 = {dmg} phantom damage!")
    elif stype == "bounce_spell":
        int_v = get_stat(p, "INT")
        dmg = round(int_v * 2)
        lines.append(f"⚡ *Chain Lightning!* INT×2 = {dmg} lightning damage!")
    elif stype in ("guaranteed_hit", "execute_nuke"):
        stat_key = sk.get("stat", get_primary_stat(p))
        dmg = round(get_stat(p, stat_key) * sk.get("mult", 2.0))
        lines.append(f"💥 *{sk['name']}!* {dmg} damage!")
    else:
        dmg = round(base * sk.get("mult", 1.0))

    # Charged killshot check
    if safe_int(p.get("charging_killshot")):
        p["charging_killshot"] = 0
        if get_class_line(p) == "archer":
            dmg = get_stat(p, "DEX") * 5
            lines.append(f"🎯 *KILLSHOT FIRED!* DEX×5 = *{dmg} damage!*")
        else:
            dmg = get_stat(p, "AGI") * 4
            lines.append(f"🎯 *KILLSHOT FIRED!* AGI×4 = *{dmg} damage!*")

    # Apply crit if base damage type
    if dmg > 0 and check_crit(p) and stype not in ("crit_dmg","void_nuke","pierce_all","charged_shot"):
        dmg = apply_crit(p, dmg)
        lines.append("💥 *Critical hit!*")

    # Per-skill balance scalar (default 1.0)
    if dmg > 0 and stype not in ("void_nuke",):
        dmg = max(1, round(dmg * sk.get("power", 1.0)))

    raid_state["enemy_hp"] = max(0, raid_state["enemy_hp"] - dmg)
    return lines, dmg

def raid_enemy_counter(p, raid_state, lines):
    """
    Fire the raid enemy's counter-attack against player p.
    Modifies p["hp"] and raid_state in place.
    Returns True if player was killed, False otherwise.
    """
    enemy = raid_state["enemy"]

    # Bleed tick on enemy first
    bleed_dmg = tick_enemy_bleed(raid_state)
    if bleed_dmg:
        lines.append(f"🩸 *{enemy['name']}* bleeds for *{bleed_dmg}*! HP: {raid_state['enemy_hp']}/{raid_state['enemy_max_hp']}")
        if raid_state["enemy_hp"] <= 0:
            return False  # enemy died to bleed  -  caller handles wave clear

    # Check if enemy is stunned/frozen/rooted
    if enemy_status_active(raid_state, "stunned_until") or enemy_status_active(raid_state, "frozen_until"):
        status = "stunned" if enemy_status_active(raid_state, "stunned_until") else "frozen"
        lines.append(f"⚡ *{enemy['name']}* is {status}  -  no counter-attack!")
        return False

    raw = random.randint(enemy["dmg_min"], enemy["dmg_max"])

    # Apply weakened/hexed reduction
    if enemy_status_active(raid_state, "weakened_until") or enemy_status_active(raid_state, "hexed_until"):
        raw = round(raw * 0.75)

    edm = calc_defense(p, raw)

    # Dodge check
    dodge_chance = get_accessory_bonus(p, "dodge_bonus") + get_enchant_bonus(p, "dodge_bonus")
    cls_p = get_player_class(p)
    if cls_p and cls_p.get("passive_key") == "evasion": dodge_chance += 0.10
    if dodge_chance > 0 and random.random() < dodge_chance:
        lines.append(f"💨 *{p['username']}* dodges *{enemy['name']}'s* attack!")
        return False

    p["hp"] = max(0, p["hp"] - edm)
    if p["hp"] == 0:
        exp_loss = apply_pvp_death(p, killer_name=enemy["name"], cause="Solo Raid")
        lines.append(
            f"💀 *{enemy['name']}* kills *{p['username']}*! "
            f"Defeated 6min. -{fmt_num(exp_loss)} EXP.")
        return True
    else:
        lines.append(
            f"🩸 *{enemy['name']}* hits *{p['username']}* for *{edm}!* "
            f"({p['hp']}/{calc_max_hp(p)} HP)")
        return False

# ── TURN-BASED RAID HELPERS ───────────────────────────────────────────────────

def _get_alive_party(raid_state):
    """Return list of party member dicts who are still alive in this raid instance."""
    return [u for u in raid_state["party"]
            if raid_state["player_hp"].get(u["id"], 1) > 0]

async def _announce_turn(bot, chat_id, raid_state):
    """Announce whose turn it is and start the 25s timer."""
    alive = _get_alive_party(raid_state)
    if not alive:
        return
    idx = raid_state.get("current_turn_idx", 0) % len(alive)
    raid_state["current_turn_idx"] = idx
    current = alive[idx]
    uid = current["id"]
    name = current["name"]

    # Auto-skip invincible players — mark acted and advance
    _skip_p = get_player(uid)
    if _skip_p and is_invincible(_skip_p):
        if "acted_this_round" not in raid_state or not isinstance(raid_state["acted_this_round"], set):
            raid_state["acted_this_round"] = set()
        raid_state["acted_this_round"].add(uid)
        await bot.send_message(chat_id=chat_id,
            text=f"🛡️ *{name}* is Still Recovering — turn skipped.",
            parse_mode="Markdown")
        await _advance_raid_turn(bot, chat_id, raid_state)
        return

    # Cancel existing timer if any
    old_task = raid_state.get("turn_task")
    if old_task and not old_task.done():
        old_task.cancel()

    enemy = raid_state["enemy"]
    php  = raid_state["player_hp"].get(uid, 0)
    pmhp = raid_state["player_max_hp"].get(uid, php)
    msg = (f"⚔️ *{name}'s turn!* ({php}/{pmhp} HP)\n"
           f"Enemy: *{enemy['name']}* ❤️ {raid_state['enemy_hp']}/{raid_state['enemy_max_hp']}\n"
           f"Use /attack within 25 seconds!")
    raid_turn_markup = InlineKeyboardMarkup([[
        InlineKeyboardButton("⚔️ Attack", callback_data=f"raid_atk_{uid}"),
    ]])
    await bot.send_message(chat_id=chat_id, text=msg, parse_mode="Markdown",
                           reply_markup=raid_turn_markup)

    task = asyncio.create_task(
        _raid_turn_timeout(bot, chat_id, raid_state, uid, name))
    raid_state["turn_task"] = task

async def _raid_turn_timeout(bot, chat_id, raid_state, uid, player_name):
    """Fires after 25s if player hasn't acted. Auto-attacks on their behalf."""
    await asyncio.sleep(25)
    alive = _get_alive_party(raid_state)
    if not alive:
        return
    idx = raid_state.get("current_turn_idx", 0) % len(alive)
    if idx >= len(alive) or alive[idx]["id"] != uid:
        return  # Turn already advanced

    p = get_player(uid)
    if not p:
        await _advance_raid_turn(bot, chat_id, raid_state)
        return

    w = get_weather()
    dmg = calc_attack_damage(p, w)
    if check_crit(p): dmg = apply_crit(p, dmg)

    raid_state["enemy_hp"] = max(0, raid_state["enemy_hp"] - dmg)
    raid_state["damage_dealt"][uid] = raid_state["damage_dealt"].get(uid, 0) + dmg

    bleed_dmg = tick_enemy_bleed(raid_state)
    lines = [f"⏱️ *Auto-attack!* *{player_name}* strikes *{raid_state['enemy']['name']}* for *{dmg}!*",
             f"❤️ Enemy HP: {raid_state['enemy_hp']}/{raid_state['enemy_max_hp']}"]
    if bleed_dmg:
        lines.append(f"🩸 Bleed: {bleed_dmg} dmg!")

    await bot.send_message(chat_id=chat_id, text="\n".join(lines), parse_mode="Markdown")

    raid_state["acted_this_round"].add(uid)

    if raid_state["enemy_hp"] <= 0:
        await _handle_wave_clear(bot, chat_id, raid_state, p)
        return

    await _advance_raid_turn(bot, chat_id, raid_state)

async def _advance_raid_turn(bot, chat_id, raid_state):
    """Move to next player, or trigger enemy phase if round complete."""
    alive = _get_alive_party(raid_state)
    if not alive:
        return

    acted = raid_state.get("acted_this_round", set())
    alive_ids = {u["id"] for u in alive}
    remaining = alive_ids - acted

    if not remaining:
        # All players acted  -  enemy phase
        await _enemy_phase(bot, chat_id, raid_state)
    else:
        # Find next alive player who hasn't acted
        current_idx = raid_state.get("current_turn_idx", 0)
        next_idx = (current_idx + 1) % len(alive)
        # Cycle to find one who hasn't acted
        for _ in range(len(alive)):
            if alive[next_idx % len(alive)]["id"] in remaining:
                break
            next_idx += 1
        raid_state["current_turn_idx"] = next_idx % len(alive)
        await _announce_turn(bot, chat_id, raid_state)

async def _enemy_phase(bot, chat_id, raid_state):
    """Enemy attacks 1 or 2 random alive players, then starts new round."""
    alive = _get_alive_party(raid_state)
    if not alive or raid_state["enemy_hp"] <= 0:
        raid_state["acted_this_round"] = set()
        raid_state["current_turn_idx"] = 0
        await _announce_turn(bot, chat_id, raid_state)
        return

    enemy = raid_state["enemy"]
    lines = [f"👹 *{enemy['name']}* attacks!"]

    # 70% hit 1, 30% hit 2
    hit_count = 2 if random.random() < 0.30 else 1
    targets = random.sample(alive, min(hit_count, len(alive)))

    for target in targets:
        uid = target["id"]
        p = get_player(uid)
        if not p: continue

        raw = random.randint(enemy["dmg_min"], enemy["dmg_max"])
        if enemy_status_active(raid_state, "weakened_until") or enemy_status_active(raid_state, "hexed_until"):
            raw = round(raw * 0.75)

        # Dodge check
        dodge = get_accessory_bonus(p, "dodge_bonus") + get_enchant_bonus(p, "dodge_bonus")
        cls_p = get_player_class(p)
        if cls_p and cls_p.get("passive_key") == "evasion": dodge += 0.10
        if dodge > 0 and random.random() < dodge:
            lines.append(f"💨 *{p['username']}* dodges!")
            continue

        edm = calc_defense(p, raw)
        raid_state["player_hp"][uid] = max(0, raid_state["player_hp"].get(uid, 1) - edm)
        php  = raid_state["player_hp"][uid]
        pmhp = raid_state["player_max_hp"].get(uid, php)

        if php == 0:
            exp_loss = apply_pvp_death(p, killer_name=enemy["name"], cause="Raid")
            save_player(p)
            lines.append(f"💀 *{enemy['name']}* kills *{p['username']}*! 6min defeat. -{fmt_num(exp_loss)} EXP.")
        else:
            lines.append(f"🩸 *{p['username']}* takes *{edm} dmg!* ({php}/{pmhp} HP)")
            if php <= round(pmhp * 0.30):
                asyncio.create_task(bot.send_message(
                    chat_id=chat_id,
                    text=f"⚠️ *{p['username']}* is critically low! ({php}/{pmhp} HP) Use /skill or a healing item!",
                    parse_mode="Markdown"))

    await bot.send_message(chat_id=chat_id, text="\n".join(lines), parse_mode="Markdown")

    # Check if entire party wiped
    still_alive = _get_alive_party(raid_state)
    if not still_alive:
        active_raids.pop(chat_id, None)
        await bot.send_message(chat_id=chat_id,
            text="💀 *All players defeated! Raid failed.*", parse_mode="Markdown")
        return

    # Start new round
    raid_state["acted_this_round"] = set()
    raid_state["current_turn_idx"] = 0
    await _announce_turn(bot, chat_id, raid_state)

async def _handle_wave_clear(bot, chat_id, raid_state, p=None):
    """Handle enemy death  -  advance wave or complete the raid."""
    tier = raid_state["tier"]
    wave_enemies = tier["wave_enemies"]
    cw = raid_state["wave"]
    raid_state.pop("enemy_statuses", None)

    lines = [f"✅ *Wave {cw} cleared!*"]

    if cw < len(wave_enemies):
        raid_state["wave"] += 1
        ne = wave_enemies[cw].copy()
        raid_state["enemy"] = ne
        raid_state["enemy_hp"] = ne["hp"]
        raid_state["enemy_max_hp"] = ne["hp"]
        lines.append(f"\n🌊 *Wave {raid_state['wave']}  -  {ne['name']}*")
        lines.append(f"❤️ HP: {ne['hp']} | 💀 {ne['dmg_min']}–{ne['dmg_max']}")
        await bot.send_message(chat_id=chat_id, text="\n".join(lines), parse_mode="Markdown")
        # New wave  -  reset round and announce first turn
        raid_state["acted_this_round"] = set()
        raid_state["current_turn_idx"] = 0
        await _announce_turn(bot, chat_id, raid_state)

    elif cw == len(wave_enemies):
        bd = BOSSES[tier["wave_boss_key"]]
        party_size = len(_get_alive_party(raid_state))
        boss_hp = max(bd["max_hp"]//2, round(bd["max_hp"]*0.6*party_size))
        raid_state["wave"] = len(wave_enemies) + 1
        raid_state["enemy"] = {
            "name": bd["name"] + " ⚡",
            "dmg_min": round(bd["dmg_min"]*0.7),
            "dmg_max": round(bd["dmg_max"]*0.7),
        }
        raid_state["enemy_hp"] = boss_hp
        raid_state["enemy_max_hp"] = boss_hp
        lines.append(f"\n🎱 *FINAL BOSS  -  {bd['name']}!* ❤️ HP: {boss_hp}")
        await bot.send_message(chat_id=chat_id, text="\n".join(lines), parse_mode="Markdown")
        raid_state["acted_this_round"] = set()
        raid_state["current_turn_idx"] = 0
        await _announce_turn(bot, chat_id, raid_state)

    else:
        # Raid complete
        active_raids.pop(chat_id, None)
        lines.append(f"\n🏆 *RAID COMPLETE  -  {tier['name']}!*\n")
        total_dmg = sum(raid_state["damage_dealt"].values())
        w2 = get_weather()
        for u in raid_state["party"]:
            pp = get_player(u["id"])
            if not pp: continue
            share = max(0.10, raid_state["damage_dealt"].get(u["id"],0)/max(1,total_dmg))
            exp_r  = round(_scaled_raid_exp(pp["level"], tier["exp_reward"]) * (0.5+share))
            gold_r = round(tier["gold_reward"]*(0.5+share))
            pp["gold"] = pp.get("gold",0) + gold_r
            pp["quests_done"] = pp.get("quests_done",0) + 1
            loot = roll_loot_table(tier.get("loot_table",[]), pp)
            if loot:
                add_item(pp,loot); r=""
                for pool in [WEAPONS,ARMORS,ACCESSORIES]:
                    if loot in pool: r=RARITY_EMOJI.get(pool[loot].get("rarity",""),""); break
                lines.append(f"🎒 *{pp['username']}* found {r} *{loot}*!")
            if u == raid_state["party"][0] and award_title(pp,"Break Leader"):
                lines.append(f"🏅 *{pp['username']}* earned: *Break Leader*!")
            add_exp(pp, exp_r, w2); save_player(pp)
            lines.append(f"✅ *{pp['username']}* ({int(share*100)}% dmg)  -  +{fmt_num(exp_r)} EXP | +{gold_r}g")
        await bot.send_message(chat_id=chat_id, text="\n".join(lines)[:4096], parse_mode="Markdown")

_pvp_miss_streaks = {}  # (attacker_id, defender_id) -> consecutive misses

def check_miss(attacker, defender):
    """Returns True if attack misses."""
    if is_invincible(defender):  return True
    if is_vanished(defender):    return True
    if cannot_attack(attacker):  return True

    # Base dodge  -  line-specific
    cls_d_line = get_class_line(defender)
    if cls_d_line == "archer":
        dodge_stat = get_stat(defender, "DEX")
    elif cls_d_line == "thief":
        dodge_stat = get_stat(defender, "LUK")
    else:
        dodge_stat = get_stat(defender, "AGI")
    dodge = min(0.40, dodge_stat * 0.008)
    # DEX secondary: non-archers gain a smaller dodge benefit from DEX (0.3% per DEX, cap 12%)
    if cls_d_line != "archer":
        dodge += min(0.12, get_stat(defender, "DEX") * 0.003)

    # Accessory dodge bonus
    dodge += get_accessory_bonus(defender, "dodge_bonus")
    dodge += get_enchant_bonus(defender, "dodge_bonus")

    # Class passives
    cls_d = get_player_class(defender)
    if cls_d:
        pk = cls_d.get("passive_key","")
        if pk == "evasion":       dodge += 0.15
        if pk == "ghost_form":    dodge += 0.20
        if pk == "void_rift":     dodge += 0.15
        if pk == "quick_hands":   dodge += get_stat(defender, "AGI") * 0.005
        # New class passives
        if pk == "waltz":         dodge += 0.15
        if pk == "wildflower_shield": dodge += 0.12
        if pk == "shield_maiden": dodge += 0.20
        if pk == "ethereal_step": dodge += 0.20
        if pk == "mirror_image":  dodge += 0.10
        if pk == "phantoms_grace":
            dodge = max(0.20, dodge)  # floor at 20%
            dodge += min(0.20, safe_int(defender.get("phantoms_grace_stacks", 0)) * 0.02)
        if pk == "sovereign_veil":
            dodge += 0.30
            if defender.get("sovereign_veil_active"):
                defender["sovereign_veil_active"] = 0; return True
        if pk == "fog_of_war":    dodge += 0.05
        if pk == "rhythm":        dodge += 0.05
        if pk == "storm_instinct": dodge += 0.05
        if pk == "nimble":     dodge += min(0.20, get_stat(defender, "AGI") * 0.005)
        # Enchantress — allure: 15% chance to fascinate attacker
        if pk == "allure":     dodge += 0.15

    # Pet passive dodge bonus (defender)
    def_pet = get_active_pet_record(defender.get("user_id"))
    if def_pet:
        dodge += get_pet_passives(def_pet.get("level",1)).get("dodge_bonus", 0)

    # Attacker miss penalty
    if is_distracted(attacker): dodge += 0.30

    # Attacker passives that pierce dodge
    cls_a = get_player_class(attacker)
    if cls_a:
        pk_a = cls_a.get("passive_key","")
        if pk_a == "eagle_eye":
            # Never miss if AGI beats defender DEF, or DEX beats defender DEX
            if (get_stat(attacker, "AGI") > get_stat(defender, "DEF") or
                    get_stat(attacker, "DEX") > get_stat(defender, "DEX")):
                return False  # never miss

    # Archer-line: DEX reduces enemy effective dodge (accuracy bonus)
    if get_class_line(attacker) == "archer":
        atk_dex = get_stat(attacker, "DEX")
        dodge -= min(0.20, atk_dex * 0.004)
        cls_a2 = get_player_class(attacker)
        if cls_a2 and cls_a2.get("passive_key") == "keen_sight":
            dodge -= min(0.15, atk_dex * 0.005)
    # Shadow Sprite companion: +20% dodge
    if "dodge_20" in _dng_pvp_effects(defender):
        dodge += 0.20

    # HARD CAP: every dodge source is individually capped but the SUM was not,
    # so stacked builds (stat + 4 accessories + passive + pet + companion)
    # exceeded 100% dodge and became unhittable by normal attacks. 60% max —
    # dodge builds stay strong without invalidating basic attacks.
    dodge = max(0.0, min(dodge, 0.60))

    # PITY RULE: after 2 consecutive misses against the same target, the 3rd
    # attack always lands. Kills the miss-spiral without weakening dodge.
    _miss_key = (attacker.get("user_id"), defender.get("user_id"))
    if _pvp_miss_streaks.get(_miss_key, 0) >= 2:
        _pvp_miss_streaks[_miss_key] = 0
        return False

    did_dodge = random.random() < dodge
    if did_dodge:
        _pvp_miss_streaks[_miss_key] = _pvp_miss_streaks.get(_miss_key, 0) + 1
        # Evasive Momentum: dodging rewards the dodger — +8% damage per stack
        # (max 3) on their next attack. Classes with their own dodge proc
        # (shadowstep/thunder_step/waltz/deaths_shadow) keep theirs instead.
        _dm_pk = (cls_d or {}).get("passive_key", "")
        if _dm_pk not in ("deaths_shadow", "shadowstep", "thunder_step", "waltz"):
            defender["dodge_momentum"] = min(3, safe_int(defender.get("dodge_momentum")) + 1)
    else:
        _pvp_miss_streaks.pop(_miss_key, None)
    if did_dodge and cls_d:
        pk = cls_d.get("passive_key","")
        # deaths_shadow: every dodge restores 10 HP
        if pk == "deaths_shadow":
            defender["hp"] = min(defender.get("max_hp", defender["hp"]), defender["hp"] + 10)
        # shadowstep: mark attacker's next strike for +50% bonus
        if pk == "shadowstep":
            defender["shadowstep_ready"] = 1
        # thunder_step: mark next attack for +40% lightning bonus
        if pk == "thunder_step":
            defender["thunder_dodge_ready"] = 1
        # waltz: mark next attack for +60% bonus damage
        if pk == "waltz":
            defender["waltz_dodge_ready"] = 1
    return did_dodge

def check_crit(attacker):
    cls = get_player_class(attacker)
    line = cls.get("line") if cls else None
    if line == "thief":
        stat_val = get_stat(attacker, "LUK")
        base_crit = min(0.50, stat_val * 0.010)
    elif line == "archer":
        stat_val = get_stat(attacker, "DEX")
        base_crit = min(0.45, stat_val * 0.009)
    else:
        stat_val = get_stat(attacker, "AGI")
        base_crit = min(0.40, stat_val * 0.008)
    base_crit += get_accessory_bonus(attacker, "crit_bonus")
    base_crit += get_enchant_bonus(attacker, "crit_bonus")
    # LUK secondary: non-thieves gain a smaller crit bonus from LUK (0.5% per LUK, cap 15%)
    if line != "thief":
        base_crit += min(0.15, get_stat(attacker, "LUK") * 0.005)
    # DEX secondary: non-archers gain a crit bonus from DEX (0.3% per DEX, cap 10%)
    if line != "archer":
        base_crit += min(0.10, get_stat(attacker, "DEX") * 0.003)
    if cls and cls.get("passive_key") == "quick_hands":
        base_crit += 0.15
    # New class passives
    if cls:
        _pk = cls.get("passive_key", "")
        if _pk == "thunder_step":    base_crit += 0.10
        if _pk == "storms_eye":      base_crit += 0.20
        if _pk == "celestial_wrath": base_crit += 0.15
        if _pk == "waltz":           base_crit += 0.05
        if _pk == "rhythm":
            base_crit += min(0.15, safe_int(attacker.get("rhythm_stacks", 0)) * 0.03)
        if _pk == "flourish":
            base_crit += min(0.10, safe_int(attacker.get("flourish_stacks", 0)) * 0.03)
        if _pk == "adrenaline":
            _hp_pct = attacker["hp"] / max(1, attacker.get("max_hp", attacker["hp"]))
            if _hp_pct < 0.30: base_crit += 0.20
        if _pk == "death_whirl":
            _hp_pct = attacker["hp"] / max(1, attacker.get("max_hp", attacker["hp"]))
            if _hp_pct < 0.40: base_crit += 0.30
        if _pk == "final_performance":
            _hp_pct = attacker["hp"] / max(1, attacker.get("max_hp", attacker["hp"]))
            if _hp_pct < 0.25: base_crit += 0.40
    atk_pet = get_active_pet_record(attacker.get("user_id"))
    if atk_pet:
        base_crit += get_pet_passives(atk_pet.get("level", 1)).get("crit_bonus", 0)
    return random.random() < base_crit

def apply_crit(attacker, dmg):
    cls = get_player_class(attacker)
    mult = 2.0
    if cls and cls.get("passive_key") == "headshot":
        mult = 3.0
    elif cls and cls.get("passive_key") == "celestial_wrath":
        mult = 2.5
    # Storm Drake companion: +25% crit damage
    if "crit_dmg_25" in _dng_pvp_effects(attacker):
        mult += 0.25
    return round(dmg * mult)

def apply_lifesteal(attacker, dmg):
    cls = get_player_class(attacker)
    pk = cls.get("passive_key","") if cls else ""
    healed = 0
    if pk == "soul_pact":
        healed = round(dmg * 0.10)
    if pk == "bloodlust":
        healed = max(10, round(dmg * 0.12))
    # New class passives
    if pk == "verdant_renewal":  healed += round(dmg * 0.08)
    if pk == "eternal_bloom":    healed += round(dmg * 0.05)
    if pk == "natural_growth":   healed += 5
    if pk == "flourish":         healed += safe_int(attacker.get("flourish_stacks", 0)) * 3
    if pk == "waltz":            healed += 5  # crits restore 5 HP
    if pk == "adrenaline":
        _hp_pct = attacker["hp"] / max(1, calc_max_hp(attacker))
        if _hp_pct < 0.30: healed += 10
    _acc_ls = get_accessory_bonus(attacker, "lifesteal_flat")
    if _acc_ls and dmg:
        healed += round(dmg * _acc_ls / 100)
    enc_heal = get_enchant_bonus(attacker, "lifesteal_flat")
    if enc_heal:
        healed += round(dmg * 0.08)  # 8% of damage dealt in PvP
    ls_pet = get_active_pet_record(attacker.get("user_id"))
    if ls_pet and dmg:
        _pet_ls_pct = get_pet_passives(ls_pet.get("level", 1)).get("lifesteal_flat", 0)
        if _pet_ls_pct:
            healed += round(dmg * _pet_ls_pct / 200)  # halved in PvP
    if healed:
        attacker["hp"] = min(calc_max_hp(attacker), attacker["hp"] + healed)
    return healed

def apply_reflect(defender, attacker, dmg):
    """Reflect damage back to attacker."""
    cls = get_player_class(defender)
    if not cls: return 0
    pk = cls.get("passive_key","")
    reflect = 0
    if pk == "judgement":
        reflect = round(get_stat(defender, "WIS") * 0.10)
    # New class passives
    if pk == "thorn_skin":   reflect += round(get_stat(defender, "WIS") * 0.5)
    if pk == "thorn_aura":   reflect += round(get_stat(defender, "WIS") * 1.0)
    if pk == "nettleskin":
        if random.random() < 0.10: reflect += 15
    if pk == "ancient_bark": reflect += round(dmg * 0.10)
    if pk == "beguile":
        if random.random() < 0.08: reflect += round(dmg * 0.50)
    # def_reflect — charge-based (new) or legacy timestamp
    if safe_int(defender.get("def_reflect_hits")) > 0 or _ts_active(defender, "def_reflect_until"):
        reflect += round(dmg * 0.50)
    if get_accessory_bonus(defender, "reflect_pct"):
        reflect += round(dmg * get_accessory_bonus(defender, "reflect_pct"))
    if reflect:
        attacker["hp"] = max(0, attacker["hp"] - reflect)
    return reflect

def check_bleed_tick(p):
    """Called in handle_message  -  tick bleed damage."""
    if not is_bleeding(p): return 0
    last = p.get("bleed_last_tick")
    now  = datetime.now()
    if last:
        elapsed = (now - datetime.fromisoformat(last)).total_seconds()
        if elapsed < 30: return 0
    dmg = safe_int(p.get("bleed_damage"), 10)
    p["hp"] = max(0, p["hp"] - dmg)
    p["bleed_last_tick"] = now.isoformat()
    return dmg

