            for row in rows21:
                changed = False
                uid = row["user_id"]
                inv  = sjl(row["inventory"], [])
                new_inv = _v21_list(inv)
                if new_inv != inv: changed = True
                ew  = ITEM_NAME_MAP_V21.get(row["equipped_weapon"],  row["equipped_weapon"])
                ea  = ITEM_NAME_MAP_V21.get(row["equipped_armor"],   row["equipped_armor"])
