def save_player(p):
    # Sync max_mp
    _true_max_mp = calc_max_mp(p)
    p["max_mp"] = _true_max_mp
    if not safe_int(p.get("mp")):
        p["mp"] = _true_max_mp  # first-time: start full
    else:
        p["mp"] = max(0, min(_true_max_mp, safe_int(p.get("mp"))))
    # Always sync max_hp to the true computed value so DB stays accurate
    _true_max = calc_max_hp(p)
    if p.get("max_hp") != _true_max:
        _delta = _true_max - p.get("max_hp", 0)
        p["max_hp"] = _true_max
        # Keep current HP in bounds but don't inflate it if player hasn't healed
        if _delta > 0:
            pass  # don't auto-fill HP on bonus gain; player has to heal up
        p["hp"] = max(0, min(_true_max, safe_int(p.get("hp"))))
    # Normalize old item names → new RPG names on every save
    inv = sjl(p.get("inventory"), [])
    inv = [_ITEM_RENAME.get(i, i) for i in inv]
    p["inventory"] = json.dumps(inv)
    for slot in ("equipped_weapon", "equipped_armor", "equipped_shield", "equipped_accessory",
                 "equipped_hat", "equipped_gloves", "equipped_boots", "equipped_mask"):
        if p.get(slot) in _ITEM_RENAME:
            p[slot] = _ITEM_RENAME[p[slot]]
    enh = sjl(p.get("enhancements"), {})
    if any(k in _ITEM_RENAME for k in enh):
        p["enhancements"] = json.dumps({_ITEM_RENAME.get(k, k): v for k, v in enh.items()})
    enc = sjl(p.get("enchants"), {})
    if any(k in _ITEM_RENAME for k in enc):
        p["enchants"] = json.dumps({_ITEM_RENAME.get(k, k): v for k, v in enc.items()})
    conn = _db(); c = conn.cursor()
    # ── STALE-SNAPSHOT GUARD ──────────────────────────────────────────────────
    # Handlers run concurrently and each holds its own copy of the player row.
    # A long-running handler (e.g. a chat message) saving an OLD snapshot after
    # a newer award (dungeon extract, PvP kill) used to ERASE the level-up and
    # its stat points. Progression only ever moves forward (nothing in the game
    # lowers a level), so compare (level, total_exp) lexicographically: if the
    # DB row is FURTHER along than this snapshot, adopt the DB's progression
    # wholesale instead of dragging the player backwards. (The old guard keyed
    # on total_exp alone and missed the case where the stale snapshot had MORE
    # exp but hadn't seen the level-up — it erased the level anyway.)
    _cur_row = c.execute(
        "SELECT tg_username, total_exp, exp, level, stat_points, gold, active_quest, last_quest_ts "
        "FROM players WHERE user_id=?",
        (p.get("user_id"),)).fetchone()
    if _cur_row:
        # Never wipe tg_username with NULL — preserve existing DB value
        if p.get("tg_username") is None and _cur_row["tg_username"]:
            p["tg_username"] = _cur_row["tg_username"]
        _db_lvl, _db_tot = safe_int(_cur_row["level"], 1), safe_int(_cur_row["total_exp"])
        _my_lvl, _my_tot = safe_int(p.get("level"), 1), safe_int(p.get("total_exp"))
        if (_db_lvl, _db_tot) > (_my_lvl, _my_tot):
            p["level"]       = _db_lvl
            p["total_exp"]   = _db_tot
            p["exp"]         = safe_int(_cur_row["exp"])
            p["stat_points"] = safe_int(_cur_row["stat_points"])
            p["max_hp"]      = calc_max_hp(p)
            p["hp"]          = min(safe_int(p.get("hp")), p["max_hp"])
        # Never let a stale snapshot erase a NEWER oracle quest: if the DB row
        # carries a quest assigned after this snapshot was loaded, keep it.
        if safe_int(_cur_row["last_quest_ts"]) > safe_int(p.get("last_quest_ts")):
            p["last_quest_ts"] = safe_int(_cur_row["last_quest_ts"])
            p["active_quest"]  = _cur_row["active_quest"]
        # ── GOLD DELTA-MERGE ──────────────────────────────────────────────────
        # Write db_gold + (this snapshot's own gold change), not the snapshot's
        # absolute gold — so two racing handlers' purchases/payouts BOTH land.
        if "_gold_baseline" in p:
            _own_delta = safe_int(p.get("gold")) - safe_int(p.get("_gold_baseline"))
            p["gold"] = max(0, safe_int(_cur_row["gold"]) + _own_delta)
            p["_gold_baseline"] = p["gold"]  # rebase for repeat saves of this dict
    fields = [
        "user_id","username","hp","max_hp","exp","level","total_exp",
        "gold","wins","losses","quests_done","heals_given","dodges",
        "crafts_done","perm_dmg_bonus","titles","active_title",
        "class_id","class_path","all_skills","stat_points","stats",
        "inventory","passive_cooldowns",
        "equipped_weapon","equipped_armor","equipped_shield","equipped_accessory",
        "equipped_hat","equipped_gloves","equipped_boots","equipped_mask",
        "defeated_until","invincible_until","distracted_until","entangled_until",
        "frozen_until","stunned_until","vanish_until",
        "poison_until","poison_damage","poison_last_tick",
        "burn_until","burn_damage","burn_last_tick",
        "ward_until","exposed_until","branded_until",
        "bleed_until","bleed_damage","bleed_last_tick",
        "hexed_until","weakened_until","blessed_until",
        "healing_blocked_until","revival_blocked_until","silenced_until",
        "temp_hp_bonus","temp_hp_until",
        "recent_attackers","contract_target","contract_until",
        "charging_killshot","steady_aim_target","steady_aim_stacks",
        "mark_first_hit","deadeye_kill_bonus","spell_cast_count",
        "holy_field_until","devotion_charge",
        "last_daily","last_quest","last_train","last_explore",
        "explore_count_today","explore_date","shop_discount_until",
        "guild_id","prestige_count","prestige_skills","shadow_level_at_ascension","created_at",
        "DEX","LUK","enhancements","enchants",
        "last_dungeon","last_pool","last_defeated_by",
        "item_reinforce_data","daily_objectives","daily_obj_date",
        "total_reinforces","total_ascensions","total_obj_completed",
        "kill_streak","max_kill_streak","revenge_target","revenge_expires",
        "kills_today","kills_today_date","is_wanted","last_claim","claim_streak","pvp_history",
        "married_to_id","married_to_name","married_at",
        "marriages",
        "def_reflect_until",
        "holding_hands_with_id","holding_hands_with_name","holding_hands_since",
        "holding_hands_list",
        "last_encounter","monster_squad",
        "influence","alliance_id","active_quest","last_quest_ts","oracle_last_used",
        "tg_username","deepest_dungeon_floor",
        "equipped_accessory_2","equipped_accessory_3","equipped_accessory_4",
        "shop_reroll_date","shop_reroll_count",
        "shield_hp","last_defend","shield_used","shield_core_bonus",
        "hug_count","kiss_count","poke_count","slap_count","pat_count",
        "stun_turns","freeze_turns","entangle_turns","silence_turns","distract_turns",
        "vanish_turns","hex_turns","blessed_turns","weakened_hits",
        "poison_stacks","burn_stacks","bleed_stacks",
        "ward_charges","shield_charges","exposed_hits","marked_hits","branded_hits",
        "regen_charges","regen_amt","heal_blocked_turns","revive_blocked_turns",
        "poison_pct","bleed_pct","burn_pct",
        "empire_buildings","empire_resources","empire_last_collect",
        "mp","max_mp","dng_companions","dodge_momentum","collection_log",
        "serpent_revive_used","pet_dex","pvp_rating","pvp_peak_rating",
    ]
    # dng_companions is held as a list in memory; store as JSON text
    if isinstance(p.get("dng_companions"), list):
        p["dng_companions"] = json.dumps(p["dng_companions"])
    # Clamp unbounded counters into SQLite's INTEGER range — a value past
    # 2^63-1 makes the whole save raise OverflowError and the player's
    # progress silently stops persisting.
    for _bigf in ("exp", "total_exp", "gold"):
        if safe_int(p.get(_bigf)) > _INT_SAFE_MAX:
            p[_bigf] = _INT_SAFE_MAX
    vals = [p.get(f) for f in fields]
    placeholders = ",".join(["?"]*len(fields))
    col_str = ",".join(fields)
    c.execute(f"INSERT OR REPLACE INTO players ({col_str}) VALUES({placeholders})", vals)
    conn.commit()

def get_or_create_shadow(uid, username):
    s = get_shadow(uid)
    if not s:
        s = {"user_id":uid,"username":username,"level":1,"exp":0,
             "total_exp":0,"message_count":0,"passive_cooldowns":"{}",
             "ascended":0,"last_seen":datetime.now().isoformat()}
        save_shadow(s)
    return s

def get_guild(gid):
    c = _db().cursor()
    c.execute("SELECT * FROM guilds WHERE guild_id=?", (gid,))
    row = c.fetchone()
    return dict(row) if row else None

def get_guild_by_name(name):
    c = _db().cursor()
    c.execute("SELECT * FROM guilds WHERE LOWER(name)=LOWER(?)", (name,))
    row = c.fetchone()
    return dict(row) if row else None

def get_active_war(gid1, gid2=None):
    """Return active war involving gid1 (optionally against gid2)."""
    c = _db().cursor()
    if gid2:
        c.execute("""SELECT * FROM guild_wars WHERE active=1 AND expires_at > ?
                        AND ((guild1_id=? AND guild2_id=?) OR (guild1_id=? AND guild2_id=?))""",
                     (datetime.now().isoformat(), gid1, gid2, gid2, gid1))
    else:
        c.execute("""SELECT * FROM guild_wars WHERE active=1 AND expires_at > ?
                        AND (guild1_id=? OR guild2_id=?)""",
                     (datetime.now().isoformat(), gid1, gid1))
    row = c.fetchone()
    return dict(row) if row else None

def save_guild(g):
    conn = _db(); c = conn.cursor()
    c.execute("""INSERT OR REPLACE INTO guilds
        (guild_id,name,leader_id,members,level,exp,bank,created_at,war_wins,bank_gold)
        VALUES(?,?,?,?,?,?,?,?,?,?)""",
        (g.get("guild_id"),g["name"],g["leader_id"],g["members"],
         safe_int(g.get("level"),1),safe_int(g.get("exp")),
         safe_int(g.get("bank")),
         g.get("created_at",datetime.now().isoformat()),
         safe_int(g.get("war_wins")),
         safe_int(g.get("bank_gold"))))
    conn.commit()

def _guild_stat_bonus_for_level(glvl):
    """Returns the all-stats bonus granted to members at this guild level (max +5)."""
    return min(5, max(0, safe_int(glvl) // 2))

def _update_guild_member_bonuses(g):
    """After guild level changes, update guild_stat_bonus for all current members."""
    bonus = _guild_stat_bonus_for_level(safe_int(g.get("level"), 1))
    members = sjl(g.get("members"), [])
    if not members: return
    conn = _db(); c = conn.cursor()
    placeholders = ",".join("?" for _ in members)
    c.execute(f"UPDATE players SET guild_stat_bonus=? WHERE user_id IN ({placeholders})",
              [bonus] + list(members))
    conn.commit()

def add_guild_exp(g, amount):
    msgs = []; g["exp"] = safe_int(g.get("exp")) + amount
    max_lv = max(GUILD_PERKS.keys())
    while safe_int(g.get("level"),1) < max_lv and \
          g["exp"] >= guild_exp_for_level(safe_int(g.get("level"),1)):
        g["exp"] -= guild_exp_for_level(safe_int(g.get("level"),1))
        g["level"] = safe_int(g.get("level"),1) + 1
        msgs.append(f"🏰 Guild leveled up to {g['level']}! "
                    f"{GUILD_PERKS.get(g['level'],{}).get('desc','')}")
    _update_guild_member_bonuses(g)
    return msgs

