async def check_pet_notifications(p, bot):
    """DM the owner if their active pet is hungry, sad, or ready to train. Rate-limited per condition.
    Timestamps are persisted in shadow_profiles.pet_notify_ts so restarts don't cause spam."""
    if not p: return
    pet = get_active_pet_record(p["user_id"])
    if not pet: return
    uid      = p["user_id"]
    name     = pet.get("nickname") or pet.get("species", "your pet")
    now      = datetime.now()

    # Load persisted timestamps from DB (fall back to in-memory for this session)
    s = get_shadow(uid)
    if s:
        try:
            raw = json.loads(s.get("pet_notify_ts") or "{}")
            # Convert ISO strings back to datetime objects
            cache = {k: datetime.fromisoformat(v) for k, v in raw.items()}
        except Exception:
            cache = {}
    else:
        cache = _pet_notify_ts.get(uid, {})

    msgs     = []

    def _due(key, hours):
        last = cache.get(key)
        return last is None or (now - last).total_seconds() >= hours * 3600

    hunger = pet.get("hunger", 100)
    mood   = pet.get("mood", 100)
    changed = False

    if hunger < 30 and _due("hunger", 4):
        msgs.append(f"🍖 *{name}* is hungry ({hunger}/100 hunger)! Use /pet to feed them.")
        cache["hunger"] = now; changed = True
    if mood < 30 and _due("mood", 4):
        msgs.append(f"😢 *{name}* is feeling low ({mood}/100 mood). Use /pet → 🎮 Play to cheer them up!")
        cache["mood"] = now; changed = True
    last_trained = pet.get("last_trained")
    if last_trained and _due("train", 8):
        try:
            hours_idle = (now - datetime.fromisoformat(last_trained)).total_seconds() / 3600
            if hours_idle >= 6:
                msgs.append(f"🏋️ *{name}* is ready to train! Use /pet to train them.")
                cache["train"] = now; changed = True
        except Exception:
            pass
    last_play = pet.get("last_play")
    if _due("play", 8):
        play_due = True
        if last_play:
            try:
                play_due = (now - datetime.fromisoformat(last_play)).total_seconds() / 3600 >= 6
            except Exception:
                pass
        if play_due:
            msgs.append(f"🎮 *{name}* wants to play! Use /pet → 🎮 Play to boost their mood.")
            cache["play"] = now; changed = True
    adv_end = pet.get("adventure_ends_at")
    if adv_end and _due("adv_done", 4):
        try:
            if (datetime.fromisoformat(adv_end) - now).total_seconds() <= 0:
                msgs.append(f"🗺️ *{name}* has returned from their adventure! Use /pet to claim the rewards.")
                cache["adv_done"] = now; changed = True
        except Exception:
            pass

    if changed and s:
        # Persist updated timestamps as ISO strings
        s["pet_notify_ts"] = json.dumps({k: v.isoformat() for k, v in cache.items()})
        save_shadow(s)
    # Keep in-memory dict in sync too
    _pet_notify_ts[uid] = cache

    if msgs:
        try:
            await bot.send_message(uid,
                "🐾 *Pet Update*\n\n" + "\n".join(msgs),
                parse_mode="Markdown")
        except Exception:
            pass



def _build_gear_text(p) -> str:
    """Return the gear display text for player p (used by gear_cmd and inline hub)."""
    lines = [f"🎽 *{p['username']}'s Equipped Gear*\n"]
    weap_name = p.get("equipped_weapon")
    if weap_name and weap_name in WEAPONS:
        w = WEAPONS[weap_name]; enh = get_enhancement(p, weap_name); enc = get_enchant(p, weap_name)
        enh_bonus = enh * 2; rarity = RARITY_EMOJI.get(w["rarity"], "")
        lines += [f"⚔️ *Weapon*", f"{rarity} {weap_name}",
                  f"ATK: {w['atk']} base + {enh_bonus} enh = *{w['atk']+enh_bonus} total*"]
        if enh: lines.append(f"Enhancement: *+{enh}* {'⭐'*enh}")
        for e in get_all_enchants(p, weap_name): lines.append(f"✨ *{e['id'].capitalize()}*  -  _{e['desc']}_")
    else:
        lines.append("⚔️ *Weapon*  -  None")
    lines.append("")
    armr_name = p.get("equipped_armor")
    if armr_name and armr_name in ARMORS:
        a = ARMORS[armr_name]; enh = get_enhancement(p, armr_name); enc = get_enchant(p, armr_name)
        enh_bonus = enh * 2; rarity = RARITY_EMOJI.get(a["rarity"], "")
        lines += [f"🛡️ *Armor*", f"{rarity} {armr_name}",
                  f"DEF: {a['def']} base + {enh_bonus} enh = *{a['def']+enh_bonus} total*"]
        if enh: lines.append(f"Enhancement: *+{enh}* {'⭐'*enh}")
        for e in get_all_enchants(p, armr_name): lines.append(f"✨ *{e['id'].capitalize()}*  -  _{e['desc']}_")
    else:
        lines.append("🛡️ *Armor*  -  None")
    lines.append("")
    shld_name = p.get("equipped_shield")
    if shld_name and shld_name in SHIELDS:
        s_data = SHIELDS[shld_name]; enh = get_enhancement(p, shld_name); enh_bonus = enh * 2
        rarity = RARITY_EMOJI.get(s_data.get("rarity",""), "")
        is_claw = s_data.get("type") == "claw"
        base_s = s_data.get("atk" if is_claw else "def", 0)
        label_s = "🗡️ *Claw* (shield slot)" if is_claw else "🔰 *Shield*"
        stat_s  = "ATK" if is_claw else "DEF"
        lines += [label_s, f"{rarity} {shld_name}",
                  f"{stat_s}: {base_s} base + {enh_bonus} enh = *{base_s+enh_bonus} total*"]
    else:
        lines.append("🔰 *Shield / Claw*  -  None")
    lines.append("")
    for _n, _sk in enumerate(("equipped_accessory","equipped_accessory_2","equipped_accessory_3","equipped_accessory_4"), 1):
        acc_name = p.get(_sk)
        if acc_name and acc_name in ACCESSORIES:
            acc = ACCESSORIES[acc_name]; rarity = RARITY_EMOJI.get(acc.get("rarity",""), "")
            lines += [f"💍 *Accessory {_n}*", f"{rarity} {acc_name}", f"_{acc.get('desc','')}_"]
            for e in get_all_enchants(p, acc_name): lines.append(f"✨ *{e['id'].capitalize()}*  -  _{e['desc']}_")
        else:
            lines.append(f"💍 *Accessory {_n}*  -  None")
    lines.append("")
    for slot_key, emoji, label, pool in [
            ("equipped_hat","🎩","Hat",HATS),("equipped_gloves","🧤","Gloves",GLOVES),
            ("equipped_boots","👢","Boots",BOOTS),("equipped_mask","🎭","Mask",MASKS)]:
        name = p.get(slot_key)
        if name and name in pool:
            d = pool[name]; enh = get_enhancement(p, name); enh_b = enh * 2
            rarity = RARITY_EMOJI.get(d.get("rarity",""), "")
            lines += [f"{emoji} *{label}*", f"{rarity} {name}",
                      f"DEF: {d['def']} base + {enh_b} enh = *{d['def']+enh_b} total*"]
        else:
            lines.append(f"{emoji} *{label}*  -  None")
    lines += ["", f"Total Weapon ATK: *{get_weapon_atk(p)}*", f"Total Armor DEF: *{get_armor_def(p)}*",
              "\n`/enhance` to upgrade  |  `/enchant` to enchant"]
    return "\n".join(lines)

async def gear_cmd(update, context):
    user = update.effective_user
    p = get_player(user.id)
    if not p:
        await send_group(update, "Use /ascend first!"); return

    lines = [f"🎽 *{p['username']}'s Equipped Gear*\n"]

    # Weapon
    weap_name = p.get("equipped_weapon")
    if weap_name and weap_name in WEAPONS:
        w = WEAPONS[weap_name]
        enh = get_enhancement(p, weap_name)
        enc = get_enchant(p, weap_name)
        base_atk = w["atk"]
        enh_bonus = enh * 2
        total_atk = base_atk + enh_bonus
        rarity = RARITY_EMOJI.get(w["rarity"], "")
        lines.append(f"⚔️ *Weapon*")
        lines.append(f"{rarity} {weap_name}")
        lines.append(f"ATK: {base_atk} base + {enh_bonus} enhancement = *{total_atk} total*")
        if enh > 0:
            lines.append(f"Enhancement: *+{enh}* {'⭐' * enh}")
        if enc:
            all_encs = get_all_enchants(p, weap_name)
            if len(all_encs) > 1:
                for e in all_encs:
                    lines.append(f"✨ {e['id'].capitalize()}  -  {e['desc']}")
            else:
                lines.append(f"Enchant: ✨ *{enc[0]['id'].capitalize() if isinstance(enc, list) else enc['id'].capitalize()}*  -  _{enc[0]['desc'] if isinstance(enc, list) else enc['desc']}_")
    else:
        lines.append(f"⚔️ *Weapon*  -  None")

    lines.append("")

    # Armor
    armr_name = p.get("equipped_armor")
    if armr_name and armr_name in ARMORS:
        a = ARMORS[armr_name]
        enh = get_enhancement(p, armr_name)
        enc = get_enchant(p, armr_name)
        base_def = a["def"]
        enh_bonus = enh * 2
        total_def = base_def + enh_bonus
        rarity = RARITY_EMOJI.get(a["rarity"], "")
        lines.append(f"🛡️ *Armor*")
        lines.append(f"{rarity} {armr_name}")
        lines.append(f"DEF: {base_def} base + {enh_bonus} enhancement = *{total_def} total*")
        if enh > 0:
            lines.append(f"Enhancement: *+{enh}* {'⭐' * enh}")
        if enc:
            all_encs = get_all_enchants(p, armr_name)
            for e in all_encs:
                lines.append(f"✨ *{e['id'].capitalize()}*  -  _{e['desc']}_")
    else:
        lines.append(f"🛡️ *Armor*  -  None")

    lines.append("")

    # Shield / Claw
    shld_name = p.get("equipped_shield")
    if shld_name and shld_name in SHIELDS:
        s_data = SHIELDS[shld_name]
        enh = get_enhancement(p, shld_name)
        enh_bonus = enh * 2
        rarity = RARITY_EMOJI.get(s_data["rarity"], "")
        is_claw = s_data.get("type") == "claw"
        if is_claw:
            base_stat = s_data.get("atk", 0)
            total_stat = base_stat + enh_bonus
            lines.append(f"🗡️ *Claw* (shield slot)")
            lines.append(f"{rarity} {shld_name}")
            lines.append(f"ATK: {base_stat} base + {enh_bonus} enhancement = *{total_stat} total*")
        else:
            base_stat = s_data.get("def", 0)
            total_stat = base_stat + enh_bonus
            lines.append(f"🔰 *Shield*")
            lines.append(f"{rarity} {shld_name}")
            lines.append(f"DEF: {base_stat} base + {enh_bonus} enhancement = *{total_stat} total*")
        if enh > 0:
            lines.append(f"Enhancement: *+{enh}* {'⭐' * enh}")
    else:
        lines.append(f"🔰 *Shield / Claw*  -  None")

    lines.append("")

    # All 4 Accessory slots
    for _slot_num, _slot_key in enumerate(
            ("equipped_accessory","equipped_accessory_2","equipped_accessory_3","equipped_accessory_4"), 1):
        acc_name = p.get(_slot_key)
        if acc_name and acc_name in ACCESSORIES:
            acc = ACCESSORIES[acc_name]
            rarity = RARITY_EMOJI.get(acc["rarity"], "")
            lines.append(f"💍 *Accessory {_slot_num}*")
            lines.append(f"{rarity} {acc_name}")
            lines.append(f"_{acc['desc']}_")
            for k, v in acc.get("effect", {}).items():
                if k == "all_stats":
                    lines.append(f"+{v} to all stats")
                elif k in ("STR","AGI","INT","WIS","DEX","LUK","DEF"):
                    lines.append(f"+{v} {k}")
                elif k == "atk":
                    lines.append(f"+{v} ATK")
                elif k == "hp":
                    lines.append(f"+{v} max HP")
                elif k == "dodge_bonus":
                    lines.append(f"+{int(v*100)}% dodge chance")
                elif k == "crit_bonus":
                    lines.append(f"+{int(v*100)}% crit chance")
                elif k == "heal_bonus":
                    lines.append(f"+{int(v*100)}% healing received")
                elif k == "gold_bonus":
                    lines.append(f"+{int(v*100)}% gold earned")
                elif k == "lifesteal_flat":
                    lines.append(f"+{v} HP lifesteal per hit")
                elif k == "block_chance":
                    lines.append(f"+{int(v*100)}% block chance")
            for e in get_all_enchants(p, acc_name):
                lines.append(f"✨ *{e['id'].capitalize()}*  -  _{e['desc']}_")
        else:
            lines.append(f"💍 *Accessory {_slot_num}*  -  None")

    lines.append("")

    # Hat / Gloves / Boots / Mask
    for slot_key, emoji, label, pool in [
            ("equipped_hat","🎩","Hat",HATS),("equipped_gloves","🧤","Gloves",GLOVES),
            ("equipped_boots","👢","Boots",BOOTS),("equipped_mask","🎭","Mask",MASKS)]:
        name = p.get(slot_key)
        if name and name in pool:
            d = pool[name]; enh = get_enhancement(p, name)
            enh_b = enh * 2; base = d["def"]
            rarity = RARITY_EMOJI.get(d.get("rarity",""), "")
            lines.append(f"{emoji} *{label}*")
            lines.append(f"{rarity} {name}")
            lines.append(f"DEF: {base} base + {enh_b} enh = *{base+enh_b} total*")
            encs = get_enchant(p, name)
            for e in encs:
                lines.append(f"✨ *{e['id'].capitalize()}*  -  _{e['desc']}_")
        else:
            lines.append(f"{emoji} *{label}*  -  None")

    lines.append("")
    lines.append(f"Total Weapon ATK: *{get_weapon_atk(p)}*")
    lines.append(f"Total Armor DEF: *{get_armor_def(p)}*")
    lines.append(f"\n`/enhance` to upgrade  |  `/enchant` to enchant")

    await send_group(update, "\n".join(lines), permanent=False, delay=120)

# ── RANK ──────────────────────────────────────────────────────────────────────
async def rank_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user
    c = _db().cursor()
    c.execute("SELECT user_id,username,level,total_exp,class_id FROM players WHERE user_id NOT IN (SELECT user_id FROM banned_users)")
    rpg_rows = c.fetchall()
    c.execute("SELECT user_id,username,level,total_exp FROM shadow_profiles WHERE user_id NOT IN (SELECT user_id FROM banned_users)")
    shd_rows = c.fetchall()

    seen = {}
    for row in shd_rows:
        uid = row["user_id"]
        seen[uid] = {"user_id":uid,"username":row["username"],
                     "level":row["level"],"total_exp":safe_int(row["total_exp"]),
                     "type":"shadow","class_id":None}
    for row in rpg_rows:
        uid = row["user_id"]; rlvl = row["level"]; rtex = safe_int(row["total_exp"])
        if uid not in seen or (rlvl,rtex) >= (seen[uid]["level"],seen[uid]["total_exp"]):
            seen[uid] = {"user_id":uid,"username":row["username"],
                         "level":rlvl,"total_exp":rtex,"type":"rpg","class_id":row["class_id"]}

    all_entries = list(seen.values())
    ranked = sorted(all_entries, key=lambda x: (x["level"], x["total_exp"]), reverse=True)

    total  = len(ranked)

    def fmt_ranked(i, e):
        medals = {1:"🥇",2:"🥈",3:"🥉"}
        prefix = medals.get(i+1, f"{i+1}.")
        cls = CLASS_TREE.get(e.get("class_id") or "", {}).get("name", "No Class") if e["type"]=="rpg" else "Shadow"
        return f"{prefix} *{e['username']}* - Lv {e['level']} - {cls}"

    if context.args and context.args[0].lower() == "wins":
        c2 = _db().cursor()
        c2.execute("SELECT username, wins, losses, level FROM players WHERE user_id NOT IN (SELECT user_id FROM banned_users) ORDER BY wins DESC LIMIT 20")
        rows2 = c2.fetchall()
        medals2 = {1:"🥇",2:"🥈",3:"🥉"}
        lines2 = ["⚔️ *Top 20  -  PVP Wins*\n"]
        for i2, row2 in enumerate(rows2, 1):
            badge2 = medals2.get(i2, f"#{i2}")
            wl2 = f"{row2['wins']}W / {row2['losses']}L"
            lines2.append(f"{badge2} *{row2['username']}*  -  {wl2} | Lv {row2['level']}")
        await send_group(update, "\n".join(lines2), permanent=False, delay=120); return

    if context.args and context.args[0].lower() == "me":
        pos = next((i+1 for i,e in enumerate(ranked) if e["user_id"]==user.id), None)
        if not pos:
            await send_group(update, "Not ranked yet  -  start chatting!"); return
        start_m = max(0, pos-3); end_m = min(total, pos+2)
        lines = [f"📊 *{user.first_name}'s Rank: #{pos} of {total}*\n"]
        for i, entry in enumerate(ranked[start_m:end_m], start=start_m):
            arrow = "▶️ " if entry["user_id"] == user.id else "    "
            lines.append(f"{arrow}{fmt_ranked(i, entry)}")
        await send_group(update, "\n".join(lines), permanent=False, delay=120); return

    PAGE_SIZE = 10
    page_entries = ranked[:PAGE_SIZE]

    lines = ["🏆 *Rankings*\n"]
    for i, e in enumerate(page_entries):
        lines.append(fmt_ranked(i, e))

    keyboard = []
    if total > PAGE_SIZE:
        keyboard.append([InlineKeyboardButton("➡️ Page 2", callback_data="rank_p_2")])
    markup = InlineKeyboardMarkup(keyboard) if keyboard else None

    try: await update.message.delete()
    except: pass
    await update.get_bot().send_message(
        chat_id=update.effective_chat.id,
        text="\n".join(lines)[:4096],
        parse_mode="Markdown",
        reply_markup=markup)

async def rank_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    await query.answer()
    if not query.data.startswith("rank_p_"): return
    page = int(query.data.split("_")[-1])

    c = _db().cursor()
    c.execute("SELECT user_id,username,level,total_exp,class_id FROM players WHERE user_id NOT IN (SELECT user_id FROM banned_users)")
    rpg_rows = c.fetchall()
    c.execute("SELECT user_id,username,level,total_exp FROM shadow_profiles WHERE user_id NOT IN (SELECT user_id FROM banned_users)")
    shd_rows = c.fetchall()

    seen = {}
    for row in shd_rows:
        uid = row["user_id"]
        seen[uid] = {"user_id":uid,"username":row["username"],
                     "level":row["level"],"total_exp":safe_int(row["total_exp"]),
                     "type":"shadow","class_id":None}
    for row in rpg_rows:
        uid = row["user_id"]; rlvl = row["level"]; rtex = safe_int(row["total_exp"])
        if uid not in seen or (rlvl,rtex) >= (seen[uid]["level"],seen[uid]["total_exp"]):
            seen[uid] = {"user_id":uid,"username":row["username"],
                         "level":rlvl,"total_exp":rtex,"type":"rpg","class_id":row["class_id"]}

    all_entries = list(seen.values())
    ranked = sorted(all_entries, key=lambda x: (x["level"], x["total_exp"]), reverse=True)

    PAGE_SIZE = 10
    total = len(ranked)
    start = (page-1)*PAGE_SIZE
    end   = start + PAGE_SIZE
    page_entries = ranked[start:end]
    if not page_entries: return

    def fmt(i, e):
        medals = {1:"🥇",2:"🥈",3:"🥉"}
        prefix = medals.get(start+i+1, f"{start+i+1}.")
        cls = CLASS_TREE.get(e.get("class_id") or "", {}).get("name", "No Class") if e["type"]=="rpg" else "Shadow"
        return f"{prefix} *{e['username']}* - Lv {e['level']} - {cls}"

    lines = [f"🏆 *Rankings  -  Page {page}*\n"]
    for i, e in enumerate(page_entries):
        lines.append(fmt(i, e))

    keyboard = []
    if page > 1:
        keyboard.append(InlineKeyboardButton(f"⬅️ Page {page-1}", callback_data=f"rank_p_{page-1}"))
    if end < total:
        keyboard.append(InlineKeyboardButton(f"➡️ Page {page+1}", callback_data=f"rank_p_{page+1}"))
    markup = InlineKeyboardMarkup([keyboard]) if keyboard else None

    await _q_edit(query, 
        text="\n".join(lines)[:4096],
        parse_mode="Markdown",
        reply_markup=markup)


