def _kit_for(p):
    """Return the class-line kit dict {main, s1, s2} or None (no class yet)."""
    return CLASS_KITS.get(get_class_line(p) or "")

def _kit_cd_state(uid):
    st = _pvp_battle_state.setdefault(uid, {})
    return st.setdefault("kit_cd", {})

def _kit_on_cd(uid, slot):
    return safe_int(_kit_cd_state(uid).get(slot)) > 0

def _kit_tick_cds(uid):
    """Decrement all of a player's kit cooldowns by 1 (called after their action)."""
    cds = _kit_cd_state(uid)
    for k in list(cds.keys()):
        cds[k] = max(0, safe_int(cds[k]) - 1)

def _kit_set_cd(uid, slot, turns):
    _kit_cd_state(uid)[slot] = turns

def _kit_apply_support(a, d, skill):
    """Apply a support skill's effects to a (self) / d (foe). Returns log text."""
    notes = []
    if skill.get("heal_pct"):
        mx = calc_max_hp(a); healed = round(mx * skill["heal_pct"])
        a["hp"] = min(mx, safe_int(a.get("hp")) + healed)
        notes.append(f"💚 +{fmt_num(healed)} HP")
    if skill.get("cleanse"):
        for _f in ("poison_stacks","bleed_stacks","burn_stacks","weakened_hits",
                   "exposed_hits","stun_turns","silence_turns","entangle_turns","hex_turns"):
            a[_f] = 0
        notes.append("🧼 Debuffs cleansed")
    for (tgt, field, op, val) in skill.get("effect", []):
        obj = a if tgt == "self" else d
        if op == "add":
            add_charges(obj, field, val)
        elif op == "set":
            obj[field] = val
        elif op == "setmax":
            obj[field] = max(safe_int(obj.get(field)), val) if not isinstance(val, float) else max(float(obj.get(field) or 0), val)
        elif op == "set_status":
            set_status(obj, field, val)
    return "  ".join(notes) if notes else ""

def _build_pvp_card_markup(player_uid, opp_uid, player_p, opp_p=None):
    """Action buttons for PvP card — Attack, Defend, Skills, Potion, Finisher."""
    inv = sjl(player_p.get("inventory"), [])
    _hp_pots = sum(1 for i in inv if i in ("Health Potion", "Greater Health Potion",
                   "Grand Restorative Flask", "Supreme Restorative Flask", "Ultimate Vitality Draught"))
    _mp_pots = sum(1 for i in inv if i in ("MP Tonic", "Minor MP Tonic",
                   "Major MP Elixir", "Grand Mana Crystal"))
    has_potion = _hp_pots > 0
    all_skills = sjl(player_p.get("all_skills"), [])
    shield_active   = safe_int(player_p.get("shield_used")) == 1
    kill_ready = opp_p is not None and _check_kill_condition(player_p, opp_p)
    rows = []
    if kill_ready:
        rows.append([InlineKeyboardButton(
            f"⚡ FINISHER — {_KILL_CONDITIONS.get(get_class_line(player_p),{}).get('name','Finisher')}",
            callback_data=f"pvpcard_finish_{player_uid}_{opp_uid}"
        )])
    # Row 1: Attack + Defend
    row1 = [InlineKeyboardButton("⚔️ Attack", callback_data=f"pvpcard_atk_{player_uid}_{opp_uid}")]
    defend_label = "🛡️ Shield ✓" if shield_active else "🛡️ Defend"
    row1.append(InlineKeyboardButton(defend_label, callback_data=f"pvpcard_def_{player_uid}_{opp_uid}"))
    rows.append(row1)
    if has_potion or _mp_pots > 0:
        _pot_row = []
        if has_potion:
            _pot_row.append(InlineKeyboardButton(f"🧪 Potion ({_hp_pots})",
                            callback_data=f"pvpcard_heal_{player_uid}_{opp_uid}"))
        if _mp_pots > 0:
            _pot_row.append(InlineKeyboardButton(f"💙 MP ({_mp_pots})",
                            callback_data=f"pvpcard_mp_{player_uid}_{opp_uid}"))
        rows.append(_pot_row)
    # ── Simplified kit: 1 main + 2 support skills (class-line based) ──────────
    kit = _kit_for(player_p)
    p_mp = safe_int(player_p.get("mp"))
    if kit:
        _silenced = is_silenced(player_p)
        for slot in ("main", "s1", "s2"):
            sk = kit[slot]
            cost = sk.get("mp", 0)
            cd_left = safe_int(_kit_cd_state(player_uid).get(slot))
            if _silenced:
                label = f"🤐 {sk['name']} (silenced)"; usable = False
            elif cd_left > 0:
                label = f"⏳ {sk['name']} ({cd_left}t)"; usable = False
            elif p_mp < cost:
                label = f"❌ {sk['emoji']} {sk['name']} ({cost}MP)"; usable = False
            else:
                label = f"{sk['emoji']} {sk['name']} ({cost}MP)"; usable = True
            if usable:
                rows.append([InlineKeyboardButton(label, callback_data=f"kitsk_{player_uid}_{slot}_{opp_uid}")])
            else:
                rows.append([InlineKeyboardButton(label, callback_data=f"kitnope_{player_uid}_{slot}")])
    rows.append([InlineKeyboardButton("🏳️ Surrender", callback_data=f"pvpyield_{player_uid}_{opp_uid}")])
    return InlineKeyboardMarkup(rows)

async def pvp_yield_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """🏳️ Surrender: concede the fight — opponent wins (bets pay out), yielder
    loses 5% of current-level EXP. No kill credit / streak / wanted marks: a
    concession is not a kill."""
    query = update.callback_query
    try:
        _, uid_s, opp_s = query.data.split("_")
        uid, opp_uid = int(uid_s), int(opp_s)
    except (ValueError, IndexError):
        await query.answer(); return
    if query.from_user.id != uid:
        await query.answer("Not your fight card!", show_alert=True); return
    pair = _pvp_pair_key(uid, opp_uid)
    if pair not in _pvp_origin_chat:
        await query.answer("No active fight to surrender.", show_alert=True); return
    _tok = _cb_lock(uid)
    if not _tok:
        await query.answer("⏳ One moment..."); return
    try:
        a = get_player(uid); d = get_player(opp_uid)
        if not a or not d:
            await query.answer("Fight data missing.", show_alert=True); return
        loss = max(0, round(safe_int(a.get("exp")) * 0.05))
        if loss:
            _exp_penalty(a, loss)
        a["losses"] = safe_int(a.get("losses")) + 1
        d["wins"]   = safe_int(d.get("wins")) + 1
        _yield_exp = exp_share(d.get("level", 1), 0.02)
        add_exp(d, _yield_exp)
        save_player(a); save_player(d)
        await query.answer("🏳️ You surrendered.")
        _grp = _pvp_origin_chat.get(pair)  # grab before finalize pops it
        _cb_unlock(uid, _tok)
        await _finalize_pvp(pair,
            f"🏳️ *{a['username']} SURRENDERS!*\n"
            f"🏆 *{d['username']}* takes the win (+{fmt_num(_yield_exp)} EXP)."
            + (f"\n💔 {a['username']} forfeits {fmt_num(loss)} EXP." if loss else ""),
            context.bot, winner_id=opp_uid)
        if _grp:
            asyncio.create_task(announce(context.bot, _grp,
                f"🏳️ *{a['username']}* surrendered to *{d['username']}*!", delay=30))
    finally:
        _cb_unlock(uid, _tok)



def _pvp_kill_exp(a, d):
    """PvP kill EXP: 6% of a level, based on the LOWER of the two levels so
    farming low-level players pays little. Each repeat kill of the same victim
    within 24h halves the payout (floor 10%)."""
    base = exp_share(min(safe_int(a.get("level"), 1), safe_int(d.get("level"), 1)), 0.06)
    cds = safe_cds(a)
    log = cds.get("pvp_kill_log") or {}
    vid = str(d.get("user_id"))
    now = datetime.now()
    entry = log.get(vid)
    count = 0
    if entry:
        try:
            if (now - datetime.fromisoformat(entry["first"])).total_seconds() < 86400:
                count = safe_int(entry.get("count"))
            else:
                entry = None  # window expired — start fresh
        except Exception:
            entry = None
    mult = max(0.10, 0.5 ** count)
    if entry:
        entry["count"] = count + 1
    else:
        entry = {"first": now.isoformat(), "count": 1}
    log[vid] = entry
    if len(log) > 30:  # keep the per-victim log bounded
        log = dict(sorted(log.items(), key=lambda kv: kv[1].get("first", ""))[-30:])
    cds["pvp_kill_log"] = log
    a["passive_cooldowns"] = json.dumps(cds)
    return max(1, round(base * mult))


async def _execute_pvp_hit(a, d, au_id, du_id, w, chat_id, bot, kit_skill=None):
    """
    Full PvP combat resolution. Modifies a and d in-place and saves them.
    Returns (action_text, lvl_msgs, result_type) where result_type is
    'miss', 'hit', or 'defeat'.

    kit_skill (optional): a CLASS_KITS 'strike' skill dict — applies its damage
    multiplier and on-hit riders on top of the normal attack pipeline.
    """
    lvl_msgs = []

    # ── Charge-based DOT ticks fire when the ATTACKER acts ────────────────────
    # Damage = % of target's max HP if _pct set, else flat _damage value
    _a_pks = get_all_passive_keys(a)
    _a_poison_immune = "cold_blood" in _a_pks or "serpentine_mastery" in _a_pks or "venom_aura" in _a_pks
    _dot_notes = []
    for _sk, _pct_k, _dk, _em, _nm in [
        ("poison_stacks", "poison_pct", "poison_damage", "🐍", "Poison"),
        ("bleed_stacks",  "bleed_pct",  "bleed_damage",  "🩸", "Bleed"),
        ("burn_stacks",   "burn_pct",   "burn_damage",   "🔥", "Burn"),
    ]:
        _n = safe_int(a.get(_sk))
        # Serpent classes with poison immunity shed venom stacks instead of taking damage
        if _n > 0 and _sk == "poison_stacks" and _a_poison_immune:
            a[_sk] = 0
            _dot_notes.append("🐍 *Poison Immunity!* Venom shrugged off by serpent nature.")
            continue
        if _n > 0:
            _pct = safe_int(a.get(_pct_k))
            if _pct > 0:
                _d_amt = max(1, round(a.get("max_hp", 100) * _pct / 100))
                _pct_txt = f"{_pct}% max HP"
            else:
                _d_amt = max(1, safe_int(a.get(_dk, 6)))
                _pct_txt = f"{_d_amt} flat"
            # INT secondary: mental focus resists DoT ticks (0.5% per INT, cap 25%)
            _int_resist = min(0.25, get_stat(a, "INT") * 0.005)
            if _int_resist > 0:
                _d_amt = max(1, round(_d_amt * (1 - _int_resist)))
            a["hp"] = max(0, a["hp"] - _d_amt)
            a[_sk] = _n - 1
            _rem = _n - 1
            _dot_notes.append(f"{_em} *{_nm} tick!* -{_d_amt} HP ({_pct_txt})" + (f" [{_rem} left]" if _rem else " *(cleared!)*"))
    _dot_prefix = "\n".join(_dot_notes) + "\n" if _dot_notes else ""

    # Blessed Specter companion: regen 3% max HP per turn when attacker acts
    if "regen_3pct" in _dng_pvp_effects(a):
        _bs_regen = max(1, round(calc_max_hp(a) * 0.03))
        a["hp"] = min(calc_max_hp(a), a["hp"] + _bs_regen)
        _dot_notes.append(f"👻 *Blessed Specter* mends {a.get('username','?')} — *+{_bs_regen} HP*!")
    _emp_regen_pct = _empire_stat_bonuses(a).get("pvp_regen_pct", 0)
    if _emp_regen_pct > 0:
        _emp_regen = max(1, round(calc_max_hp(a) * _emp_regen_pct))
        a["hp"] = min(calc_max_hp(a), a["hp"] + _emp_regen)
        _dot_notes.append(f"🌿 *Garden Blessing* restores {a.get('username','?')} — *+{_emp_regen} HP*!")
    if _dot_notes: _dot_prefix = "\n".join(_dot_notes) + "\n"
    # MP regen per turn — magic classes only (others restore on revive or potion)
    for _mp_p in (a, d):
        if get_class_line(_mp_p) in _MAGIC_LINES:
            _mp_max = safe_int(_mp_p.get("max_mp")) or calc_max_mp(_mp_p)
            _mp_p["mp"] = min(_mp_max, safe_int(_mp_p.get("mp", 0)) + 5)

    # ── Auto-cure: fire top-priority active affliction ────────────────────────
    _cure_prio = sjl(a.get("cure_priority"), []) or _DEFAULT_CURE_PRIORITY
    _cured_note = ""
    for _cp_key in _cure_prio:
        _cp_field = _CURE_ALIAS.get(_cp_key)
        if _cp_field and safe_int(a.get(_cp_field, 0)) > 0:
            a[_cp_field] -= 1
            _cured_note = f"💊 *Auto-cure:* {_cp_key.title()} cured (1 stack removed)"
            break
    if _cured_note:
        _dot_prefix = _dot_prefix + _cured_note + "\n"

    # ── Per-turn charge burn: decrement every time this player acts ──────────
    for _turn_field in ("heal_blocked_turns", "silence_turns", "hex_turns", "revive_blocked_turns"):
        if safe_int(a.get(_turn_field)) > 0:
            a[_turn_field] -= 1

    # ── Charge-based stun/freeze/entangle — consume one turn, force miss ──────
    if safe_int(a.get("stun_turns")) > 0:
        a["stun_turns"] -= 1
        _rem = a["stun_turns"]
        save_player(a)
        return (f"{_dot_prefix}⚡ *{a['username']}* is *Stunned!* Lost their attack!"
                + (f" ({_rem} turn{'s' if _rem!=1 else ''} left)" if _rem else " *(stun cleared!)*"),
                [], "miss")
    if safe_int(a.get("freeze_turns")) > 0:
        a["freeze_turns"] -= 1
        _rem = a["freeze_turns"]
        save_player(a)
        return (f"{_dot_prefix}🧊 *{a['username']}* is *Frozen!* Cannot act!"
                + (f" ({_rem} turn{'s' if _rem!=1 else ''} left)" if _rem else " *(freeze cleared!)*"),
                [], "miss")
    if safe_int(a.get("entangle_turns")) > 0:
        a["entangle_turns"] -= 1
        _rem = a["entangle_turns"]
        save_player(a)
        return (f"{_dot_prefix}🌿 *{a['username']}* is *Entangled!* Cannot move!"
                + (f" ({_rem} turn{'s' if _rem!=1 else ''} left)" if _rem else " *(root cleared!)*"),
                [], "miss")

    # ── Charge-based distract — 30% miss chance, consume turn ─────────────────
    if safe_int(a.get("distract_turns")) > 0:
        a["distract_turns"] -= 1
        if random.random() < 0.30:
            save_player(a)
            return f"{_dot_prefix}😵 *{a['username']}* was *Distracted!* Missed the attack!", [], "miss"

    # Charged killshot
    if safe_int(a.get("charging_killshot")):
        a["charging_killshot"] = 0
        if get_class_line(a) == "archer":
            dmg_after_def = get_stat(a, "DEX") * 5
            action = (f"🎯 *KILLSHOT FIRED!* *{a['username']}* → *{d['username']}*  -  "
                      f"DEX×5 = *{dmg_after_def} damage!* Cannot be dodged!")
        else:
            dmg_after_def = get_stat(a, "AGI") * 4
            action = (f"🎯 *KILLSHOT FIRED!* *{a['username']}* → *{d['username']}*  -  "
                      f"AGI×4 = *{dmg_after_def} damage!* Cannot be dodged!")
        d["hp"] = max(0, d["hp"] - dmg_after_def)
        update_recent_attackers(d, au_id)
        if d["hp"] <= 0:
            d["hp"] = 0
            d["defeated_until"] = (datetime.now() + timedelta(minutes=6)).isoformat()
            d["last_defeated_by"] = f"{a['username']} (Killshot)"
            _d_was_wanted = safe_int(d.get("is_wanted"))
            d["kill_streak"] = 0; d["is_wanted"] = 0; d["shield_used"] = 0; d["shield_hp"] = 0; d["shield_core_bonus"] = 0
            d["revenge_target"] = au_id
            d["revenge_expires"] = (datetime.now() + timedelta(hours=24)).isoformat()
            _fire(check_and_claim_bounty(bot, a, d, chat_id))
            exp_loss = round(d.get("exp", 0) * 0.10)
            _exp_penalty(d, exp_loss)
            d["losses"] = d.get("losses", 0) + 1
            a["wins"] = a.get("wins", 0) + 1
            a["kill_streak"] = safe_int(a.get("kill_streak")) + 1
            if a["kill_streak"] > safe_int(a.get("max_kill_streak")):
                a["max_kill_streak"] = a["kill_streak"]
            today_str = datetime.now().strftime("%Y-%m-%d")
            if a.get("kills_today_date") != today_str:
                a["kills_today"] = 0; a["kills_today_date"] = today_str
            a["kills_today"] = safe_int(a.get("kills_today")) + 1
            if a["kills_today"] >= 5: a["is_wanted"] = 1
            hist_ks = sjl(d.get("pvp_history"), [])
            hist_ks.insert(0, {"attacker": a["username"], "dmg": "KO",
                               "ts": datetime.now().strftime("%m/%d %H:%M")})
            d["pvp_history"] = json.dumps(hist_ks[:5])
            for _desc, _exp, _gold in track_objective(a, "pvp_win"):
                a["gold"] = a.get("gold", 0) + _gold; add_exp(a, _exp)
            exp_gain = _pvp_kill_exp(a, d)
            _lvl_gap = safe_int(a.get("level"), 1) - safe_int(d.get("level"), 1)
            if _lvl_gap >= 30:
                exp_gain = max(1, round(exp_gain * 0.10))
                action += f"\n😒 _No honor in stomping someone {_lvl_gap} levels down — EXP slashed._"
            if _d_was_wanted:
                wanted_gold = 250; wanted_exp = round(exp_gain * 0.5)
                a["gold"] = a.get("gold", 0) + wanted_gold
                exp_gain += wanted_exp
                action += f"\n🔴 *WANTED BOUNTY!* +{wanted_gold}g +{wanted_exp} bonus EXP for taking down a wanted player!"
                asyncio.create_task(announce(bot, chat_id,
                    f"🔴 *{a['username']}* brought down the WANTED *{d['username']}*! +{wanted_gold}g reward!", delay=5))
            lmsgs, leveled = add_exp(a, exp_gain, w); lvl_msgs = lmsgs
            _defeat_timer_ks = time_until(d.get("defeated_until")) or "6m"
            action += f"\n💀 *{d['username']}* DEFEATED! +{fmt_num(exp_gain)} EXP to {a['username']}.\n⏳ *{d['username']}* back in *{_defeat_timer_ks}*."
            if leveled and a["level"] % 10 == 0:
                asyncio.create_task(announce(bot, chat_id,
                    f"🎉 *{a['username']}* reached *Level {a['level']}*! ⚔️", delay=30))
        check_titles(a); check_titles(d)
        save_player(a); save_player(d)
        if lvl_msgs: action += "\n\n" + "\n".join(lvl_msgs)
        return action, lvl_msgs, "defeat" if d["hp"] <= 0 else "hit"

    # Grant mark_first_hit bonus when switching to a new target
    if "marked" in get_all_passive_keys(a):
        if safe_int(a.get("mark_first_hit_target")) != du_id:
            a["mark_first_hit"] = 1
            a["mark_first_hit_target"] = du_id

    # Miss check
    if check_miss(a, d):
        d["dodges"] = d.get("dodges", 0) + 1
        check_titles(d)
        # Consume one vanish charge when the attacker misses due to vanish
        if safe_int(d.get("vanish_turns")) > 0:
            d["vanish_turns"] -= 1
        cls_d_miss = get_player_class(d)
        if cls_d_miss:
            pk_d_miss = cls_d_miss.get("passive_key", "")
            if pk_d_miss == "shadowstep":
                cds_d = safe_cds(d); cds_d["shadowstep_primed"] = "1"
                d["passive_cooldowns"] = json.dumps(cds_d)
            if pk_d_miss == "deaths_shadow":
                d["hp"] = min(d["max_hp"], d["hp"] + 10)
        if "flourish" in get_all_passive_keys(d):
            d["flourish_stacks"] = min(3, safe_int(d.get("flourish_stacks", 0)) + 1)
        if "harmonize" in get_all_passive_keys(a):
            a["harmony_stacks"] = 0
        if "melody" in get_all_passive_keys(a):
            a["melody_stacks"] = 0
        if "rhythm" in get_all_passive_keys(a):
            a["rhythm_stacks"] = 0
        save_player(d); save_player(a)
        return f"🌀 *{a['username']}* swings at *{d['username']}*  -  *MISS!*", [], "miss"

    # Damage
    dmg = calc_attack_damage(a, w)
    extra_notes = []

    _a_weap = a.get("equipped_weapon", "")
    _a_weap_type = WEAPONS.get(_a_weap, {}).get("type", "")
    if _a_weap_type == "throwing_star":
        if SHIELDS.get(a.get("equipped_shield", ""), {}).get("type", "") != "claw":
            dmg = round(dmg * 0.75)
            extra_notes.append("⚠️ _Missing claw  -  75% damage_")

    crit_forced = safe_cds(a).pop("next_crit_skill", None)
    if crit_forced: a["passive_cooldowns"] = json.dumps(safe_cds(a))
    # Backstab-style forced crit chance
    _kit_crit = kit_skill and random.random() < kit_skill.get("rider", {}).get("crit", 0) if kit_skill else False
    if crit_forced or _kit_crit or check_crit(a):
        dmg = apply_crit(a, dmg); crit_note = " 💥 CRIT!"
    else:
        crit_note = ""

    # ── KIT MAIN SKILL + universal self-buffs (empower/warcry) ────────────────
    _kit_notes = []
    # War Cry stacks — +15% damage each, persist all fight (any attack)
    _wc = safe_int(a.get("warcry_stacks"))
    if _wc > 0:
        dmg = round(dmg * (1 + 0.15 * _wc))
        _kit_notes.append(f"📣 War Cry ×{_wc}")
    # Empowered next attack (Vanish / Crescendo) — consumed on any attack
    _emp = float(a.get("empower_next") or 0)
    if _emp > 0:
        dmg = round(dmg * (1 + _emp)); a["empower_next"] = 0
        _kit_notes.append(f"✨ Empowered +{round(_emp*100)}%")
    if kit_skill and kit_skill.get("kind") == "strike":
        rider = kit_skill.get("rider", {})
        dmg = round(dmg * kit_skill.get("mult", 1.0))
        if rider.get("pierce"):
            dmg = round(dmg * 1.25)          # proxy for ignoring part of DEF
        if rider.get("focus"):
            dmg = round(dmg * 1.25)
        if rider.get("execute"):
            if d.get("max_hp") and d["hp"] / max(1, calc_max_hp(d)) < rider["execute"]:
                dmg *= 2; _kit_notes.append("💀 Execute!")
        if rider.get("laststand"):
            _hp_ratio = a["hp"] / max(1, calc_max_hp(a))
            dmg = round(dmg * (1 + (1 - _hp_ratio) * 0.5))
        if rider.get("lifesteal"):
            _ls = round(dmg * rider["lifesteal"])
            a["hp"] = min(calc_max_hp(a), a["hp"] + _ls); _kit_notes.append(f"🩸 Lifesteal +{fmt_num(_ls)}")
        if rider.get("bleed"):
            add_charges(d, "bleed_stacks", rider["bleed"]); d["bleed_pct"] = max(safe_int(d.get("bleed_pct")), 10)
            _kit_notes.append(f"🩸 Bleed ×{rider['bleed']}")
        if rider.get("poison"):
            add_charges(d, "poison_stacks", rider["poison"]); d["poison_pct"] = max(safe_int(d.get("poison_pct")), 12)
            _kit_notes.append(f"🧪 Poison ×{rider['poison']}")
        if rider.get("expose"):
            add_charges(d, "exposed_hits", rider["expose"]); _kit_notes.append(f"🎯 Exposed ×{rider['expose']}")
        _kit_notes.insert(0, f"{kit_skill.get('emoji','✨')} *{kit_skill['name']}!*")
    if _kit_notes:
        extra_notes.extend(_kit_notes)

    cds_a = safe_cds(a)
    if cds_a.get("shadowstep_primed"):
        dmg = round(dmg * 1.50)
        cds_a.pop("shadowstep_primed"); a["passive_cooldowns"] = json.dumps(cds_a)
        extra_notes.append("🌑 *Shadowstep!* +50% damage after dodge!")

    cls_a = get_player_class(a)
    if cls_a:
        pk_a = cls_a.get("passive_key", "")
        if pk_a == "execute":
            if d["hp"] / max(1, d["max_hp"]) < 0.25 and "execute_immune" not in _dng_pvp_effects(d):
                dmg *= 2; extra_notes.append("💀 *Execute!* Double damage below 25% HP!")
        if pk_a == "devotion":
            charge = safe_int(a.get("devotion_charge"))
            if charge > 0:
                dmg += 5; a["devotion_charge"] = 0
                extra_notes.append("✨ *Devotion charge!* +5 bonus damage!")
        if pk_a == "battle_cry":
            a["battle_cry_str_hits"] = 5  # refresh to 5 on every attack
        if pk_a == "warcry":
            if len(get_recent_attackers(a)) > 1:
                dmg = round(dmg * 1.20); extra_notes.append("😣 *Warcry!* +20% damage!")
        if pk_a == "flurry" and random.random() < 0.20:
            dmg *= 2; extra_notes.append("⚡ *Flurry!* Double hit!")
        if pk_a == "one_shot" and random.random() < 0.10:
            dmg *= 5; extra_notes.append("🎯 *ONE-SHOT!* 5x damage!")
        if pk_a == "trailblazer" and random.random() < 0.15:
            if safe_int(d.get("distract_turns", 0)) < 3:
                add_charges(d, "distract_turns", 1)
                extra_notes.append(f"🎯 *Trailblazer!* {d['username']} distracted (30% miss chance for 1 hit)!")
        if pk_a == "steady_aim":
            if a.get("steady_aim_target") == d["user_id"]:
                a["steady_aim_stacks"] = min(5, safe_int(a.get("steady_aim_stacks")) + 1)
            else:
                a["steady_aim_target"] = d["user_id"]; a["steady_aim_stacks"] = 1

    revenge_bonus_note = ""
    if safe_int(a.get("revenge_target")) == du_id:
        rev_exp = a.get("revenge_expires")
        if rev_exp and datetime.now() < datetime.fromisoformat(rev_exp):
            dmg = round(dmg * 1.15); revenge_bonus_note = " 🔥 *Revenge!* +15% dmg"
            a["revenge_target"] = None; a["revenge_expires"] = None

    cls_d = get_player_class(d)
    if cls_d:
        pk_d = cls_d.get("passive_key", "")
        if pk_d == "bulwark" and random.random() < 0.15:
            extra_notes.append("🛡️ *Bulwark!* Attack completely blocked!"); dmg = 0
        if pk_d == "defensive_stance":
            if d.get("hp", 1) / max(1, d.get("max_hp", 1)) > 0.50:
                dmg = max(1, dmg - 30)
        if pk_d == "devotion": d["devotion_charge"] = safe_int(d.get("devotion_charge")) + 1
        if pk_d == "nettleskin" and random.random() < 0.10:
            a["poison_pct"] = 30
            add_charges(a, "poison_stacks", 3)
            extra_notes.append("🌿 *Nettleskin!* Attacker Poisoned ×3 (30%/action)!")
        if pk_d == "judgement" and random.random() < 0.30:
            wis_dmg = max(1, round(safe_stats(d).get("WIS", 5) * 0.50))
            a["hp"] = max(1, a["hp"] - wis_dmg)
            extra_notes.append(f"⚖️ *Judgement!* {d['username']} retaliates for *{wis_dmg} holy dmg*!")

    reflect = apply_reflect(d, a, dmg)
    if reflect:
        extra_notes.append(f"🌵 *Thorns!* Reflects *{reflect} dmg* back to {a['username']}!")

    if cls_d and cls_d.get("line") == "priest" and d.get("class_path") == "A":
        ward_chance = get_proc_chance(0.15, d)
        if not has_ward(d) and random.random() < ward_chance:
            add_charges(d, "ward_charges", 1)
            dmg = round(dmg * 0.60)
            extra_notes.append("✨ *Holy Ward procs!* Damage reduced by 40%!")
    # Consume ward charge (charge-based first, then legacy timestamp)
    if safe_int(d.get("ward_charges")) > 0:
        dmg = round(dmg * 0.60)
        d["ward_charges"] -= 1
        _wc_rem = d["ward_charges"]
        extra_notes.append("✨ *Ward!* Hit reduced 40%." + (f" ({_wc_rem} left)" if _wc_rem else " *(ward exhausted!)*"))
    elif _ts_active(d, "ward_until"):
        dmg = round(dmg * 0.60); d["ward_until"] = None
        extra_notes.append("✨ *Holy Ward absorbs the hit!* -40% damage.")
    # Consume shield charge (full negate)
    if safe_int(d.get("shield_charges")) > 0:
        d["shield_charges"] -= 1
        _sc_rem = d["shield_charges"]
        save_player(d); save_player(a)
        return (f"🛡️ *{d['username']}*'s *Shield* negated the attack!" +
                (f" ({_sc_rem} charges left)" if _sc_rem else " *(shield broken!)*"),
                [], "miss")
    # Consume regen charges (trigger on being hit)
    if safe_int(d.get("regen_charges")) > 0:
        _rg_heal = max(1, safe_int(d.get("regen_amt", 0)))
        d["hp"] = min(d.get("max_hp", d["hp"]), d["hp"] + _rg_heal)
        d["regen_charges"] -= 1
        extra_notes.append(f"💚 *Regen trigger!* +{_rg_heal} HP ({d['regen_charges']} left)")

    _d_hp_before_attack = d["hp"]
    # Void Sovereign companion: +10% all stats — simulate with 10% extra DR here
    _void_sov_dr = 0.10 if "all_stats_10" in _dng_pvp_effects(d) else 0
    dmg_after_def = calc_defense(d, dmg) if dmg > 0 else 0
    if dmg_after_def > 0 and _void_sov_dr:
        dmg_after_def = max(0, int(dmg_after_def * (1 - _void_sov_dr)))
    # Iron Guardian companion: +120 flat DEF absorb per hit
    if dmg_after_def > 0 and "flat_def_120" in _dng_pvp_effects(d):
        dmg_after_def = max(0, dmg_after_def - 120)

    # Serpent defender: show the snake companion absorption in combat messages
    if dmg > 0 and get_class_line(d) == "serpent":
        _serp_pks_d = get_all_passive_keys(d)
        _sabsorb = (0.15 if "immortal_coils" in _serp_pks_d
                    else 0.22 if "coiling_stance" in _serp_pks_d
                    else 0.18 if ("armored_scales" in _serp_pks_d or "serpents_resolve" in _serp_pks_d)
                    else 0.15)
        _sabsorbed = round(dmg * _sabsorb)
        extra_notes.append(f"🐍 *Serpent Companion* coils to absorb *{_sabsorbed} dmg*!")

    if _ts_active(d, "holy_field_until"):
        wis_dmg = round(safe_stats(d).get("WIS", 5) * 2)
        a["hp"] = max(0, a["hp"] - wis_dmg)
        reflect_note = f" | ✨ Holy Field reflects {wis_dmg} dmg!"
    else:
        reflect_note = ""

    if cls_d and cls_d.get("passive_key") == "unbreakable":
        if d["hp"] - dmg_after_def <= 0 and not d.get("unbreakable_used"):
            dmg_after_def = d["hp"] - 1; d["unbreakable_used"] = True

    def_pet_rec = get_active_pet_record(du_id)
    if def_pet_rec:
        dmg_after_def, pet_status_type, pet_status_val = apply_pet_defense(def_pet_rec, a, dmg_after_def, extra_notes, calc_max_hp(d))
        if pet_status_type == "stun" and safe_int(a.get("stun_turns", 0)) < 3: add_charges(a, "stun_turns", 1)
        elif pet_status_type == "poison" and pet_status_val:
            a["poison_damage"] = pet_status_val; add_charges(a, "poison_stacks", 2)
        elif pet_status_type == "lifesteal_to_owner" and pet_status_val:
            d["hp"] = min(calc_max_hp(d), d.get("hp", 0) + pet_status_val)

    # ── Dungeon item / companion defender effects ─────────────────────────────
    _d_dng_fx = _dng_pvp_effects(d)
    _d_dng_st = _dng_pvp_state(du_id)
    _a_dng_fx = _dng_pvp_effects(a)
    _a_dng_st = _dng_pvp_state(au_id)

    # Cryptwalker's Blade: attacker gains 1-hit immunity after a kill
    if _a_dng_st.get("cryptwalker_shield"):
        _a_dng_st["cryptwalker_shield"] = False
        extra_notes.append(f"🗡️ *Cryptwalker's Shield!* {a.get('username','?')} negates this hit!")
        dmg_after_def = 0

    # Void Crown: 20% chance to fully negate any attack
    if dmg_after_def > 0 and "negate_20" in _d_dng_fx and random.random() < 0.20:
        extra_notes.append(f"🕳️ *Void Crown!* The attack dissolves into nothing!")
        dmg_after_def = 0

    # Abyssal Plate: immune to first 5 attacks per PvP battle
    if dmg_after_def > 0 and _d_dng_st.get("abyssal_plate_hits", 0) > 0:
        _d_dng_st["abyssal_plate_hits"] -= 1
        _rem = _d_dng_st["abyssal_plate_hits"]
        extra_notes.append(f"🛡️ *Abyssal Plate!* Attack negated! ({_rem} charges left)")
        dmg_after_def = 0

    # Crystal Golem companion: absorbs first 3 hits, 50% counter
    if dmg_after_def > 0 and _d_dng_st.get("golem_absorbs", 0) > 0:
        _d_dng_st["golem_absorbs"] -= 1
        counter_dmg = max(1, int(dmg_after_def * 0.50))
        a["hp"] = max(0, a["hp"] - counter_dmg)
        extra_notes.append(f"💎 *Crystal Golem* absorbs the hit & counters for *{counter_dmg}* dmg! ({_d_dng_st['golem_absorbs']} left)")
        dmg_after_def = 0

    # Void Sovereign companion: 20% damage negation
    if dmg_after_def > 0 and "dmg_negate_20" in _d_dng_fx and random.random() < 0.20:
        extra_notes.append(f"👁️ *Void Sovereign!* 20% damage negated!")
        dmg_after_def = max(0, int(dmg_after_def * 0.80))

    # Rageborn Gauntlets: attacker +40% ATK when below 40% HP
    if dmg_after_def > 0 and "rage_atk_40" in _a_dng_fx:
        _a_hp_pct = a.get("hp", 1) / max(1, calc_max_hp(a))
        if _a_hp_pct < 0.40:
            dmg_after_def = int(dmg_after_def * 1.40)
            extra_notes.append(f"🔴 *Rageborn Gauntlets!* Low HP fury! Damage ×1.4!")

    # Shield absorbs damage before real HP
    _d_shield = safe_int(d.get("shield_hp"))
    _shield_absorbed = 0
    _dmg_before_shield = dmg_after_def
    if _d_shield > 0 and dmg_after_def > 0:
        _shield_absorbed = min(_d_shield, dmg_after_def)
        d["shield_hp"] = _d_shield - _shield_absorbed
        dmg_after_def -= _shield_absorbed
        if d["shield_hp"] == 0:
            extra_notes.append(f"🛡️ Shield *SHATTERED*! (absorbed *{_shield_absorbed}* → {dmg_after_def} to HP)")
        else:
            extra_notes.append(f"🛡️ Shield absorbed *{_shield_absorbed}*! ({d['shield_hp']} HP left → {dmg_after_def} to HP)")

    d_hp_after = max(0, d["hp"] - dmg_after_def)
    d["hp"] = d_hp_after
    if "flourish" in get_all_passive_keys(d):
        d["flourish_stacks"] = 0
    healed = apply_lifesteal(a, dmg_after_def)
    # Blood Pact Ring: 10% lifesteal on every hit for attacker
    if dmg_after_def > 0 and "lifesteal_10" in _a_dng_fx:
        _bpr_heal = max(1, int(dmg_after_def * 0.10))
        a["hp"] = min(calc_max_hp(a), a["hp"] + _bpr_heal)
        extra_notes.append(f"💍 *Blood Pact Ring* drains *+{_bpr_heal} HP*!")
    # Void Wisp companion: 12% chance to silence attacker when defender is hit
    if dmg_after_def > 0 and "silence_on_hit_12" in _d_dng_fx and random.random() < 0.12:
        add_charges(a, "silence_turns", 2)
        extra_notes.append(f"🌀 *Void Wisp!* {a.get('username','?')} is *Silenced* for 2 turns!")
    # Consume attacker charge-based buffs/debuffs (one charge per attack)
    if safe_int(a.get("battle_cry_str_hits")) > 0:
        a["battle_cry_str_hits"] -= 1
    if safe_int(a.get("blessed_turns")) > 0:
        a["blessed_turns"] -= 1
    if safe_int(a.get("cursed_hits")) > 0:
        a["cursed_hits"] -= 1

    # Defender post-hit passive regen/procs (fires after damage is applied)
    if cls_d and dmg_after_def > 0:
        _pk_d_post = cls_d.get("passive_key", "")
        if _pk_d_post == "garden_aura":
            _ga_hp = max(1, round(safe_stats(d).get("WIS", 5)))
            d["hp"] = min(calc_max_hp(d), d["hp"] + _ga_hp)
            extra_notes.append(f"🌸 *Garden Aura!* +{_ga_hp} HP nature regen!")
        if _pk_d_post == "renew" and random.random() < 0.20:
            _rn_hp = max(1, round(safe_stats(d).get("WIS", 5) * 3))
            d["hp"] = min(calc_max_hp(d), d["hp"] + _rn_hp)
            extra_notes.append(f"✨ *Renew!* +{_rn_hp} HP divine regen!")
        if _pk_d_post == "divine_grace" and random.random() < 0.15:
            _dg_hp = round(calc_max_hp(d) * 0.05)
            d["hp"] = min(calc_max_hp(d), d["hp"] + _dg_hp)
            extra_notes.append(f"🙏 *Divine Grace!* +{_dg_hp} HP (5% max HP restored by faith)!")
        if _pk_d_post == "mend" and random.random() < 0.20:
            _mend_hp = max(1, round(safe_stats(d).get("WIS", 5) * 2))
            d["hp"] = min(calc_max_hp(d), d["hp"] + _mend_hp)
            extra_notes.append(f"✨ *Mend!* +{_mend_hp} HP divine restoration!")
        if _pk_d_post == "natural_growth":
            _ng_hp = max(1, round(safe_stats(d).get("WIS", 5)))
            d["hp"] = min(calc_max_hp(d), d["hp"] + _ng_hp)
            extra_notes.append(f"🌿 *Natural Growth!* +{_ng_hp} HP nature regen!")
        if _pk_d_post == "allure" and random.random() < 0.15:
            add_charges(a, "hex_turns", 2)
            extra_notes.append(f"💫 *Allure!* {a['username']} fascinated (25% less damage for 2 hits)!")

    # Storm Drake companion: 15% chance lightning proc on basic attacks
    if dmg_after_def > 0 and "lightning_proc_15" in _a_dng_fx and random.random() < 0.15:
        _lp_dmg = max(1, round(dmg_after_def * 0.40))
        d["hp"] = max(0, d["hp"] - _lp_dmg)
        extra_notes.append(f"⚡ *Storm Drake lightning!* Zaps {d.get('username','?')} for *{_lp_dmg}* bonus damage!")

    # Burn proc from weapon enchant
    if get_enchant_bonus(a, "burn_proc") and random.random() < 0.10:
        add_charges(d, "burn_stacks", 2)
        d["burn_pct"] = 10
        extra_notes.append(f"🔥 *{a.get('username','?')}*'s weapon ignites {d.get('username','?')}! Burn ×2 (10%/action)!")

    # reflect_flat enchant
    ref = get_enchant_bonus(d, "reflect_flat")
    if ref > 0 and dmg_after_def > 0:
        a["hp"] = max(0, a["hp"] - ref)
        extra_notes.append(f"🔱 *{d.get('username','?')}*'s armor reflects {ref} dmg!")

    if cls_a and dmg_after_def > 0:
        pk_a = cls_a.get("passive_key", "")
        if pk_a == "feint" and random.random() < 0.05 and safe_int(d.get("distract_turns", 0)) < 3:
            add_charges(d, "distract_turns", 1)
            extra_notes.append(f"🗡️ *Feint!* {d['username']} distracted for 1 attack!")
        if pk_a == "throat_cut" and random.random() < 0.05:
            if safe_int(d.get("silence_turns", 0)) < 4:
                add_charges(d, "silence_turns", 1)
                extra_notes.append(f"🤐 *Throat Cut!* {d['username']} silenced for 1 skill!")
        if pk_a == "cursed_blade": add_charges(d, "cursed_hits", 2)
        if pk_a == "warning_shot" and random.random() < 0.20 and safe_int(d.get("distract_turns", 0)) < 3:
            add_charges(d, "distract_turns", 1)
            extra_notes.append(f"🎯 *Warning Shot!* {d['username']} distracted (30% miss for 1 hit)!")
        if pk_a == "natural_growth" and random.random() < 0.15:
            add_charges(d, "poison_stacks", 5)
            extra_notes.append(f"🌱 *Natural Growth!* {d['username']} poisoned (15 dmg × 5 hits)!")
        if pk_a == "purge":
            _purged = False
            for buf in ["blessed_until", "def_reflect_until", "invincible_until", "temp_hp_until"]:
                if _ts_active(d, buf): d[buf] = None; _purged = True; break
            if not _purged:
                for buf in ["blessed_turns", "def_reflect_hits", "battle_cry_str_hits"]:
                    if safe_int(d.get(buf)) > 0: d[buf] = 0; break
        if pk_a == "curse_touch" and random.random() < 0.08:
            add_charges(d, "weakened_hits", 3)
            extra_notes.append("💜 *Curse Touch!* Weakened ×3 — +25% dmg taken next 3 hits!")
        if pk_a == "shadow_hex" and (safe_int(d.get("hex_turns")) > 0 or _ts_active(d, "hexed_until")):
            bonus_hex = round(dmg_after_def * 0.15)  # up from 0.05
            dmg_after_def += bonus_hex; d["hp"] = max(0, d["hp"] - bonus_hex)
            extra_notes.append(f"🕸️ *Shadow Hex!* +{bonus_hex} on hexed target!")
        if pk_a == "dark_sense":
            _debuffed = (safe_int(d.get("hex_turns")) > 0 or safe_int(d.get("weakened_hits")) > 0 or
                         safe_int(d.get("cursed_hits")) > 0 or safe_int(d.get("marked_hits")) > 0 or
                         safe_int(d.get("exposed_hits")) > 0 or safe_int(d.get("distract_turns")) > 0 or
                         safe_int(d.get("poison_stacks")) > 0 or _ts_active(d, "hexed_until"))
            if _debuffed:
                _ds_bonus = round(dmg_after_def * 0.15)
                dmg_after_def += _ds_bonus; d["hp"] = max(0, d["hp"] - _ds_bonus)
                extra_notes.append(f"👁️ *Dark Sense!* +{_ds_bonus} bonus dmg vs debuffed target!")
        if pk_a == "marked_for_death":
            _mfd_target = (safe_int(d.get("marked_hits")) > 0 or safe_int(d.get("hex_turns")) > 0 or
                           safe_int(d.get("weakened_hits")) > 0 or safe_int(d.get("exposed_hits")) > 0 or
                           _ts_active(d, "hexed_until"))
            if _mfd_target:
                _mfd_bonus = round(dmg_after_def * 0.20)
                dmg_after_def += _mfd_bonus; d["hp"] = max(0, d["hp"] - _mfd_bonus)
                extra_notes.append(f"🎯 *Marked for Death!* +{_mfd_bonus} bonus dmg vs marked target!")
        if "harmonize" in get_all_passive_keys(a):
            a["harmony_stacks"] = min(3, safe_int(a.get("harmony_stacks", 0)) + 1)
        if pk_a == "melody":
            a["melody_stacks"] = min(3, safe_int(a.get("melody_stacks", 0)) + 1)
        if "rhythm" in get_all_passive_keys(a):
            a["rhythm_stacks"] = min(4, safe_int(a.get("rhythm_stacks", 0)) + 1)
        # ── Serpent attacker passives ─────────────────────────────────────────
        # cold_blood: ignore 5 flat DEF on every hit
        if "cold_blood" in _a_pks:
            _cb_pierce = 5
            dmg_after_def += _cb_pierce; d["hp"] = max(0, d["hp"] - _cb_pierce)
        if pk_a == "vipers_edge" and random.random() < 0.20:
            if safe_int(d.get("poison_stacks", 0)) < 8:
                add_charges(d, "poison_stacks", 1)
                _ve_pct = (40 if "serpentine_mastery" in _a_pks else
                           30 if "death_venom"        in _a_pks else
                           27 if "toxic_fangs"         in _a_pks else 20)
                d["poison_pct"] = max(safe_int(d.get("poison_pct", 0)), _ve_pct)
                extra_notes.append(f"🐍 *Viper's Edge!* Venom seeps in — {d['username']} poisoned! ({_ve_pct}% max HP/action)")
        if pk_a == "venom_spit" and random.random() < 0.15:
            if safe_int(d.get("distract_turns", 0)) < 3:
                add_charges(d, "distract_turns", min(2, 3 - safe_int(d.get("distract_turns", 0))))
                extra_notes.append(f"🐍 *Venom Spit!* {d['username']} blinded — Distract ×2!")
        if pk_a == "toxic_fangs" and safe_int(d.get("poison_stacks", 0)) > 0:
            _tf_bonus = round(dmg_after_def * 0.10)
            dmg_after_def += _tf_bonus; d["hp"] = max(0, d["hp"] - _tf_bonus)
            extra_notes.append(f"☠️ *Toxic Fangs!* +{_tf_bonus} bonus vs poisoned target!")
        if pk_a == "death_venom" and safe_int(d.get("poison_stacks", 0)) > 0:
            _dv_bonus = round(dmg_after_def * 0.15)
            dmg_after_def += _dv_bonus; d["hp"] = max(0, d["hp"] - _dv_bonus)
            extra_notes.append(f"☠️ *Death Venom!* +{_dv_bonus} bonus vs poisoned target!")
        if pk_a == "serpents_resolve" and a.get("hp", 1) / max(1, calc_max_hp(a)) < 0.40:
            _sr_bonus = round(dmg_after_def * 0.20)
            dmg_after_def += _sr_bonus; d["hp"] = max(0, d["hp"] - _sr_bonus)
            extra_notes.append(f"🐍 *Serpent's Resolve!* Low HP fuels the strike! +{_sr_bonus} dmg!")
    # ── Serpent defender passives ─────────────────────────────────────────────
    if cls_d and dmg_after_def > 0:
        _pk_d_serp = cls_d.get("passive_key", "")
        if _pk_d_serp == "viper_scales" and random.random() < 0.15:
            if safe_int(a.get("poison_stacks", 0)) < 8:
                add_charges(a, "poison_stacks", 1); a["poison_pct"] = 20
                extra_notes.append(f"🐍 *Viper Scales!* {a['username']} struck serpent scales — Venom applied!")
        if _pk_d_serp == "venom_aura" and random.random() < 0.25:
            if safe_int(a.get("poison_stacks", 0)) < 8:
                add_charges(a, "poison_stacks", 2); a["poison_pct"] = 20
                extra_notes.append(f"🌿 *Venom Aura!* {a['username']} enveloped in venom — Venom ×2!")
        if _pk_d_serp == "armored_scales" and random.random() < 0.10:
            _as_dmg = max(1, round(get_stat(d, "STR") * 0.5))
            a["hp"] = max(0, a["hp"] - _as_dmg)
            extra_notes.append(f"🛡️ *Armored Scales!* {d['username']}'s scales retaliate — {a['username']} takes {_as_dmg} dmg!")
        # (immortal_coils survive-at-1-HP is evaluated at the END of the action,
        #  after companion echoes — see the final gate next to the Last Stand
        #  Locket — so a follow-up hit in the same action can't waste the proc)
        # coiling_stance: -10% damage taken when below 50% HP (only when actual damage was dealt)
        if "coiling_stance" in get_all_passive_keys(d) and dmg_after_def > 0 and safe_int(d.get("hp", 0)) / max(1, calc_max_hp(d)) < 0.50:
            _cs_reduce = round(dmg_after_def * 0.10)
            d["hp"] = min(calc_max_hp(d), d["hp"] + _cs_reduce)
            extra_notes.append(f"🐍 *Coiling Stance!* {d['username']} resists — {_cs_reduce} damage absorbed!")

    # (serpent attacker kill-heal moved after the end-of-action survival gates
    #  so it only procs on a true kill)

    # mana_overload_reflect fires regardless of attacker class
    if d.get("mana_overload_reflect"):
        reflect_dmg = d.pop("mana_overload_reflect")
        a["hp"] = max(1, a["hp"] - reflect_dmg)
        extra_notes.append(f"⚡ *Mana Overload!* {d['username']} reflects *{reflect_dmg} dmg*!")

    # ── Automatic class affliction proc (15% per hit) ────────────────────────
    _line_a_auto = get_class_line(a) if cls_a else None
    if dmg_after_def > 0 and _line_a_auto:
        _affl_pool = _CLASS_AUTO_AFFLICTIONS.get(_line_a_auto, [])
        if _affl_pool and random.random() < 0.15:
            _affl = random.choice(_affl_pool)
            _afk, _afa, _afpk, _afpv, _afem, _afmsg = _affl
            _cur_af = safe_int(d.get(_afk, 0))
            if _cur_af < _AUTO_AFFLICTION_CAP.get(_afk, 3):
                add_charges(d, _afk, _afa)
                if _afpk: d[_afpk] = _afpv
                # Serpent tier boosts auto-affliction venom potency
                if _afpk == "poison_pct" and _line_a_auto == "serpent":
                    _tier_pct = (40 if "serpentine_mastery" in _a_pks else
                                 30 if "death_venom"        in _a_pks else
                                 27 if "toxic_fangs"         in _a_pks else 20)
                    d["poison_pct"] = max(safe_int(d.get("poison_pct", 0)), _tier_pct)
                _afl = _line_a_auto.replace("_"," ").title()
                extra_notes.append(f"{_afem} *{_afl}!* {d['username']}: {_afmsg}")

    # ── Limb damage proc (15% per hit) ───────────────────────────────────────
    if dmg_after_def > 0 and random.random() < 0.15:
        _lp = random.choices(_LIMB_PROCS, weights=_LIMB_WEIGHTS, k=1)[0]
        _, _lname, _ldk, _lda, _lcap, _lem = _lp
        _lcur = safe_int(d.get(_ldk, 0))
        if _lcur < _lcap:
            add_charges(d, _ldk, _lda)
            extra_notes.append(f"{_lem} *{d['username']}'s {_lname} cracked!* {_ldk.replace('_',' ').title()} ×{_lda} applied!")

    update_recent_attackers(d, au_id)
    proc_fired, proc_msg, proc_extra = calc_proc_effect(a, d, dmg_after_def)
    oh_fired, oh_msg, oh_extra = _apply_weapon_on_hit(a, d, dmg_after_def)

    _display_dmg = _dmg_before_shield if _shield_absorbed else dmg_after_def
    action = f"⚔️ *{a['username']}* → *{d['username']}* for *{_display_dmg} dmg*{crit_note}{revenge_bonus_note}{reflect_note}"
    if extra_notes:
        action += "\n" + "\n".join(extra_notes)
        extra_notes.clear()  # notes appended after this point flush before return
    if healed:      action += f" | 🦸 +{healed} HP"
    if proc_fired:  action += f"\n{proc_msg}"
    if oh_fired:    action += f"\n{oh_msg}"

    active_pet = get_active_pet_record(au_id)
    if active_pet:
        pet_atk    = _pet_combat_atk(active_pet, a)
        sp_pet     = PET_SPECIES.get(active_pet.get("species"), {})
        pname      = _pet_display_name(active_pet)
        pers       = sp_pet.get("personality", "calm")
        emoji_p    = sp_pet.get("emoji", "🐾")
        _p_hunger  = active_pet.get("hunger", 100)
        _p_mood    = active_pet.get("mood", 100)
        # Elemental matchup vs defender's active pet
        def_pet      = get_active_pet_record(du_id)
        elem_mult    = _get_pet_element_mult(active_pet, def_pet)
        # Skill proc
        skill_fired, pskill = _pet_skill_check(active_pet)
        if skill_fired and pskill:
            pet_atk  = round(pet_atk * pskill["mult"])
            skill_tag = f" _{pskill['name']}_"
            # Water skill heals owner
            if pskill.get("heal_pct") and active_pet.get("hunger",100) >= 40:
                heal_from_skill = round(pet_atk * pskill["heal_pct"])
                a["hp"] = min(calc_max_hp(a), a["hp"] + heal_from_skill)
        else:
            skill_tag = ""
        pet_atk = round(pet_atk * elem_mult * get_weather().get("dmg_mod", 1.0))
        d["hp"]  = max(0, d["hp"] - pet_atk)
        battle_msg  = PERSONALITY_BATTLE.get(pers, "attacks")
        elem_tag    = " 🌟*(type adv!)*" if elem_mult > 1.0 else (" *(resisted)*" if elem_mult < 1.0 else "")
        if _p_hunger >= 70 and _p_mood >= 70:
            action += f"\n{emoji_p} *{pname}* {battle_msg} for *{pet_atk} dmg*{skill_tag}{elem_tag}! ✨"
        elif _p_hunger < 40 or _p_mood < 40:
            action += f"\n{emoji_p} *{pname}* {battle_msg} for *{pet_atk} dmg*{skill_tag}{elem_tag} 😞"
        else:
            action += f"\n{emoji_p} *{pname}* {battle_msg} for *{pet_atk} dmg*{skill_tag}{elem_tag}!"

    # Class companion auto-proc (all classes get a unique built-in companion)
    _d_dng_fx_cc = _dng_pvp_effects(d)
    _a_dng_fx_cc = _dng_pvp_effects(a)
    def _cc_deal(raw):
        actual = calc_defense(d, raw)
        d["hp"] = max(0, d["hp"] - actual)
        # Blood Pact Ring lifesteal on companion damage
        if actual > 0 and "lifesteal_10" in _a_dng_fx_cc:
            a["hp"] = min(calc_max_hp(a), a["hp"] + max(1, int(actual * 0.10)))
        return actual
    def _cc_apply_status(effect, val):
        # Dungeon item status immunities
        if effect in ("stun_turns",) and "immune_cc" in _d_dng_fx_cc:
            return  # Unbroken Crown blocks stun
        if effect in ("silence_turns",) and ("immune_cc" in _d_dng_fx_cc or "immune_silence" in _d_dng_fx_cc):
            return  # Unbroken Crown or Blessed Specter blocks silence
        if effect in ("burn",) and ("immune_dot" in _d_dng_fx_cc or "immune_burn" in _d_dng_fx_cc):
            return  # Voidheart Pendant or Ember Fairy blocks burn
        if effect in ("poison_stacks",) and "immune_dot" in _d_dng_fx_cc:
            return  # Voidheart Pendant blocks poison
        # Null Regalia: debuffs last 50% shorter
        if "debuff_half" in _d_dng_fx_cc:
            val = max(1, val // 2)
        if effect == "burn": add_charges(d, "burn_stacks", val); d["burn_pct"] = 10
        elif effect == "poison_stacks": add_charges(d, "poison_stacks", val)
        elif effect == "distract_turns": add_charges(d, "distract_turns", val)
        elif effect == "stun_turns": add_charges(d, "stun_turns", val)
        elif effect == "silence_turns": add_charges(d, "silence_turns", val)
        elif effect == "hex_turns": add_charges(d, "hex_turns", val)
        elif effect == "branded_hits": add_charges(d, "branded_hits", val)
        elif effect == "def_reflect_hits": a["def_reflect_hits"] = safe_int(a.get("def_reflect_hits")) + val
        elif effect == "bleed_stacks": add_charges(d, "bleed_stacks", val)
    for _cc_line in _class_companion_strike(a, _cc_deal, _cc_apply_status):
        action += f"\n{_cc_line}"

    # kill_heal enchant
    kh = get_enchant_bonus(a, "kill_heal")
    if kh > 0 and d_hp_after <= 0:
        a["hp"] = min(calc_max_hp(a), a["hp"] + int(kh))
        extra_notes.append(f"🧛 *{a.get('username','?')}* drains {int(kh)} HP from the kill!")

    # The Last Stand Locket: survive the killing blow once per combat at 20% HP
    if d["hp"] <= 0 and _dng_pvp_state(du_id).get("last_stand_available"):
        _dng_pvp_state(du_id)["last_stand_available"] = False
        d["hp"] = max(1, round(calc_max_hp(d) * 0.20))
        extra_notes.append(f"🕯️ *The Last Stand Locket!* {d['username']} refuses to fall — revived at {d['hp']} HP!")

    # Immortal Coils (final gate): evaluated against the action's TOTAL damage
    # — after crits, companion echoes, and every rider — once per hour
    if d["hp"] <= 0 and "immortal_coils" in get_all_passive_keys(d) and not _ts_active(d, "serpent_revive_used"):
        d["hp"] = 1
        set_status(d, "serpent_revive_used", 3600)
        extra_notes.append(f"🐍 *Immortal Coils!* {d['username']} refuses to fall — survives at 1 HP! (1h cooldown)")

    # Serpent attacker kill-heal — after all survival gates so it only procs on a true kill
    if cls_a and d["hp"] <= 0:
        _pk_a_serp = cls_a.get("passive_key", "")
        if _pk_a_serp in ("serpentine_mastery", "immortal_coils"):
            _kill_pct = 0.15 if _pk_a_serp == "immortal_coils" else 0.20
            _sk_heal = round(calc_max_hp(a) * _kill_pct)
            a["hp"] = min(calc_max_hp(a), a["hp"] + _sk_heal)
            extra_notes.append(f"🐍 *{_pk_a_serp.replace('_',' ').title()}!* Kill heals {a['username']} for {_sk_heal} HP!")

    if d["hp"] <= 0:
        d["hp"] = 0
        d["defeated_until"] = (datetime.now() + timedelta(minutes=6)).isoformat()
        d["last_defeated_by"] = f"{a['username']} (PvP)"
        _d_was_wanted = safe_int(d.get("is_wanted"))
        # Clean up per-battle dungeon state for both players
        _pvp_battle_state.pop(au_id, None); _pvp_battle_state.pop(du_id, None)
        # Cryptwalker's Blade: killing blow gives attacker 1-hit immunity next turn
        if "kill_shield" in _dng_pvp_effects(a):
            _pvp_battle_state.setdefault(au_id, {})["cryptwalker_shield"] = True
        d["kill_streak"] = 0; d["is_wanted"] = 0; d["shield_used"] = 0; d["shield_hp"] = 0; d["shield_core_bonus"] = 0
        d["revenge_target"] = au_id
        d["revenge_expires"] = (datetime.now() + timedelta(hours=24)).isoformat()
        # Clear turn-based combat debuffs from both players when battle ends
        for _cf in ("heal_blocked_turns", "revive_blocked_turns", "silence_turns", "hex_turns",
                    "stun_turns", "freeze_turns", "entangle_turns", "distract_turns"):
            d[_cf] = 0
            if safe_int(a.get(_cf)) > 0:
                a[_cf] = 0
        exp_loss = round(d.get("exp", 0) * 0.10)
        _exp_penalty(d, exp_loss)
        d["losses"] = d.get("losses", 0) + 1
        a["wins"] = a.get("wins", 0) + 1
        a["kill_streak"] = safe_int(a.get("kill_streak")) + 1
        if a["kill_streak"] > safe_int(a.get("max_kill_streak")):
            a["max_kill_streak"] = a["kill_streak"]
        today_str = datetime.now().strftime("%Y-%m-%d")
        if a.get("kills_today_date") != today_str:
            a["kills_today"] = 0; a["kills_today_date"] = today_str
        a["kills_today"] = safe_int(a.get("kills_today")) + 1
        if a["kills_today"] >= 5: a["is_wanted"] = 1
        hist = sjl(d.get("pvp_history"), [])
        hist.insert(0, {"attacker": a["username"], "dmg": "KO",
                        "ts": datetime.now().strftime("%m/%d %H:%M")})
        d["pvp_history"] = json.dumps(hist[:5])
        for _desc, _exp, _gold in track_objective(a, "pvp_win"):
            a["gold"] = a.get("gold", 0) + _gold; add_exp(a, _exp)
        if cls_a and cls_a.get("passive_key") == "dead_or_alive":
            d["defeated_until"] = (datetime.now() + timedelta(hours=1)).isoformat()
            action += f"\n☠️ *LAST SHOT!* {d['username']} defeated for 1 hour!"
            asyncio.create_task(announce(bot, chat_id,
                f"🏹 *{a['username']}* took down *{d['username']}* with *Last Shot*! "
                f"1-hour defeat.", delay=30))
            a["gold"] = a.get("gold", 0) + 150
        exp_gain = _pvp_kill_exp(a, d)
        if _d_was_wanted:
            wanted_gold = 250; wanted_exp = round(exp_gain * 0.5)
            a["gold"] = a.get("gold", 0) + wanted_gold
            exp_gain += wanted_exp
            action += f"\n🔴 *WANTED BOUNTY!* +{wanted_gold}g +{wanted_exp} bonus EXP for taking down a wanted player!"
            asyncio.create_task(announce(bot, chat_id,
                f"🔴 *{a['username']}* brought down the WANTED *{d['username']}*! +{wanted_gold}g reward!", delay=5))
        lmsgs, leveled = add_exp(a, exp_gain, w); lvl_msgs = lmsgs
        if cls_a and cls_a.get("passive_key") == "conqueror":
            restore = round(a["max_hp"] * 0.20)
            a["hp"] = min(a["max_hp"], a["hp"] + restore)
            _wk_add = min(5, max(0, 5 - safe_int(d.get("weakened_hits", 0))))
            if _wk_add: add_charges(d, "weakened_hits", _wk_add)
        _fire(check_and_claim_bounty(bot, a, d, chat_id))
        a_guild = get_guild(a.get("guild_id")) if a.get("guild_id") else None
        d_guild = get_guild(d.get("guild_id")) if d.get("guild_id") else None
        if a_guild and d_guild and a_guild["guild_id"] != d_guild["guild_id"]:
            war_gw = get_active_war(a_guild["guild_id"], d_guild["guild_id"])
            if war_gw:
                _db_kw = _db(); c_kr = _db_kw.cursor()
                if str(war_gw["guild1_id"]) == str(a_guild["guild_id"]):
                    c_kr.execute("UPDATE guild_wars SET kills1=kills1+1 WHERE war_id=?", (war_gw["war_id"],))
                else:
                    c_kr.execute("UPDATE guild_wars SET kills2=kills2+1 WHERE war_id=?", (war_gw["war_id"],))
                _db_kw.commit()
                action += f"\n⚔️ *Guild War kill!* Score updated for {a_guild['name']}."
        if cls_a and cls_a.get("passive_key") == "dead_or_alive":
            a["deadeye_kill_bonus"] = min(50, safe_int(a.get("deadeye_kill_bonus")) + 2)
        if cls_a and cls_a.get("passive_key") == "marked_for_death":
            mfd_bonus = round((d.get("gold", 0) * 0.05 + 25) * 0.25)
            a["gold"] = a.get("gold", 0) + mfd_bonus
        _defeat_timer_pvp = time_until(d.get("defeated_until")) or "6m"
        action += f"\n💀 *{d['username']}* DEFEATED! +{fmt_num(exp_gain)} EXP to {a['username']}.\n⏳ *{d['username']}* back in *{_defeat_timer_pvp}*."
        if leveled:
            _lvl_grp = _pvp_origin_chat.get((au_id, du_id)) or _pvp_origin_chat.get((du_id, au_id)) or chat_id
            asyncio.create_task(announce(bot, _lvl_grp,
                f"🎉 *{a['username']}* reached *Level {a['level']}*! ⚔️", delay=30))

    if d["hp"] > 0:
        hist_nl = sjl(d.get("pvp_history"), [])
        _hist_entry = {"attacker": a["username"], "dmg": _dmg_before_shield,
                       "ts": datetime.now().strftime("%m/%d %H:%M")}
        if _shield_absorbed:
            _hist_entry["shield"] = _shield_absorbed
            _hist_entry["hp_dmg"] = dmg_after_def
        hist_nl.insert(0, _hist_entry)
        d["pvp_history"] = json.dumps(hist_nl[:5])

    # Flush notes generated after the mid-action merge (locket / Immortal
    # Coils survives, kill heals) — they were previously never displayed
    if extra_notes:
        action += "\n" + "\n".join(extra_notes)
        extra_notes.clear()

    # Fight Card 2.0 damage accounting (lazy-init on first hit of the fight)
    _stat_pair = _pvp_pair_key(au_id, du_id)
    if _stat_pair not in _pvp_stats:
        _pvp_stats_init(_stat_pair, a, d)
    _pvp_stats_record(_stat_pair, au_id, max(0, _d_hp_before_attack - d["hp"]))

    check_titles(a); check_titles(d)
    # Save on the event-loop thread: a WAL write is ~1ms, and pushing it to a
    # worker thread made it the bot's only concurrent DB writer — the source
    # of 10s "database is locked" busy-waits that froze the update pipeline.
    save_player(a); save_player(d)

    if d["hp"] > 0:
        _total_hp_lost = max(0, _d_hp_before_attack - d["hp"])
        asyncio.create_task(_notify_attack(bot, d, a["username"], _total_hp_lost))

    statuses = get_active_statuses(d)
    if statuses: action += "\n" + " | ".join(statuses)
    if lvl_msgs: action += "\n\n" + "\n".join(lvl_msgs)

    return action, lvl_msgs, "defeat" if d["hp"] <= 0 else "hit"


def get_player_by_username(name):
    """Look up player by Telegram @handle, RPG name, or Telegram display name (case-insensitive)."""
    c = _db().cursor()
    key = name.lower().lstrip("@")
    # 1) Try @handle (tg_username column)
    c.execute("SELECT * FROM players WHERE LOWER(tg_username)=?", (key,))
    row = c.fetchone()
    if not row:
        # 2) Try RPG display name (username column)
        c.execute("SELECT * FROM players WHERE LOWER(username)=?", (key,))
        row = c.fetchone()
    if not row:
        # 3) Try Telegram display name via shadow_profiles (for users without @handle)
        c.execute("""SELECT p.* FROM players p
                     JOIN shadow_profiles s ON s.user_id = p.user_id
                     WHERE LOWER(s.username)=?""", (key,))
        row = c.fetchone()
    return dict(row) if row else None


