def _auto_recover(p):
    """A player whose defeat timer expired but who never healed sits at 0 HP
    forever — invisible to attackers and a free one-hit kill if targeted
    directly. Once the timer lapses they're back on their feet at 50% HP."""
    if safe_int(p.get("hp")) <= 0 and not is_defeated(p):
        p["hp"] = max(1, round(calc_max_hp(p) * 0.50))
        p["defeated_until"] = None
        save_player(p)
        return True
    return False

def _get_attackable_players(attacker_uid, attacker_guild_id, page=0, per_page=3):
    """Return (page_list, total) of players attackable right now."""
    c = _db().cursor()
    c.execute("SELECT * FROM players WHERE user_id != ?", (attacker_uid,))
    rows = c.fetchall()
    results = []
    excl = {"recovering": 0, "protected": 0, "busy": 0, "guild": 0, "offline": 0}
    _now = datetime.now()
    for row in rows:
        tp = dict(row)
        if tp.get("hp", 1) <= 0:
            if is_defeated(tp):
                excl["recovering"] += 1; continue
            _auto_recover(tp)  # timer expired, never healed — stand them back up
        if is_defeated(tp): excl["recovering"] += 1; continue
        if is_invincible(tp): excl["recovering"] += 1; continue
        if safe_int(tp.get("level"), 1) < 10: excl["protected"] += 1; continue  # Newbie Protection
        if safe_int(tp.get("user_id")) in active_dungeons: excl["busy"] += 1; continue
        if safe_int(tp.get("user_id")) in active_encounters: excl["busy"] += 1; continue
        if attacker_guild_id and tp.get("guild_id") and \
           str(tp.get("guild_id")) == str(attacker_guild_id): excl["guild"] += 1; continue
        _shadow = get_shadow(tp["user_id"])
        if _shadow and _shadow.get("last_seen"):
            try:
                if (_now - datetime.fromisoformat(_shadow["last_seen"])).total_seconds() > _PVP_ACTIVE_WINDOW:
                    excl["offline"] += 1; continue
            except Exception:
                pass
        results.append(tp)
    _last_pool_exclusions[attacker_uid] = excl
    results.sort(key=lambda x: (-safe_int(x.get("is_wanted", 0)),
                                 -x.get("level", 1),
                                 x.get("username", "")))
    total = len(results)
    start = page * per_page
    return results[start:start + per_page], total

def _build_target_picker_markup(attacker_uid, guild_id, page, mode="atk"):
    """Build inline keyboard for attack/skill target picker."""
    players, total = _get_attackable_players(attacker_uid, guild_id, page)
    per_page = 3
    rows = []
    for tp in players:
        name     = tp.get("username", "?")
        lvl      = tp.get("level", 1)
        hp_pct   = round(tp.get("hp", 0) / max(1, tp.get("max_hp", 1)) * 100)
        wanted   = " 🔴" if safe_int(tp.get("is_wanted")) else ""
        cb_pfx   = "atk" if mode == "atk" else "skl2"
        rows.append([InlineKeyboardButton(
            f"{'⚔️' if mode == 'atk' else '🔮'} {name} (Lv.{lvl}) ❤️{hp_pct}%{wanted}",
            callback_data=f"{cb_pfx}_pick_{attacker_uid}_{tp['user_id']}"
        )])
    nav = []
    if page > 0:
        nav.append(InlineKeyboardButton("◀️", callback_data=f"{'atk' if mode=='atk' else 'skl2'}_page_{attacker_uid}_{page-1}"))
    if (page + 1) * per_page < total:
        nav.append(InlineKeyboardButton("▶️", callback_data=f"{'atk' if mode=='atk' else 'skl2'}_page_{attacker_uid}_{page+1}"))
    if nav:
        rows.append(nav)
    rows.append([InlineKeyboardButton("❌ Close", callback_data=f"close_msg_{attacker_uid}")])
    return InlineKeyboardMarkup(rows)

async def attack_picker_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle atk_pick_{uid}_{target} and atk_page_{uid}_{page} callbacks."""
    query = update.callback_query
    data  = query.data
    parts = data.split("_")
    try:
        action     = parts[1]   # "pick" or "page"
        uid        = int(parts[2])
        fourth     = int(parts[3])
    except (IndexError, ValueError):
        await query.answer(); return
    if query.from_user.id != uid:
        await query.answer("Not your picker!", show_alert=True); return

    a = get_player(uid)
    if not a:
        await query.answer("Use /ascend first!", show_alert=True); return

    if action == "page":
        markup = _build_target_picker_markup(uid, a.get("guild_id"), fourth, "atk")
        try:
            await query.edit_message_reply_markup(reply_markup=markup)
        except Exception:
            pass
        await query.answer()
        return

    # action == "pick" — fourth is target_uid
    target_uid = fourth

    # Answer immediately so Telegram stops the loading spinner on first tap
    await query.answer()

    # Lock prevents concurrent double-tap from firing two attacks
    _tok = _cb_lock(uid)
    if not _tok:
        return  # silently drop — lock is the guard

    try:
        if is_defeated(a):
            await query.answer("You're defeated!", show_alert=True); return
        if is_invincible(a):
            await query.answer("You're invincible!", show_alert=True); return
        if is_vanished(a):
            await query.answer("You're vanished — can't attack while hidden!", show_alert=True); return
        _cc = _consume_cc(a)
        if _cc:
            await query.answer(_cc, show_alert=True); return

        d = get_player(target_uid)
        if not d:
            await query.answer("Target not found.", show_alert=True); return
        if is_defeated(d):
            await query.answer(d.get("username","?") + " is already defeated!", show_alert=True); return
        if is_invincible(d):
            await query.answer(d.get("username","?") + " is invincible!", show_alert=True); return
        _pk_a = get_player(uid)
        if _pk_a:
            _pk_ok, _pk_why = _pvp_attack_allowed(_pk_a, d)
            if not _pk_ok:
                await query.answer(_pk_why.replace("*", "").replace("_", "")[:190], show_alert=True); return

        # Delete the picker message
        try:
            await query.message.delete()
        except Exception:
            pass

        pair = _pvp_pair_key(uid, target_uid)
        _is_new_battle_pk = pair not in _pvp_origin_chat
        _pk_grp = _resolve_pvp_group_chat(uid, query.message.chat_id)
        _pvp_cards.setdefault(pair, {})
        _pvp_origin_chat[pair] = _pk_grp
        _target_pickers[uid] = {"last_pick": datetime.now().isoformat(), "chat_id": _pk_grp}

        # Alert the defender — clear any old card so Telegram sends a fresh push notification
        _pvp_dm_last_msg.pop(target_uid, None)
        _pvp_log_msg.pop(target_uid, None)
        try:
            await context.bot.send_message(chat_id=target_uid,
                text=f"⚔️ *{a['username']}* is attacking you!", parse_mode="Markdown")
        except Exception:
            pass
        if _is_new_battle_pk:
            asyncio.create_task(announce(context.bot, _pk_grp, _pvp_fight_start_line(a["username"], d["username"]), permanent=True))
            _bt = asyncio.create_task(_open_fight_bets(context.bot, _pk_grp, pair, a, d))
            _bg_tasks.add(_bt); _bt.add_done_callback(_bg_tasks.discard)
        start_txt = "⚔️ *" + a["username"] + "* vs *" + d["username"] + "* — fight started!"
        _pvp_log_append(pair, start_txt)
        fresh_a = get_player(uid) or a
        fresh_d = get_player(target_uid) or d
        _cb_unlock(uid, _tok)
        await _pvp_notify_both(pair, fresh_a, fresh_d, uid, target_uid, start_txt, context.bot)
    finally:
        _cb_unlock(uid, _tok)  # token-checked: can't release a newer tap's lock


async def pvp_rematch_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """⚔️ Rematch button on the end-of-fight card — restarts the fight in one tap."""
    query = update.callback_query
    parts = query.data.split("_")
    try:
        uid = int(parts[1]); opp_uid = int(parts[2])
    except (IndexError, ValueError):
        await query.answer(); return
    if query.from_user.id != uid:
        await query.answer("This isn't your rematch button!", show_alert=True); return
    a = get_player(uid); d = get_player(opp_uid)
    if not a or not d:
        await query.answer("Opponent not found.", show_alert=True); return
    if is_defeated(a):
        await query.answer("You're still defeated — heal up first!", show_alert=True); return
    if is_defeated(d):
        await query.answer(f"{d['username']} is still recovering — try again in a few minutes!",
                           show_alert=True); return
    if is_invincible(d):
        await query.answer(f"{d['username']} is invincible right now — wait for their grace "
                           f"period to end!", show_alert=True); return
    _rm_ok, _rm_why = _pvp_attack_allowed(a, d)
    if not _rm_ok:
        await query.answer(_rm_why.replace("*", "").replace("_", "")[:190], show_alert=True); return
    _tok = _cb_lock(uid)
    if not _tok:
        await query.answer("⏳ Still processing!"); return
    try:
        await query.answer("⚔️ Rematch!")
        pair = _pvp_pair_key(uid, opp_uid)
        _pvp_cards.setdefault(pair, {})
        _pvp_battle_logs.pop(pair, None)
        _pk_grp = _resolve_pvp_group_chat(uid, query.message.chat_id if query.message else uid)
        _pvp_origin_chat[pair] = _pk_grp
        # Fresh battle state for per-fight items/companions
        _dng_pvp_init(uid, a); _dng_pvp_init(opp_uid, d)
        try:
            await context.bot.send_message(chat_id=opp_uid,
                text=f"⚔️ *{a['username']}* challenges you to a rematch!", parse_mode="Markdown")
        except Exception:
            pass
        start_txt = f"⚔️ *REMATCH!* *{a['username']}* vs *{d['username']}* — round two!"
        _pvp_log_append(pair, start_txt)
        _bt = asyncio.create_task(_open_fight_bets(context.bot, _pk_grp, pair, a, d))
        _bg_tasks.add(_bt); _bt.add_done_callback(_bg_tasks.discard)
        _cb_unlock(uid, _tok)
        await _pvp_notify_both(pair, a, d, uid, opp_uid, start_txt, context.bot)
    finally:
        _cb_unlock(uid, _tok)

async def skill_target_picker_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle skl2_pick_{uid}_{target} and skl2_page_{uid}_{page} callbacks."""
    query = update.callback_query
    data  = query.data
    parts = data.split("_")
    try:
        action = parts[1]   # "pick" or "page"
        uid    = int(parts[2])
        fourth = int(parts[3])
    except (IndexError, ValueError):
        await query.answer(); return
    if query.from_user.id != uid:
        await query.answer("Not your picker!", show_alert=True); return

    p = get_player(uid)
    if not p:
        await query.answer(); return

    if action == "page":
        markup = _build_target_picker_markup(uid, p.get("guild_id"), fourth, "skl")
        try:
            await query.edit_message_reply_markup(reply_markup=markup)
        except Exception:
            pass
        await query.answer()
        return

    # action == "pick" — show skill picker for this target
    target_uid = fourth
    if is_defeated(p):
        await query.answer("You're defeated!", show_alert=True); return
    if is_invincible(p):
        await query.answer("You're invincible!", show_alert=True); return

    tp = get_player(target_uid)
    if not tp:
        await query.answer("Target not found!", show_alert=True); return
    if is_defeated(tp):
        await query.answer(f"{tp.get('username','?')} is already defeated!", show_alert=True); return

    all_skills = sjl(p.get("all_skills"), [])
    if not all_skills:
        await query.answer("No skills unlocked!", show_alert=True); return

    # Exclude purely self/group utility types that can't target an enemy
    SELF_ONLY_TYPES = {"self_heal", "group_heal", "mass_cleanse", "party_def_buff",
                       "party_atk_buff", "party_full_buff", "ultimate_buff", "self_atk_buff"}
    pvp_skills = [sk for sk in all_skills
                  if sk.get("type", "damage") not in SELF_ONLY_TYPES
                  and p.get("level", 1) >= sk.get("unlock", 5)]
    if not pvp_skills:
        await query.answer("No skills available!", show_alert=True); return

    # Answer before editing to stop spinner
    await query.answer()
    markup = _build_skill_picker_keyboard(pvp_skills, uid, 0, target_uid)
    try:
        await _q_edit(query, 
            f"🔮 *Choose a skill to use on {tp.get('username','?')}:*",
            parse_mode="Markdown", reply_markup=markup)
    except Exception:
        pass


# ── PVP ANNOUNCEMENT HELPERS ──────────────────────────────────────────────────
_PVP_FIGHT_LINES = [
    "⚔️ *{a}* and *{d}* are throwing hands!",
    "🥊 *{a}* just challenged *{d}*, it's going down!",
    "🎱 *{a}* squared up on *{d}*. Let's see how this plays out.",
    "💥 *{a}* vs *{d}*, someone's getting dropped.",
    "⚔️ *{a}* picked a fight with *{d}*. Bold move.",
]

def _pvp_fight_start_line(a_name: str, d_name: str) -> str:
    return random.choice(_PVP_FIGHT_LINES).format(a=a_name, d=d_name)

def _resolve_pvp_group_chat(uid: int, fallback: int) -> int:
    """Best-effort group chat ID for PvP announcements, even when called from DM."""
    s = get_shadow(uid)
    grp = (s.get("home_group") if s else None) or _megaphone_state.get("group")
    if not grp:
        try:
            _c = _db().cursor()
            _c.execute("SELECT home_group FROM shadow_profiles WHERE home_group IS NOT NULL ORDER BY last_seen DESC LIMIT 1")
            row = _c.fetchone()
            if row: grp = row[0]
        except Exception:
            pass
    return grp or fallback

# ── ATTACK ────────────────────────────────────────────────────────────────────
async def pvp_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """PvP hub: rating, record, streak, king, revenge, bounties, cooldowns."""
    user = update.effective_user
    p = get_player(user.id)
    if not p:
        await send_group(update, "Use /ascend first!", delay=9); return
    rating = _pvp_rating(p)
    peak = max(safe_int(p.get("pvp_peak_rating"), rating), rating)
    wins = safe_int(p.get("wins")); losses = safe_int(p.get("losses"))
    total = wins + losses
    wr = round(wins / total * 100) if total else 0
    ks = safe_int(p.get("kill_streak")); mks = safe_int(p.get("max_kill_streak"))
    lines = [
        f"⚔️ *{p['username']}'s PvP Hub*",
        f"{_pvp_rank_name(rating)}  ·  *{rating}* rating  _(peak {peak})_",
        f"📊 Record: *{wins}W* / *{losses}L*  ({wr}% win rate)",
        f"🔥 Streak: *{ks}*  (best {mks})",
    ]
    if _is_king(p):
        _k = _get_king()
        lines.append("👑 *You hold the King of the Table crown!* (+5% damage)")
    else:
        _k = _get_king()
        if _k:
            lines.append(f"👑 King: *{_k['name']}* — dethrone them for the crown")
    # revenge
    rt = safe_int(p.get("revenge_target"))
    if rt and _ts_active(p, "revenge_expires"):
        rtp = get_player(rt)
        if rtp:
            lines.append(f"🗡️ *Revenge available* vs *{rtp['username']}* — bonus EXP if you strike back")
    # wanted
    if safe_int(p.get("is_wanted")):
        lines.append("🔴 *You are WANTED* — bonus bounty for whoever takes you down")
    # bounties
    try:
        c = _db().cursor()
        now = datetime.now().isoformat()
        on_me = c.execute("SELECT COUNT(*), COALESCE(SUM(reward),0) FROM bounties "
                          "WHERE target_id=? AND claimed_by IS NULL AND expires_at > ?",
                          (user.id, now)).fetchone()
        by_me = c.execute("SELECT COUNT(*) FROM bounties WHERE placer_id=? "
                          "AND claimed_by IS NULL AND expires_at > ?", (user.id, now)).fetchone()
        if on_me and on_me[0]:
            lines.append(f"🎯 *{on_me[0]} bounty(ies) on your head* — total {fmt_num(on_me[1])}g")
        if by_me and by_me[0]:
            lines.append(f"📌 You've placed *{by_me[0]}* active bounty(ies)")
    except Exception:
        pass
    # status / cooldown
    if is_defeated(p):
        lines.append(f"💀 *Defeated* — back in {time_until(p.get('defeated_until')) or 'soon'}")
    elif is_invincible(p):
        lines.append(f"🛡️ *Recovering* (invincible) — {time_until(p.get('invincible_until')) or 'soon'}")
    else:
        lines.append("✅ *Ready to fight!*")
    lines.append("")
    lines.append("_/attack · /royale · /quickdraw · /russian · /standoff · /pvptop_")
    markup = InlineKeyboardMarkup([[
        InlineKeyboardButton("⚔️ Find a target", callback_data=f"pvphub_attack_{user.id}"),
        InlineKeyboardButton("🏆 Leaderboard", callback_data="pvphub_top"),
    ]])
    await send_group(update, "\n".join(lines), permanent=True, reply_markup=markup)

async def pvptop_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Top 10 players by PvP rating."""
    p = get_player(update.effective_user.id)
    try:
        c = _db().cursor()
        rows = c.execute("SELECT username, pvp_rating, wins, losses FROM players "
                         "WHERE pvp_rating IS NOT NULL ORDER BY pvp_rating DESC LIMIT 10").fetchall()
    except Exception:
        rows = []
    if not rows:
        await send_group(update, "🏆 No rated fighters yet — win a PvP fight to get on the board!", delay=12); return
    lines = ["🏆 *PvP LEADERBOARD*  _(by rating)_", ""]
    medals = ["🥇", "🥈", "🥉"] + ["▫️"] * 7
    for i, r in enumerate(rows):
        rt = safe_int(r["pvp_rating"], 1000)
        lines.append(f"{medals[i]} *{r['username']}* — {rt} {_pvp_rank_name(rt)}  "
                     f"_({safe_int(r['wins'])}W/{safe_int(r['losses'])}L)_")
    champ = _ws_get("pvp_champion")
    if champ:
        lines.append("")
        lines.append(f"👑 *Reigning Weekly Champion:* {champ.get('name','?')} ({champ.get('rating','?')})")
    await send_group(update, "\n".join(lines), permanent=True, delay=60)

async def pvphub_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    data = query.data
    if data == "pvphub_top":
        p = get_player(query.from_user.id)
        try:
            c = _db().cursor()
            rows = c.execute("SELECT username, pvp_rating, wins, losses FROM players "
                             "WHERE pvp_rating IS NOT NULL ORDER BY pvp_rating DESC LIMIT 10").fetchall()
        except Exception:
            rows = []
        lines = ["🏆 *PvP LEADERBOARD*", ""]
        medals = ["🥇", "🥈", "🥉"] + ["▫️"] * 7
        for i, r in enumerate(rows):
            rt = safe_int(r["pvp_rating"], 1000)
            lines.append(f"{medals[i]} *{r['username']}* — {rt} {_pvp_rank_name(rt)}")
        await _q_edit(query, "\n".join(lines) if rows else "No rated fighters yet!",
                      parse_mode="Markdown")
        await query.answer(); return
    if data.startswith("pvphub_attack_"):
        uid = int(data.split("_")[2])
        if query.from_user.id != uid:
            await query.answer("Not your hub!", show_alert=True); return
        a = get_player(uid)
        players, total = _get_attackable_players(uid, a.get("guild_id") if a else None)
        if not players:
            await query.answer("No targets available right now — try /royale!", show_alert=True); return
        markup = _build_target_picker_markup(uid, a.get("guild_id") if a else None, 0, "atk")
        await _q_edit(query, f"⚔️ *Choose a target* ({total} available)",
                      parse_mode="Markdown", reply_markup=markup)
        await query.answer(); return

async def attack_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    au = update.effective_user
    a  = get_player(au.id)
    if not a:
        await send_group(update, "Use /ascend first!", delay=9); return
    if is_defeated(a):
        await send_group(update, _defeated_msg(a), delay=15); return

    chat_id = update.effective_chat.id

    # PvP: invincibility blocks attacking
    if is_invincible(a):
        await send_group(update, "🛡️ You're *Still Recovering*  -  you can't attack while invincible.", delay=9); return
    if is_vanished(a):
        await send_group(update, "👻 You're vanished  -  you can't attack while hidden.", delay=9); return
    _cc = _consume_cc(a)
    if _cc:
        await send_group(update, _cc, delay=9); return
    chat = chat_id
    du_id = None; du_name = None

    if update.message and update.message.reply_to_message:
        _du = update.message.reply_to_message.from_user
        du_id = _du.id; du_name = _du.first_name
    elif context.args:
        # Check for text_mention entity first \u2014 this fires for users without @handles.
        # A text_mention entity has entity.user.id even when the user has no @username.
        found = None
        if update.message and update.message.entities:
            for ent in update.message.entities:
                if ent.type == "text_mention" and ent.user:
                    found = get_player(ent.user.id)
                    if not found:
                        await send_group(update,
                            f"\u274c *{ent.user.first_name}* hasn't ascended yet!", delay=9); return
                    du_id = ent.user.id; du_name = ent.user.first_name
                    break
        if not found:
            # Join all args so multi-word display names like "John Smith" work
            name_arg = " ".join(context.args).strip()
            found = get_player_by_username(name_arg)
            if not found:
                await send_group(update,
                    "\u274c No player found. Reply to their message, or use their @handle or display name.", delay=9); return
            du_id = found["user_id"]; du_name = found["username"]
    else:
        # No target specified — show inline target picker
        players, total = _get_attackable_players(au.id, a.get("guild_id"))
        if not players:
            _ex = _last_pool_exclusions.get(au.id, {})
            _ex_bits = []
            if _ex.get("offline"):    _ex_bits.append(f"{_ex['offline']} away >8h")
            if _ex.get("recovering"): _ex_bits.append(f"{_ex['recovering']} recovering")
            if _ex.get("protected"):  _ex_bits.append(f"{_ex['protected']} newbie-protected")
            if _ex.get("busy"):       _ex_bits.append(f"{_ex['busy']} in a dungeon")
            if _ex.get("guild"):      _ex_bits.append(f"{_ex['guild']} guildmates")
            _ex_note = ("\n_Hidden: " + ", ".join(_ex_bits) + "._") if _ex_bits else ""
            await send_group(update,
                "⚔️ No players available to attack right now." + _ex_note +
                "\n_Try /royale, /quickdraw or an /encounter instead!_", delay=15); return
        markup = _build_target_picker_markup(au.id, a.get("guild_id"), 0, "atk")
        await send_group(update,
            f"⚔️ *Choose a target* ({total} available)",
            permanent=True, reply_markup=markup)
        return

    if du_id == au.id:
        await send_group(update, "You can't attack yourself.", delay=9); return
    d = get_player(du_id)
    if not d:
        await send_group(update, f"{du_name} hasn't ascended yet!", delay=9); return
    if is_defeated(d):
        await send_group(update, f"\U0001f480 {d['username']} is already defeated!", delay=9); return
    _auto_recover(d)  # timer expired at 0 HP \u2014 stand them up instead of a free one-hit kill
    if is_invincible(d):
        await send_group(update, f"\U0001f6e1\ufe0f {d['username']} is *Still Recovering*  -  invincible for now.", delay=9); return
    _atk_ok, _atk_why = _pvp_attack_allowed(a, d)
    if not _atk_ok:
        await send_group(update, _atk_why, delay=9); return
    raid_d, kind_d = in_active_raid(du_id, chat)
    if raid_d:
        await send_group(update, f"\u2694\ufe0f *{d['username']}* is in a raid right now  -  can't be targeted!", delay=9); return
    t_boss, _ = in_active_boss(du_id, chat_id)
    if t_boss:
        await send_group(update, f"\u2694\ufe0f *{d['username']}* is in a boss fight  -  can't be targeted!", delay=9); return
    if a.get("guild_id") and str(a.get("guild_id")) == str(d.get("guild_id")):
        g = get_guild(a["guild_id"])
        gname = g["name"] if g else "your Guild"
        await send_group(update,
            f"\U0001f3f0 *{d['username']}* is in *{gname}* \u2014 you can't attack your own guild members!",
            delay=9); return
    s_tgt = get_shadow(du_id)
    target_last_seen = s_tgt.get("last_seen") if s_tgt else None
    if target_last_seen:
        try:
            away_secs = (datetime.now() - datetime.fromisoformat(target_last_seen)).total_seconds()
            if away_secs > _PVP_ACTIVE_WINDOW:
                away_str = f"{int(away_secs // 60)} min" if away_secs < 7200 else f"{int(away_secs // 3600)}h"
                await send_group(update, f"\U0001f4a4 *{d['username']}* stepped away *(last seen {away_str} ago)*  -  can't attack offline players.", delay=9)
                try:
                    await context.bot.send_message(chat_id=du_id,
                        text=f"\U0001f3b1 *{a['username']}* tried to attack you while you were away!\nHead back to the table.",
                        parse_mode="Markdown")
                except Exception: pass
                return
        except Exception: pass

    try: await update.message.delete()
    except: pass

    bot  = update.get_bot()
    pair = _pvp_pair_key(au.id, du_id)
    _is_new_battle = pair not in _pvp_origin_chat
    _grp_chat = _resolve_pvp_group_chat(au.id, chat_id)
    _pvp_cards.setdefault(pair, {})
    _pvp_origin_chat[pair] = _grp_chat
    # Alert the defender — clear old card so Telegram sends a fresh push notification
    _pvp_dm_last_msg.pop(du_id, None)
    _pvp_log_msg.pop(du_id, None)
    try:
        await bot.send_message(chat_id=du_id,
            text=f"⚔️ *{a['username']}* is attacking you!", parse_mode="Markdown")
    except Exception:
        pass
    if _is_new_battle:
        asyncio.create_task(announce(bot, _grp_chat, _pvp_fight_start_line(a["username"], d["username"]), permanent=True))
    start_txt = "⚔️ *" + a["username"] + "* vs *" + d["username"] + "* — fight started!"
    _pvp_log_append(pair, start_txt)
    fresh_a = get_player(au.id) or a
    fresh_d = get_player(du_id) or d
    await _pvp_notify_both(pair, fresh_a, fresh_d, au.id, du_id, start_txt, bot)


# ── PVP CARD CALLBACK ─────────────────────────────────────────────────────────
async def pvp_card_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle Attack / Defend / Heal / Finisher buttons on PvP DM battle cards.
    NOTE: a callback query can only be answered ONCE — answering generically up
    front used to kill every alert below (ownership, fight-over, status popup),
    so the answer now happens per-branch with a flavored toast."""
    query = update.callback_query
    data = query.data
    parts = data.split("_")
    try:
        action_type = parts[1]
        uid         = int(parts[2])
        target_id   = int(parts[3])
    except (IndexError, ValueError):
        await query.answer()
        return

    if query.from_user.id != uid:
        await query.answer("These aren't your buttons!", show_alert=True); return

    pair = _pvp_pair_key(uid, target_id)

    if pair not in _pvp_cards:
        await query.answer("This fight has already ended.", show_alert=True)
        return

    _tok = _cb_lock(uid)
    if not _tok:
        await query.answer("⏳ Still processing — one tap at a time!")
        return

    try:
        a = get_player(uid)
        d = get_player(target_id)
        if not a or not d:
            await query.answer()
            return

        # ── OPTIONS ───────────────────────────────────────────────────────────
        if action_type == "opts":
            inv = sjl(a.get("inventory"), [])
            shield_hp = safe_int(a.get("shield_hp"))
            shield_max = _shield_max(a)
            potions = [i for i in inv if "Potion" in i or "Flask" in i]
            msg = "*⚙️ Your status:*\n"
            msg += f"❤️ HP: {a['hp']}/{a['max_hp']}\n"
            if safe_int(a.get("shield_used")):
                msg += f"🛡️ Shield: {shield_hp}/{shield_max} HP\n"
            if potions:
                msg += "🧪 Potions: " + ", ".join(potions) + "\n"
            msg += f"📊 Level {a.get('level',1)} {a.get('class','?')}"
            await query.answer(msg[:200], show_alert=True)
            return

        # ── HEAL ──────────────────────────────────────────────────────────────
        if action_type == "heal":
            if is_healing_blocked(a):
                if safe_int(a.get("heal_blocked_turns")) > 0:
                    a["heal_blocked_turns"] -= 1; save_player(a)
                await query.answer("🚫 Healing blocked!", show_alert=True); return
            try: await query.answer("🧪 Drinking...")
            except Exception: pass
            inv = sjl(a.get("inventory"), [])
            potion = None; heal_amount = 0
            for pname, pamt in [("Ultimate Vitality Draught", 15000),
                                 ("Supreme Restorative Flask", 5000),
                                 ("Grand Restorative Flask", 1500),
                                 ("Greater Health Potion", 500),
                                 ("Health Potion", 250)]:
                if pname in inv:
                    potion = pname; heal_amount = pamt; break
            if not potion:
                no_pot_entry = f"🧪 *{a['username']}* reaches for a potion — *none left!*"
                _pvp_log_append(pair, no_pot_entry)
                fresh_a = get_player(uid) or a
                fresh_d = get_player(target_id) or d
                _cb_unlock(uid, _tok)
                await _pvp_notify_both(pair, fresh_a, fresh_d, uid, target_id, no_pot_entry, context.bot)
                return
            inv.remove(potion); a["inventory"] = json.dumps(inv)
            old_hp = a["hp"]
            a["hp"] = min(a["max_hp"], a["hp"] + heal_amount)
            actual = a["hp"] - old_hp
            save_player(a)
            heal_entry = f"🧪 *{a['username']}* uses *{potion}* — *+{actual} HP* ❤️ {a['hp']}/{a['max_hp']}"
            _pvp_log_append(pair, heal_entry)
            fresh_a = get_player(uid) or a
            fresh_d = get_player(target_id) or d
            _cb_unlock(uid, _tok)
            await _pvp_notify_both(pair, fresh_a, fresh_d, uid, target_id, heal_entry, context.bot)
            return

        # ── MP POTION ─────────────────────────────────────────────────────────
        if action_type == "mp":
            try: await query.answer("💙 Drinking...")
            except Exception: pass
            inv = sjl(a.get("inventory"), [])
            _mp_item = None; _mp_gain = 0
            _pvp_mmax = safe_int(a.get("max_mp")) or calc_max_mp(a)
            for iname in ("MP Tonic", "Minor MP Tonic", "Major MP Elixir", "Grand Mana Crystal"):
                if iname in inv:
                    _mp_item = iname
                    _pctk = "MP Tonic" if iname == "Minor MP Tonic" else iname
                    _mp_gain = max(1, round(_pvp_mmax * _MP_POTION_PCT.get(_pctk, 0.35)))
                    break
            if not _mp_item:
                no_mp_entry = f"💙 *{a['username']}* reaches for a mana potion — *none left!*"
                _pvp_log_append(pair, no_mp_entry)
                fresh_a = get_player(uid) or a
                fresh_d = get_player(target_id) or d
                _cb_unlock(uid, _tok)
                await _pvp_notify_both(pair, fresh_a, fresh_d, uid, target_id, no_mp_entry, context.bot)
                return
            inv.remove(_mp_item); a["inventory"] = json.dumps(inv)
            _max_mp = safe_int(a.get("max_mp")) or calc_max_mp(a)
            _old_mp = safe_int(a.get("mp", 0))
            if _mp_gain < 0:  # Grand Mana Crystal — full restore
                a["mp"] = _max_mp
            else:
                a["mp"] = min(_max_mp, _old_mp + _mp_gain)
            _actual = a["mp"] - _old_mp
            save_player(a)
            mp_entry = f"💙 *{a['username']}* uses *{_mp_item}* — *+{_actual} MP* 💙 {a['mp']}/{_max_mp}"
            _pvp_log_append(pair, mp_entry)
            fresh_a = get_player(uid) or a
            fresh_d = get_player(target_id) or d
            _cb_unlock(uid, _tok)
            await _pvp_notify_both(pair, fresh_a, fresh_d, uid, target_id, mp_entry, context.bot)
            return

        # ── DEFEND ────────────────────────────────────────────────────────────
        if action_type == "def":
            if safe_int(a.get("shield_used")) == 1:
                cur_sh = safe_int(a.get("shield_hp"))
                if cur_sh > 0:
                    await query.answer(f"🛡️ {cur_sh}/{_shield_max(a)} HP remaining.", show_alert=True)
                else:
                    await query.answer("🛡️ Shield depleted — revive to restore.", show_alert=True)
                return
            if is_defeated(a):
                await query.answer("You're defeated!", show_alert=True); return
            try: await query.answer("🛡️ Defending...")
            except Exception: pass
            max_sh = _shield_max(a)
            a["shield_hp"] = max_sh; a["shield_used"] = 1
            save_player(a)
            shield_entry = f"🛡️ *{a['username']}* raises their shield — *{max_sh} HP*"
            _pvp_log_append(pair, shield_entry)
            fresh_a = get_player(uid) or a
            fresh_d = get_player(target_id) or d
            _cb_unlock(uid, _tok)
            await _pvp_notify_both(pair, fresh_a, fresh_d, uid, target_id, shield_entry, context.bot)
            return

        # ── FINISHER ──────────────────────────────────────────────────────────
        if action_type == "finish":
            line_a = get_class_line(a)
            kc = _KILL_CONDITIONS.get(line_a)
            if not kc or not _check_kill_condition(a, d):
                await query.answer("⚡ Kill condition not met!", show_alert=True); return
            if is_vanished(a):
                await query.answer("You're vanished — can't use finisher while hidden!", show_alert=True); return
            try: await query.answer("⚡ FINISHER!")
            except Exception: pass
            stat_val = get_stat(a, kc["stat"])
            dmg = round(stat_val * kc["mult"])
            if kc.get("drain_pct"):
                drain_amt = round(d["hp"] * kc["drain_pct"])
                a["hp"] = min(calc_max_hp(a), a["hp"] + drain_amt)
                dmg += drain_amt
            if kc.get("dot_burst") and safe_int(d.get("poison_stacks", 0)) > 0:
                n_p = safe_int(d["poison_stacks"])
                burst = round(d.get("max_hp", 100) * safe_int(d.get("poison_pct", 20)) / 100 * n_p)
                dmg += burst; d["poison_stacks"] = 0
            hp_pct_before = d["hp"] / max(1, d.get("max_hp", d["hp"]))
            is_instakill = hp_pct_before <= 0.50
            if is_instakill:
                d["hp"] = 0
            else:
                d["hp"] = max(0, d["hp"] - dmg)
            kill_msg = (f"⚡ *FINISHER!* *{a['username']}* → *{d['username']}*\n"
                        f"*{kc['name']}* — {kc['stat']}×{kc['mult']} = *{dmg} damage!*")
            if is_instakill and d["hp"] == 0:
                kill_msg += f"\n💀 *INSTAKILL!* {d['username']} was at {round(hp_pct_before*100)}% HP!"
            _pvp_log_append(pair, kill_msg)
            if d["hp"] <= 0:
                apply_pvp_death(d, a["username"], kc["name"], killer_id=uid)
                a["wins"] = a.get("wins", 0) + 1
                a["kill_streak"] = safe_int(a.get("kill_streak")) + 1
                if a["kill_streak"] > safe_int(a.get("max_kill_streak")):
                    a["max_kill_streak"] = a["kill_streak"]
                _fin_today = datetime.now().strftime("%Y-%m-%d")
                if a.get("kills_today_date") != _fin_today:
                    a["kills_today"] = 0; a["kills_today_date"] = _fin_today
                a["kills_today"] = safe_int(a.get("kills_today")) + 1
                if a["kills_today"] >= 5: a["is_wanted"] = 1
                _fin_exp = _pvp_kill_exp(a, d)
                add_exp(a, _fin_exp, get_weather())
                for _fd, _fe, _fg in track_objective(a, "pvp_win"):
                    a["gold"] = a.get("gold", 0) + _fg; add_exp(a, _fe)
                _fin_cls_a = get_player_class(a)
                if _fin_cls_a and _fin_cls_a.get("passive_key") == "dead_or_alive":
                    d["defeated_until"] = (datetime.now() + timedelta(hours=1)).isoformat()
                a_guild = get_guild(a.get("guild_id")) if a.get("guild_id") else None
                d_guild = get_guild(d.get("guild_id")) if d.get("guild_id") else None
                if a_guild and d_guild and a_guild["guild_id"] != d_guild["guild_id"]:
                    war_gw = get_active_war(a_guild["guild_id"], d_guild["guild_id"])
                    if war_gw:
                        _db_fw = _db(); _c_fw = _db_fw.cursor()
                        if str(war_gw["guild1_id"]) == str(a_guild["guild_id"]):
                            _c_fw.execute("UPDATE guild_wars SET kills1=kills1+1 WHERE war_id=?", (war_gw["war_id"],))
                        else:
                            _c_fw.execute("UPDATE guild_wars SET kills2=kills2+1 WHERE war_id=?", (war_gw["war_id"],))
                        _db_fw.commit()
                check_titles(a); check_titles(d)
                save_player(a); save_player(d)
                _fire(check_and_claim_bounty(context.bot, a, d, _pvp_origin_chat.get(pair, uid)))
                _fin_grp = _pvp_origin_chat.get(pair) or _megaphone_state.get("group") or uid
                _fin_a = get_player(uid) or a; _fin_d = get_player(target_id) or d
                _win_announce_text = (f"💀 *{_fin_a.get('username','?')}* defeated *{_fin_d.get('username','?')}*! "
                                      f"(Lv {_fin_a.get('level',1)} vs Lv {_fin_d.get('level',1)})")
                asyncio.create_task(announce(context.bot, _fin_grp, _win_announce_text, permanent=True))
                _cb_unlock(uid, _tok)
                await _finalize_pvp(pair, kill_msg, context.bot, winner_id=uid)
            else:
                save_player(a); save_player(d)
                fresh_a = get_player(uid) or a
                fresh_d = get_player(target_id) or d
                _cb_unlock(uid, _tok)
                await _pvp_notify_both(pair, fresh_a, fresh_d, uid, target_id, kill_msg, context.bot)
            return

        # ── ATTACK ────────────────────────────────────────────────────────────
        if action_type != "atk": return

        if is_defeated(a):
            await query.answer("You're defeated — can't attack!", show_alert=True); return
        if is_invincible(a):
            await query.answer("You're invincible — can't attack!", show_alert=True); return
        if is_vanished(a):
            await query.answer("You're vanished — can't attack while hidden!", show_alert=True); return
        _cc = _consume_cc(a)
        if _cc:
            await query.answer(_cc, show_alert=True); return
        if is_defeated(d):
            await query.answer(f"{d['username']} is already defeated!", show_alert=True); return
        if is_invincible(d):
            await query.answer(f"{d['username']} is invincible right now!", show_alert=True); return
        if a.get("guild_id") and str(a.get("guild_id")) == str(d.get("guild_id")):
            await query.answer("Can't attack your own guild member!", show_alert=True); return
        try: await query.answer("⚔️ Attacking...")
        except Exception: pass

        w = get_weather()
        chat_id = _pvp_origin_chat.get(pair) or query.message.chat_id
        # Initialize dungeon item battle state on first hit
        if uid not in _pvp_battle_state: _dng_pvp_init(uid, a)
        if target_id not in _pvp_battle_state: _dng_pvp_init(target_id, d)
        _kit_tick_cds(uid)  # a basic attack also advances kit cooldowns
        result_text, lvl_msgs, result_type = await _execute_pvp_hit(
            a, d, uid, target_id, w, chat_id, context.bot)

        _pvp_log_append(pair, result_text)

        if result_type == "defeat":
            _atk_grp = _pvp_origin_chat.get(pair) or _megaphone_state.get("group") or uid
            _win_a = get_player(uid) or a; _win_d = get_player(target_id) or d
            _atk_win_txt = (f"💀 *{_win_a.get('username','?')}* defeated *{_win_d.get('username','?')}*! "
                            f"(Lv {_win_a.get('level',1)} vs Lv {_win_d.get('level',1)})")
            asyncio.create_task(announce(context.bot, _atk_grp, _atk_win_txt, permanent=True))
            _cb_unlock(uid, _tok)
            await _finalize_pvp(pair, result_text, context.bot, winner_id=uid)
            return

        fresh_a = get_player(uid) or a
        fresh_d = get_player(target_id) or d
        _cb_unlock(uid, _tok)
        await _pvp_notify_both(pair, fresh_a, fresh_d, uid, target_id, result_text, context.bot)

    finally:
        _cb_unlock(uid, _tok)  # token-checked: can't release a newer tap's lock


async def kit_card_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """PvP fight-card kit skills: kitsk_{uid}_{slot}_{opp} (use) and
    kitnope_{uid}_{slot} (unavailable — explain why)."""
    query = update.callback_query
    data = query.data
    parts = data.split("_")
    if data.startswith("kitnope_"):
        try:
            uid = int(parts[1]); slot = parts[2]
        except (IndexError, ValueError):
            await query.answer(); return
        if query.from_user.id != uid:
            await query.answer("Not your card!", show_alert=True); return
        p = get_player(uid); kit = _kit_for(p) if p else None
        sk = kit.get(slot) if kit else None
        if not sk:
            await query.answer(); return
        cd = safe_int(_kit_cd_state(uid).get(slot))
        if is_silenced(p):
            await query.answer(f"🤐 Silenced — can't use {sk['name']}!", show_alert=True)
        elif cd > 0:
            await query.answer(f"⏳ {sk['name']} on cooldown ({cd} turn{'s' if cd!=1 else ''}).", show_alert=True)
        else:
            await query.answer(f"❌ Need {sk.get('mp',0)} MP for {sk['name']}.", show_alert=True)
        return
    # kitsk_
    try:
        uid = int(parts[1]); slot = parts[2]; target_id = int(parts[3])
    except (IndexError, ValueError):
        await query.answer(); return
    if query.from_user.id != uid:
        await query.answer("These aren't your buttons!", show_alert=True); return
    pair = _pvp_pair_key(uid, target_id)
    if pair not in _pvp_cards:
        await query.answer("This fight has already ended.", show_alert=True); return
    _tok = _cb_lock(uid)
    if not _tok:
        await query.answer("⏳ Still processing — one tap at a time!"); return
    try:
        a = get_player(uid); d = get_player(target_id)
        if not a or not d:
            await query.answer(); return
        kit = _kit_for(a)
        sk = kit.get(slot) if kit else None
        if not sk:
            await query.answer("You don't have that skill."); return
        if is_defeated(a) or is_invincible(a):
            await query.answer("You can't act right now!", show_alert=True); return
        if is_silenced(a):
            await query.answer(f"🤐 Silenced — can't use {sk['name']}!", show_alert=True); return
        if _kit_on_cd(uid, slot):
            await query.answer(f"⏳ {sk['name']} is on cooldown.", show_alert=True); return
        cost = sk.get("mp", 0)
        if safe_int(a.get("mp")) < cost:
            await query.answer(f"❌ Need {cost} MP.", show_alert=True); return
        _cc = _consume_cc(a)
        if _cc:
            await query.answer(_cc, show_alert=True); return
        # Pay MP, advance cooldowns, set this skill's cooldown
        a["mp"] = safe_int(a.get("mp")) - cost
        _kit_tick_cds(uid)
        _kit_set_cd(uid, slot, sk.get("cd", 0))
        if uid not in _pvp_battle_state: _dng_pvp_init(uid, a)
        if target_id not in _pvp_battle_state: _dng_pvp_init(target_id, d)

        if sk.get("kind") == "strike":
            try: await query.answer(f"{sk['emoji']} {sk['name']}!")
            except Exception: pass
            w = get_weather()
            chat_id = _pvp_origin_chat.get(pair) or query.message.chat_id
            save_player(a)  # persist MP/cd before the hit pipeline re-reads? hit uses a in-memory
            result_text, lvl_msgs, result_type = await _execute_pvp_hit(
                a, d, uid, target_id, w, chat_id, context.bot, kit_skill=sk)
            _pvp_log_append(pair, result_text)
            if result_type == "defeat":
                _grp = _pvp_origin_chat.get(pair) or _megaphone_state.get("group") or uid
                _wa = get_player(uid) or a; _wd = get_player(target_id) or d
                asyncio.create_task(announce(context.bot, _grp,
                    f"💀 *{_wa.get('username','?')}* defeated *{_wd.get('username','?')}*!", permanent=True))
                _cb_unlock(uid, _tok)
                await _finalize_pvp(pair, result_text, context.bot, winner_id=uid)
                return
            fresh_a = get_player(uid) or a; fresh_d = get_player(target_id) or d
            _cb_unlock(uid, _tok)
            await _pvp_notify_both(pair, fresh_a, fresh_d, uid, target_id, result_text, context.bot)
        else:
            # Support skill — apply effects, no attack
            try: await query.answer(f"{sk['emoji']} {sk['name']}!")
            except Exception: pass
            notes = _kit_apply_support(a, d, sk)
            save_player(a); save_player(d)
            entry = f"{sk['emoji']} *{a['username']}* uses *{sk['name']}!*" + (f"\n{notes}" if notes else "")
            _pvp_log_append(pair, entry)
            fresh_a = get_player(uid) or a; fresh_d = get_player(target_id) or d
            _cb_unlock(uid, _tok)
            await _pvp_notify_both(pair, fresh_a, fresh_d, uid, target_id, entry, context.bot)
    finally:
        _cb_unlock(uid, _tok)


# ── DEFEND (damage-absorbing shield) ─────────────────────────────────────────
_SHIELD_CORE_ADD  = 150   # capacity added per Monster Core consumed
_SHIELD_BASE_PCT  = 0.25  # base shield = 25% of max HP

def _shield_max(p):
    """Effective shield capacity = base (25% max HP) + accumulated core bonuses."""
    return max(100, int(calc_max_hp(p) * _SHIELD_BASE_PCT)) + safe_int(p.get("shield_core_bonus"))

async def defend_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user
    p    = get_player(user.id)
    if not p:
        await send_group(update, "Use /ascend first!", delay=9); return
    if is_defeated(p):
        await send_group(update, _defeated_msg(p), delay=15); return

    arg    = (context.args[0].lower() if context.args else "")
    max_sh = _shield_max(p)
    cur_sh = safe_int(p.get("shield_hp"))

    # ── /defend core — consume a Monster Core to raise the shield's max ─────
    if arg == "core":
        if safe_int(p.get("shield_used")) == 1:
            await send_group(update,
                "🛡️ Shield already active — cores must be added before activation.", delay=9)
            return
        inv  = sjl(p.get("inventory"), [])
        core = next((i for i in inv if i.startswith("Monster Core (") or i == "Rare Monster Core"), None)
        if not core:
            await send_group(update, "No Monster Cores in inventory.", delay=9); return
        inv.remove(core)
        p["inventory"] = json.dumps(inv)
        p["shield_core_bonus"] = safe_int(p.get("shield_core_bonus")) + _SHIELD_CORE_ADD
        new_max = _shield_max(p)
        save_player(p)
        await send_group(update,
            f"⚙️ Core absorbed — shield max raised to *{new_max} HP*.", delay=12)
        return

    # ── /defend — activate shield at full capacity (once per life) ──────────
    if safe_int(p.get("shield_used")) == 1:
        if cur_sh > 0:
            await send_group(update,
                f"🛡️ Shield active — *{cur_sh}/{max_sh} HP*", delay=9)
        else:
            await send_group(update,
                "🛡️ Shield depleted. Resets on revival.", delay=9)
        return

    p["shield_hp"]   = max_sh
    p["shield_used"] = 1
    save_player(p)
    await send_group(update,
        f"🛡️ Shield raised — *{p['shield_hp']} HP*. Absorbs damage before your HP.", delay=12)


# ── HEAL ──────────────────────────────────────────────────────────────────────
async def heal_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    hu = update.effective_user
    h  = get_player(hu.id)
    if not h:
        await send_group(update, "Use /ascend first!", delay=9); return
    if not (update.message and update.message.reply_to_message):
        # No reply — heal yourself
        tu = hu
        t  = h
    else:
        tu = update.message.reply_to_message.from_user
        if tu.id == hu.id:
            # Reply to own message — still a self-heal; keep same object
            t = h
        else:
            t = get_player(tu.id)
    if not t:
        await send_group(update, f"{tu.first_name} hasn't ascended yet!", delay=9); return

    # Check if target can be healed/revived
    target_is_dead = t["hp"] <= 0
    if target_is_dead and is_revival_blocked(t):
        await send_group(update,
            f"☠️ *{t['username']}* has been condemned by a Zealot  -  they cannot be revived for now.\n"
            f"Only a *Saint's Absolution* can lift this.", delay=15); return
    if is_healing_blocked(t) and not target_is_dead:
        if safe_int(t.get("heal_blocked_turns")) > 0:
            t["heal_blocked_turns"] -= 1
            save_player(t)
        await send_group(update,
            f"🚫 *{t['username']}* cannot be healed right now (Void Collapse active).", delay=9); return

    # Block non-priest potions on defeated targets
    if is_defeated(t) and get_class_line(h) != "priest":
        await send_group(update,
            f"❌ *{t['username']}* is defeated  -  vials can't revive them!\n"
            f"Use a *Scroll of Revival* from your inventory, or ask a Priest.", delay=9)
        return

    is_priest_healer = get_class_line(h) == "priest"

    inv = sjl(h.get("inventory"), [])
    potion = None
    heal_amount = 0

    if is_priest_healer:
        # Priest line  -  free revive via skill (Holy Light)
        heal_amount = safe_stats(h).get("WIS",5) * 50
        if get_player_class(h) and get_player_class(h).get("passive_key") == "mending_aura":
            heal_amount = round(heal_amount * 1.25)
    else:
        # Non-priest — requires potion; heals a % of the TARGET's max HP
        for _hn in ("Ultimate Vitality Draught", "Supreme Restorative Flask",
                    "Grand Restorative Flask", "Greater Health Potion", "Health Potion"):
            if _hn in inv:
                potion = _hn
                heal_amount = max(1, round(calc_max_hp(t) * _HP_POTION_PCT[_hn]))
                break
        if not potion:
            await send_group(update,
                "❌ You need a Health Potion to heal someone!\n"
                "Chalkers can heal for free with /skill.", delay=9); return
        inv.remove(potion)
        h["inventory"] = json.dumps(inv)

    # WIS bonus
    heal_amount += safe_stats(h).get("WIS",5)

    # Accessory heal bonus
    if get_accessory_bonus(h, "heal_bonus"):
        heal_amount = round(heal_amount * (1 + get_accessory_bonus(h, "heal_bonus")))

    # Apply — use calc_max_hp to handle stale max_hp values
    real_max_t = calc_max_hp(t)
    t["max_hp"] = real_max_t
    _pre_heal_hp = t["hp"]
    was_defeated = target_is_dead
    # WIS secondary on target: spiritual attunement boosts heals received (1% per WIS, cap 25%)
    _t_wis_amp = min(0.25, get_stat(t, "WIS") * 0.01)
    if _t_wis_amp > 0:
        heal_amount = round(heal_amount * (1 + _t_wis_amp))
    t["hp"] = min(real_max_t, t["hp"] + heal_amount)
    if was_defeated:
        t["defeated_until"]  = None
        t["invincible_until"] = (datetime.now() + timedelta(minutes=5)).isoformat()
        t["hp"] = round(real_max_t * 0.70)
        t["shield_used"] = 0; t["shield_hp"] = 0; t["shield_core_bonus"] = 0
        # Restore MP on revive for all classes
        t["mp"] = safe_int(t.get("max_mp")) or calc_max_mp(t)

    h["heals_given"] = h.get("heals_given",0) + 1
    _heal_was_useful = t["hp"] > _pre_heal_hp  # only XP if HP actually increased
    if tu.id != hu.id and _heal_was_useful:
        for _d, _e, _g in track_objective(h, "heal_ally"):
            h["gold"] = h.get("gold",0) + _g; add_exp(h, _e)
    new_t = check_titles(h)
    if _heal_was_useful:
        _heal_pct = 0.01 if (tu.id != hu.id and h.get("guild_id") and str(h.get("guild_id")) == str(t.get("guild_id"))) else 0.004
        _heal_exp = exp_share(h["level"], _heal_pct)
        lmsgs, leveled = add_exp(h, _heal_exp)
    else:
        lmsgs, leveled = [], False
    save_player(h)
    if tu.id != hu.id:
        save_player(t)

    is_self = (tu.id == hu.id)
    if is_priest_healer:
        cls_name_h = get_player_class(h)["name"] if get_player_class(h) else "Priest"
        if is_self and was_defeated:
            msg = (
                f"🙏 *{h['username']}* ({cls_name_h}) channels divine energy and *revives themselves*!\n"
                f"❤️ HP restored: *{heal_amount}* → {t['hp']}/{t['max_hp']}\n"
                f"✨ *5 min invincibility* granted  -  _(Still Recovering)_"
            )
        elif is_self:
            msg = (
                f"🙏 *{h['username']}* ({cls_name_h}) heals themselves for *{heal_amount} HP*!\n"
                f"❤️ HP: {t['hp']}/{t['max_hp']}"
            )
        else:
            msg = (
                f"🙏 *{h['username']}* ({cls_name_h}) heals *{t['username']}* for *{heal_amount} HP*!\n"
                f"❤️ {t['username']}: {t['hp']}/{t['max_hp']} HP"
            )
            if was_defeated:
                msg += f"\n✨ *{t['username']}* is revived! *5 min invincibility* granted  -  _(Still Recovering)_"
            # Divine Shard: priest_aoe — also heal 1 nearby guild member
            if get_accessory_bonus(h, "priest_aoe"):
                _aoe_heal = max(1, heal_amount // 2)
                _aoe_healed = []
                _gid = h.get("guild_id")
                if _gid:
                    _g = get_guild(_gid)
                    _gmembers = [m for m in sjl(_g.get("members"), []) if m != hu.id and m != tu.id] if _g else []
                    random.shuffle(_gmembers)
                    for _mid in _gmembers[:2]:
                        _mp = get_player(_mid)
                        if _mp and not is_defeated(_mp):
                            _mp["hp"] = min(calc_max_hp(_mp), _mp["hp"] + _aoe_heal)
                            save_player(_mp)
                            _aoe_healed.append(_mp["username"])
                if _aoe_healed:
                    msg += f"\n✨ *Divine Shard* radiates — also heals {', '.join(_aoe_healed)} for *{_aoe_heal} HP*!"
    else:
        msg = (
            f"💊 *{h['username']}* uses *{potion}* to heal *{t['username']}* for *{heal_amount} HP*!\n"
            f"❤️ {t['username']}: {t['hp']}/{t['max_hp']} HP"
        )
        if was_defeated:
            msg += f"\n✨ *{t['username']}* is revived! *5 min invincibility* granted  -  _(Still Recovering)_"
    if new_t:
        msg += f"\n🏅 *{h['username']}* earned: *{new_t[0]}*!"
    if leveled and h["level"] % 10 == 0:
        asyncio.create_task(announce(context.bot, update.effective_chat.id,
            f"🎉 *{h['username']}* reached *Level {h['level']}*! 💊", delay=30))
    await send_group(update, msg, delay=30)

# ── STATS ─────────────────────────────────────────────────────────────────────
def _exp_bar(current, needed, length=10):
    pct    = min(1.0, current / max(1, needed))
    filled = round(pct * length)
    bar    = "█" * filled + "░" * (length - filled)
    return f"✨ [{bar}] {fmt_num(current)}/{fmt_num(needed)} EXP ({int(pct*100)}%)"

def get_fame_tier(n):
    tiers = [
        (-999999,-300,"🩸 Reviled"),(-299,-150,"💀 Notorious"),(-149,-75,"🌑 Distrusted"),
        (-74,-25,"👁️ Suspicious"),(-24,-1,"🌫️ Shady"),(0,0,"🌑 Shadow"),
        (1,24,"👤 Whisper"),(25,74,"🗣️ Face"),(75,149,"🌟 Voice"),
        (150,299,"📖 Known"),(300,499,"🔥 Talked About"),(500,799,"⭐ Notable"),
        (800,1199,"🌠 Prominent"),(1200,1799,"✨ Famous"),(1800,2499,"🌟 Celebrated"),
        (2500,3499,"💫 Renowned"),(3500,4999,"🔮 Revered"),(5000,7499,"👑 Exalted"),
        (7500,9999,"🌌 Mythic"),(10000,999999,"🎱 Oracle"),
    ]
    for lo, hi, name in tiers:
        if lo <= n <= hi: return name
    return "👤 Whisper"

def _add_influence(p, amount):
    # influence can be NULL in the DB — a bare .get() returned None and made
    # this crash, silently killing oracle-quest completion and the greeting
    # influence bonus for every affected player
    p["influence"] = safe_int(p.get("influence")) + amount

def _build_stats_pages(p, viewing_name=None):
    real_max     = calc_max_hp(p)
    defeated_str = " *(Defeated)*" if is_defeated(p) else ""
    recovering   = " *(Invincible)*" if is_invincible(p) else ""
    cls          = get_player_class(p)
    cls_name     = cls["name"] if cls else ("Choose at Lv 5  -  /class" if p["level"] >= 5 else "Unlocks at Lv 5")
    path_str     = f"  -  Path {p.get('class_path','?')}" if p.get("class_path") else ""
    eff          = {st: get_stat(p, st) for st in ["STR","DEF","AGI","INT","WIS","DEX","LUK"]}
    sp           = safe_int(p.get("stat_points"))
    tier         = get_tier(p["level"])
    w            = get_weather()
    statuses     = get_active_statuses(p)
    cp           = safe_int(calc_combat_power(p)) if callable(globals().get("calc_combat_power")) else 0
    name         = viewing_name or p["username"]

    guild_str = "None"
    if p.get("guild_id") and str(p.get("guild_id")) != "None":
        g = get_guild(p["guild_id"])
        if g:
            glvl = safe_int(g.get("level"), 1)
            perk = GUILD_PERKS.get(glvl, {})
            guild_str = g['name']

    _p_party = _get_party_of(p["user_id"])
    party_str = _party_display_name(_p_party).replace("*", "") if _p_party else "None"
    if _p_party:
        pmembers = _get_party_members(_p_party["id"])
        party_str += f" ({len(pmembers)} members)"

    exp_cur  = safe_int(p.get("exp"))
    exp_need = exp_for_level(p["level"])
    exp_pct  = int(exp_cur / max(1, exp_need) * 100)
    _exp_filled = round(exp_pct / 10)
    _exp_bar_str = "█" * _exp_filled + "░" * (10 - _exp_filled)

    weap_name = p.get("equipped_weapon") or "None"
    armr_name = p.get("equipped_armor") or "None"
    shld_name = p.get("equipped_shield") or "None"
    acc_names = [p.get(s) or "None" for s in ("equipped_accessory","equipped_accessory_2","equipped_accessory_3","equipped_accessory_4")]

    def quick_gear(n):
        if n == "None": return "None"
        enh  = get_enhancement(p, n)
        encs = get_enchant(p, n)
        return f"{n}{f' +{enh}' if enh else ''}{f' ✨×{len(encs)}' if encs else ''}"

    inv = Counter(sjl(p.get("inventory"), []))
    inv_lines = [
        f"{RARITY_EMOJI.get(WEAPONS.get(k,ARMORS.get(k,ACCESSORIES.get(k,CONSUMABLES.get(k,{})))).get('rarity',''),'⚪')} {k} x{v}"
        for k, v in inv.items()
    ] or ["Empty"]

    title_list = safe_titles(p)
    shadow = get_shadow(p["user_id"])
    msg_count = safe_int(shadow.get("message_count")) if shadow else 0

    # Page 1 - Profile
    defeated_cause   = p.get("last_defeated_by")
    defeat_countdown = time_until(p.get("defeated_until"))
    recover_countdown = time_until(p.get("invincible_until"))

    married_str = ""
    _stats_marriages = sjl(p.get("marriages"), [])
    if not _stats_marriages and p.get("married_to_id"):
        _stats_marriages = [{"id": p["married_to_id"], "name": p["married_to_name"]}]
    if _stats_marriages:
        spouse_names = ", ".join(f"*{m['name']}*" for m in _stats_marriages)
        married_str = f"💍 {spouse_names}"

    _active_pet = get_active_pet_record(p["user_id"])
    pet_lines = []
    if _active_pet:
        _sp           = PET_SPECIES.get(_active_pet.get("species"), {})
        _nick         = _active_pet.get("nickname")
        _species_name = _sp.get("name", "Pet")
        _display_name = _nick if _nick else _species_name
        _phun         = _active_pet.get("hunger", 100)
        _pmood        = _active_pet.get("mood", 100)
        _pemoji       = _sp.get("emoji", "🐾")
        _hun_icon     = "🍗" if _phun >= 60 else ("😐" if _phun >= 30 else "😫")
        _mood_icon    = "😊" if _pmood >= 60 else ("😐" if _pmood >= 30 else "😢")
        pet_lines = [
            f"{_pemoji} *{_display_name}* | Lv {_active_pet.get('level', 1)}",
            f"  {_hun_icon} Hunger: {_phun}",
            f"  {_mood_icon} Mood: {_pmood}",
        ]

    _sh_hp   = safe_int(p.get("shield_hp"))
    _sh_used = safe_int(p.get("shield_used"))
    _sh_max  = _shield_max(p)
    if _sh_hp > 0:
        shield_line = f"🛡️ Shield: {_sh_hp}/{_sh_max}"
    elif _sh_used == 0:
        shield_line = f"🛡️ Shield: Ready ({_sh_max} HP)"
    else:
        shield_line = "🛡️ Shield: Depleted"

    _ks     = safe_int(p.get("kill_streak"))
    _losses = safe_int(p.get("losses"))
    _fame   = get_fame_tier(safe_int(p.get("influence")))

    # ── Profile header ──
    page1_lines = [
        f"🎱 *{name}*",
        f"🌟 Level {p['level']} | {tier['name']}",
        f"🧙 {cls_name}",
        f"🏰 {guild_str}",
        f"⚔️ Party: {party_str}",
        f"🏅 {p.get('active_title') or '—'}",
        "",
        f"🌍 {w['name']}",
        f"{_fame}",
    ]
    if pet_lines:
        page1_lines += pet_lines
    if married_str:
        page1_lines += ["", married_str]

    # ── Combat / progression ──
    page1_lines += [
        "",
        f"❤️ HP: {p['hp']}/{real_max}",
        f"💙 MP: {safe_int(p.get('mp'))}/{calc_max_mp(p)}",
        shield_line,
        f"✨ EXP `[{_exp_bar_str}]`",
        "",
        f"💰 Gold: {p['gold']}",
        f"💬 Messages: {msg_count:,}",
        f"⚔️ {p['wins']}W / {_losses}L",
        f"📣 Influence: {safe_int(p.get('influence')):,}",
    ]
    if _ks >= 1:
        page1_lines.append(f"🔥 Streak: {_ks}" + (f"  (best {safe_int(p.get('max_kill_streak'))})" if _ks >= 3 else ""))
    if p.get("is_wanted"):
        page1_lines.append("🔴 *WANTED*")

    # ── Status ──
    if is_defeated(p):
        if defeated_cause:
            page1_lines.append(f"☠️ Defeated by: _{defeated_cause}_")
        if defeat_countdown:
            page1_lines.append(f"⏳ Back in: *{defeat_countdown}*")
    if is_invincible(p) and recover_countdown:
        page1_lines.append(f"🛡️ Recovering — *{recover_countdown}*")

    # Page 2 - Stats
    page2_lines = [
        f"⚔️ *{name}* — Stats",
        f"🧙 {cls_name}",
        "",
        f"❤️ Max HP: {real_max}",
        f"💙 Max MP: {calc_max_mp(p)}",
        f"STR: {eff['STR']}",
        f"AGI: {eff['AGI']}",
        f"INT: {eff['INT']}",
        f"WIS: {eff['WIS']}",
        f"DEX: {eff['DEX']}",
        f"LUK: {eff['LUK']}",
        f"DEF: {eff['DEF']}",
        f"🛡️ Armor DEF: {get_armor_def(p)}",
    ]
    if cp > 0:
        page2_lines += ["", f"⚡ Combat Power: {cp:,}"]
    if sp > 0:
        page2_lines.append(f"💡 {sp} stat pt{'s' if sp != 1 else ''} to spend — /allocate")
    if statuses:
        page2_lines += ["", "⚠️ *Active Effects*"] + [f"  {st}" for st in statuses]

    # Page 3 - Gear
    _, active_sets = get_active_set_bonuses(p)
    set_lines = [f"✨ *{sn}*" for sn in active_sets]
    page3_lines = [
        f"🎒 *{name}* — Gear",
        "",
        f"⚔️ {quick_gear(weap_name)}",
        f"🛡️ {quick_gear(armr_name)}",
        f"🔰 {quick_gear(shld_name)}",
        f"💍 {quick_gear(acc_names[0])}",
        f"💍 {quick_gear(acc_names[1])}",
        f"💍 {quick_gear(acc_names[2])}",
        f"💍 {quick_gear(acc_names[3])}",
        "",
    ]
    if set_lines:
        page3_lines += ["🌟 *Active Set Bonuses:*"] + set_lines + [""]
    page3_lines.append("_/gear for full details_")

    # Page 4 - Inventory
    page4_lines = [f"🎒 *{name}* — Inventory", ""] + inv_lines + ["", "_/inventory for paginated full view_"]

    # Page 5 - Titles
    page5_lines = [f"🏅 *{name}* — Titles", ""] + ([f"  {t}" for t in title_list] or ["  None"])

    return [
        "\n".join(page1_lines),
        "\n".join(page2_lines),
        "\n".join(page3_lines),
        "\n".join(page4_lines),
        "\n".join(page5_lines),
    ]


async def _send_stats_page(target, target_uid: int, page: int, edit: bool = False,
                           caller_name: str = None, back_rows=None):
    p = get_player(target_uid)
    if not p:
        text = "No RPG profile found."
        if edit:
            await target.edit_message_text(text, parse_mode="Markdown")
        else:
            await send_group(target, text, delay=9)
        return

    try:
        pages = _build_stats_pages(p, viewing_name=caller_name)
    except Exception as e:
        err = f"❌ Stats error: {e}"
        if edit:
            try: await target.edit_message_text(err)
            except Exception: pass
        else:
            await send_group(target, err, delay=20)
        return
    PAGE_LABELS = ["Profile", "Stats", "Gear", "Inventory", "Titles"]
    total = len(pages)
    page  = max(1, min(page, total))
    text  = pages[page - 1]
    row   = []
    if page > 1:
        label = PAGE_LABELS[page - 2] if page - 2 < len(PAGE_LABELS) else str(page - 1)
        row.append(InlineKeyboardButton(f"◀ {label}", callback_data=f"stats_p_{target_uid}_{page-1}"))
    if page < total:
        label = PAGE_LABELS[page] if page < len(PAGE_LABELS) else str(page + 1)
        row.append(InlineKeyboardButton(f"{label} ▶", callback_data=f"stats_p_{target_uid}_{page+1}"))
    close_row = [InlineKeyboardButton("❌ Close", callback_data="close_msg")]
    _rows = [row, close_row] if row else [close_row]
    if back_rows: _rows.extend(back_rows)
    markup = InlineKeyboardMarkup(_rows)
    if edit:
        await target.edit_message_text(text, parse_mode="Markdown", reply_markup=markup)
    else:
        chat_id = target.effective_chat.id
        bot = target.get_bot()
        key = (chat_id, target.effective_user.id)
        old_id = last_bot_message.get(key)
        import asyncio as _aio
        results = await _aio.gather(
            bot.send_message(chat_id=chat_id, text=text[:4096],
                             parse_mode="Markdown", reply_markup=markup),
            bot.delete_message(chat_id=chat_id, message_id=old_id) if old_id else _aio.sleep(0),
            target.message.delete(),
            return_exceptions=True,
        )
        new_msg = results[0]
        if isinstance(new_msg, Exception):
            try:
                new_msg = await bot.send_message(chat_id=chat_id, text=text[:4096],
                                                 parse_mode="Markdown", reply_markup=markup)
            except Exception:
                return
        last_bot_message[key] = new_msg.message_id


async def stats_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    await query.answer()
    parts = query.data.split("_")   # stats_p_<uid>_<page>
    target_uid = int(parts[2])
    page       = int(parts[3])
    await _send_stats_page(query, target_uid, page, edit=True)


async def stats_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user

    viewing_other = False
    if update.message and update.message.reply_to_message:
        target_uid = update.message.reply_to_message.from_user.id
        if target_uid != user.id:
            viewing_other = True
        else:
            target_uid = user.id
    else:
        target_uid = user.id

    p = get_player(target_uid)
    s = get_shadow(target_uid)
    if not p and not s:
        await send_group(update,
            "No profile yet  -  just start chatting to build your level!", delay=9); return
    if p and not viewing_other: p["username"] = user.first_name
    if p and not viewing_other and getattr(user, "username", None):
        p["tg_username"] = user.username
    if s and not viewing_other: s["username"] = user.first_name
    if not p:
        tier = get_tier(s["level"])
        await send_group(update,
            f"👤 *{s['username']}*  -  Shadow Profile\n\n"
            f"{tier['emoji']} Level *{s['level']}*\n"
            f"✨ EXP: {fmt_num(s['exp'])}/{fmt_num(exp_for_level(s['level']))}\n"
            f"🏆 Lifetime: *{fmt_num(safe_int(s.get('total_exp')))}* EXP\n"
            f"💬 Messages: {s.get('message_count',0):,}\n\n"
            f"_Send /ascend in a private chat to enter the RPG!_",
            permanent=False, delay=9); return

    if s and not viewing_other: sync_levels(p, s); save_player(p); save_shadow(s)

    if is_defeated(p) and p["hp"] > 0:
        p["defeated_until"] = None; save_player(p)

    if not viewing_other:
        _stripped = _unequip_class_gear(p)
        if _stripped:
            save_player(p)

    real_max = calc_max_hp(p)
    if real_max != p["max_hp"] and not viewing_other:
        hp_delta = real_max - p["max_hp"]
        p["max_hp"] = real_max
        if hp_delta > 0:
            p["hp"] = min(real_max, p["hp"] + hp_delta)
        elif p["hp"] > real_max:
            p["hp"] = real_max
        save_player(p)

    caller_name = user.first_name if not viewing_other else None
    if viewing_other:
        target_user = update.message.reply_to_message.from_user
        p["username"] = target_user.first_name

    await _send_stats_page(update, target_uid, page=1, caller_name=caller_name)

