async def shop_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user; p = get_player(user.id)
    if not p:
        await send_group(update, "Use /ascend first!", delay=9); return
    discount = _shop_discount(p)
    tab = "pot"
    if context.args:
        arg = context.args[0].lower()
        if arg in SHOP_TABS_ORDER:
            tab = arg
    text, markup = _build_shop_view(p, tab, user.id, discount)
    await send_group(update, text, delay=60, reply_markup=markup)

async def shoplegend_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user; p = get_player(user.id)
    if not p:
        await send_group(update, "Use /ascend first!", delay=9); return
    chat_id = update.effective_chat.id
    expiry  = legend_shop_expiry.get(chat_id)
    if not expiry or datetime.now() > expiry:
        await send_group(update,
            "👑 No legendary craftsman here right now.\n"
            "Watch for the event announcement!", delay=9)
        return
    discount = _shop_discount(p)
    text, markup = _build_shop_view(p, "legend", user.id, discount)
    mins_left = max(0, int((expiry - datetime.now()).total_seconds() // 60))
    text = f"👑 *Legendary Craftsman's Wares* ⏳ {mins_left}m left\n\n" + text
    await send_group(update, text, delay=60, reply_markup=markup)

# ── INVENTORY / EQUIP / USE / SELL ────────────────────────────────────────────
INV_SECTIONS = ["Equipped", "Weapons", "Armors", "Shields", "Accessories", "Hats", "Gloves", "Boots", "Masks", "Consumables", "Materials"]

def _build_inv_sections(p):
    """Return ordered list of section names that have content for this player."""
    inv = Counter(sjl(p.get("inventory"), []))
    present = []
    has_equipped = any(p.get(k) for k in ["equipped_weapon","equipped_armor","equipped_shield","equipped_accessory",
                                           "equipped_hat","equipped_gloves","equipped_boots","equipped_mask"])
    if has_equipped:
        present.append("Equipped")
    if any(k in WEAPONS for k in inv) or p.get("equipped_weapon"):         present.append("Weapons")
    if any(k in ARMORS for k in inv) or p.get("equipped_armor"):           present.append("Armors")
    if any(k in SHIELDS for k in inv) or p.get("equipped_shield"):         present.append("Shields")
    if any(k in ACCESSORIES for k in inv) or p.get("equipped_accessory"): present.append("Accessories")
    if any(k in HATS for k in inv) or p.get("equipped_hat"):               present.append("Hats")
    if any(k in GLOVES for k in inv) or p.get("equipped_gloves"):          present.append("Gloves")
    if any(k in BOOTS for k in inv) or p.get("equipped_boots"):            present.append("Boots")
    if any(k in MASKS for k in inv) or p.get("equipped_mask"):             present.append("Masks")
    if any(k in CONSUMABLES for k in inv): present.append("Consumables")
    _all_gear = {**WEAPONS,**ARMORS,**SHIELDS,**ACCESSORIES,**HATS,**GLOVES,**BOOTS,**MASKS,**CONSUMABLES}
    if any(k not in _all_gear for k in inv):
        present.append("Materials")
    if not present:
        present.append("Equipped")
    return present

def _render_bag_item(p, item, count):
    """Return formatted line(s) for a single bag item."""
    if item in WEAPONS:
        d = WEAPONS[item]
        line = d.get("line", "")
        arch = LINE_ARCHETYPE.get(line, line.capitalize())
        weap_emoji = {"mage": "🪄", "thief": "🔪", "archer": "🏹", "priest": "📿"}.get(line, "⚔️")
        type_tag = f"{weap_emoji} Weapon [{arch}]" if arch else f"{weap_emoji} Weapon"
        rarity = RARITY_EMOJI.get(d.get("rarity",""), "⚪")
        stat_str = f"+{d['atk']} ATK"
    elif item in ARMORS:
        d = ARMORS[item]
        line = d.get("line", "")
        arch = LINE_ARCHETYPE.get(line, line.capitalize())
        type_tag = f"🛡️ Armor [{arch}]" if arch else "🛡️ Armor"
        rarity = RARITY_EMOJI.get(d.get("rarity",""), "⚪")
        stat_str = f"+{d['def']} DEF"
    elif item in SHIELDS:
        d = SHIELDS[item]
        line = d.get("line", "")
        arch = LINE_ARCHETYPE.get(line, line.capitalize())
        is_claw = d.get("type") == "claw"
        type_tag = (f"🗡️ Claw [{arch}]" if arch else "🗡️ Claw") if is_claw else (f"🔰 Shield [{arch}]" if arch else "🔰 Shield")
        rarity = RARITY_EMOJI.get(d.get("rarity",""), "⚪")
        stat_str = f"+{d.get('atk',0)} ATK" if is_claw else f"+{d.get('def',0)} DEF"
    elif item in ACCESSORIES:
        d = ACCESSORIES[item]
        type_tag = "💍 Accessory"
        rarity = RARITY_EMOJI.get(d.get("rarity",""), "⚪")
        stat_str = d.get("desc","")[:40]
    elif item in HATS:
        d = HATS[item]; type_tag = "🎩 Hat"
        rarity = RARITY_EMOJI.get(d.get("rarity",""), "⚪"); stat_str = f"+{d['def']} DEF"
    elif item in GLOVES:
        d = GLOVES[item]; type_tag = "🧤 Gloves"
        rarity = RARITY_EMOJI.get(d.get("rarity",""), "⚪"); stat_str = f"+{d['def']} DEF"
    elif item in BOOTS:
        d = BOOTS[item]; type_tag = "👢 Boots"
        rarity = RARITY_EMOJI.get(d.get("rarity",""), "⚪"); stat_str = f"+{d['def']} DEF"
    elif item in MASKS:
        d = MASKS[item]; type_tag = "🎭 Mask"
        rarity = RARITY_EMOJI.get(d.get("rarity",""), "⚪"); stat_str = f"+{d['def']} DEF"
    elif item in CONSUMABLES:
        d = CONSUMABLES[item]
        type_tag = "🧪 Consumable"
        rarity = "⚪"
        stat_str = d.get("desc","")
    else:
        type_tag = "📦 Material"; rarity = "⚪"; stat_str = ""
    enh = get_enhancement(p, item)
    _all_enchantable = {**WEAPONS,**ARMORS,**SHIELDS,**ACCESSORIES,**HATS,**GLOVES,**BOOTS,**MASKS}
    encs = get_enchant(p, item) if item in _all_enchantable else []
    enh_str = f" *+{enh}*" if enh > 0 else ""
    enc_str = f" ✨×{len(encs)}" if encs else ""
    return f"{rarity} *{item}*{enh_str}{enc_str} x{count}\n  {type_tag} - _{stat_str}_"

async def _send_inventory_section(target, p, section="Equipped", edit=False, uid=0, back_rows=None):
    sections = _build_inv_sections(p)
    if section not in sections:
        section = sections[0]

    inv = Counter(sjl(p.get("inventory"), []))
    lines = [f"🎒 *{p['username']}'s Inventory*\n"]

    if section == "Equipped":
        has_any = False
        for slot_key, emoji in [("equipped_weapon","⚔️"),("equipped_armor","🛡️"),
                                  ("equipped_shield","🔰"),("equipped_accessory","💍"),
                                  ("equipped_hat","🎩"),("equipped_gloves","🧤"),
                                  ("equipped_boots","👢"),("equipped_mask","🎭")]:
            name = p.get(slot_key)
            if not name: continue
            has_any = True
            enh = get_enhancement(p, name)
            encs_slot = get_enchant(p, name)
            tags = []
            if enh: tags.append(f"+{enh}")
            if encs_slot: tags.append(f"✨×{len(encs_slot)}")
            tag_str = " " + " ".join(tags) if tags else ""
            slot_label = slot_key.replace("equipped_","").capitalize()
            lines.append(f"{emoji} *{name}*{tag_str}  _({slot_label})_")
        if not has_any:
            lines.append("_Nothing equipped._")
    else:
        _all_gear_inv = {**WEAPONS,**ARMORS,**SHIELDS,**ACCESSORIES,**HATS,**GLOVES,**BOOTS,**MASKS,**CONSUMABLES}
        pool_map = {
            "Weapons":     (WEAPONS,     lambda k: k in WEAPONS),
            "Armors":      (ARMORS,      lambda k: k in ARMORS),
            "Shields":     (SHIELDS,     lambda k: k in SHIELDS),
            "Accessories": (ACCESSORIES, lambda k: k in ACCESSORIES),
            "Hats":        (HATS,        lambda k: k in HATS),
            "Gloves":      (GLOVES,      lambda k: k in GLOVES),
            "Boots":       (BOOTS,       lambda k: k in BOOTS),
            "Masks":       (MASKS,       lambda k: k in MASKS),
            "Consumables": (CONSUMABLES, lambda k: k in CONSUMABLES),
            "Materials":   ({},          lambda k: k not in _all_gear_inv),
        }
        _, pred = pool_map.get(section, ({}, lambda k: False))
        bucket = [(k, v) for k, v in inv.items() if pred(k)]
        if bucket:
            for item, count in sorted(bucket, key=lambda kv: kv[0]):
                lines.append(_render_bag_item(p, item, count))
        else:
            lines.append(f"_No {section.lower()} in bag._")

    lines.append(f"\n_/equip | /enhance | /enchant | /reinforce | /use_")

    # Navigation buttons — named like /stats
    idx = sections.index(section)
    btn_row = []
    _inv_uid = uid or p.get("user_id", 0)
    if idx > 0:
        prev = sections[idx - 1]
        btn_row.append(InlineKeyboardButton(f"◀ {prev}", callback_data=f"inv_s_{_inv_uid}_{prev}"))
    if idx < len(sections) - 1:
        nxt = sections[idx + 1]
        btn_row.append(InlineKeyboardButton(f"{nxt} ▶", callback_data=f"inv_s_{_inv_uid}_{nxt}"))
    markup = InlineKeyboardMarkup([btn_row]) if btn_row else None

    close_btn_row = [InlineKeyboardButton("❌ Close", callback_data=f"close_msg_{p['user_id']}")]
    _inv_rows = list(markup.inline_keyboard) if markup else []
    _inv_rows.append(close_btn_row)
    if back_rows: _inv_rows.extend(back_rows)
    markup = InlineKeyboardMarkup(_inv_rows)
    lines.append("\n_💰 Use /sell to sell items by rarity_")
    text = "\n".join(lines)[:4096]
    if edit:
        try:
            await target.edit_message_text(text=text, parse_mode="Markdown", reply_markup=markup)
        except Exception:
            try:
                await target.edit_message_text(text=text, reply_markup=markup)
            except Exception:
                pass
    else:
        try:
            await target.message.delete()
        except Exception:
            pass
        key = (target.effective_chat.id, target.effective_user.id)
        old_id = last_bot_message.get(key)
        try:
            if old_id:
                await target.get_bot().delete_message(chat_id=target.effective_chat.id, message_id=old_id)
        except Exception:
            pass
        new_msg = await target.get_bot().send_message(
            chat_id=target.effective_chat.id, text=text,
            parse_mode="Markdown", reply_markup=markup)
        last_bot_message[key] = new_msg.message_id

async def inventory_callback(update, context):
    query = update.callback_query
    if not query.data.startswith("inv_s_"): await query.answer(); return
    # format: inv_s_{uid}_{section}
    parts = query.data[len("inv_s_"):].split("_", 1)
    try:
        uid     = int(parts[0])
        section = parts[1]
    except (IndexError, ValueError):
        await query.answer(); return
    if query.from_user.id != uid:
        await query.answer("Not your inventory!", show_alert=True); return
    await query.answer()
    p = get_player(uid)
    if not p: return
    await _send_inventory_section(query, p, section, edit=True, uid=uid)

async def inventory_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user; p = get_player(user.id)
    if not p:
        await send_group(update, "Use /ascend first!", delay=9); return
    await _send_inventory_section(update, p, section="Equipped", edit=False, uid=user.id)


def _build_equip_page_markup(p, uid, page, page_size=5):
    """Return (has_items, InlineKeyboardMarkup) for the given equip page."""
    inv = sjl(p.get("inventory"), [])
    all_btns = []
    for slot_emoji, slot_label, pool in [
        ("⚔️", "Weapon",    WEAPONS),
        ("🛡️", "Armor",     ARMORS),
        ("🔰", "Shield",    SHIELDS),
        ("💍", "Accessory", ACCESSORIES),
        ("🎩", "Hat",       HATS),
        ("🧤", "Gloves",    GLOVES),
        ("👢", "Boots",     BOOTS),
        ("🎭", "Mask",      MASKS),
    ]:
        for it in sorted(set(k for k in inv if k in pool)):
            d_it = pool[it]
            rarity = RARITY_EMOJI.get(d_it.get("rarity", ""), "⚪")
            enh = get_enhancement(p, it)
            enh_str = f" +{enh}" if enh else ""
            stat_val = d_it.get("atk") or d_it.get("def", 0)
            stat_key = "ATK" if "atk" in d_it else "DEF"
            wtag = _weapon_class_tag(it)
            tag_str = f" [{wtag}]" if wtag else ""
            all_btns.append(InlineKeyboardButton(
                f"{slot_emoji} [{slot_label}] {rarity}{it}{enh_str} (+{stat_val} {stat_key}){tag_str}",
                callback_data=f"eqp_{uid}_{it}"))
    if not all_btns:
        return False, InlineKeyboardMarkup([[InlineKeyboardButton("❌ Close", callback_data=f"close_msg_{uid}")]])
    total = len(all_btns)
    total_pages = max(1, (total + page_size - 1) // page_size)
    page = max(0, min(page, total_pages - 1))
    rows = [[btn] for btn in all_btns[page * page_size:(page + 1) * page_size]]
    if total_pages > 1:
        nav = []
        if page > 0:
            nav.append(InlineKeyboardButton("◀️ Prev", callback_data=f"eqpg_{uid}_{page - 1}"))
        nav.append(InlineKeyboardButton(f"{page + 1}/{total_pages}", callback_data=f"eqpg_{uid}_{page}"))
        if page < total_pages - 1:
            nav.append(InlineKeyboardButton("Next ▶️", callback_data=f"eqpg_{uid}_{page + 1}"))
        rows.append(nav)
    rows.append([InlineKeyboardButton("❌ Close", callback_data=f"close_msg_{uid}")])
    return True, InlineKeyboardMarkup(rows)


async def equip_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user; p = get_player(user.id)
    if not p:
        await send_group(update, "Use /ascend first!", delay=9); return
    if not context.args:
        uid = user.id

        weap = p.get("equipped_weapon") or "None"
        armr = p.get("equipped_armor")  or "None"
        shld = p.get("equipped_shield") or "None"

        def _gear_summary_line(slot, name, pool):
            if name == "None": return f"{slot}: _None_"
            enh = get_enhancement(p, name)
            encs_g = get_enchant(p, name)
            enh_str = f" *+{enh}*" if enh else ""
            enc_str = f" ✨×{len(encs_g)}" if encs_g else ""
            d_s = pool.get(name, {})
            stat_val = d_s.get("atk") or d_s.get("def", 0)
            stat_label = "ATK" if "atk" in d_s else "DEF"
            rarity = RARITY_EMOJI.get(d_s.get("rarity",""), "")
            return f"{slot}: {rarity} *{name}*{enh_str}{enc_str} (+{stat_val} {stat_label})"

        lines = [f"🎽 *{p['username']}'s Gear:*\n",
                 _gear_summary_line("⚔️ Weapon",  weap, WEAPONS),
                 _gear_summary_line("🛡️ Armor",   armr, ARMORS),
                 _gear_summary_line("🔰 Shield",  shld, SHIELDS)]
        for _sn, _sk in enumerate(
                ("equipped_accessory","equipped_accessory_2","equipped_accessory_3","equipped_accessory_4"), 1):
            acc_n = p.get(_sk)
            if acc_n:
                acc_data = ACCESSORIES.get(acc_n, {})
                rarity = RARITY_EMOJI.get(acc_data.get("rarity",""), "")
                encs_acc = get_enchant(p, acc_n)
                enc_str = f" ✨×{len(encs_acc)}" if encs_acc else ""
                lines.append(f"💍 Accessory {_sn}: {rarity} *{acc_n}*{enc_str}  -  _{acc_data.get('desc','')}_")
            else:
                lines.append(f"💍 Accessory {_sn}: _None_")
        for slot_emoji, slot_label, slot_key, pool in [
                ("🎩","Hat","equipped_hat",HATS),("🧤","Gloves","equipped_gloves",GLOVES),
                ("👢","Boots","equipped_boots",BOOTS),("🎭","Mask","equipped_mask",MASKS)]:
            lines.append(_gear_summary_line(f"{slot_emoji} {slot_label}", p.get(slot_key) or "None", pool))

        has_items, markup = _build_equip_page_markup(p, uid, 0)
        lines.append("\n_Select an item to equip:_" if has_items else "\n_No equippable items in bag. Visit /shop!_")
        await send_group(update, "\n".join(lines), delay=60, reply_markup=markup); return
    item_typed = " ".join(context.args)
    inv = sjl(p.get("inventory"), [])
    item_name = resolve_item_ci(item_typed, inv)
    if not item_name:
        await send_group(update, f"You don't have *{item_typed}* in your inventory!", delay=9); return

    # Safety check  -  unknown items are never silently deleted
    all_known = set(WEAPONS) | set(ARMORS) | set(SHIELDS) | set(ACCESSORIES) | set(HATS) | set(GLOVES) | set(BOOTS) | set(MASKS)
    if item_name not in all_known:
        await send_group(update,
            f"⚠️ *{item_name}* is a legacy item from before the reskin.\n"
            f"It will be exchanged automatically  -  please wait for the next deploy.",
            delay=15)
        return

    # Determine item type and equip
    if item_name in WEAPONS:
        ok, reason = can_equip_weapon(p, item_name)
        if not ok:
            await send_group(update, f"❌ {reason}", delay=9); return
        old_name = p.get("equipped_weapon")
        old_atk = get_weapon_atk(p)
        p["equipped_weapon"] = item_name
        inv.remove(item_name)
        if old_name: inv.append(old_name)
        p["inventory"] = json.dumps(inv); save_player(p)
        new_atk = get_weapon_atk(p)
        if old_name:
            compare = f"*{old_name}* ({old_atk} ATK) -> *{item_name}* ({new_atk} ATK)"
        else:
            compare = f"ATK: {old_atk} -> {new_atk}"
        await send_group(update,
            f"⚔️ Equipped *{item_name}*!\n{compare}\n"
            + (f"_Unequipped {old_name}_" if old_name else ""), delay=15)
    elif item_name in ARMORS:
        ok, reason = can_equip_armor(p, item_name)
        if not ok:
            await send_group(update, f"❌ {reason}", delay=9); return
        old_name = p.get("equipped_armor")
        old_def = get_armor_def(p)
        p["equipped_armor"] = item_name
        inv.remove(item_name)
        if old_name: inv.append(old_name)
        p["inventory"] = json.dumps(inv); save_player(p)
        new_def = get_armor_def(p)
        if old_name:
            compare = f"*{old_name}* ({old_def} DEF) -> *{item_name}* ({new_def} DEF)"
        else:
            compare = f"DEF: {old_def} -> {new_def}"
        await send_group(update,
            f"🛡️ Equipped *{item_name}*!\n{compare}\n"
            + (f"_Unequipped {old_name}_" if old_name else ""), delay=15)
    elif item_name in SHIELDS:
        s_data = SHIELDS[item_name]
        cls_line = get_class_line(p)
        path = p.get("class_path")
        is_claw = s_data.get("type") == "claw"
        if is_claw:
            if cls_line != "thief" or path != "B":
                await send_group(update,
                    "❌ Only Assassin path (Cutthroat/Assassin/Blade Master/Specialist) can use claws.", delay=9); return
        else:
            if cls_line != "warrior" or path != "A":
                await send_group(update,
                    "❌ Only Warrior Path A (Page/Squire/Knight/Paladin) can use shields.", delay=9); return
        old_name = p.get("equipped_shield")
        old_def = get_armor_def(p)
        p["equipped_shield"] = item_name
        inv.remove(item_name)
        if old_name: inv.append(old_name)
        p["inventory"] = json.dumps(inv); save_player(p)
        new_def = get_armor_def(p)
        if is_claw:
            stat_val = s_data.get("atk", 0)
            await send_group(update,
                f"🗡️ Equipped *{item_name}*! +{stat_val} ATK (claw slot)\n"
                + (f"_Unequipped {old_name}_" if old_name else ""), delay=15)
        else:
            if old_name:
                compare = f"*{old_name}* ({old_def} DEF) -> *{item_name}* ({new_def} DEF)"
            else:
                compare = f"DEF: {old_def} -> {new_def}"
            await send_group(update,
                f"🔰 Equipped *{item_name}*!\n{compare}\n"
                + (f"_Unequipped {old_name}_" if old_name else ""), delay=15)
    elif item_name in ACCESSORIES:
        slot = _first_free_acc_slot(p)
        old = p.get(slot)
        p[slot] = item_name
        inv.remove(item_name)
        if old: inv.append(old)
        p["inventory"] = json.dumps(inv); save_player(p)
        acc = ACCESSORIES[item_name]
        slot_num = ("","2","3","4")[("equipped_accessory","equipped_accessory_2","equipped_accessory_3","equipped_accessory_4").index(slot)]
        await send_group(update,
            f"💍 Equipped *{item_name}*{f' (slot {slot_num})' if slot_num else ''}\n_{acc['desc']}_\n"
            + (f"_Unequipped {old}_" if old else ""), delay=15)
    elif item_name in HATS or item_name in GLOVES or item_name in BOOTS or item_name in MASKS:
        if item_name in HATS:
            slot_key, emoji, pool = "equipped_hat", "🎩", HATS
        elif item_name in GLOVES:
            slot_key, emoji, pool = "equipped_gloves", "🧤", GLOVES
        elif item_name in BOOTS:
            slot_key, emoji, pool = "equipped_boots", "👢", BOOTS
        else:
            slot_key, emoji, pool = "equipped_mask", "🎭", MASKS
        old_def = get_armor_def(p)
        old = p.get(slot_key)
        p[slot_key] = item_name
        inv.remove(item_name)
        if old: inv.append(old)
        p["inventory"] = json.dumps(inv); save_player(p)
        new_def = get_armor_def(p)
        item_data = pool[item_name]
        compare = f"*{old}* -> *{item_name}*" if old else f"DEF: {old_def} -> {new_def}"
        await send_group(update,
            f"{emoji} Equipped *{item_name}*! (+{item_data['def']} DEF)\n{compare}\n"
            + (f"_Unequipped {old}_" if old else ""), delay=15)
    else:
        await send_group(update,
            f"*{item_name}* is not equippable. Use /use for consumables.", delay=9)

async def unequip_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user; p = get_player(user.id)
    if not p:
        await send_group(update, "Use /ascend first!", delay=9); return
    uid = user.id
    slots = [("⚔️ Weapon", "equipped_weapon"), ("🛡️ Armor", "equipped_armor"),
             ("🔰 Shield", "equipped_shield"),
             ("💍 Accessory 1", "equipped_accessory"),
             ("💍 Accessory 2", "equipped_accessory_2"),
             ("💍 Accessory 3", "equipped_accessory_3"),
             ("💍 Accessory 4", "equipped_accessory_4"),
             ("🎩 Hat", "equipped_hat"), ("🧤 Gloves", "equipped_gloves"),
             ("👢 Boots", "equipped_boots"), ("🎭 Mask", "equipped_mask")]
    buttons = []
    for label, key in slots:
        name = p.get(key)
        if name:
            buttons.append([InlineKeyboardButton(f"{label}: {name}", callback_data=f"uneqp_{uid}_{key}")])
