async def use_full_heal_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """One-tap 'Heal to FULL': drinks HP potions until full — smallest potion
    that closes the gap first (no waste), biggest owned as fallback."""
    query = update.callback_query
    try:
        uid = int(query.data.split("_")[1])
    except (IndexError, ValueError):
        await query.answer(); return
    if query.from_user.id != uid:
        await query.answer("Not your inventory!", show_alert=True); return
    p = get_player(uid)
    if not p:
        await query.answer("Use /ascend first!", show_alert=True); return
    if is_defeated(p):
        await query.answer("You're defeated — potions won't help!", show_alert=True); return
    inv = sjl(p.get("inventory"), [])
    mx = calc_max_hp(p)
    _order = ("Health Potion", "Greater Health Potion", "Grand Restorative Flask",
              "Supreme Restorative Flask", "Ultimate Vitality Draught")
    used = []
    for _ in range(30):
        if p["hp"] >= mx: break
        owned = [pn for pn in _order if pn in inv]
        if not owned: break
        missing = mx - p["hp"]
        pick = next((pn for pn in owned if _potion_heal_amount(p, pn) >= missing), owned[-1])
        inv.remove(pick)
        _apply_potion(p, pick)
        used.append(pick)
    if not used:
        await query.answer("Already at full HP!" if p["hp"] >= mx
                           else "No HP potions in your bag — visit /shop!", show_alert=True)
        return
    p["inventory"] = json.dumps(inv)
    save_player(p)
    counts = ", ".join(f"{n} ×{c}" if c > 1 else n for n, c in Counter(used).items())
    await query.answer("❤️ Fully healed!" if p["hp"] >= mx else "Drank everything you had!")
    await _q_edit(query,
        f"🧪 *Heal to Full*\nUsed: {counts}\n❤️ *{p['hp']:,}/{mx:,} HP*",
        parse_mode="Markdown")

async def use_item_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle /use button: useitem_{uid}_{item_name}"""
    query = update.callback_query
    parts = query.data.split("_", 2)
    try:
        uid       = int(parts[1])
        item_name = parts[2]
    except (IndexError, ValueError):
        await query.answer(); return
    if query.from_user.id != uid:
        await query.answer("Not your inventory!", show_alert=True); return
    p = get_player(uid)
    if not p:
        await query.answer("Use /ascend first!", show_alert=True); return
    inv = sjl(p.get("inventory"), [])
    if item_name not in inv:
        await query.answer(f"{item_name} not in your bag!", show_alert=True); return
    inv.remove(item_name); p["inventory"] = json.dumps(inv)
    msg = f"✅ Used *{item_name}*. "
    if item_name in _HP_POTION_PCT or item_name in _MP_POTION_PCT:
        _pstatus, _pnote = _apply_potion(p, item_name)
        if _pstatus == "defeated":
            inv.append(item_name); p["inventory"] = json.dumps(inv); save_player(p)
            await query.answer("You're defeated — potions won't help!", show_alert=True); return
        msg += _pnote
    elif item_name == "Scroll of Revival":
        if not is_defeated(p):
            inv.append(item_name); p["inventory"] = json.dumps(inv); save_player(p)
            await query.answer("You're not defeated — save it for when you need it!", show_alert=True); return
        if is_revival_blocked(p):
            inv.append(item_name); p["inventory"] = json.dumps(inv); save_player(p)
            await query.answer("You've been condemned — can't be revived!", show_alert=True); return
        p["defeated_until"] = None; p["hp"] = round(calc_max_hp(p) * 0.70)
        p["mp"] = safe_int(p.get("max_mp")) or calc_max_mp(p)
        p["shield_used"] = 0; p["shield_hp"] = 0; p["shield_core_bonus"] = 0
        set_status(p, "invincible_until", 300)
        msg += f"💚 Revived at {p['hp']} HP (70%)! 5m invincibility granted."
    elif item_name.startswith("Monster Core (") or item_name == "Rare Monster Core":
        _core_stat_map = {
            "Monster Core (Fire)":      {"STR": 1},
            "Monster Core (Water)":     {"WIS": 1},
            "Monster Core (Earth)":     {"DEF": 1},
            "Monster Core (Wind)":      {"AGI": 1},
            "Monster Core (Lightning)": {"DEX": 1},
            "Monster Core (Ice)":       {"INT": 1},
            "Monster Core (Shadow)":    {"LUK": 1},
            "Monster Core (Holy)":      {"STR":1,"AGI":1,"INT":1,"WIS":1,"DEX":1,"LUK":1},
            "Monster Core (Void)":      {"STR":2,"AGI":2,"INT":2},
            "Rare Monster Core":        {"STR":1,"AGI":1,"INT":1,"WIS":1,"DEX":1,"LUK":1},
        }
        boosts = _core_stat_map.get(item_name, {})
        if boosts:
            stats = safe_stats(p)
            for stat, val in boosts.items():
                stats[stat] = stats.get(stat, 0) + val
            p["stats"] = json.dumps(stats)
            boost_str = ", ".join(f"+{v} {s}" for s, v in boosts.items())
            msg += f"🔮 Permanent stat boost: *{boost_str}*!"
        else:
            msg += "_(No direct effect)_"
    else:
        msg += "_(No direct effect)_"
    save_player(p)
    await query.answer()
    # Rebuild the menu so the player can use more items without re-opening
    inv_after = sjl(p.get("inventory"), [])
    remaining = [(k, inv_after.count(k)) for k in dict.fromkeys(inv_after) if k in CONSUMABLES]
    if remaining:
        btns = []
        if safe_int(p.get("hp")) < calc_max_hp(p) and any(pn in inv_after for pn in _HP_POTION_PCT):
            btns.append([InlineKeyboardButton(
                "❤️‍🩹 HEAL TO FULL — auto-use potions", callback_data=f"usefull_{uid}")])
        for _itm, _cnt in remaining:
            _dc = CONSUMABLES[_itm]
            btns.append([InlineKeyboardButton(
                f"🧪 {_itm} x{_cnt}  —  {_dc.get('desc','')[:40]}",
                callback_data=f"useitem_{uid}_{_itm}")])
        btns.append([InlineKeyboardButton("❌ Close", callback_data=f"close_msg_{uid}")])
        try:
            await _q_edit(query, 
                f"{msg}\n\n🧪 *Use another item:*",
                parse_mode="Markdown", reply_markup=InlineKeyboardMarkup(btns))
        except Exception:
            pass
    else:
        try:
            await _q_edit(query, f"{msg}\n\n_Bag empty._", parse_mode="Markdown")
        except Exception:
            pass

