async def use_item_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user; p = get_player(user.id)
    if not p:
        await send_group(update, "Use /ascend first!", delay=9); return
    if not context.args:
        inv = sjl(p.get("inventory"), [])
        consumables_in_bag = [(k, inv.count(k)) for k in dict.fromkeys(inv) if k in CONSUMABLES]
        if not consumables_in_bag:
            await send_group(update, "🧪 *Use Item*\n\nNo consumables in your bag.", delay=12); return
        uid = user.id
        buttons = []
        if safe_int(p.get("hp")) < calc_max_hp(p) and any(pn in inv for pn in _HP_POTION_PCT):
            buttons.append([InlineKeyboardButton(
                "❤️‍🩹 HEAL TO FULL — auto-use potions", callback_data=f"usefull_{uid}")])
        for item, count in consumables_in_bag:
            d_c = CONSUMABLES[item]
            buttons.append([InlineKeyboardButton(
                f"🧪 {item} x{count}  —  {d_c.get('desc','')[:40]}",
                callback_data=f"useitem_{uid}_{item}")])
        buttons.append([InlineKeyboardButton("❌ Close", callback_data=f"close_msg_{uid}")])
        markup = InlineKeyboardMarkup(buttons)
        await send_group(update, "🧪 *Use Item — Select a consumable:*", delay=60, reply_markup=markup)
        return
    item_typed = " ".join(context.args)
    inv  = sjl(p.get("inventory"), [])
    item = resolve_item_ci(item_typed, inv)
    if not item:
        await send_group(update, f"You don't have *{item_typed}*!", delay=9); return

    # Safety check  -  never silently delete unknown items
    all_known_consumables = set(CONSUMABLES)
    all_known_gear = set(WEAPONS) | set(ARMORS) | set(SHIELDS) | set(ACCESSORIES) | set(HATS) | set(GLOVES) | set(BOOTS) | set(MASKS)
    if item not in all_known_consumables and item not in all_known_gear:
        inv.append(item)
        p["inventory"] = json.dumps(inv)
        save_player(p)
        await send_group(update,
            f"⚠️ *{item}* is a legacy item from before the reskin.\n"
            f"It will be exchanged automatically  -  please wait for the next deploy.",
            delay=15)
        return

    inv.remove(item); p["inventory"] = json.dumps(inv)
    msg = f"✅ Used *{item}*. "
    if item in _HP_POTION_PCT or item in _MP_POTION_PCT:
        _pstatus, _pnote = _apply_potion(p, item)
        if _pstatus == "defeated":
            inv.append(item); p["inventory"] = json.dumps(inv)
            save_player(p)
            await send_group(update,
                "❌ You're defeated  -  potions won't help.\n"
                "Use a *Scroll of Revival* to revive yourself, or wait for a Priest.", delay=9)
            return
        msg += _pnote
    elif item == "Scroll of Revival":
        if not is_defeated(p):
            inv.append(item); p["inventory"] = json.dumps(inv)
            save_player(p)
            await send_group(update,
                "You're not defeated  -  save your Scroll of Revival for when you need it!", delay=9)
            return
        if is_revival_blocked(p):
            inv.append(item); p["inventory"] = json.dumps(inv)
            save_player(p)
            await send_group(update,
                "☠️ You have been condemned by Verdict  -  you cannot be revived!\n"
                "Only a *Cleric's Absolution* can lift this curse.", delay=9)
            return
        p["defeated_until"] = None
        p["hp"] = round(calc_max_hp(p) * 0.70)
        p["shield_used"] = 0; p["shield_hp"] = 0; p["shield_core_bonus"] = 0
        set_status(p, "invincible_until", 300)
        msg += f"💚 Revived at {p['hp']} HP (70%)! 5m invincibility granted."
    elif item.startswith("Monster Core (") or item == "Rare Monster Core":
        _core_stat_map = {
            "Monster Core (Fire)":      {"STR": 1},
            "Monster Core (Water)":     {"WIS": 1},
            "Monster Core (Earth)":     {"DEF": 1},
            "Monster Core (Wind)":      {"AGI": 1},
            "Monster Core (Lightning)": {"DEX": 1},
            "Monster Core (Ice)":       {"INT": 1},
            "Monster Core (Shadow)":    {"LUK": 1},
            "Monster Core (Holy)":      {"STR":1,"AGI":1,"INT":1,"WIS":1,"DEX":1,"LUK":1},
            "Monster Core (Void)":      {"STR":2,"AGI":2,"INT":2},
            "Rare Monster Core":        {"STR":1,"AGI":1,"INT":1,"WIS":1,"DEX":1,"LUK":1},
        }
        boosts = _core_stat_map.get(item, {})
        if boosts:
            stats = safe_stats(p)
            for stat, val in boosts.items():
                stats[stat] = stats.get(stat, 0) + val
            p["stats"] = json.dumps(stats)
            boost_str = ", ".join(f"+{v} {s}" for s, v in boosts.items())
            msg += f"🔮 Permanent stat boost: *{boost_str}*!"
        else:
            msg += "_(No direct effect  -  used as crafting material or quest item)_"
    else:
        msg += "_(No direct effect  -  used as crafting material or quest item)_"
    save_player(p)
    await send_group(update, msg, delay=15)

_SELL_PAGE_SIZE = 8
_SELL_RARITY_VALUES = {"common": 20, "uncommon": 60, "rare": 200, "epic": 600, "legendary": 2000, "mythic": 8000}
_SELL_PROTECTED = {
    # Potions & consumables — never bulk-sold
    "Health Potion", "Greater Health Potion", "Grand Restorative Flask",
    "Fortune Coin", "Scroll of Revival", "Holy Water Vial",
    # Crafting / eggs / misc
    "Iron Shard", "Enchanting Scroll",
    "Common Egg", "Rare Egg", "Dragon Egg", "Mythic Egg", "Pet Snack",
}

def _sellable_items(p):
    """Return sorted list of (item_name, price, rarity, count) for all sellable unequipped gear."""
    inv = sjl(p.get("inventory"), [])
    equipped = {p.get("equipped_weapon"), p.get("equipped_armor"),
                p.get("equipped_shield"), p.get("equipped_accessory"),
                p.get("equipped_hat"), p.get("equipped_gloves"),
                p.get("equipped_boots"), p.get("equipped_mask")}
    counts = Counter(inv)
    seen = set(); result = []
    for item in inv:
        if item in seen or item in equipped or item in _SELL_PROTECTED:
            continue
        seen.add(item)
        for pool in [WEAPONS, ARMORS, SHIELDS, ACCESSORIES, HATS, GLOVES, BOOTS, MASKS]:
            if item in pool:
                rar = pool[item].get("rarity", "common")
                result.append((item, _SELL_RARITY_VALUES.get(rar, 20), rar, counts[item]))
                break
    rar_order = {"common": 0, "uncommon": 1, "rare": 2, "epic": 3, "legendary": 4, "mythic": 5}
    result.sort(key=lambda x: (rar_order.get(x[2], 0), x[0]))
    return result

def _build_sell_browse(p, page=0):
    uid = p["user_id"]
    items = _sellable_items(p)
    total = len(items)
    max_page = max(0, (total - 1) // _SELL_PAGE_SIZE) if total else 0
    page = max(0, min(page, max_page))
    start = page * _SELL_PAGE_SIZE
    chunk = items[start:start + _SELL_PAGE_SIZE]
    lines = [f"💰 *Sell Items* — page {page+1}/{max_page+1}\n"]
    rows = []
    for item, price, rarity, count in chunk:
        emoji = RARITY_EMOJI.get(rarity, "⚪")
        qty = f" ×{count}" if count > 1 else ""
        rows.append([InlineKeyboardButton(
            f"{emoji} {item}{qty} — {price}g",
            callback_data=f"sll_{uid}_{page}_{item}")])
    if not chunk:
        lines.append("_Nothing left to sell._")
    nav = []
    if page > 0:
        nav.append(InlineKeyboardButton("◀ Prev", callback_data=f"sellbrowse_{uid}_{page-1}"))
    if page < max_page:
        nav.append(InlineKeyboardButton("Next ▶", callback_data=f"sellbrowse_{uid}_{page+1}"))
    if nav:
        rows.append(nav)
    rows.append([InlineKeyboardButton("❌ Close", callback_data=f"close_msg_{uid}")])
    return "\n".join(lines), InlineKeyboardMarkup(rows)

async def sell_browse_callback(update, context):
    query = update.callback_query
    parts = query.data.split("_")
    try:
        uid = int(parts[1]); page = int(parts[2])
    except (IndexError, ValueError):
        await query.answer(); return
    if query.from_user.id != uid:
        await query.answer("Not your sell menu!", show_alert=True); return
    await query.answer()
    p = get_player(uid)
    if not p: return
    text, markup = _build_sell_browse(p, page)
    try:
        await _q_edit(query, text, parse_mode="Markdown", reply_markup=markup)
    except Exception:
        pass

async def sell_item_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle sell button: sll_{uid}_{page}_{item_name}"""
    query = update.callback_query
    parts = query.data.split("_", 3)
    try:
        uid = int(parts[1])
        # Support both old format (no page) and new format (with page)
        if len(parts) == 4:
            page = int(parts[2]); item_name = parts[3]
        else:
            page = 0; item_name = parts[2]
    except (IndexError, ValueError):
        await query.answer(); return
    if query.from_user.id != uid:
        await query.answer("Not your inventory!", show_alert=True); return
    p = get_player(uid)
    if not p:
        await query.answer("Use /ascend first!", show_alert=True); return
    inv = sjl(p.get("inventory"), [])
    if item_name not in inv:
        await query.answer(f"{item_name} not in inventory!", show_alert=True); return
    price = 0
    for pool_c in [WEAPONS, ARMORS, SHIELDS, ACCESSORIES]:
        if item_name in pool_c:
            price = _SELL_RARITY_VALUES.get(pool_c[item_name].get("rarity","common"), 20)
            break
    if price == 0:
        await query.answer(f"{item_name} cannot be sold.", show_alert=True); return
    await query.answer(f"Sold {item_name} for {price}g!")
    inv.remove(item_name)
    p["inventory"] = json.dumps(inv)
    p["gold"] = p.get("gold", 0) + price
    save_player(p)
    # Refresh the browse menu so player can keep selling
    text, markup = _build_sell_browse(p, page)
    try:
        await _q_edit(query, 
            f"✅ *Sold {item_name}* for *{price}g!*  Balance: *{p['gold']}g*\n\n" + text,
            parse_mode="Markdown", reply_markup=markup)
    except Exception:
        pass

async def sell_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user; p = get_player(user.id)
    if not p:
        await send_group(update, "Use /ascend first!", delay=9); return
    if not context.args:
        uid = user.id
        inv = sjl(p.get("inventory"), [])
        if not inv:
            await send_group(update, "Your inventory is empty.", delay=9); return
        buttons = [
            [InlineKeyboardButton("Sell Off-Class Common",    callback_data=f"sellr_{uid}_common"),
             InlineKeyboardButton("Sell Off-Class Uncommon",  callback_data=f"sellr_{uid}_uncommon")],
            [InlineKeyboardButton("Sell Off-Class Rare",      callback_data=f"sellr_{uid}_rare"),
             InlineKeyboardButton("Sell Off-Class Epic",      callback_data=f"sellr_{uid}_epic")],
            [InlineKeyboardButton("💰 Sell All Off-Class Weapons/Armor", callback_data=f"sellr_{uid}_all")],
            [InlineKeyboardButton("⚔️ Sell Off-Class Items",             callback_data=f"selloffc_{uid}")],
            [InlineKeyboardButton("🔍 Browse & Sell Individual Items", callback_data=f"sellbrowse_{uid}_0")],
        ]
        await send_group(update,
            "💰 *Sell Items*\n\nBulk sell by rarity, or sell gear that doesn't match your class. Equipped gear and key materials are always protected.",
            reply_markup=InlineKeyboardMarkup(buttons), delay=45)
        return

    BULK_SELL_PROTECTED = _SELL_PROTECTED

    if context.args[0].lower() == "all":
        inv = sjl(p.get("inventory"), [])
        if not inv:
            await send_group(update, "Your inventory is empty.", delay=9); return
        rarity_filter = None
        if len(context.args) > 1:
            rf = context.args[1].lower()
            if rf in ("common","uncommon","rare","epic","legendary"):
                rarity_filter = rf
        sold_items = []; total_gold = 0; remaining_inv = []
        equipped = {p.get("equipped_weapon"), p.get("equipped_armor"),
                    p.get("equipped_shield"),
                    p.get("equipped_accessory"), p.get("equipped_accessory_2"),
                    p.get("equipped_accessory_3"), p.get("equipped_accessory_4"),
                    p.get("equipped_hat"), p.get("equipped_gloves"),
                    p.get("equipped_boots"), p.get("equipped_mask")}
        player_line = get_class_line(p)
        rarity_prices_s = {"common":20,"uncommon":60,"rare":200,"epic":600,"legendary":2000}
        for item_s in inv:
            if item_s in BULK_SELL_PROTECTED or item_s in equipped:
                remaining_inv.append(item_s); continue
            # Only sell weapons and armors — shields/accessories/hats/gloves/boots/masks are kept
            item_rarity = None; item_price = 0; item_line = None
            for pool_s in [WEAPONS, ARMORS]:
                if item_s in pool_s:
                    item_rarity = pool_s[item_s].get("rarity","common")
                    item_price = rarity_prices_s.get(item_rarity, 20)
                    item_line = pool_s[item_s].get("line") or pool_s[item_s].get("class")
                    break
            if item_price == 0:
                remaining_inv.append(item_s); continue
            # Only sell off-class items
            if item_line and player_line and item_line == player_line:
                remaining_inv.append(item_s); continue
            should_sell = (not rarity_filter) or (rarity_filter == item_rarity)
            if should_sell:
                sold_items.append(item_s); total_gold += item_price
            else:
                remaining_inv.append(item_s)
        if not sold_items:
            await send_group(update,
                f"Nothing to sell{' of that rarity' if rarity_filter else ''}.", delay=9); return
        p["inventory"] = json.dumps(remaining_inv)
        p["gold"] = p.get("gold", 0) + total_gold
        save_player(p)
        from collections import Counter as _Counter
        sold_summary = _Counter(sold_items)
        summary_str = ", ".join(f"{k} x{v}" for k, v in sold_summary.items())
        await send_group(update,
            f"💰 *Bulk Sold!*\n_{summary_str}_\n\nEarned *{total_gold}g* | Balance: {p['gold']}g",
            delay=20); return

    SELL_RARITIES = {"common", "uncommon", "rare", "epic", "legendary"}
    if context.args and context.args[0].lower() in SELL_RARITIES:
        target_rarity = context.args[0].lower()
        inv = sjl(p.get("inventory"), [])
        sold_items = []; gold_earned = 0
        remaining = []
        equipped_slots = {p.get("equipped_weapon"), p.get("equipped_armor"),
                          p.get("equipped_shield"),
                          p.get("equipped_accessory"), p.get("equipped_accessory_2"),
                          p.get("equipped_accessory_3"), p.get("equipped_accessory_4"),
                          p.get("equipped_hat"), p.get("equipped_gloves"),
                          p.get("equipped_boots"), p.get("equipped_mask")}
        RARITY_SELL_VALUES = {"common":20,"uncommon":60,"rare":200,"epic":600,"legendary":2000}
        for item_r_entry in inv:
            if item_r_entry in BULK_SELL_PROTECTED or item_r_entry in equipped_slots:
                remaining.append(item_r_entry); continue
            item_r = ""; item_val = 0
            for pool_r in [WEAPONS, ARMORS, SHIELDS, ACCESSORIES, HATS, GLOVES, BOOTS, MASKS, CONSUMABLES]:
                if item_r_entry in pool_r:
                    item_r = pool_r[item_r_entry].get("rarity","common")
                    item_val = RARITY_SELL_VALUES.get(item_r, 5)
                    break
            if item_r == target_rarity:
                sold_items.append(item_r_entry)
                gold_earned += item_val
            else:
                remaining.append(item_r_entry)
        if not sold_items:
            await send_group(update, f"No {target_rarity} items to sell.", delay=9); return
        p["inventory"] = json.dumps(remaining)
        p["gold"] = p.get("gold", 0) + gold_earned
        save_player(p)
        await send_group(update,
            f"💰 Sold {len(sold_items)} *{target_rarity}* item(s) for *{gold_earned} gold*.\n"
            f"Items: {', '.join(sold_items[:10])}{'...' if len(sold_items)>10 else ''}", delay=15); return

    # Single-item sell
    # Strip trailing "confirm" from args to get item name
    args_list = list(context.args)
    confirmed = len(args_list) > 1 and args_list[-1].lower() == "confirm"
    if confirmed:
        args_list = args_list[:-1]
    item_typed = " ".join(args_list)
    inv  = sjl(p.get("inventory"), [])
    item_name = resolve_item_ci(item_typed, inv)
    if not item_name:
        await send_group(update, f"You don't have *{item_typed}*!", delay=9); return

    # Check if item is equipped
    equipped_slots = {p.get("equipped_weapon"), p.get("equipped_armor"),
                      p.get("equipped_shield"), p.get("equipped_accessory"),
                      p.get("equipped_hat"), p.get("equipped_gloves"),
                      p.get("equipped_boots"), p.get("equipped_mask")}
    if item_name in equipped_slots and not confirmed:
        await send_group(update,
            f"⚠️ *{item_name}* is currently equipped!\n"
            f"Use /equip to swap it out first, or `/sell {item_name} confirm` to sell anyway.", delay=12); return

    # Warn on rare+
    item_rarity = ""
    for pool_check in [WEAPONS, ARMORS, SHIELDS, ACCESSORIES]:
        if item_name in pool_check:
            item_rarity = pool_check[item_name].get("rarity","")
            break
    if item_rarity in ("rare","epic","legendary") and not confirmed:
        rarity_emoji = RARITY_EMOJI.get(item_rarity, "")
        await send_group(update,
            f"⚠️ {rarity_emoji} *{item_name}* is a *{item_rarity.capitalize()}* item!\n"
            f"Type `/sell {item_name} confirm` to sell it.", delay=12); return

    # Determine sell price
    price = 0
    for pool in [WEAPONS, ARMORS, ACCESSORIES, SHIELDS]:
        if item_name in pool:
            d = pool[item_name]
            rarity_prices = {"common":20,"uncommon":60,"rare":200,"epic":600,"legendary":2000}
            price = rarity_prices.get(d.get("rarity","common"),20)
            break
    for pool2 in [CONSUMABLES]:
        if item_name in pool2:
            price = pool2[item_name].get("sell",10); break
    if price == 0: price = 10
    inv.remove(item_name); p["inventory"] = json.dumps(inv)
    p["gold"] = p.get("gold",0) + price
    save_player(p)
    await send_group(update,
        f"💰 Sold *{item_name}* for *{price} gold*!\nTotal: {p['gold']}g", delay=15)


async def sell_rarity_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle bulk-sell by rarity button."""
    query = update.callback_query
    parts = query.data.split("_", 2)
    try: uid = int(parts[1]); rarity_filter = parts[2]
    except (IndexError, ValueError): await query.answer(); return
    if query.from_user.id != uid:
        await query.answer("This isn't your sell menu!", show_alert=True); return
    p = get_player(uid)
    if not p: await query.answer("Player not found.", show_alert=True); return

    rarity_prices = {"common":20,"uncommon":60,"rare":200,"epic":600,"legendary":2000}
    inv = sjl(p.get("inventory"), [])
    equipped = {
        p.get("equipped_weapon"), p.get("equipped_armor"),
        p.get("equipped_shield"),
        p.get("equipped_accessory"), p.get("equipped_accessory_2"),
        p.get("equipped_accessory_3"), p.get("equipped_accessory_4"),
        p.get("equipped_hat"), p.get("equipped_gloves"),
        p.get("equipped_boots"), p.get("equipped_mask"),
    }
    player_line = get_class_line(p)
    sold_items = []; total_gold = 0; remaining_inv = []
    for item_s in inv:
        if item_s in _SELL_PROTECTED or item_s in equipped:
            remaining_inv.append(item_s); continue
        # Only weapons and armors are bulk-sellable; shields/accessories/hats/gloves/boots/masks kept
        item_rarity = None; item_price = 0; item_line = None
        for pool_s in [WEAPONS, ARMORS]:
            if item_s in pool_s:
                item_rarity = pool_s[item_s].get("rarity","common")
                item_price = rarity_prices.get(item_rarity, 20)
                item_line = pool_s[item_s].get("line") or pool_s[item_s].get("class")
                break
        if item_price == 0:
            remaining_inv.append(item_s); continue
        # Keep same-class items
        if item_line and player_line and item_line == player_line:
            remaining_inv.append(item_s); continue
        should_sell = (rarity_filter == "all") or (item_rarity == rarity_filter)
        if should_sell:
            sold_items.append(item_s); total_gold += item_price
        else:
            remaining_inv.append(item_s)
    if not sold_items:
        await query.answer(f"Nothing to sell of that rarity.", show_alert=True); return
    p["inventory"] = json.dumps(remaining_inv)
    p["gold"] = p.get("gold", 0) + total_gold
    save_player(p)
    label = rarity_filter.capitalize() if rarity_filter != "all" else "Everything"
    await query.answer(f"Sold {len(sold_items)} items for {total_gold}g!")
    await _q_edit(query, 
        f"💰 *Sold {len(sold_items)} {label} item{'s' if len(sold_items)!=1 else ''}*\n"
        f"+*{total_gold:,}g* | Balance: *{p['gold']:,}g*",
        parse_mode="Markdown")


async def sell_offclass_callback(update, context):
    """Sell all weapon/armor/shield items that don't match the player's class line."""
    query = update.callback_query
    parts = query.data.split("_", 1)
    try: uid = int(parts[1])
    except (IndexError, ValueError): await query.answer(); return
    if query.from_user.id != uid:
        await query.answer("This isn't your sell menu!", show_alert=True); return
    p = get_player(uid)
    if not p: await query.answer("Player not found.", show_alert=True); return

    player_line = get_class_line(p)
    inv = sjl(p.get("inventory"), [])
    equipped = {
        p.get("equipped_weapon"), p.get("equipped_armor"),
        p.get("equipped_shield"),
        p.get("equipped_accessory"), p.get("equipped_accessory_2"),
        p.get("equipped_accessory_3"), p.get("equipped_accessory_4"),
        p.get("equipped_hat"), p.get("equipped_gloves"),
        p.get("equipped_boots"), p.get("equipped_mask"),
    }
    RARITY_SELL = {"common": 20, "uncommon": 60, "rare": 200, "epic": 600, "legendary": 2000}
    sold_items = []; total_gold = 0; remaining_inv = []
    for item_s in inv:
        if item_s in equipped:
            remaining_inv.append(item_s); continue
        item_data = None; item_pool = None
        for pool in [WEAPONS, ARMORS, SHIELDS]:
            if item_s in pool:
                item_data = pool[item_s]; item_pool = pool; break
        if item_data is None:
            remaining_inv.append(item_s); continue
        item_line = item_data.get("line") or item_data.get("class")
        if item_line and player_line and item_line != player_line:
            rarity = item_data.get("rarity", "common")
            price  = RARITY_SELL.get(rarity, 20)
            sold_items.append(item_s); total_gold += price
        else:
            remaining_inv.append(item_s)
    if not sold_items:
        await query.answer("No off-class gear to sell!", show_alert=True); return
    p["inventory"] = json.dumps(remaining_inv)
    p["gold"] = p.get("gold", 0) + total_gold
    save_player(p)
    await query.answer(f"Sold {len(sold_items)} off-class items for {total_gold}g!")
    await _q_edit(query, 
        f"⚔️ *Sold {len(sold_items)} off-class item{'s' if len(sold_items)!=1 else ''}*\n"
        f"+*{total_gold:,}g* | Balance: *{p['gold']:,}g*",
        parse_mode="Markdown")


