async def _dispatch_secret_quest(uid: int, bot):
    p = get_player(uid)
    if not p: return
    if p.get("active_quest"): return
    if time.time() - (p.get("last_quest_ts") or 0) < 28800: return

    # 40% of assignments are TARGETED: say the phrase to a specific recently-
    # active player — doubles as a social nudge between players
    target = None
    if random.random() < 0.40:
        try:
            c = _db().cursor()
            cutoff = (datetime.now() - timedelta(hours=48)).isoformat()
            c.execute("""SELECT s.user_id, p.username FROM shadow_profiles s
                         JOIN players p ON p.user_id = s.user_id
                         WHERE s.last_seen >= ? AND s.user_id != ?
                         ORDER BY RANDOM() LIMIT 1""", (cutoff, uid))
            row = c.fetchone()
            if row and row["username"]:
                target = (row["user_id"], row["username"])
        except Exception:
            target = None

    if target:
        phrase, exp_r, inf_r = random.choice(_TARGETED_QUEST_TPL)
        quest = {"type":"targeted","phrase":phrase,"reward_exp":exp_r,"reward_inf":inf_r,
                 "target_id":target[0],"target_name":target[1],"expires":int(time.time())+86400}
        _exp_preview = exp_share(p["level"], min(0.15, exp_r / 900 * 0.15))
        dm = (f"🎱 *The oracle has a task for you.*\n\n"
              f"_Say this to *{target[1]}* in the group — reply to one of their "
              f"messages, or include their name:_\n\n"
              f"*\"{phrase}\"*\n\n"
              f"⏳ _Expires in 24 hours_\n"
              f"💫 Reward: *{fmt_num(_exp_preview)} EXP + {inf_r} Influence + Health Potion*")
    else:
        phrase, exp_r, inf_r = random.choice(_CHAT_QUEST_TPL)
        quest = {"type":"chat","phrase":phrase,"reward_exp":exp_r,"reward_inf":inf_r,"expires":int(time.time())+86400}
        _exp_preview = exp_share(p["level"], min(0.15, exp_r / 900 * 0.15))
        dm = (f"🎱 *The oracle has a task for you.*\n\n"
              f"_Say this in the group:_\n\n"
              f"*\"{phrase}\"*\n\n"
              f"⏳ _Expires in 24 hours_\n"
              f"💫 Reward: *{fmt_num(_exp_preview)} EXP + {inf_r} Influence + Health Potion*")
    p["active_quest"] = json.dumps(quest); p["last_quest_ts"] = int(time.time()); save_player(p)
    try: await bot.send_message(uid, dm, parse_mode="Markdown")
    except: pass

async def _try_complete_quest_social(p, action, target_id, bot):
    q = sjl(p.get("active_quest"), None)
    if not q or q.get("type") != "social" or q.get("action") != action: return
    if q.get("target_id") != target_id: return
    if q.get("expires", 0) < time.time(): p["active_quest"] = None; save_player(p); return
    inf_r = q.get("reward_inf", 15)
    exp_r = exp_share(p["level"], min(0.15, q.get("reward_exp", 200) / 900 * 0.15))
    add_exp(p, exp_r); _add_influence(p, inf_r)
    p["active_quest"] = None; save_player(p)
    try: await bot.send_message(p["user_id"], f"✅ *Assignment complete.*\n\nThe Order takes note.\n\n+{fmt_num(exp_r)} EXP  +{inf_r} Influence", parse_mode="Markdown")
    except: pass

def _phrase_norm(s):
    """Normalize for phrase matching: lowercase, strip ALL punctuation
    (players type smart quotes, drop periods, swap commas), collapse spaces."""
    return re.sub(r"\s+", " ", re.sub(r"[^a-z0-9\s]", " ", str(s).lower())).strip()

def _phrase_matches(phrase, text):
    np_, nt = _phrase_norm(phrase), _phrase_norm(text)
    return bool(np_) and np_ in nt

async def _try_complete_quest_phrase(p, text, reply_to_id, bot):
    q = sjl(p.get("active_quest"), None)
    if not q: return
    if q.get("expires", 0) < time.time(): p["active_quest"] = None; save_player(p); return
    qtype = q.get("type"); text_l = text.lower().strip(); matched = False
    if qtype == "chat":
        if _phrase_matches(q.get("phrase",""), text): matched = True
    elif qtype == "targeted":
        phrase = q.get("phrase",""); tname = q.get("target_name","").lower(); tid = q.get("target_id")
        if _phrase_matches(phrase, text):
            if _phrase_norm(tname) in _phrase_norm(text) or (reply_to_id and reply_to_id == tid):
                matched = True
            elif not q.get("nudged"):
                # Right words, wrong aim — tell them instead of failing silently
                q["nudged"] = True
                p["active_quest"] = json.dumps(q); save_player(p)
                try:
                    await bot.send_message(p["user_id"],
                        f"🎱 _The oracle heard you… but the words weren't aimed._\n\n"
                        f"Say it *to {q.get('target_name','them')}*: **reply to one of their "
                        f"messages**, or include their name in your message. The task is still open.",
                        parse_mode="Markdown")
                except Exception:
                    pass
                return
    if not matched: return
    inf_r = q.get("reward_inf", 50)
    exp_r = exp_share(p["level"], min(0.15, q.get("reward_exp", 800) / 900 * 0.15))
    add_exp(p, exp_r); _add_influence(p, inf_r)
    add_item(p, "Greater Health Potion")
    p["active_quest"] = None; save_player(p)
    try: await bot.send_message(p["user_id"], f"✅ *Assignment complete.*\n\nThe Order takes note.\n\n+{fmt_num(exp_r)} EXP | +{inf_r} Influence | 🧪 Greater Health Potion", parse_mode="Markdown")
    except: pass

async def _try_complete_broadcast_quest(p, text, bot):
    global _broadcast_quest, _broadcast_claims
    if not _broadcast_quest: return
    if _broadcast_quest["expires"] < time.time():
        _broadcast_quest = None; _broadcast_claims = set(); return
    uid = p["user_id"]
    if uid in _broadcast_claims: return
    if not _phrase_matches(_broadcast_quest["phrase"], text): return
    exp = _broadcast_quest["exp"]
    add_exp(p, exp)
    save_player(p)
    _broadcast_claims.add(uid)
    try:
        await bot.send_message(uid,
            f"✅ *Quest Complete!*\n\n_{_broadcast_quest['phrase']}_\n\n+{fmt_num(exp)} EXP rewarded!",
            parse_mode="Markdown")
    except: pass

# ─── Alliance Main Menu Helper ──────────────────────────────
async def _alliance_main_menu(update_or_none, p, query=None):
    aid = p.get("alliance_id")
    a = get_alliance(aid) if aid else None
    if a:
        members = sjl(a.get("members"), [])
        n = len(members); pool = a.get("influence_pool", 0)
        is_leader = (a.get("leader_id") == p["user_id"])
        leader_p = get_player(a.get("leader_id"))
        leader_name = leader_p.get("username","Unknown") if leader_p else "Unknown"
        role = "👑 *Order Leader*" if is_leader else "⚔️ *Order Member*"
        text = (f"⚔️ *{a['name']}*\n\n{role}\nMembers: {n}/30  •  Pool: {pool:,}\nLeader: @{leader_name}")
        kb = [[InlineKeyboardButton("👥 Members", callback_data="allianceM"),
               InlineKeyboardButton("🎁 Perks", callback_data="allianceP")]]
        if is_leader:
            kb.append([InlineKeyboardButton("📨 Invite", callback_data="allianceInv"),
                       InlineKeyboardButton("💀 Disband", callback_data="allianceDis")])
        else:
            kb.append([InlineKeyboardButton("🚪 Leave Order", callback_data="allianceLv")])
        kb.append([InlineKeyboardButton("❌ Close", callback_data="allianceX")])
    else:
        text = ("⚔️ *Secret Orders*\n\nYou are not bound to any order.\n\n"
                "_Orders are cross-guild alliances of up to 30 members. They span multiple guilds, share an influence pool, and unlock perks together._")
        kb = [[InlineKeyboardButton("📜 Found an Order", callback_data="allianceFnd"),
               InlineKeyboardButton("🔍 Browse Orders", callback_data="allianceBrw")],
              [InlineKeyboardButton("❌ Close", callback_data="allianceX")]]
    markup = InlineKeyboardMarkup(kb)
    if query:
        try: await _q_edit(query, text, parse_mode="Markdown", reply_markup=markup)
        except: pass
    else:
        await send_group(update_or_none, text, reply_markup=markup, permanent=True)

async def alliance_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user
    p = get_player(user.id)
    if not p: await send_group(update, "Use /ascend first!", delay=9); return

    # Reply-to invite flow
    if update.message and update.message.reply_to_message:
        du = update.message.reply_to_message.from_user
        if du.is_bot:
            await send_group(update, "You can't invite a bot to your order!", delay=9); return
        if du.id == user.id:
            await send_group(update, "You can't invite yourself!", delay=9); return
        aid = p.get("alliance_id")
        if not aid:
            await send_group(update, "You're not in an order! Use /alliance to create or join one.", delay=9); return
        a = get_alliance(aid)
        if not a:
            await send_group(update, "Order not found.", delay=9); return
        if a.get("leader_id") != user.id:
            await send_group(update, "Only the order leader can send invites.", delay=9); return
        members = sjl(a.get("members"), [])
        if len(members) >= 30:
            await send_group(update, "Your order is full (30 members max).", delay=9); return
        if du.id in members:
            await send_group(update, f"{du.first_name} is already in your order!", delay=9); return
        tp = get_player(du.id)
        if not tp:
            await send_group(update, f"{du.first_name} hasn't ascended yet!", delay=9); return
        if tp.get("alliance_id"):
            await send_group(update, f"{du.first_name} is already in an order!", delay=9); return
        pending_alliance_inv[user.id] = {
            "target_id":  du.id,
            "alliance_id": aid,
            "chat_id":    update.effective_chat.id,
            "expires":    (datetime.now() + timedelta(minutes=5)).isoformat(),
        }
        a_name = _social_name(user)
        d_name = _social_name(du)
        markup = InlineKeyboardMarkup([[
            InlineKeyboardButton("⚔️ Accept",  callback_data=f"ainv_accept_{user.id}"),
            InlineKeyboardButton("❌ Decline", callback_data=f"ainv_decline_{user.id}"),
        ]])
        await send_group(update,
            f"⚔️ {a_name} invites {d_name} to join *{a['name']}*!\n\n"
            f"_{du.first_name}, do you accept?_\n_Expires in 5m._",
            permanent=False, delay=300, reply_markup=markup)
        return

    await _social_hub(update, p)


async def alliance_invite_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    await query.answer()
    parts = query.data.split("_")
    action    = parts[1]
    inviter_id = int(parts[2])

    inv = pending_alliance_inv.get(inviter_id)
    if not inv:
        await _q_edit(query, "⚔️ This invite has already expired.", parse_mode="Markdown"); return
    if datetime.now() > datetime.fromisoformat(inv["expires"]):
        pending_alliance_inv.pop(inviter_id, None)
        await _q_edit(query, "⚔️ This invite has expired.", parse_mode="Markdown"); return
    if query.from_user.id != inv["target_id"]:
        await query.answer("This invite isn't for you!", show_alert=True); return

    pending_alliance_inv.pop(inviter_id, None)

    if action == "decline":
        await _q_edit(query, 
            f"❌ *{query.from_user.first_name}* declined the order invitation.",
            parse_mode="Markdown"); return

    tp = get_player(inv["target_id"])
    if not tp:
        await _q_edit(query, "❌ Player data not found.", parse_mode="Markdown"); return
    if tp.get("alliance_id"):
        await _q_edit(query, "❌ You're already in an order!", parse_mode="Markdown"); return

    a = get_alliance(inv["alliance_id"])
    if not a:
        await _q_edit(query, "❌ That order no longer exists.", parse_mode="Markdown"); return

    members = sjl(a.get("members"), [])
    if len(members) >= 30:
        await _q_edit(query, "❌ That order is now full!", parse_mode="Markdown"); return
    if inv["target_id"] in members:
        await _q_edit(query, "❌ You're already a member!", parse_mode="Markdown"); return

    members.append(inv["target_id"])
    a["members"] = json.dumps(members)
    save_alliance(a)
    tp["alliance_id"] = inv["alliance_id"]
    save_player(tp)

    await _q_edit(query, 
        f"⚔️ *{query.from_user.first_name}* joined *{a['name']}*!\n\n"
        f"_Welcome to the order, adventurer._",
        parse_mode="Markdown")

async def alliance_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query; await query.answer()
    user = query.from_user
    p = get_player(user.id)
    if not p: await query.answer("Use /ascend first!", show_alert=True); return
    data = query.data
    aid = p.get("alliance_id"); a = get_alliance(aid) if aid else None

    if data == "allianceX":
        try: await query.message.delete()
        except: pass
        return
    if data == "allianceBk":
        await _alliance_main_menu(None, p, query=query); return

    if data == "allianceM":
        if not a: await query.answer("Not in an order.", show_alert=True); return
        members = sjl(a.get("members"), [])
        lines = [f"👥 *{a['name']} — Members*\n"]
        for mid in members:
            mp = get_player(mid)
            if not mp: continue
            role = "👑" if mid == a.get("leader_id") else "⚔️"
            lines.append(f"{role} @{mp['username']}  •  {get_fame_tier(mp.get('influence',0))}")
        kb = [[InlineKeyboardButton("🔙 Back", callback_data="allianceBk"),
               InlineKeyboardButton("❌ Close", callback_data="allianceX")]]
        await _q_edit(query, "\n".join(lines), parse_mode="Markdown", reply_markup=InlineKeyboardMarkup(kb)); return

    if data == "allianceP":
        if not a: await query.answer("Not in an order.", show_alert=True); return
        pool = a.get("influence_pool", 0)
        lines = [f"🎁 *{a['name']} — Perks*\n", f"Influence Pool: *{pool:,}*\n",
                 "✅ Brotherhood — Members below 30% HP gain +10 DEF",
                 "✅ Shared Whispers — Secret quest EXP doubled",
                 "✅ Pooled Wisdom — +2% influence gains"]
        lines.append(("✅ " if pool >= 100 else f"🔒 _(need {100-pool} more)_ ") +
                     "Marked Path — +5% gold from encounters")
        lines.append(("✅ " if pool >= 500 else f"🔒 _(need {500-pool} more)_ ") +
                     "Blood Pact — +5% damage vs non-alliance in arena")
        lines.append(("✅ " if pool >= 1000 else f"🔒 _(need {1000-pool} more)_ ") +
                     "Oracle's Eye — /secrets unlocks one extra tier")
        kb = [[InlineKeyboardButton("🔙 Back", callback_data="allianceBk"),
               InlineKeyboardButton("❌ Close", callback_data="allianceX")]]
        await _q_edit(query, "\n".join(lines), parse_mode="Markdown", reply_markup=InlineKeyboardMarkup(kb)); return

    if data == "allianceFnd":
        if a: await query.answer("Already in an order.", show_alert=True); return
        context.user_data["awaiting_alliance_name"] = query.message.message_id
        await _q_edit(query, 
            "📜 *Found a Secret Order*\n\nReply to this DM with the name for your order _(max 20 chars, unique)_.",
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup([[InlineKeyboardButton("❌ Cancel", callback_data="allianceX")]])); return

    if data == "allianceBrw":
        alliances = get_all_alliances()
        if not alliances:
            await _q_edit(query, "🔍 *Orders*\n\nNo orders founded yet. Be the first.",
                parse_mode="Markdown",
                reply_markup=InlineKeyboardMarkup([[InlineKeyboardButton("🔙 Back", callback_data="allianceBk"),
                    InlineKeyboardButton("❌ Close", callback_data="allianceX")]])); return
        lines = ["🔍 *Secret Orders*\n"]; kb_rows = []
        for al in alliances[:8]:
            mbs = sjl(al.get("members"), []); pool = al.get("influence_pool", 0); n2 = len(mbs)
            lines.append(f"⚔️ *{al['name']}*  —  {n2}/30  •  Pool: {pool:,}")
            if n2 < 30 and al["id"] != (aid or ""):
                kb_rows.append([InlineKeyboardButton(f"Join {al['name']}", callback_data=f"allianceJn_{al['id']}")])
        kb_rows.append([InlineKeyboardButton("🔙 Back", callback_data="allianceBk"),
                        InlineKeyboardButton("❌ Close", callback_data="allianceX")])
        await _q_edit(query, "\n".join(lines), parse_mode="Markdown", reply_markup=InlineKeyboardMarkup(kb_rows)); return

    if data.startswith("allianceJn_"):
        join_aid = data[len("allianceJn_"):]
        if aid: await query.answer("Leave your current order first.", show_alert=True); return
        ta = get_alliance(join_aid)
        if not ta: await query.answer("Order not found.", show_alert=True); return
        mbs = sjl(ta.get("members"), [])
        if len(mbs) >= 30: await query.answer("Order is full.", show_alert=True); return
        mbs.append(p["user_id"]); ta["members"] = json.dumps(mbs); save_alliance(ta)
        p["alliance_id"] = join_aid; save_player(p)
        await query.answer(f"You joined {ta['name']}!", show_alert=True)
        await _alliance_main_menu(None, get_player(p["user_id"]), query=query); return

    if data == "allianceLv":
        if not a: await query.answer("Not in an order.", show_alert=True); return
        if a.get("leader_id") == p["user_id"]: await query.answer("Leaders must disband.", show_alert=True); return
        mbs = sjl(a.get("members"), []); mbs = [m for m in mbs if m != p["user_id"]]
        a["members"] = json.dumps(mbs); save_alliance(a); p["alliance_id"] = None; save_player(p)
        await query.answer(f"You left {a['name']}.", show_alert=True)
        await _alliance_main_menu(None, get_player(p["user_id"]), query=query); return

    if data == "allianceDis":
        if not a or a.get("leader_id") != p["user_id"]: await query.answer("Leaders only.", show_alert=True); return
        await _q_edit(query, f"⚠️ *Disband {a['name']}?*\n\nThis removes all members and cannot be undone.",
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup([[
                InlineKeyboardButton("💀 Yes, Disband", callback_data="allianceDis2"),
                InlineKeyboardButton("❌ Cancel", callback_data="allianceBk")]])); return

    if data == "allianceDis2":
        if not a or a.get("leader_id") != p["user_id"]: await query.answer("Not authorized.", show_alert=True); return
        for mid in sjl(a.get("members"), []):
            mp = get_player(mid)
            if mp: mp["alliance_id"] = None; save_player(mp)
        delete_alliance(aid)
        await query.answer("Order disbanded.", show_alert=True)
        await _alliance_main_menu(None, get_player(p["user_id"]), query=query); return

    if data == "allianceInv":
        if not a or a.get("leader_id") != p["user_id"]: await query.answer("Leaders only.", show_alert=True); return
        mbs_inv = sjl(a.get("members"), [])
        if len(mbs_inv) >= 30: await query.answer("Order is full (30/30).", show_alert=True); return
        _iconn = _connect_db(); _ic = _iconn.cursor()
        _ic.execute("SELECT user_id, username FROM players WHERE level >= 1 ORDER BY level DESC LIMIT 40")
        _all_pl = [{"id": r[0], "username": r[1]} for r in _ic.fetchall()]; _iconn.close()
        candidates = [pl for pl in _all_pl if pl["id"] not in mbs_inv and pl["id"] != p["user_id"]][:20]
        if not candidates:
            await query.answer("No eligible players to invite.", show_alert=True); return
        inv_kb = []
        for pl in candidates:
            inv_kb.append([InlineKeyboardButton(f"+ @{pl['username']}", callback_data=f"allianceAdd_{pl['id']}")])
        inv_kb.append([InlineKeyboardButton("🔙 Back", callback_data="allianceBk"),
                       InlineKeyboardButton("❌ Close", callback_data="allianceX")])
        await _q_edit(query, 
            f"📨 *Invite to {a['name']}* ({len(mbs_inv)}/30)\n\nSelect a player to add to the order:",
            parse_mode="Markdown", reply_markup=InlineKeyboardMarkup(inv_kb)); return

    if data.startswith("allianceAdd_"):
        if not a or a.get("leader_id") != p["user_id"]: await query.answer("Leaders only.", show_alert=True); return
        mbs_add = sjl(a.get("members"), [])
        if len(mbs_add) >= 30: await query.answer("Order is full.", show_alert=True); return
        try: invite_uid = int(data[len("allianceAdd_"):])
        except ValueError: await query.answer("Invalid player.", show_alert=True); return
        if invite_uid in mbs_add: await query.answer("Already a member.", show_alert=True); return
        ip = get_player(invite_uid)
        if not ip: await query.answer("Player not found.", show_alert=True); return
        if ip.get("alliance_id"): await query.answer(f"@{ip['username']} is already in another order.", show_alert=True); return
        mbs_add.append(invite_uid); a["members"] = json.dumps(mbs_add); save_alliance(a)
        ip["alliance_id"] = a["id"]; save_player(ip)
        try:
            await context.bot.send_message(invite_uid,
                f"⚔️ You have been added to the Secret Order *{a['name']}* by @{p['username']}.\nUse /alliance to view your order.",
                parse_mode="Markdown")
        except: pass
        await query.answer(f"@{ip['username']} added to {a['name']}!", show_alert=True)
        await _alliance_main_menu(None, get_player(p["user_id"]), query=query); return

