async def megaphone_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if update.effective_chat.type != "private":
        try: await update.message.delete()
        except: pass
        return
    text = " ".join(context.args).strip() if context.args else ""
    if not text:
        await update.message.reply_text("Usage: /megaphone <your message>")
        return
    s = get_shadow(update.effective_user.id)
    home_group = (s.get("home_group") if s else None) or _megaphone_state.get("group")
    if not home_group:
        try:
            c = _db().cursor()
            c.execute("SELECT home_group FROM shadow_profiles WHERE home_group IS NOT NULL LIMIT 1")
            row = c.fetchone()
            if row: home_group = row[0]
        except Exception:
            pass
    if not home_group:
        await update.message.reply_text("Couldn't find the group. Use any command in the group first, then try again.")
        return
    try:
        await context.bot.send_message(home_group, text)
        await update.message.reply_text("📣 Sent.")
    except Exception:
        await update.message.reply_text("Failed to send — make sure the bot is still in the group.")

