_ORACLE_RESP = [
    ("It is certain.","pos"),("Without a doubt.","pos"),("Signs point to yes.","pos"),
    ("Outlook good.","pos"),("The stars align.","pos"),("Undeniably.","pos"),("As I see it, yes.","pos"),
    ("Ask again later.","neu"),("Cannot predict now.","neu"),("Concentrate and ask again.","neu"),
    ("Reply hazy, try again.","neu"),("The void is quiet today.","neu"),
    ("Don't count on it.","neg"),("Outlook not so good.","neg"),("Very doubtful.","neg"),
    ("My sources say no.","neg"),("The shadows say otherwise.","neg"),("Better left unknown.","neg"),
]

async def oracle_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    p = get_player(update.effective_user.id)
    if not p: await send_group(update, "Use /ascend first!", delay=9); return
    inv = sjl(p.get("inventory"), [])
    eight_balls = ["Cracked 8-Ball","Magic 8-Ball","Enchanted 8-Ball","Ancient 8-Ball","Void 8-Ball"]
    has_ball = (any(b in inv for b in eight_balls) or
                any(p.get(s) in eight_balls for s in ("equipped_accessory","equipped_hat","equipped_mask")))
    if not has_ball:
        await send_group(update, "🎱 You need a *Magic 8-Ball* (or better) to consult the oracle.\n\n_Rare drops from bosses._", delay=9); return
    if time.time() - p.get("oracle_last_used", 0) < 72000:
        rem = int(72000 - (time.time() - p.get("oracle_last_used", 0)))
        h, m = divmod(rem // 60, 60)
        await send_group(update, f"🎱 The oracle is resting. Returns in *{h}h {m}m*.", delay=9); return
    resp, tone = random.choice(_ORACLE_RESP)
    effects = {
        "pos": [("+5 LUK for 2 hours", lambda pp: set_status(pp,"blessed_until",7200)),
                ("+50 gold",            lambda pp: pp.update({"gold": pp.get("gold",0)+50})),
                ("+5 influence",        lambda pp: _add_influence(pp, 5))],
        "neu": [("The void offered nothing.", lambda pp: None)],
        "neg": [("-5 influence _(the ball has spoken)_", lambda pp: _add_influence(pp, -5))],
    }
    eff_desc, eff_fn = random.choice(effects.get(tone, effects["neu"]))
    eff_fn(p)
    p["oracle_last_used"] = int(time.time()); save_player(p)
    tone_icon = {"pos":"✨","neu":"🌫️","neg":"🌑"}.get(tone,"🎱")
    await send_group(update, f"🎱 *The Oracle Speaks...*\n\n\"{resp}\"\n\n{tone_icon} _{eff_desc}_", permanent=True)

# ── GUILD ─────────────────────────────────────────────────────────────────────
async def _social_hub(update_or_none, p, query=None):
    """Combined Guild + Party + Secret Order standing card."""
    gid = p.get("guild_id")
    g   = get_guild(gid) if gid and str(gid) not in ("None", "", "0") else None
    aid = p.get("alliance_id")
    a   = get_alliance(aid) if aid else None
    uid = p["user_id"]

    lines = ["🏰 *Your Social Standing*\n"]
    kb    = []

    # ── Guild ──
    if g:
        glvl   = safe_int(g.get("level"), 1)
        mcount = len(sjl(g.get("members", "[]"), []))
        wins   = safe_int(g.get("war_wins", 0))
        lines.append(f"🏰 *{g['name']}*  •  Lv {glvl} | {mcount} members | {wins}W")
        kb.append([InlineKeyboardButton("🏰 Guild Info",  callback_data=f"ginfo_{g['guild_id']}"),
                   InlineKeyboardButton("⚔️ Guild War",   callback_data="social_guildwar")])
    else:
        lines.append("🏰 *Guild:* _None_")
        kb.append([InlineKeyboardButton("🏰 Join Guild",   callback_data="social_gjoin"),
                   InlineKeyboardButton("+ Create Guild",  callback_data="social_gcreate")])

    lines.append("")

    # ── Party ──
    _sh_party = _get_party_of(uid)
    if _sh_party:
        _sh_members = _get_party_members(_sh_party["id"])
        pname_str = _party_display_name(_sh_party).replace("*","")
        lines.append(f"⚔️ *Party:* {pname_str}  •  {len(_sh_members)} members")
        is_leader = _sh_party["leader_id"] == uid
        if is_leader:
            kb.append([InlineKeyboardButton("⚔️ View Party", callback_data="social_party_view"),
                       InlineKeyboardButton("🚪 Disband",    callback_data="social_party_disband")])
        else:
            kb.append([InlineKeyboardButton("⚔️ View Party", callback_data="social_party_view"),
                       InlineKeyboardButton("🚪 Leave Party", callback_data="social_party_leave")])
    else:
        lines.append("⚔️ *Party:* _None_\n_Reply to a player with /party to invite them_")
        kb.append([InlineKeyboardButton("⚔️ Party Info", callback_data="social_party_view")])

    lines.append("")

    # ── Secret Order ──
    if a:
        amcount  = len(sjl(a.get("members", "[]"), []))
        pool     = a.get("influence_pool", 0)
        is_lead  = a.get("leader_id") == uid
        role_tag = "👑 Leader" if is_lead else "⚔️ Member"
        lines.append(f"🕵️ *{a['name']}*  •  {amcount}/30 | Pool: {pool:,}\n_{role_tag}_")
        kb.append([InlineKeyboardButton("🕵️ Manage Order", callback_data="social_alliance")])
    else:
        lines.append("🕵️ *Secret Order:* _None_\n_Cross-guild alliances · up to 30 members_")
        kb.append([InlineKeyboardButton("🕵️ Found an Order", callback_data="allianceFnd"),
                   InlineKeyboardButton("🔍 Browse Orders",  callback_data="allianceBrw")])

    kb.append([InlineKeyboardButton("❌ Close", callback_data="socialX")])
    markup = InlineKeyboardMarkup(kb)
    text   = "\n".join(lines)

    if query:
        try: await _q_edit(query, text, parse_mode="Markdown", reply_markup=markup)
        except: pass
    else:
        await send_group(update_or_none, text, reply_markup=markup, permanent=True)


async def social_hub_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query; await query.answer()
    user  = query.from_user
    p     = get_player(user.id)
    data  = query.data

    if data == "socialX":
        try: await query.message.delete()
        except: pass
        return

    if data == "social_hub":
        if not p: await query.answer("Use /ascend first!", show_alert=True); return
        await _social_hub(None, get_player(p["user_id"]), query=query); return

    if not p: await query.answer("Use /ascend first!", show_alert=True); return

    if data == "social_party_leave":
        party = _get_party_of(p["user_id"])
        if not party:
            await query.answer("You're not in a party.", show_alert=True); return
        _leave_party(p["user_id"])
        await query.answer("You left the party.", show_alert=False)
        await _social_hub(None, get_player(p["user_id"]), query=query)
        return

    if data == "social_party_disband":
        party = _get_party_of(p["user_id"])
        if not party or party["leader_id"] != p["user_id"]:
            await query.answer("You're not the party leader.", show_alert=True); return
        members = _get_party_members(party["id"])
        for mid in members:
            _leave_party(mid)
        await query.answer("Party disbanded.", show_alert=False)
        await _social_hub(None, get_player(p["user_id"]), query=query)
        return

    if data == "social_party_close":
        try: await query.message.delete()
        except Exception: pass
        return

    if data == "social_party_view":
        # Redirect to the full party menu
        await _party_menu(None, get_player(p["user_id"]) or p, query=query); return

    if data == "social_party_invite_info":
        party = _get_party_of(p["user_id"])
        if not party:
            await query.answer("You're not in a party.", show_alert=True); return
        try:
            await _q_edit(query, 
                "📨 *Invite to Party*\n\n"
                "To invite someone:\n"
                "• *Reply* to their message with `/party`\n"
                "• Or type `/partyinvite @username`\n\n"
                "_They'll receive a DM with Accept/Decline buttons._",
                parse_mode="Markdown",
                reply_markup=InlineKeyboardMarkup([[
                    InlineKeyboardButton("← Back", callback_data="social_party_view")
                ]]))
        except Exception: pass
        return

    if data == "social_party_rename_info":
        party = _get_party_of(p["user_id"])
        if not party or party["leader_id"] != p["user_id"]:
            await query.answer("Only the party leader can rename.", show_alert=True); return
        try:
            await _q_edit(query, 
                "✏️ *Rename Party*\n\nType in chat:\n`/partyname <new name>`",
                parse_mode="Markdown",
                reply_markup=InlineKeyboardMarkup([[
                    InlineKeyboardButton("← Back", callback_data="social_party_view")
                ]]))
        except Exception: pass
        return

    if data == "social_party_kick_menu":
        uid_k = p["user_id"]
        party = _get_party_of(uid_k)
        if not party or party["leader_id"] != uid_k:
            await query.answer("Only the party leader can kick.", show_alert=True); return
        members = _get_party_members(party["id"])
        others = [mid for mid in members if mid != uid_k]
        if not others:
            await query.answer("No members to kick.", show_alert=True); return
        lines = ["🚫 *Kick a Member*\n\nSelect a player to remove from the party:\n"]
        kb = []
        for mid in others:
            mp = get_player(mid)
            if not mp: continue
            kb.append([InlineKeyboardButton(
                f"🚫 {mp['username']} (Lv.{mp['level']})",
                callback_data=f"social_party_kick_{mid}")])
        kb.append([InlineKeyboardButton("← Back", callback_data="social_party_view")])
        try:
            await _q_edit(query, "\n".join(lines), parse_mode="Markdown",
                                          reply_markup=InlineKeyboardMarkup(kb))
        except Exception: pass
        return

    if data.startswith("social_party_kick_") and data != "social_party_kick_menu":
        uid_k = p["user_id"]
        try: target_uid = int(data.split("_")[-1])
        except (ValueError, IndexError):
            await query.answer("Invalid action.", show_alert=True); return
        party = _get_party_of(uid_k)
        if not party or party["leader_id"] != uid_k:
            await query.answer("Only the party leader can kick.", show_alert=True); return
        target_party = _get_party_of(target_uid)
        if not target_party or target_party["id"] != party["id"]:
            await query.answer("That player isn't in your party.", show_alert=True); return
        tp = get_player(target_uid)
        tp_name = tp["username"] if tp else str(target_uid)
        _leave_party(target_uid)
        # Notify kicked player
        try:
            await context.bot.send_message(
                chat_id=target_uid,
                text=f"🚫 You were removed from *{_party_display_name(party)}*.",
                parse_mode="Markdown")
        except Exception: pass
        await query.answer(f"🚫 {tp_name} was removed.", show_alert=False)
        await _party_menu(None, get_player(uid_k) or p, query=query)
        return

    if data == "social_gjoin":
        if p.get("guild_id") and str(p.get("guild_id")) not in ("None", ""):
            await query.answer("Already in a guild.", show_alert=True); return
        conn_sg = _connect_db(); conn_sg.row_factory = sqlite3.Row; c_sg = conn_sg.cursor()
        c_sg.execute("SELECT guild_id, name, level, members FROM guilds ORDER BY level DESC LIMIT 10")
        rows = [dict(r) for r in c_sg.fetchall()]; conn_sg.close()
        if not rows:
            await query.answer("No guilds yet — use /guildcreate to found one!", show_alert=True); return
        medals = ["🥇","🥈","🥉"] + ["🏰"]*7
        lines = ["🏰 *Join a Guild:*\n"]
        gj_kb = []
        for i, row in enumerate(rows):
            mcount = len(sjl(row["members"], []))
            lines.append(f"{medals[i]} *{row['name']}*  Lv {safe_int(row['level'],1)} | {mcount} members")
            gj_kb.append([InlineKeyboardButton(f"Join {row['name']}", callback_data=f"guildjoin_{row['guild_id']}")])
        gj_kb.append([InlineKeyboardButton("🔙 Back", callback_data="social_hub")])
        await _q_edit(query, "\n".join(lines), parse_mode="Markdown",
                                      reply_markup=InlineKeyboardMarkup(gj_kb)); return

    if data == "social_gcreate":
        await _q_edit(query, 
            "🏰 *Create a Guild*\n\nType in chat:\n`/guildcreate [name]`\n\n_Costs 100 gold._",
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup([[InlineKeyboardButton("🔙 Back", callback_data="social_hub")]])); return

    if data == "social_alliance":
        await _alliance_main_menu(None, p, query=query); return

    if data == "social_guildwar":
        if not p.get("guild_id") or str(p.get("guild_id")) in ("None", ""):
            await query.answer("You need a guild for guild wars.", show_alert=True); return
        await _q_edit(query, 
            "⚔️ Use `/guildwar` in chat to declare or check active wars.",
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup([[InlineKeyboardButton("🔙 Back", callback_data="social_hub")]])); return


async def guild_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user
    p = get_player(user.id)
    if not p: await send_group(update, "Use /ascend first!", delay=9); return

    # Reply-to invite flow
    if update.message and update.message.reply_to_message:
        du = update.message.reply_to_message.from_user
        if du.is_bot:
            await send_group(update, "You can't invite a bot to your guild!", delay=9); return
        if du.id == user.id:
            await send_group(update, "You can't invite yourself!", delay=9); return
        gid = p.get("guild_id")
        if not gid or str(gid) in ("None", "", "0"):
            await send_group(update, "You're not in a guild! Use /guildcreate to start one.", delay=9); return
        g = get_guild(gid)
        if not g:
            await send_group(update, "Guild not found.", delay=9); return
        if g.get("leader_id") != user.id:
            await send_group(update, "Only the guild leader can send invites.", delay=9); return
        members = sjl(g.get("members"), [])
        if len(members) >= 50:
            await send_group(update, "Your guild is full (50 members max).", delay=9); return
        if du.id in members:
            await send_group(update, f"{du.first_name} is already in your guild!", delay=9); return
        tp = get_player(du.id)
        if not tp:
            await send_group(update, f"{du.first_name} hasn't ascended yet!", delay=9); return
        if tp.get("guild_id") and str(tp.get("guild_id")) not in ("None", "", "0"):
            await send_group(update, f"{du.first_name} is already in a guild!", delay=9); return
        pending_guild_inv[user.id] = {
            "target_id": du.id,
            "guild_id":  gid,
            "chat_id":   update.effective_chat.id,
            "expires":   (datetime.now() + timedelta(minutes=5)).isoformat(),
        }
        a_name = _social_name(user)
        d_name = _social_name(du)
        markup = InlineKeyboardMarkup([[
            InlineKeyboardButton("🏰 Accept",  callback_data=f"ginv_accept_{user.id}"),
            InlineKeyboardButton("❌ Decline", callback_data=f"ginv_decline_{user.id}"),
        ]])
        await send_group(update,
            f"🏰 {a_name} invites {d_name} to join *{g['name']}*!\n\n"
            f"_{du.first_name}, do you accept?_\n_Expires in 5m._",
            permanent=False, delay=300, reply_markup=markup)
        return

    await _social_hub(update, p)


async def guild_invite_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    await query.answer()
    parts = query.data.split("_")
    action     = parts[1]
    inviter_id = int(parts[2])

    inv = pending_guild_inv.get(inviter_id)
    if not inv:
        await _q_edit(query, "🏰 This invite has already expired.", parse_mode="Markdown"); return
    if datetime.now() > datetime.fromisoformat(inv["expires"]):
        pending_guild_inv.pop(inviter_id, None)
        await _q_edit(query, "🏰 This invite has expired.", parse_mode="Markdown"); return
    if query.from_user.id != inv["target_id"]:
        await query.answer("This invite isn't for you!", show_alert=True); return

    pending_guild_inv.pop(inviter_id, None)

    if action == "decline":
        await _q_edit(query, 
            f"❌ *{query.from_user.first_name}* declined the guild invitation.",
            parse_mode="Markdown"); return

    tp = get_player(inv["target_id"])
    if not tp:
        await _q_edit(query, "❌ Player data not found.", parse_mode="Markdown"); return
    if tp.get("guild_id") and str(tp.get("guild_id")) not in ("None", "", "0"):
        await _q_edit(query, "❌ You're already in a guild!", parse_mode="Markdown"); return

    g = get_guild(inv["guild_id"])
    if not g:
        await _q_edit(query, "❌ That guild no longer exists.", parse_mode="Markdown"); return

    members = sjl(g.get("members"), [])
    if len(members) >= 50:
        await _q_edit(query, "❌ That guild is now full!", parse_mode="Markdown"); return
    if inv["target_id"] in members:
        await _q_edit(query, "❌ You're already a member!", parse_mode="Markdown"); return

    members.append(inv["target_id"])
    g["members"] = json.dumps(members)
    save_guild(g)
    tp["guild_id"] = inv["guild_id"]
    save_player(tp)

    await _q_edit(query, 
        f"🏰 *{query.from_user.first_name}* joined *{g['name']}*!\n\n"
        f"_Welcome to the guild, adventurer._",
        parse_mode="Markdown")


async def guildcreate_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user; p = get_player(user.id)
    if not p:
        await send_group(update, "Use /ascend first!", delay=9); return
    if not context.args:
        await send_group(update, "Usage: /guildcreate [name]", delay=9); return
    if p.get("guild_id") and str(p.get("guild_id")) != "None":
        await send_group(update, "You're already in a guild!", delay=9); return
    if p.get("gold",0) < 100:
        await send_group(update, "Need 100 gold to found a hall!", delay=9); return
    name = " ".join(context.args)
    conn = _connect_db(); c = conn.cursor()
    try:
        c.execute("INSERT INTO guilds (name,leader_id,members,level,exp,bank) VALUES(?,?,?,1,0,0)",
                  (name, user.id, json.dumps([user.id])))
        conn.commit(); gid = c.lastrowid
    except sqlite3.IntegrityError:
        await send_group(update, f"Guild '{name}' already exists!", delay=9)
        conn.close(); return
    conn.close()
    p["guild_id"] = gid; p["gold"] = p.get("gold",0) - 100
    award_title(p, "Guild Founder"); save_player(p)
    asyncio.create_task(announce(context.bot, update.effective_chat.id,
        f"🏰 *{name}* guild founded by *{user.first_name}*!"))
    await send_group(update, f"🏰 *{name}* founded!\n🏅 Title: *Guild Founder*!", delay=15)


async def guildjoin_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    user = query.from_user
    p = get_player(user.id)
    if not p:
        await query.answer("Use /ascend first!", show_alert=True); return
    if p.get("guild_id") and str(p.get("guild_id")) != "None":
        await query.answer("You're already in a guild!", show_alert=True); return
    gid = int(query.data.split("_")[-1])
    g = get_guild(gid)
    if not g:
        await query.answer("Guild no longer exists.", show_alert=True); return
    members = sjl(g["members"], [])
    if user.id in members:
        await query.answer("You're already in this guild.", show_alert=True); return
    members.append(user.id)
    g["members"] = json.dumps(members); save_guild(g)
    p["guild_id"] = gid
    p["guild_stat_bonus"] = _guild_stat_bonus_for_level(safe_int(g.get("level"), 1))
    save_player(p)
    asyncio.create_task(announce(context.bot, query.message.chat.id,
        f"🏰 *{user.first_name}* joined *{g['name']}*!"))
    await query.answer()
    await _q_edit(query, f"✅ You joined *{g['name']}*!", parse_mode="Markdown")


async def guildjoin_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user; p = get_player(user.id)
    if not p:
        await send_group(update, "Use /ascend first!", delay=9); return
    if p.get("guild_id") and str(p.get("guild_id")) != "None":
        await send_group(update, "You're already in a guild! Use /guildleave first.", delay=9); return
    conn = _connect_db(); conn.row_factory = sqlite3.Row; c = conn.cursor()
    c.execute("SELECT guild_id,name,level,members FROM guilds ORDER BY level DESC LIMIT 10")
    rows = c.fetchall(); conn.close()
    if not rows:
        await send_group(update, "No halls exist yet  -  use /guildcreate to found one!", delay=9); return
    medals = ["🥇","🥈","🥉"] + ["🏰"]*7
    lines = ["🏰 *Available Guilds  -  tap to join:*\n"]
    buttons = []
    for i, row in enumerate(rows):
        mcount = len(sjl(row["members"], []))
        lines.append(f"{medals[i]} *{row['name']}*  -  Lv {safe_int(row['level'],1)} | {mcount} members")
        buttons.append([InlineKeyboardButton(
            f"Join {row['name']}", callback_data=f"guildjoin_{row['guild_id']}")])
    markup = InlineKeyboardMarkup(buttons)
    await send_group(update, "\n".join(lines), reply_markup=markup, delay=20)


def _build_guildinfo_overview(g, viewer_id=None):
    """Return (text, markup) for a guild overview card."""
    member_ids = sjl(g.get("members", "[]"), [])
    leader     = get_player(g["leader_id"])
    glvl       = safe_int(g.get("level"), 1)
    perk       = GUILD_PERKS.get(glvl, {})
    nxt        = guild_exp_for_level(glvl) if glvl < 10 else "MAX"
    wins       = safe_int(g.get("war_wins", 0))
    gid        = g["guild_id"]
    is_leader  = viewer_id and g["leader_id"] == viewer_id
    text = (
        f"🏰 *{g['name']}*\n"
        f"👑 Leader: {leader['username'] if leader else '?'}\n"
        f"⭐ Level: {glvl}/10  |  EXP: {safe_int(g.get('exp'))}/{nxt}\n"
        f"🏆 War Wins: {wins}\n"
        f"💰 Bank: {safe_int(g.get('bank'))}g\n"
        f"🎁 Perks: _{perk.get('desc', 'None')}_"
    )
    rows = [[InlineKeyboardButton(f"👥 Members ({len(member_ids)})", callback_data=f"ginfoM_{gid}")]]
    if is_leader:
        rows.append([InlineKeyboardButton("✏️ Rename Guild", callback_data=f"grename_{gid}")])
    rows.append([InlineKeyboardButton("🔙 All Guilds", callback_data="ginfoList"),
                 InlineKeyboardButton("🏠 Social Hub",  callback_data="social_hub")])
    markup = InlineKeyboardMarkup(rows)
    return text, markup


async def guildinfo_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user; p = get_player(user.id)
    if not p:
        await send_group(update, "Use /ascend first!", delay=9); return

    # /guildinfo [Hall Name] — direct typed lookup
    if context.args:
        target_name = " ".join(context.args)
        g = get_guild_by_name(target_name)
        if not g:
            await send_group(update, f"Guild *{target_name}* not found.", delay=9); return
        text, markup = _build_guildinfo_overview(g, viewer_id=user.id)
        await send_group(update, text, reply_markup=markup, delay=25)
        return

    # No args — show all halls as a button list
    conn_gi = _connect_db(); conn_gi.row_factory = sqlite3.Row; c_gi = conn_gi.cursor()
    c_gi.execute("SELECT guild_id, name, level, members, war_wins FROM guilds ORDER BY level DESC, war_wins DESC LIMIT 15")
    rows = [dict(r) for r in c_gi.fetchall()]; conn_gi.close()

    if not rows:
        await send_group(update, "No halls exist yet. Use /guildcreate to found one!", delay=9); return

    my_gid = str(p.get("guild_id", ""))
    lines  = ["🏰 *Guilds  —  tap to inspect:*\n"]
    buttons = []
    medals  = ["🥇", "🥈", "🥉"] + ["🏰"] * 12
    for i, row in enumerate(rows):
        mcount = len(sjl(row["members"], []))
        star   = " ⭐" if str(row["guild_id"]) == my_gid else ""
        lines.append(f"{medals[i]} *{row['name']}*  Lv {safe_int(row['level'], 1)} | {mcount} members | {safe_int(row['war_wins'])}W{star}")
        buttons.append([InlineKeyboardButton(
            f"🏰 {row['name']}", callback_data=f"ginfo_{row['guild_id']}")])

    await send_group(update, "\n".join(lines), reply_markup=InlineKeyboardMarkup(buttons), delay=30)


async def guildinfo_view_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Show guild overview card when a hall is selected."""
    query = update.callback_query
    try:
        gid = int(query.data.split("_", 1)[1])
    except (IndexError, ValueError):
        await query.answer(); return
    g = get_guild(gid)
    if not g:
        await query.answer("Guild no longer exists.", show_alert=True); return
    text, markup = _build_guildinfo_overview(g, viewer_id=query.from_user.id)
    await query.answer()
    await _q_edit(query, text, reply_markup=markup, parse_mode="Markdown")


async def guildinfo_members_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Show member list for a guild."""
    query = update.callback_query
    try:
        gid = int(query.data.split("_", 1)[1])
    except (IndexError, ValueError):
        await query.answer(); return
    g = get_guild(gid)
    if not g:
        await query.answer("Guild no longer exists.", show_alert=True); return

    member_ids = sjl(g.get("members", "[]"), [])
    member_rows = []
    if member_ids:
        conn_m = _connect_db(); conn_m.row_factory = sqlite3.Row; c_m = conn_m.cursor()
        placeholders = ",".join("?" * len(member_ids))
        c_m.execute(
            f"SELECT username, level, class_id FROM players WHERE user_id IN ({placeholders})"
            f" ORDER BY level DESC", member_ids)
        member_rows = [dict(r) for r in c_m.fetchall()]
        conn_m.close()

    lines = [f"👥 *{g['name']} — Members ({len(member_ids)})*\n"]
    for r in member_rows:
        cls = CLASS_TREE.get(r["class_id"] or "", {}).get("name", "No Class")
        lines.append(f"• *{r['username']}* — Lv {r['level']} {cls}")
    if not member_rows:
        lines.append("(no registered members)")

    markup = InlineKeyboardMarkup([
        [InlineKeyboardButton("🔙 Back to Guild", callback_data=f"ginfo_{gid}")],
    ])
    await query.answer()
    await _q_edit(query, "\n".join(lines), reply_markup=markup, parse_mode="Markdown")


async def guildinfo_list_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Return to the full hall list."""
    query = update.callback_query
    conn_gl = _connect_db(); conn_gl.row_factory = sqlite3.Row; c_gl = conn_gl.cursor()
    c_gl.execute("SELECT guild_id, name, level, members, war_wins FROM guilds ORDER BY level DESC, war_wins DESC LIMIT 15")
    rows = [dict(r) for r in c_gl.fetchall()]; conn_gl.close()

    p = get_player(query.from_user.id)
    my_gid = str(p.get("guild_id", "")) if p else ""
    lines   = ["🏰 *Guilds  —  tap to inspect:*\n"]
    buttons = []
    medals  = ["🥇", "🥈", "🥉"] + ["🏰"] * 12
    for i, row in enumerate(rows):
        mcount = len(sjl(row["members"], []))
        star   = " ⭐" if str(row["guild_id"]) == my_gid else ""
        lines.append(f"{medals[i]} *{row['name']}*  Lv {safe_int(row['level'], 1)} | {mcount} members | {safe_int(row['war_wins'])}W{star}")
        buttons.append([InlineKeyboardButton(
            f"🏰 {row['name']}", callback_data=f"ginfo_{row['guild_id']}")])

    await query.answer()
    await _q_edit(query, "\n".join(lines), reply_markup=InlineKeyboardMarkup(buttons), parse_mode="Markdown")


