async def guildkick_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user; p = get_player(user.id)
    if not p:
        await send_group(update, "Use /ascend first!", delay=9); return
    if not p.get("guild_id"):
        await send_group(update, "You're not in a guild!", delay=9); return
    g = get_guild(p["guild_id"])
    if not g or g["leader_id"] != user.id:
        await send_group(update, "Only the guild leader can kick members.", delay=9); return

    def _do_kick(tp):
        members = sjl(g["members"], [])
        if tp["user_id"] in members: members.remove(tp["user_id"])
        g["members"] = json.dumps(members); save_guild(g)
        tp["guild_id"] = None; save_player(tp)

    # If replying to a message, kick that player directly
    if update.message.reply_to_message:
        ru = update.message.reply_to_message.from_user
        if not ru:
            await send_group(update, "Can't identify that user.", delay=9); return
        if ru.id == user.id:
            await send_group(update, "You can't kick yourself! Use /guilddisband to close the guild.", delay=9); return
        tp = get_player(ru.id)
        if not tp or str(tp.get("guild_id")) != str(p.get("guild_id")):
            await send_group(update, "That player isn't in your guild.", delay=9); return
        _do_kick(tp)
        await send_group(update, f"🚫 *{tp['username']}* has been kicked from *{g['name']}*.", delay=15)
        return

    # If name arg provided, search members by display name
    if context.args:
        query_name = " ".join(context.args).lower()
        members = sjl(g["members"], [])
        matches = []
        for mid in members:
            if mid == user.id: continue
            mp = get_player(mid)
            if mp and query_name in mp["username"].lower():
                matches.append(mp)
        if not matches:
            await send_group(update, f"No guild member matches *{' '.join(context.args)}*.", delay=9); return
        if len(matches) > 1:
            names = ", ".join(f"*{m['username']}*" for m in matches)
            await send_group(update, f"Multiple matches: {names}\nBe more specific.", delay=12); return
        tp = matches[0]
        _do_kick(tp)
        await send_group(update, f"🚫 *{tp['username']}* has been kicked from *{g['name']}*.", delay=15)
        return

    # No reply, no name — show member picker buttons
    members = sjl(g["members"], [])
    kickable = [mid for mid in members if mid != user.id]
    if not kickable:
        await send_group(update, "No members to kick.", delay=9); return

    buttons = []
    for mid in kickable:
        mp = get_player(mid)
        if mp:
            buttons.append([InlineKeyboardButton(
                f"🚫 {mp['username']} (Lv {mp['level']})",
                callback_data=f"gkick_{user.id}_{mid}")])

    if not buttons:
        await send_group(update, "No kickable members found.", delay=9); return

    markup = InlineKeyboardMarkup(buttons)
    await send_group(update,
        f"🚫 *{g['name']} — Kick a Member*\n\nTap a name to remove them from the guild:",
        delay=90, reply_markup=markup)


async def guildkick_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle member kick button."""
    query = update.callback_query
    await query.answer()
    parts = query.data.split("_", 2)
    try:
        uid = int(parts[1]); target_uid = int(parts[2])
    except (IndexError, ValueError):
        return
    if query.from_user.id != uid:
        await query.answer("Only the Guild leader can kick members!", show_alert=True); return

    p = get_player(uid)
    if not p:
        await _q_edit(query, "Player not found."); return
    g = get_guild(p.get("guild_id")) if p.get("guild_id") else None
    if not g or g.get("leader_id") != uid:
        await _q_edit(query, "Only the Guild leader can kick members."); return

    tp = get_player(target_uid)
    if not tp or str(tp.get("guild_id")) != str(g["guild_id"]):
        await _q_edit(query, "That player is no longer in your guild."); return
    if target_uid == uid:
        await _q_edit(query, "You can't kick yourself!"); return

    members = sjl(g["members"], [])
    if target_uid in members: members.remove(target_uid)
    g["members"] = json.dumps(members); save_guild(g)
    tp["guild_id"] = None; tp["guild_stat_bonus"] = 0; save_player(tp)
    await _q_edit(query, 
        f"🚫 *{tp['username']}* has been kicked from *{g['name']}*.",
        parse_mode="Markdown")


