    tradeable_pools = set(WEAPONS) | set(ARMORS) | set(SHIELDS) | set(ACCESSORIES) | set(CONSUMABLES)
    trade_items = [(k, inv.count(k)) for k in dict.fromkeys(inv) if k in tradeable_pools]
