async def _party_menu(update_or_none, p, query=None):
    """Show the party management menu card."""
    uid = p["user_id"]
    party = _get_party_of(uid)

    if not party:
        text = (
            "⚔️ *Party*\n\n"
            "You're not in a party.\n\n"
            "_Reply to a player in chat with /party to invite them.\n"
            "Party members earn *+25% EXP* from each other's Battle & Hunt encounters._"
        )
        kb = [[InlineKeyboardButton("❌ Close", callback_data="social_party_close")]]
        markup = InlineKeyboardMarkup(kb)
    else:
        members = _get_party_members(party["id"])
        pname = _party_display_name(party).strip("*")
        is_leader = party["leader_id"] == uid

        lines = [f"⚔️ *{pname}*  •  {len(members)} member{'s' if len(members) != 1 else ''}",
                 "_+25% EXP from all Battle & Hunt encounter wins._\n"]
        for mid in members:
            mp = get_player(mid)
            if not mp: continue
            you_tag = " _(you)_" if mid == uid else ""
            crown = " 👑" if mid == party["leader_id"] else ""
            lines.append(f"• *{mp['username']}* Lv.{mp['level']}{crown}{you_tag}")
        text = "\n".join(lines)

        kb = []
        if is_leader:
            kb.append([InlineKeyboardButton("📨 Invite",      callback_data="social_party_invite_info"),
                       InlineKeyboardButton("🚫 Kick Member", callback_data="social_party_kick_menu")])
            kb.append([InlineKeyboardButton("✏️ Rename",      callback_data="social_party_rename_info"),
                       InlineKeyboardButton("🗑️ Disband",     callback_data="social_party_disband")])
        else:
            kb.append([InlineKeyboardButton("🚪 Leave Party", callback_data="social_party_leave")])
        kb.append([InlineKeyboardButton("❌ Close", callback_data="social_party_close")])
        markup = InlineKeyboardMarkup(kb)

    if query:
        try: await _q_edit(query, text, parse_mode="Markdown", reply_markup=markup)
        except Exception: pass
    elif update_or_none:
        await send_group(update_or_none, text, reply_markup=markup, permanent=True)


async def party_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user
    p = get_player(user.id)
    if not p:
        await send_group(update, "Use /ascend first!", delay=9); return
    uid = user.id

    # Reply to someone → treat as /partyinvite
    if update.message and update.message.reply_to_message:
        du = update.message.reply_to_message.from_user
        if du and du.id != uid:
            target = get_player(du.id)
            if not target:
                await send_group(update, f"❌ {du.first_name} hasn't ascended yet.", delay=8); return
            if _get_party_of(du.id):
                await send_group(update, f"❌ *{target['username']}* is already in a party.", delay=8); return
            party = _get_party_of(uid)
            party_id = party["id"] if party else _create_party(uid)
            markup = InlineKeyboardMarkup([[
                InlineKeyboardButton("✅ Accept", callback_data=f"party_accept_{uid}_{du.id}_{party_id}"),
                InlineKeyboardButton("❌ Decline", callback_data=f"party_decline_{uid}_{du.id}"),
            ]])
            try:
                await context.bot.send_message(
                    chat_id=du.id,
                    text=f"⚔️ *{p['username']}* invited you to their party!\n\n"
                         f"_+25% EXP from all Battle & Hunt encounter wins._",
                    parse_mode="Markdown", reply_markup=markup)
                await send_group(update, f"📨 Party invite sent to *{target['username']}*!", delay=10)
            except Exception:
                await send_group(update, f"❌ Couldn't DM *{target['username']}* — they need to message the bot first.", delay=10)
            return

    await _party_menu(update, p)


async def partyinvite_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user
    p = get_player(user.id)
    if not p:
        await send_group(update, "Use /ascend first!", delay=9); return
    uid = user.id
    args = context.args
    if not args:
        await send_group(update, "Usage: `/partyinvite @username`", delay=8); return
    target_name = args[0].lstrip("@")
    target = get_player_by_username(target_name)
    if not target:
        await send_group(update, f"❌ Player '{target_name}' not found.", delay=8); return
    if target["user_id"] == uid:
        await send_group(update, "❌ You can't invite yourself.", delay=8); return
    if _get_party_of(target["user_id"]):
        await send_group(update, f"❌ *{target['username']}* is already in a party.", delay=8); return
    party = _get_party_of(uid)
    party_id = party["id"] if party else _create_party(uid)
    markup = InlineKeyboardMarkup([[
        InlineKeyboardButton("✅ Accept", callback_data=f"party_accept_{uid}_{target['user_id']}_{party_id}"),
        InlineKeyboardButton("❌ Decline", callback_data=f"party_decline_{uid}_{target['user_id']}"),
    ]])
    try:
        await context.bot.send_message(
            target["user_id"],
            f"⚔️ *{p['username']}* invites you to their party!\n"
            f"Party members earn *+25% EXP* from each other's encounters.",
            parse_mode="Markdown", reply_markup=markup)
        await send_group(update, f"✉️ Party invite sent to *{target['username']}*!", delay=8)
    except Exception:
        await send_group(update, f"❌ Couldn't DM *{target['username']}*. They need to start the bot first.", delay=10)


