_RARITY_ORDER = ["common", "uncommon", "rare", "epic", "legendary", "mythic"]

def _bulk_sellable(owner_id, mode):
    """Return (list_of_pets_to_sell, total_gold) for a bulk-sell mode.
    Never sells the active pet, shinies, or the highest-level copy of a species.
    mode: 'dupes' (extra copies of a species) or a rarity floor name."""
    pets = get_all_pets(owner_id)
    # best copy per species is protected (keeps your prize of each kind)
    best_of = {}
    for pt in pets:
        s = pt.get("species")
        if s not in best_of or safe_int(pt.get("level")) > safe_int(best_of[s].get("level")):
            best_of[s] = pt
    sell = []
    for pt in pets:
        if pt.get("is_active"): continue
        if pt.get("is_shiny"): continue          # never bulk-sell a shiny
        if best_of.get(pt.get("species")) is pt: continue  # keep the best of each species
        rar = PET_SPECIES.get(pt.get("species"), {}).get("rarity", "common")
        if mode == "dupes":
            sell.append(pt)
        elif mode in _RARITY_ORDER:
            # sell everything at or below the chosen rarity floor
            if _RARITY_ORDER.index(rar) <= _RARITY_ORDER.index(mode):
                sell.append(pt)
    total = sum(_pet_sell_price(pt) for pt in sell)
    return sell, total

def _bulk_sell_menu(owner_id):
    dupes, dupes_g = _bulk_sellable(owner_id, "dupes")
    unc, unc_g = _bulk_sellable(owner_id, "uncommon")
    rare, rare_g = _bulk_sellable(owner_id, "rare")
    lines = [
        "💰 *Bulk Sell Pets*\n",
        "_Protected always: your active pet, every shiny, and the highest-level copy of each species._\n",
        f"🔁 *Duplicates:* {len(dupes)} pets → *{dupes_g:,}g*",
        f"⚪ *Common+Uncommon dupes:* {len(unc)} → *{unc_g:,}g*",
        f"🔵 *Up to Rare dupes:* {len(rare)} → *{rare_g:,}g*",
    ]
    rows = []
    if dupes:
        rows.append([InlineKeyboardButton(f"🔁 Sell {len(dupes)} duplicates ({dupes_g:,}g)",
                     callback_data="petbulk_do_dupes")])
    if unc:
        rows.append([InlineKeyboardButton(f"⚪ Sell common+uncommon dupes ({unc_g:,}g)",
                     callback_data="petbulk_do_uncommon")])
    if rare:
        rows.append([InlineKeyboardButton(f"🔵 Sell up to rare dupes ({rare_g:,}g)",
                     callback_data="petbulk_do_rare")])
    if not rows:
        lines.append("\n_No duplicate pets to sell — every species is unique in your kennel._")
    rows.append([InlineKeyboardButton("🔙 All Pets", callback_data="petlist_0")])
    return "\n".join(lines), InlineKeyboardMarkup(rows)

async def petbulk_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    user = query.from_user
    data = query.data
    if data == "petbulk_menu":
        text, markup = _bulk_sell_menu(user.id)
        await _q_edit(query, text, parse_mode="Markdown", reply_markup=markup)
        await query.answer(); return
    if data.startswith("petbulk_do_"):
        mode = data.split("_", 2)[2]
        sell, total = _bulk_sellable(user.id, mode)
        if not sell:
            await query.answer("Nothing to sell in that group anymore.", show_alert=True)
            text, markup = _bulk_sell_menu(user.id)
            await _q_edit(query, text, parse_mode="Markdown", reply_markup=markup); return
        conn = _connect_db(); c = conn.cursor()
        ids = [safe_int(pt.get("pet_id")) for pt in sell if pt.get("pet_id") is not None]
        c.executemany("DELETE FROM pets WHERE pet_id=? AND owner_id=?",
                      [(pid, user.id) for pid in ids])
        conn.commit(); conn.close()
        p = get_player(user.id)
        if p:
            p["gold"] = safe_int(p.get("gold")) + total
            save_player(p)
        await query.answer(f"💰 Sold {len(ids)} pets for {total:,}g!")
        await _q_edit(query,
            f"💰 *Bulk sale complete!*\n\nSold *{len(ids)}* pets for *{total:,}g*.\n"
            f"_Your bestiary records are untouched — every species you've owned still counts._",
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup([[
                InlineKeyboardButton("📋 All Pets", callback_data="petlist_0"),
                InlineKeyboardButton("📖 Bestiary", callback_data="bestiary_0")]]))
        return

def _bestiary_page(p, page=0):
    dex = _pet_dex(p)
    n = len(dex)
    pct = round(n / max(1, _ALL_SPECIES_COUNT) * 100)
    cds = safe_cds(p)
    claimed = set(cds.get("bestiary_claimed") or [])
    lines = [f"📖 *{p['username']}'s Bestiary*",
             f"Collected *{n}/{_ALL_SPECIES_COUNT}* species  ({pct}%)",
             f"⚔️ Collector's Bond: *+{round(_collector_atk_pct(p['user_id'])*100)}% pet ATK*"]
    glob = _collector_global(p)
    if glob["gold_pct"] or glob["exp_pct"]:
        lines.append(f"🌟 Perks: +{round(glob['gold_pct']*100)}% gold, +{round(glob['exp_pct']*100)}% EXP")
    # milestone claim status
    claim_rows = []
    lines.append("")
    for idx, (need, perk, reward) in enumerate(_BESTIARY_MILESTONES):
        key = str(need)
        if n >= need and key not in claimed:
            lines.append(f"🎁 *{need} species — CLAIM READY!* ({perk})")
            claim_rows.append([InlineKeyboardButton(f"🎁 Claim {need}-species reward",
                               callback_data=f"bestiary_claim_{need}")])
        elif n >= need:
            lines.append(f"✅ {need} species — {perk} _(claimed)_")
        else:
            lines.append(f"🔒 {need} species — {perk}  _({need - n} to go)_")
    # species checklist by rarity, paged
    lines.append("")
    per_page = 3  # rarities per page
    rar_slice = _RARITY_ORDER[page*per_page:(page+1)*per_page]
    for rar in rar_slice:
        species = [(k, v) for k, v in PET_SPECIES.items() if v.get("rarity") == rar]
        got = sum(1 for k, _ in species if k in dex)
        lines.append(f"{RARITY_EMOJI.get(rar,'')} *{rar.capitalize()}* ({got}/{len(species)})")
        row = []
        for k, v in species:
            mark = v.get("emoji", "🐾") if k in dex else "❓"
            row.append(mark)
        lines.append("  " + " ".join(row))
    rows = list(claim_rows)
    nav = []
    if page > 0:
        nav.append(InlineKeyboardButton("◀️", callback_data=f"bestiary_{page-1}"))
    if (page+1)*per_page < len(_RARITY_ORDER):
        nav.append(InlineKeyboardButton("▶️", callback_data=f"bestiary_{page+1}"))
    if nav: rows.append(nav)
    rows.append([InlineKeyboardButton("📋 My Pets", callback_data="petlist_0"),
                 InlineKeyboardButton("❌ Close", callback_data="close_msg")])
    return "\n".join(lines), InlineKeyboardMarkup(rows)

async def bestiary_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user
    p = get_player(user.id)
    if not p:
        await send_group(update, "Use /ascend first!", delay=9); return
    text, markup = _bestiary_page(p, 0)
    await send_group(update, text, permanent=True, reply_markup=markup)

async def bestiary_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    user = query.from_user
    p = get_player(user.id)
    if not p:
        await query.answer("Use /ascend first!", show_alert=True); return
    data = query.data
    if data.startswith("bestiary_claim_"):
        need = int(data.split("_")[2])
        milestone = next((m for m in _BESTIARY_MILESTONES if m[0] == need), None)
        if not milestone:
            await query.answer(); return
        n = len(_pet_dex(p))
        cds = safe_cds(p)
        claimed = cds.get("bestiary_claimed") or []
        if n < need:
            await query.answer(f"You need {need} species first!", show_alert=True); return
        if str(need) in claimed:
            await query.answer("Already claimed!"); return
        _, perk, reward = milestone
        parts = []
        if reward.get("gold"):
            p["gold"] = safe_int(p.get("gold")) + reward["gold"]; parts.append(f"+{reward['gold']:,}g")
        if reward.get("stat_points"):
            p["stat_points"] = safe_int(p.get("stat_points")) + reward["stat_points"]
            parts.append(f"+{reward['stat_points']} stat points")
        if reward.get("item"):
            add_item(p, reward["item"]); parts.append(f"🥚 {reward['item']}")
        claimed.append(str(need)); cds["bestiary_claimed"] = claimed
        p["passive_cooldowns"] = json.dumps(cds)
        save_player(p)
        await query.answer(f"🎁 Claimed! {', '.join(parts)}")
        text, markup = _bestiary_page(p, 0)
        await _q_edit(query, text, parse_mode="Markdown", reply_markup=markup)
        return
    try:
        page = int(data.split("_")[1])
    except (IndexError, ValueError):
        page = 0
    text, markup = _bestiary_page(p, page)
    await _q_edit(query, text, parse_mode="Markdown", reply_markup=markup)
    await query.answer()

async def pet_main_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handles petmain, petlist_N, petview_ID, petactivate_ID, petfeed_ID, pettrain_ID, petrelease_ID"""
    query = update.callback_query
    user  = query.from_user
    data  = query.data

    if data == "petmain":
        p = get_player(user.id)
        pet = get_active_pet_record(user.id)
        if not pet:
            text = "🐾 No active pet. Get eggs from dungeons or the Pet Shop!"
            markup = _pet_main_markup()
        else:
            text = _build_pet_card(pet)
            pid = pet["pet_id"]
            adv_end = pet.get("adventure_ends_at")
            adv_btn = None
            if adv_end:
                try:
                    rem = (datetime.fromisoformat(adv_end) - datetime.now()).total_seconds()
                    if rem <= 0:
                        adv_btn = InlineKeyboardButton("🎉 Claim Adventure!", callback_data=f"petadv_status_{pid}")
                    else:
                        rm = f"{int(rem//3600)}h {int((rem%3600)//60)}m" if rem >= 3600 else f"{int(rem//60)}m"
                        adv_btn = InlineKeyboardButton(f"🗺️ Adventure ({rm})", callback_data=f"petadv_status_{pid}")
                except Exception:
                    adv_btn = InlineKeyboardButton("🗺️ Adventure", callback_data=f"petadv_pick_{pid}")
            else:
                adv_btn = InlineKeyboardButton("🗺️ Adventure", callback_data=f"petadv_pick_{pid}")
            # Job button state
            job_end = pet.get("job_ends_at")
            if job_end:
                try:
                    _jrem = (datetime.fromisoformat(job_end) - datetime.now()).total_seconds()
                    if _jrem <= 0:
                        job_btn = InlineKeyboardButton("💼 Claim Job!", callback_data=f"petjob_claim_{pid}")
                    else:
                        _jrm = f"{int(_jrem//3600)}h {int((_jrem%3600)//60)}m" if _jrem >= 3600 else f"{int(_jrem//60)}m"
                        job_btn = InlineKeyboardButton(f"💼 Job ({_jrm})", callback_data=f"petjob_status_{pid}")
                except Exception:
                    job_btn = InlineKeyboardButton("💼 Job", callback_data=f"petjob_pick_{pid}")
            else:
                job_btn = InlineKeyboardButton("💼 Send on Job", callback_data=f"petjob_pick_{pid}")
            markup = InlineKeyboardMarkup([
                [InlineKeyboardButton("🍖 Feed",    callback_data=f"petfeed_{pid}"),
                 InlineKeyboardButton("🏋️ Train",  callback_data=f"pettrain_{pid}"),
                 InlineKeyboardButton("🎮 Play",    callback_data=f"petplay_{pid}")],
                [InlineKeyboardButton("⚔️ Pet Battle", callback_data=f"petbattle_pick_{pid}"),
                 adv_btn],
                [job_btn],
                [InlineKeyboardButton("📝 Rename",  callback_data=f"petrename_{pid}"),
                 InlineKeyboardButton("📋 All Pets", callback_data="petlist_0")],
                [InlineKeyboardButton("📖 Bestiary", callback_data="bestiary_0"),
                 InlineKeyboardButton("💰 Bulk Sell", callback_data="petbulk_menu")],
                [InlineKeyboardButton("🛒 Pet Shop", callback_data="petshop"),
                 InlineKeyboardButton("🥚 Hatch Egg", callback_data="hatch_egg")],
            ])
        await _q_edit(query, text, parse_mode="Markdown", reply_markup=markup)
        await query.answer(); return

    if data.startswith("petlist_"):
        page = int(data.split("_")[1])
        pets = get_all_pets(user.id)
        if not pets:
            await _q_edit(query, "🐾 You have no pets yet!", reply_markup=_pet_main_markup())
            await query.answer(); return
        await _q_edit(query, 
            f"🐾 *Your Pets* ({len(pets)} total)\nTap a pet to view or manage.",
            parse_mode="Markdown", reply_markup=_pet_list_markup(pets, page, uid=user.id))
        await query.answer(); return

    if data.startswith("petview_"):
        pid = int(data.split("_")[1])
        conn = _connect_db(); conn.row_factory = sqlite3.Row; c = conn.cursor()
        c.execute("SELECT * FROM pets WHERE pet_id=? AND owner_id=?", (pid, user.id))
        row = c.fetchone(); conn.close()
        if not row: await query.answer("Pet not found.", show_alert=True); return
        pet = dict(row); _decay_pet(pet)
        await _q_edit(query, _build_pet_card(pet), parse_mode="Markdown",
            reply_markup=_pet_view_markup(pid, bool(pet.get("is_active")), uid=user.id, pet=pet))
        await query.answer(); return

    if data.startswith("petactivate_"):
        pid = int(data.split("_")[1])
        conn = _connect_db(); c = conn.cursor()
        c.execute("UPDATE pets SET is_active=0 WHERE owner_id=?", (user.id,))
        c.execute("UPDATE pets SET is_active=1 WHERE pet_id=? AND owner_id=?", (pid, user.id))
        conn.commit(); conn.close()
        conn2 = _connect_db(); conn2.row_factory = sqlite3.Row; c2 = conn2.cursor()
        c2.execute("SELECT * FROM pets WHERE pet_id=?", (pid,))
        row = c2.fetchone(); conn2.close()
        if not row: await query.answer("Pet not found.", show_alert=True); return
        pet = dict(row); _decay_pet(pet)
        sp = PET_SPECIES.get(pet["species"],{})
        await query.answer(f"✅ {sp.get('name','Pet')} is now your active companion!")
        await _q_edit(query, _build_pet_card(pet), parse_mode="Markdown",
            reply_markup=_pet_view_markup(pid, True, uid=user.id, pet=pet)); return

    if data.startswith("petfeed_"):
        pid = int(data.split("_")[1])
        conn = _connect_db(); conn.row_factory = sqlite3.Row; c = conn.cursor()
        c.execute("SELECT * FROM pets WHERE pet_id=? AND owner_id=?", (pid, user.id))
        row = c.fetchone(); conn.close()
        if not row: await query.answer("Pet not found.", show_alert=True); return
        pet = dict(row); _decay_pet(pet)
        p = get_player(user.id)
        inv = sjl(p.get("inventory"), [])
        sp = PET_SPECIES.get(pet["species"], {})
        pname = _pet_display_name(pet)
        pers  = sp.get("personality","calm")
        if "Pet Snack" in inv:
            inv.remove("Pet Snack"); p["inventory"] = json.dumps(inv); save_player(p)
            cost_note = "_(used 1 Pet Snack)_"
        elif p.get("gold",0) >= 10:
            p["gold"] -= 10; save_player(p)
            cost_note = "_(cost 10g)_"
        else:
            await query.answer("No Pet Snacks and not enough gold (need 10g).", show_alert=True); return
        pet["hunger"] = min(100, pet.get("hunger",0) + 30)
        pet["mood"]   = min(100, pet.get("mood",0)   + 10)
        pet["bond_score"] = min(200, pet.get("bond_score",0) + 3)
        pet["last_fed"] = datetime.now().isoformat()
        save_pet(pet)
        feed_msg = PERSONALITY_FEED.get(pers, "eats happily.")
        await query.answer(f"🍖 Fed {pname}!")
        await _q_edit(query, 
            f"🍖 *{pname}* {feed_msg}\n{cost_note}\n\n" + _build_pet_card(pet),
            parse_mode="Markdown", reply_markup=_pet_view_markup(pid, bool(pet.get("is_active")), uid=user.id, pet=pet)); return

    if data.startswith("pettrain_"):
        pid = int(data.split("_")[1])
        conn = _connect_db(); conn.row_factory = sqlite3.Row; c = conn.cursor()
        c.execute("SELECT * FROM pets WHERE pet_id=? AND owner_id=?", (pid, user.id))
        row = c.fetchone(); conn.close()
        if not row: await query.answer("Pet not found.", show_alert=True); return
        pet = dict(row); _decay_pet(pet)
        sp = PET_SPECIES.get(pet["species"], {})
        pname = _pet_display_name(pet)
        pers  = sp.get("personality","calm")
        # Cooldown: 4 hours
        last_trained = pet.get("last_trained")
        if last_trained:
            try:
                elapsed = (datetime.now() - datetime.fromisoformat(last_trained)).total_seconds()
                if elapsed < 14400:
                    remaining = round((14400 - elapsed) / 60)
                    await query.answer(f"⏳ {pname} needs rest. Try again in {remaining} min.", show_alert=True); return
            except Exception: pass
        if pet.get("hunger", 100) < 20:
            await query.answer(f"😫 {pname} is too hungry to train! Feed them first.", show_alert=True); return
        gain = 30 + pet.get("level",1) * 5
        pet["exp"] += gain
        pet["mood"] = min(100, pet.get("mood",100) + 5)
        pet["bond_score"] = min(200, pet.get("bond_score",0) + 5)
        pet["last_trained"] = datetime.now().isoformat()
        # Level up (capped at player_level * 3)
        _owner_p = get_player(user.id)
        _pet_train_cap = min(100, (_owner_p["level"] if _owner_p else 1) * 3)
        lvl_ups = []
        while pet["exp"] >= pet_exp_for_level(pet["level"]) and pet["level"] < _pet_train_cap:
            pet["exp"] -= pet_exp_for_level(pet["level"])
            pet["level"] += 1
            lvl_ups.append(pet["level"])
        save_pet(pet)
        train_msg = PERSONALITY_TRAIN.get(pers, "trains diligently.")
        lvl_note = "".join(f"\n🎉 *Level Up!* {pname} is now level {l}!" for l in lvl_ups)
        await query.answer(f"🏋️ {pname} trained! +{fmt_num(gain)} EXP")
        await _q_edit(query, 
            f"🏋️ *{pname}* {train_msg}\n+{fmt_num(gain)} EXP gained!{lvl_note}\n\n" + _build_pet_card(pet),
            parse_mode="Markdown", reply_markup=_pet_view_markup(pid, bool(pet.get("is_active")), uid=user.id, pet=pet)); return

    if data.startswith("petplay_"):
        pid = int(data.split("_")[1])
        conn = _connect_db(); conn.row_factory = sqlite3.Row; c = conn.cursor()
        c.execute("SELECT * FROM pets WHERE pet_id=? AND owner_id=?", (pid, user.id))
        row = c.fetchone(); conn.close()
        if not row: await query.answer("Pet not found.", show_alert=True); return
        pet = dict(row); _decay_pet(pet)
        sp = PET_SPECIES.get(pet["species"], {})
        pname = _pet_display_name(pet)
        pers  = sp.get("personality","calm")
        last_play = pet.get("last_play")
        if last_play:
            try:
                elapsed = (datetime.now() - datetime.fromisoformat(last_play)).total_seconds()
                if elapsed < 3600:
                    remaining = round((3600 - elapsed) / 60)
                    await query.answer(f"😴 {pname} is tired. Play again in {remaining} min.", show_alert=True); return
            except Exception: pass
        pet["mood"] = min(100, pet.get("mood", 100) + 20)
        pet["bond_score"] = min(200, pet.get("bond_score", 0) + 8)
        pet["last_play"] = datetime.now().isoformat()
        save_pet(pet)
        play_msgs = {
            "playful": "zooms around like a tiny hurricane!",
            "fierce": "pounces on a toy with total commitment!",
            "calm": "stretches luxuriously and nuzzles up to you.",
            "mischievous": "immediately steals something and won't give it back.",
            "loyal": "sits by your side and leans against you warmly.",
            "lazy": "rolls over, demands belly rubs, gets belly rubs.",
            "timid": "peeks out shyly then slowly relaxes into the fun.",
            "greedy": "plays enthusiastically until they spot something shiny.",
        }
        play_msg = play_msgs.get(pers, "plays happily!")
