def _gearhub_markup(uid: int, page: int = 1) -> InlineKeyboardMarkup:
    total = len(_GEAR_HUB_PAGES)
    page  = max(1, min(page, total))
    rows  = []
    for btn_row in _GEAR_HUB_PAGES[page - 1]:
        rows.append([InlineKeyboardButton(lbl, callback_data=f"{cb}_{uid}") for lbl, cb in btn_row])
    rows.append(_hub_nav_row("gearhub_", page, total, uid))
    rows.append([InlineKeyboardButton("🏠 Home", callback_data=f"empire_home_{uid}"),
                 InlineKeyboardButton("❌ Close", callback_data=f"close_msg_{uid}")])
    return InlineKeyboardMarkup(rows)

async def gearhub_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user
    p = get_player(user.id)
    try: await update.message.delete()
    except: pass
    if not p:
        await send_group(update, "Use /ascend first to join!", delay=9); return
    text = (
        f"⚔️ *{p['username']}'s Gear Hub*\n\n"
        f"Page 1: Equipment  |  Page 2: Upgrades\n"
        f"Page 3: Economy"
    )
    msg = await context.bot.send_message(
        chat_id=update.effective_chat.id, text=text, parse_mode="Markdown",
        reply_markup=_gearhub_markup(user.id, page=1))
    asyncio.create_task(_auto_delete(context.bot, update.effective_chat.id, msg.message_id, 120))

async def gearhub_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    uid   = query.from_user.id
    data  = query.data
    parts = data.split("_")

    # Page navigation OR back from action panel — restores full hub header + buttons
    if data.startswith("gearhub_pg_") or data.startswith("gearhub_back_"):
        try:
            page    = int(parts[2])
            req_uid = int(parts[3])
        except (IndexError, ValueError):
            await query.answer(); return
        if uid != req_uid:
            await query.answer("Not your hub.", show_alert=True); return
        await query.answer()
        p = get_player(uid)
        if not p: return
        header = (f"⚙️ *{p['username']}'s Gear Hub*\n\n"
                  f"Page 1: Equipment  |  Page 2: Upgrades\nPage 3: Economy")
        try: await _q_edit(query, header, parse_mode="Markdown",
                                           reply_markup=_gearhub_markup(uid, page=page))
        except Exception: pass
        return

    try: req_uid = int(parts[-1])
    except (IndexError, ValueError): req_uid = 0
    if uid != req_uid:
        await query.answer("Not your hub.", show_alert=True); return
    await query.answer()

    action = parts[1] if len(parts) > 1 else ""
    p = get_player(uid)
    if not p:
        await query.answer("Register first.", show_alert=True); return

    _PAGE = {"inv":1,"gear":1,"equip":1,"unequip":1,"shop":1,"sell":1,
             "enhance":2,"reinforce":2,"forge":2,"perma":2,"enchant":2,"pool":2,
             "trade":3,"accept":3,"decline":3,"deposit":3,"withdraw":3,"cp":3,"permpool":3}
    page = _PAGE.get(action, 1)
    back = InlineKeyboardMarkup([[InlineKeyboardButton("← Back", callback_data=f"gearhub_back_{page}_{uid}")]])

    if action == "inv":
        back_rows = [[InlineKeyboardButton("← Back", callback_data=f"gearhub_back_1_{uid}")]]
        await _send_inventory_section(query, p, section="Equipped", edit=True, uid=uid, back_rows=back_rows)
    elif action == "gear":
        try: await _q_edit(query, _build_gear_text(p)[:4096], parse_mode="Markdown", reply_markup=back)
        except Exception:
            try: await _q_edit(query, _build_gear_text(p)[:4096], reply_markup=back)
            except Exception: pass
    elif action == "shop":
        discount = _shop_discount(p)
        text, markup = _build_shop_view(p, "pot", uid, discount)
        rows = list(markup.inline_keyboard)
        rows.insert(-1, [InlineKeyboardButton("← Back to Gear Hub", callback_data=f"gearhub_back_1_{uid}")])
        markup = InlineKeyboardMarkup(rows)
        try: await _q_edit(query, text[:4096], parse_mode="Markdown", reply_markup=markup)
        except Exception:
            try: await _q_edit(query, text[:4096], reply_markup=markup)
            except Exception: pass
    elif action == "cp":
        cp = calc_combat_power(p)
        try: await _q_edit(query, 
            f"📊 *Combat Power*\n\n*{p['username']}*: *{cp:,} CP*\n\n"
            f"Higher CP = bigger damage multiplier.\n"
            f"Improve it by upgrading gear, enhancing items, and reinforcing.",
            parse_mode="Markdown", reply_markup=back)
        except Exception: pass

    elif action == "equip":
        has_items, equip_markup = _build_equip_page_markup(p, uid, 0)
        rows = list(equip_markup.inline_keyboard) if equip_markup else []
        rows.append([InlineKeyboardButton("← Back", callback_data=f"gearhub_back_1_{uid}")])
        txt = _build_gear_text(p) + ("\n\n_Select an item below to equip:_" if has_items
                                     else "\n\n_No equippable items in bag — visit Shop!_")
        try: await _q_edit(query, txt[:4096], parse_mode="Markdown",
                                           reply_markup=InlineKeyboardMarkup(rows))
        except Exception:
            try: await _q_edit(query, txt[:4096],
                                               reply_markup=InlineKeyboardMarkup(rows))
            except Exception: pass

    elif action == "sell":
        inv = sjl(p.get("inventory"), [])
        if not inv:
            try: await _q_edit(query, 
                "💰 *Sell*\n\nYour bag is empty.", parse_mode="Markdown", reply_markup=back)
            except Exception: pass
        else:
            sell_rows = [
                [InlineKeyboardButton("Sell Off-Class Common",    callback_data=f"sellr_{uid}_common"),
                 InlineKeyboardButton("Sell Off-Class Uncommon",  callback_data=f"sellr_{uid}_uncommon")],
                [InlineKeyboardButton("Sell Off-Class Rare",      callback_data=f"sellr_{uid}_rare"),
                 InlineKeyboardButton("Sell Off-Class Epic",      callback_data=f"sellr_{uid}_epic")],
                [InlineKeyboardButton("💰 Sell All Off-Class Weapons/Armor", callback_data=f"sellr_{uid}_all")],
                [InlineKeyboardButton("⚔️ Sell Off-Class Items",             callback_data=f"selloffc_{uid}")],
                [InlineKeyboardButton("← Back", callback_data=f"gearhub_back_1_{uid}")],
            ]
            try: await _q_edit(query, 
                "💰 *Sell Items*\n\nBulk-sell by rarity, or clear off-class gear.\n"
                "_Equipped gear and key materials are always protected._",
                parse_mode="Markdown", reply_markup=InlineKeyboardMarkup(sell_rows))
            except Exception: pass

    elif action in ("pool", "permpool"):
        s_cd = get_shadow(uid)
        pool_ts = p.get("last_pool") or (s_cd.get("last_pool") if s_cd else None)
        if pool_ts:
            try:
                elapsed = (datetime.now() - datetime.fromisoformat(pool_ts)).total_seconds()
                if elapsed < 3:
                    remaining = int(3 - elapsed)
                    try: await _q_edit(query, 
                        f"🎱 *Pool*\n\n⏳ Cooldown: *{remaining}s*", parse_mode="Markdown", reply_markup=back)
                    except Exception: pass
                    return
            except Exception:
                pass
        shot = roll_pool_shot_with_luk(p)
        rarity_prefix = {"common":"🎱","uncommon":"🎯","rare":"🔵","epic":"🟣",
                         "legendary":"🟡","mythic":"🔴"}.get(shot["rarity"], "🎱")
        item_found = None
        if shot.get("loot"):
            item_found = roll_loot_table(shot["loot"])
            if item_found: add_item(p, item_found)
        gold_bonus = max(1.0, 1.0 + (p["level"] - 1) * 0.12)
        exp_gain   = _scaled_shot_exp(p["level"], shot["exp"])
        gold_gain  = (max(5 + p["level"], int(shot["gold"] * gold_bonus)) if shot["gold"] > 0 else 0)
        p["gold"] = p.get("gold", 0) + gold_gain
        p["last_pool"] = datetime.now().isoformat()
        if s_cd: s_cd["last_pool"] = p["last_pool"]; save_shadow(s_cd)
        lmsgs, _ = add_exp(p, exp_gain); save_player(p)
        result = (f"{rarity_prefix} *Pool Shot — {shot['rarity'].capitalize()}*\n\n"
                  f"_{shot['text']}_\n\n"
                  f"✨ +{fmt_num(exp_gain)} EXP  |  💰 +{gold_gain}g")
        if item_found: result += f"  |  🎒 *{item_found}*!"
        if lmsgs: result += "\n\n" + "\n".join(lmsgs[:2])
        try: await _q_edit(query, result, parse_mode="Markdown", reply_markup=back)
        except Exception: pass

    elif action == "unequip":
        # Show currently equipped items
        weap = p.get("equipped_weapon") or "None"
        armr = p.get("equipped_armor") or "None"
        shld = p.get("equipped_shield") or "None"
        acc1 = p.get("equipped_accessory") or "None"
        acc2 = p.get("equipped_accessory_2") or "None"
        lines_ue = [
            "❌ *Unequip*\n",
            f"⚔️ Weapon: {weap}",
            f"🛡️ Armor: {armr}",
            f"🔰 Shield: {shld}",
            f"💍 Acc 1: {acc1}",
            f"💍 Acc 2: {acc2}",
            "",
            "_To unequip an item, use the Equip menu and select it again, or use /unequip in the chat._"
        ]
        txt_ue = "\n".join(l for l in lines_ue if l != "None" or True)
        try: await _q_edit(query, txt_ue, parse_mode="Markdown", reply_markup=back)
        except Exception: pass

    elif action in ("enhance", "reinforce", "forge", "enchant", "perma"):
        _upg_info = {
            "enhance":  ("✨", "Enhance",  "Boost a weapon or armor's power with Iron Shards. Each enhancement adds +ATK or +DEF."),
            "reinforce": ("🔩","Reinforce", "Permanently boost your gear's base stats using Reinforcement Stones."),
            "forge":    ("⚒️", "Forge",    "Combine materials to craft new gear. Requires specific reagents found through exploration."),
            "enchant":  ("🔮", "Enchant",  "Apply magical properties to gear — EXP bonuses, kill heals, crit boosts and more."),
            "perma":    ("💎", "Perm DMG", "Permanently increase your base damage using Essence Crystals."),
        }
        _uem, _uname, _udesc = _upg_info[action]
        weap_cur = p.get("equipped_weapon") or "None"
        armr_cur = p.get("equipped_armor") or "None"
        txt_upg = (f"{_uem} *{_uname}*\n\n"
                   f"{_udesc}\n\n"
                   f"*Currently equipped:*\n"
                   f"⚔️ {weap_cur}  |  🛡️ {armr_cur}\n\n"
                   f"_Use the upgrade commands in the group chat to apply upgrades._")
        try: await _q_edit(query, txt_upg, parse_mode="Markdown", reply_markup=back)
        except Exception: pass

    elif action in ("trade", "accept", "decline"):
        txt_tr = ("🤝 *Trade*\n\n"
                  "Send items or gold to another player.\n\n"
                  "*How it works:*\n"
                  "• Use /trade @player [item] [qty] to offer\n"
                  "• Recipient uses /accept or /decline\n"
                  "• Both players must be in the same group chat")
        if action == "accept":
            txt_tr = "✅ *Accept Trade*\n\nIf someone has offered you a trade, use /accept in the group chat to confirm it."
        elif action == "decline":
            txt_tr = "❌ *Decline Trade*\n\nUse /decline to reject a pending trade offer."
        try: await _q_edit(query, txt_tr, parse_mode="Markdown", reply_markup=back)
        except Exception: pass

    elif action in ("deposit", "withdraw"):
        gid = p.get("guild_id")
        if not gid:
            txt_bk = "🏦 *Guild Bank*\n\n_Join a guild first to access the guild bank._"
        else:
            g = get_guild(gid)
            balance = safe_int(g.get("gold", 0)) if g else 0
            yours = safe_int(p.get("gold", 0))
            txt_bk = (f"🏦 *Guild Bank*\n\n"
                      f"💰 Bank balance: *{balance:,}g*\n"
                      f"👤 Your gold: *{yours:,}g*\n\n"
                      f"{'Deposit into the guild bank or withdraw with the bank commands in the group chat.' if action=='deposit' else 'Withdraw from the guild bank using the bank commands in the group chat.'}")
        try: await _q_edit(query, txt_bk, parse_mode="Markdown", reply_markup=back)
        except Exception: pass

    else:
        tip = _GEAR_HUB_TIPS.get(action)
        if tip:
            title, desc = tip
            try: await _q_edit(query, f"{title}\n\n{desc}", parse_mode="Markdown", reply_markup=back)
            except Exception: pass
        else:
            try: await _q_edit(query, f"_{action}_ — use the command in chat.", parse_mode="Markdown", reply_markup=back)
            except Exception: pass

