def _activities_hub_markup(uid: int, page: int = 1) -> InlineKeyboardMarkup:
    total = len(_ACTIVITIES_HUB_PAGES)
    page  = max(1, min(page, total))
    rows  = []
    for btn_row in _ACTIVITIES_HUB_PAGES[page - 1]:
        rows.append([InlineKeyboardButton(lbl, callback_data=f"{cb}_{uid}") for lbl, cb in btn_row])
    rows.append(_hub_nav_row("acthub_", page, total, uid))
    rows.append([InlineKeyboardButton("🏠 Home", callback_data=f"empire_home_{uid}"),
                 InlineKeyboardButton("❌ Close", callback_data=f"close_msg_{uid}")])
    return InlineKeyboardMarkup(rows)

async def activitieshub_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user
    p = get_player(user.id)
    try: await update.message.delete()
    except: pass
    if not p:
        await send_group(update, "Use /ascend first to join!", delay=9); return
    text = (
        f"🌍 *{p['username']}'s Activities Hub*\n\n"
        f"Page 1: Daily Activities  |  Page 2: Challenges\n"
        f"Page 3: Character"
    )
    msg = await context.bot.send_message(
        chat_id=update.effective_chat.id, text=text, parse_mode="Markdown",
        reply_markup=_activities_hub_markup(user.id, page=1))
    asyncio.create_task(_auto_delete(context.bot, update.effective_chat.id, msg.message_id, 120))

async def activitieshub_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    uid   = query.from_user.id
    data  = query.data
    parts = data.split("_")

    # Page navigation OR back from action panel — restores full hub header + buttons
    if data.startswith("acthub_pg_") or data.startswith("acthub_back_"):
        try:
            page    = int(parts[2])
            req_uid = int(parts[3])
        except (IndexError, ValueError):
            await query.answer(); return
        if uid != req_uid:
            await query.answer("Not your hub.", show_alert=True); return
        await query.answer()
        p = get_player(uid)
        if not p: return
        header = (f"🌍 *{p['username']}'s Activities Hub*\n\n"
                  f"Page 1: Daily  |  Page 2: Challenges\nPage 3: Character")
        try: await _q_edit(query, header, parse_mode="Markdown",
                                           reply_markup=_activities_hub_markup(uid, page=page))
        except Exception: pass
        return

    try: req_uid = int(parts[-1])
    except (IndexError, ValueError): req_uid = 0
    if uid != req_uid:
        await query.answer("Not your hub.", show_alert=True); return
    await query.answer()

    action = parts[1] if len(parts) > 1 else ""
    p = get_player(uid)
    if not p:
        await query.answer("Register first.", show_alert=True); return

    _PAGE = {"hustle":1,"daily":1,"claim":1,"train":1,"quest":1,"explore":1,
             "dungeon":2,"dungeonhard":2,"dungeonleg":2,"oracle":2,"objectives":2,"cooldowns":2,
             "stats":3,"allocate":3,"class":3,"prestige":3,"skills":3,"changelog":3}
    page = _PAGE.get(action, 1)
    back = InlineKeyboardMarkup([[InlineKeyboardButton("← Back", callback_data=f"acthub_back_{page}_{uid}")]])

    async def _show(text):
        try: await _q_edit(query, text[:4096], parse_mode="Markdown", reply_markup=back)
        except Exception: pass

    # ── Hustle: run all ready cooldowns inline ──────────────────────
    if action == "hustle":
        if is_defeated(p):
            await _show("⚡ *Hustle*\n\n💀 Too beaten up to hustle right now."); return
        now = datetime.now(); ran = []; skipped = []
        if check_cooldown(p.get("last_daily"), 86400):
            p["last_daily"] = now.isoformat()
            gold = scaled_gold(p["level"], 100); p["gold"] = p.get("gold", 0) + gold
            daily_exp = exp_share(p["level"], 0.10)
            lmsgs, _ = add_exp(p, daily_exp)
            entry = f"🎁 Daily: +{fmt_num(daily_exp)} EXP, +{gold}g"
            if random.random() < 0.10:
                item = random.choice(["Health Potion","Greater Health Potion","Grand Restorative Flask"])
                add_item(p, item); entry += f", *{item}*"
            ran.append(entry)
        else: skipped.append(f"🎁 Daily — {time_remaining(p.get('last_daily'), 86400)}")
        if check_cooldown(p.get("last_train"), 1800):
            p["last_train"] = now.isoformat()
            base = exp_share(p["level"], 0.04)
            cls = get_player_class(p)
            if cls:
                pk = cls.get("passive_key","")
                if pk in ("arcane_mind","spell_surge","arcane_mastery","mana_overload","eternal_wisdom"): base = round(base*1.30)
                elif pk in ("iron_will","holy_stance","devotion","bulwark","divine_judgment"):            base = round(base*1.20)
                elif pk in ("quick_hands","evasion","shadowstep","ghost_form","deaths_shadow",
                            "eagle_eye","trailblazer","natures_bond","guardian_stance","pathfinder"):    base = round(base*1.35)
                elif pk in ("mending_aura","divine_grace","sacred_ground","resurrection","divine_presence",
                            "dark_sense","purge","judgement","wrath_of_the_righteous"):                 base = round(base*1.15)
            lmsgs, _ = add_exp(p, base); ran.append(f"🏋️ Train: +{fmt_num(base)} EXP")
        else: skipped.append(f"🏋️ Train — {time_remaining(p.get('last_train'), 1800)}")
        today = now.strftime("%Y-%m-%d"); yesterday = (now - timedelta(days=1)).strftime("%Y-%m-%d")
        last_claim = p.get("last_claim")
        if last_claim != today:
            streak = safe_int(p.get("claim_streak")); streak = streak+1 if last_claim==yesterday else 1
            gold_reward = 50 + min(streak*10, 200); p["gold"] = p.get("gold",0) + gold_reward
            if streak >= 3:  add_item(p, "Iron Shard")
            if streak >= 14: add_item(p, "Enchanting Scroll")
            p["last_claim"] = today; p["claim_streak"] = streak
            ran.append(f"🎁 Claim: +{gold_reward}g (Day {streak})")
        else: skipped.append("🎁 Claim — already claimed today")
        s_cd = get_shadow(uid)
        pool_ts = p.get("last_pool") or (s_cd.get("last_pool") if s_cd else None)
        pool_ready = True
        if pool_ts:
            try:
                if (now - datetime.fromisoformat(pool_ts)).total_seconds() < 8: pool_ready = False
            except Exception: pass
        if pool_ready:
            shot = roll_pool_shot_with_luk(p)
            exp_gain = _scaled_shot_exp(p["level"], shot["exp"])
            gold_gain = (max(5 + p["level"], int(shot["gold"] * max(1.0, 1.0+(p["level"]-1)*0.12))) if shot["gold"] > 0 else 0)
            p["gold"] = p.get("gold",0)+gold_gain; p["last_pool"] = now.isoformat()
            if s_cd: s_cd["last_pool"] = p["last_pool"]; save_shadow(s_cd)
            lmsgs, _ = add_exp(p, exp_gain)
            entry = f"🎱 Pool ({shot['rarity']}): +{fmt_num(exp_gain)} EXP, +{gold_gain}g"
            if shot.get("loot"):
                loot = roll_loot_table(shot["loot"])
                if loot: add_item(p, loot); entry += f", *{loot}*"
            ran.append(entry)
        else: skipped.append("🎱 Pool — on cooldown")
        save_player(p)
        lines = ["⚡ *Hustle Results*\n"]
        if ran:
            lines.append("*Completed:*"); lines.extend(f"✅ {r}" for r in ran)
        if skipped:
            lines.append("\n*On cooldown:*"); lines.extend(f"⏳ {s}" for s in skipped)
        if not ran and not skipped: lines.append("_Nothing ready to run._")
        await _show("\n".join(lines))

    # ── Claim: execute inline ────────────────────────────────────────
    elif action == "claim":
        today = datetime.now().strftime("%Y-%m-%d")
        yesterday = (datetime.now() - timedelta(days=1)).strftime("%Y-%m-%d")
        last = p.get("last_claim")
        if last == today:
            await _show("🎁 *Claim*\n\n✅ Already claimed today! Come back tomorrow.")
        else:
            streak = safe_int(p.get("claim_streak"))
            streak = streak+1 if last==yesterday else 1
            gold_reward = 50 + min(streak*10, 200); inv_adds = []
            if streak >= 3:  add_item(p, "Iron Shard"); inv_adds.append("🪨 +1 Iron Shard")
            if streak >= 14: add_item(p, "Enchanting Scroll"); inv_adds.append("📜 +1 Enchanting Scroll")
            p["gold"] = p.get("gold",0)+gold_reward; p["last_claim"] = today; p["claim_streak"] = streak
            save_player(p)
            streak_emojis = "🔥" * min(streak, 7)
            lines = [f"🎁 *Daily Claim — Day {streak}!* {streak_emojis}\n",
                     f"💰 +{gold_reward} gold"] + inv_adds
            lines.append(f"\n_Streak: {streak} day{'s' if streak!=1 else ''} — claim again tomorrow!_")
            await _show("\n".join(lines))

    # ── Daily: execute inline ────────────────────────────────────────
    elif action == "daily":
        if not check_cooldown(p.get("last_daily"), 86400):
            await _show(f"📅 *Daily*\n\n⏳ Already claimed. Ready in {time_remaining(p.get('last_daily'), 86400)}.")
        else:
            p["last_daily"] = datetime.now().isoformat()
            gold = scaled_gold(p["level"], 100); p["gold"] = p.get("gold", 0) + gold
            item = None
            if random.random() < 0.10:
                item = random.choice(["Health Potion","Greater Health Potion","Grand Restorative Flask"])
                add_item(p, item)
            daily_exp = exp_share(p["level"], 0.10)
            lmsgs, _ = add_exp(p, daily_exp); save_player(p)
            text = f"🎁 *Daily Reward!*\n\n✨ +{fmt_num(daily_exp)} EXP | 💰 +{gold} Gold"
            if item: text += f" | 🎒 *{item}*"
            if lmsgs: text += "\n\n" + "\n".join(lmsgs[:3])
            await _show(text)

    # ── Train: execute inline ────────────────────────────────────────
    elif action == "train":
        if is_defeated(p):
            await _show("🏋️ *Train*\n\n💀 Too beaten up to train right now.")
        elif not check_cooldown(p.get("last_train"), 1800):
            await _show(f"🏋️ *Train*\n\n⏳ Ready in {time_remaining(p.get('last_train'), 1800)}.")
        else:
            p["last_train"] = datetime.now().isoformat()
            base = exp_share(p["level"], 0.04)
            cls = get_player_class(p); note = ""
            if cls:
                pk = cls.get("passive_key", "")
                if pk in ("arcane_mind","spell_surge","arcane_mastery","mana_overload","eternal_wisdom"):
                    base = round(base*1.30); note = f"\n🔮 *{cls['name']}* focus bonus! +30%"
                elif pk in ("iron_will","holy_stance","devotion","bulwark","divine_judgment"):
                    base = round(base*1.20); note = f"\n🛡️ *{cls['name']}* endurance bonus! +20%"
                elif pk in ("quick_hands","evasion","shadowstep","ghost_form","deaths_shadow",
                            "eagle_eye","trailblazer","natures_bond","guardian_stance","pathfinder"):
                    base = round(base*1.35); note = f"\n⚡ *{cls['name']}* speed bonus! +35%"
                elif pk in ("mending_aura","divine_grace","sacred_ground","resurrection","divine_presence",
                            "dark_sense","purge","judgement","wrath_of_the_righteous"):
                    base = round(base*1.15); note = f"\n✨ *{cls['name']}* wisdom bonus! +15%"
            lmsgs, _ = add_exp(p, base); save_player(p)
            text = f"🏋️ *Training Session*\n\n_{random.choice(TRAIN_MESSAGES)}_\n\n✨ +{fmt_num(base)} EXP{note}"
            if lmsgs: text += "\n\n" + "\n".join(lmsgs[:3])
            await _show(text)

    # ── Cooldowns: display inline ────────────────────────────────────
    elif action == "cooldowns":
        s_cd = get_shadow(uid)
        pool_ts = p.get("last_pool") or (s_cd.get("last_pool") if s_cd else None)
        today = datetime.now().strftime("%Y-%m-%d")
        exp_count = safe_int(p.get("explore_count_today")) if p.get("explore_date") == today else 0
        lines = [f"⏳ *{p['username']}'s Cooldowns:*\n",
                 f"🎁 Daily:    {time_remaining(p.get('last_daily'), 86400)}",
                 f"🗺️ Quest:    {time_remaining(p.get('last_quest'), 3600)}",
                 f"🏋️ Train:    {time_remaining(p.get('last_train'), 1800)}",
                 f"🎱 Pool:     {time_remaining(pool_ts, 8)}",
                 f"🗺️ Explore:  {exp_count}/2 today",
                 f"🏰 Dungeon:  {time_remaining(p.get('last_dungeon'), 86400)}"]
        if is_defeated(p):
            diff = datetime.fromisoformat(p["defeated_until"]) - datetime.now()
            h2, r2 = divmod(int(max(0, diff.total_seconds())), 3600); m2 = r2 // 60
            lines.append(f"💀 Defeat:   {h2}h {m2}m remaining")
        await _show("\n".join(lines))

    # ── Objectives: display inline ───────────────────────────────────
    elif action == "objectives":
        refresh_daily_objectives(p); save_player(p)
        objs = sjl(p.get("daily_objectives"), [])
        lines = ["🎯 *Daily Objectives*\n_Reset each day at midnight_\n"]
        for obj in objs:
            prog = safe_int(obj.get("progress")); tgt = max(1, safe_int(obj.get("target")))
            done = prog >= tgt; chk = "✅" if done else "⬜"
            fill = round(min(prog, tgt) / tgt * 8)
            bar = "█" * fill + "░" * (8 - fill)
            lines.append(f"{chk} *{obj['desc']}*\n`{bar}` {prog}/{tgt}  ·  +{fmt_num(obj.get('reward_exp',0))} EXP, {obj.get('reward_gold',0)}g")
        lines.append(f"\n📊 Completed today: {safe_int(p.get('objectives_completed'))}")
        await _show("\n\n".join(lines))

    # ── Changelog: display inline ────────────────────────────────────
    elif action == "changelog":
        entries = CHANGELOG[-3:]
        lines = ["📋 *8Ball World — Recent Updates*\n"]
        for entry in reversed(entries):
            lines.append(f"*{entry['version']}* _{entry['date']}_")
            for c in entry["changes"][:5]: lines.append(f"• {c}")
            lines.append("")
        await _show("\n".join(lines))

    # ── Allocate: show info inline ───────────────────────────────────
    elif action == "allocate":
        sp = safe_int(p.get("stat_points"))
        await _show(f"⬆️ *Allocate Stats*\n\nStat Points Available: *{sp}*\n\n"
                    f"Type in chat:\n`/allocate STR 5` — +5 Strength\n"
                    f"Stats: STR · DEX · INT · WIS · AGI · LUK")

    # ── Stats: real stats page ───────────────────────────────────────
    elif action == "stats":
        back_row = [[InlineKeyboardButton("← Back", callback_data=f"acthub_back_3_{uid}")]]
        await _send_stats_page(query, uid, page=1, edit=True, back_rows=back_row)

    # ── Class: real class info ───────────────────────────────────────
    elif action == "class":
        cls = get_player_class(p)
        if not cls:
            if p["level"] < 5:
                await _show(f"🎓 *Class*\n\nClasses unlock at Level *5*. You're Level {p['level']}.\n\n_Keep leveling!_")
            else:
                await _show(f"🎓 *Choose Your Class*\n\nUse `/class` to pick!\n\n"
                            f"Available: {', '.join(BASE_CLASSES)}\n\nExample: `/class warrior`")
        else:
            all_skills = get_combat_skills(p)
            lines = [f"🎓 *{p['username']}* — *{cls['name']}*\n", f"_{cls.get('desc','')}_\n"]
            if all_skills:
                lines.append(f"*Skills ({len(all_skills)}):*")
                for s in all_skills[:6]:
                    stype = s.get("type", "damage")
                    icon = ("⚔️" if stype in ("damage","combo_dmg","freeze_nuke","execute_nuke",
                                              "holy_nuke","fear_kill","nature_nuke","drain")
                            else "💚" if stype in ("self_heal","group_heal","revive_heal","full_revive","regen")
                            else "✨" if stype in ("dmg_reduction_buff","self_heal_buff","heal_shield",
                                                   "self_atk_buff","party_atk_buff","party_full_buff")
                            else "⚡")
                    lines.append(f"{icon} *{s['name']}*  -  _{s['desc']}_")
            path = p.get("class_path")
            if path:
                line_k = cls.get("line")
                fp = CLASS_PATHS.get(line_k, {}).get(path, [])
                path_str = " → ".join(CLASS_TREE.get(k,{}).get("name","?") for k in fp)
                lines.append(f"\n*Path {path}:* {path_str}")
            await _show("\n".join(lines))

    # ── Prestige: real prestige options ─────────────────────────────
    elif action == "prestige":
        cid = p.get("class_id")
        if not cid:
            await _show("⭐ *Prestige*\n\nChoose a class first with `/class` at Level 5.")
        else:
            path = p.get("class_path")
            if path:
                cur_cls = get_player_class(p)
                cur_name = cur_cls["name"] if cur_cls else "Unknown"
                line_k = CLASS_TREE.get(cid, {}).get("line")
                fp = CLASS_PATHS.get(line_k, {}).get(path, [])
                path_str = " → ".join(CLASS_TREE.get(k,{}).get("name","?") for k in fp)
                next_t = next((lvl for lvl in [30, 60, 100] if p["level"] < lvl), None)
                if next_t:
                    await _show(f"⭐ *Path {path}* — {cur_name}\n\n📜 {path_str}\n\nAdvances at Level *{next_t}*. Keep leveling!")
                else:
                    await _show(f"👑 *Path {path}* — {cur_name}\n\n📜 {path_str}\n\n🏆 Final class form achieved! Level cap is *250* — keep growing!")
            elif p["level"] < 10:
                await _show(f"⭐ *Prestige*\n\nPath selection unlocks at Level *10*. You're Level {p['level']}.")
            else:
                cls_d = CLASS_TREE.get(cid, {})
                line_k = cls_d.get("line")
                paths = CLASS_PATHS.get(line_k, {})
                lines = [f"⭐ *Choose Your Path!*\n\n_This choice is permanent._\n"]
                for label in ["A", "B"]:
                    key = (paths.get(label) or [None])[0]
                    if not key: continue
                    nc = CLASS_TREE.get(key, {})
                    sk = (nc.get("skills") or [{}])[0]
                    fp = paths.get(label, [])
                    path_str = " → ".join(CLASS_TREE.get(k,{}).get("name","?") for k in fp)
                    lines.append(f"*Path {label}: {nc.get('name','?')}*\n_{nc.get('desc','')}_\n"
                                 f"🔸 {sk.get('name','?')}: {sk.get('desc','')}\n📜 {path_str}\n")
                lines.append("_Use `/prestige A` or `/prestige B` to choose._")
                await _show("\n".join(lines))

    # ── Skills: real skills list ─────────────────────────────────────
    elif action == "skills":
        cls = get_player_class(p)
        if not cls:
            await _show("✨ *Skills*\n\nChoose a class at Level 5 with `/class`.")
        else:
            all_skills = get_combat_skills(p)
            if not all_skills:
                await _show("✨ *Skills*\n\nNo skills yet. Level up or pick a class!")
            else:
                lines = [f"✨ *{p['username']}'s Skills* — {cls['name']}\n"]
                for i, s in enumerate(all_skills, 1):
                    stype = s.get("type", "damage")
                    icon = ("⚔️" if stype in ("damage","combo_dmg","freeze_nuke","execute_nuke",
                                              "holy_nuke","fear_kill","nature_nuke","drain")
                            else "💚" if stype in ("self_heal","group_heal","revive_heal","full_revive","regen")
                            else "✨" if stype in ("dmg_reduction_buff","self_heal_buff","heal_shield",
                                                   "self_atk_buff","party_atk_buff","party_full_buff")
                            else "⚡")
                    unlock_note = f" _(Lv.{s.get('unlock',5)})_" if p["level"] < s.get("unlock", 5) else ""
                    lines.append(f"*{i}.* {icon} *{s['name']}*{unlock_note}\n   _{s['desc']}_\n")
                lines.append("_/skill [name or #] in a reply to fire a skill_")
                await _show("\n".join(lines))

    elif action == "quest":
        aq = p.get("active_quest")
        if aq:
            import json as _json
            try: _qdata = _json.loads(aq) if isinstance(aq, str) else aq
            except: _qdata = {}
            txt = (f"📜 *Active Quest*\n\n"
                   f"*{_qdata.get('text','Quest in progress...')}*\n\n"
                   f"_Check the group chat for quest objectives and progress._")
        else:
            txt = ("📜 *Quest*\n\n"
                   "✅ No active quest — you're free to take one!\n\n"
                   "_Quests give EXP, gold, and rare loot. Head to the group chat to start one._")
        try: await _q_edit(query, txt, parse_mode="Markdown", reply_markup=back)
        except Exception: pass

    elif action == "explore":
        if is_defeated(p):
            txt = "🌍 *Explore*\n\n💀 Too beaten up to explore right now."
        else:
            today = datetime.now().strftime("%Y-%m-%d")
            exp_count = safe_int(p.get("explore_count_today")) if p.get("explore_date") == today else 0
            exp_bar = "█" * exp_count + "░" * (2 - exp_count)
            if exp_count >= 2:
                txt = f"🌍 *Explore*\n\n[{exp_bar}] 2/2 used today. Resets at midnight!"
            else:
                txt = (f"🌍 *Explore*\n\n[{exp_bar}] {exp_count}/2 used today.\n\n"
                       f"✅ *Ready!* Best loot in the game — head to the group chat to explore.")
        try: await _q_edit(query, txt, parse_mode="Markdown", reply_markup=back)
        except Exception: pass

    elif action in ("dungeon", "dungeonhard", "dungeonleg"):
        _dng_info2 = {"dungeon":("🏚️","Dungeon",1),"dungeonhard":("🔥","Dungeon Hard",15),"dungeonleg":("💀","Dungeon Legendary",40)}
        _dem2, _dname2, _dmin2 = _dng_info2[action]
        if p["level"] < _dmin2:
            txt = f"{_dem2} *{_dname2}*\n\n🔒 Requires Level {_dmin2}. You are Level {p['level']}."
        elif is_defeated(p):
            txt = f"{_dem2} *{_dname2}*\n\n💀 You're defeated — recover first."
        elif not check_cooldown(p.get("last_dungeon"), 86400):
            txt = f"{_dem2} *{_dname2}*\n\n⏳ Ready in: *{time_remaining(p.get('last_dungeon'), 86400)}*"
        else:
            txt = f"{_dem2} *{_dname2}*\n\n✅ *Ready!* Head to the group chat to start your run."
        try: await _q_edit(query, txt, parse_mode="Markdown", reply_markup=back)
        except Exception: pass

    elif action == "oracle":
        # Execute pool shot inline (same logic as pool button)
        s_cd_ora = get_shadow(uid)
        pool_ts_ora = p.get("last_pool") or (s_cd_ora.get("last_pool") if s_cd_ora else None)
        pool_ready_ora = True
        if pool_ts_ora:
            try:
                if (datetime.now() - datetime.fromisoformat(pool_ts_ora)).total_seconds() < 8:
                    pool_ready_ora = False
            except Exception: pass
        if not pool_ready_ora:
            txt = "🔮 *Oracle*\n\n⏳ The oracle is cooling down — try again in a moment."
        else:
            shot = roll_pool_shot_with_luk(p)
            exp_gain = _scaled_shot_exp(p["level"], shot["exp"])
            gold_gain = (max(5 + p["level"], int(shot["gold"] * max(1.0, 1.0 + (p["level"] - 1) * 0.12))) if shot["gold"] > 0 else 0)
            p["gold"] = p.get("gold", 0) + gold_gain
            p["last_pool"] = datetime.now().isoformat()
            if s_cd_ora: s_cd_ora["last_pool"] = p["last_pool"]; save_shadow(s_cd_ora)
            lmsgs_ora, _ = add_exp(p, exp_gain); save_player(p)
            loot_note = ""
            if shot.get("loot"):
                loot_item = roll_loot_table(shot["loot"])
                if loot_item: add_item(p, loot_item); save_player(p); loot_note = f"\n🎒 *{loot_item}*"
            txt = (f"🔮 *Oracle — {shot['rarity'].title()}*\n\n"
                   f"_{shot['text'][:120]}_\n\n"
                   f"✨ +{fmt_num(exp_gain)} EXP  |  💰 +{gold_gain}g{loot_note}")
            if lmsgs_ora: txt += "\n\n" + "\n".join(lmsgs_ora[:2])
        try: await _q_edit(query, txt, parse_mode="Markdown", reply_markup=back)
        except Exception: pass

    # ── All other actions: show tip panel ────────────────────────────
    else:
        tip = _ACTIVITIES_HUB_TIPS.get(action)
        if tip:
            title, desc = tip
            await _show(f"{title}\n\n{desc}")
        else:
            await _show(f"_{action}_ — use the command in chat.")

# ── EMPIRE (Master Hub) ───────────────────────────────────────────────────────
def _empire_markup(uid: int) -> InlineKeyboardMarkup:
    rows = [
        [InlineKeyboardButton("⚔️ Combat",     callback_data=f"empire_combat_{uid}"),
         InlineKeyboardButton("🌍 Activities", callback_data=f"empire_activities_{uid}")],
        [InlineKeyboardButton("⚙️ Gear",       callback_data=f"empire_gear_{uid}"),
         InlineKeyboardButton("💬 Social",     callback_data=f"empire_social_{uid}")],
        [InlineKeyboardButton("🐾 Pet Hub",    callback_data=f"empire_pethub_{uid}")],
        [InlineKeyboardButton("❌ Close",       callback_data=f"close_msg_{uid}")],
    ]
    return InlineKeyboardMarkup(rows)

async def empire_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user; p = get_player(user.id)
    try: await update.message.delete()
    except: pass
    if not p:
        await send_group(update, "Use /ascend first!", delay=9); return
    # Initialize a NULL collect clock (pre-migration empires) but DON'T bank —
    # collection belongs to the Collect button so it never shows empty
    if sjl(p.get("empire_buildings"), {}) and not p.get("empire_last_collect"):
        p["empire_last_collect"] = (datetime.now() - timedelta(hours=8)).isoformat()
        save_player(p)
    text, markup = _build_empire_overview(p, user.id)
    msg = await context.bot.send_message(
        chat_id=update.effective_chat.id, text=text[:4096], parse_mode="Markdown",
        reply_markup=markup)
    asyncio.create_task(_auto_delete(context.bot, update.effective_chat.id, msg.message_id, 120))

async def empire_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    uid   = query.from_user.id
    data  = query.data
    parts = data.split("_")

    hub = parts[1] if len(parts) > 1 else ""

    # ── Empire building sub-commands (uid is parts[2], not parts[-1]) ──
    if hub == "tab":
        try: req_uid = int(parts[2])
        except (IndexError, ValueError): req_uid = 0
        if uid != req_uid:
            await query.answer("Not your menu.", show_alert=True); return
        await query.answer()
        tabname = parts[3] if len(parts) > 3 else "overview"
        p = get_player(uid)
        if not p: return
        if tabname == "overview":
            text, markup = _build_empire_overview(p, uid)
        elif tabname == "build":
            text, markup = _build_empire_build(p, uid)
        elif tabname == "stats":
            text, markup = _build_empire_stats(p, uid)
        else:
            return
        try: await _q_edit(query, text, parse_mode="Markdown", reply_markup=markup)
        except Exception: pass
        return

    if hub == "collect":
        try: req_uid = int(parts[2])
        except (IndexError, ValueError): req_uid = 0
        if uid != req_uid:
            await query.answer("Not your menu.", show_alert=True); return
        p = get_player(uid)
        if not p: return
        notes = _empire_collect(p)
        save_player(p)
        if notes:
            await query.answer("\n".join(notes[:3]), show_alert=True)
        else:
            await query.answer("Nothing to collect yet — buildings generate resources over time.", show_alert=True)
        text, markup = _build_empire_overview(p, uid)
        try: await _q_edit(query, text, parse_mode="Markdown", reply_markup=markup)
        except Exception: pass
        return

    if hub == "build":
        try: req_uid = int(parts[2])
        except (IndexError, ValueError): req_uid = 0
        if uid != req_uid:
            await query.answer("Not your menu.", show_alert=True); return
        bkey = parts[3] if len(parts) > 3 else ""
        p = get_player(uid)
        if not p: return
        b = EMPIRE_BUILDINGS.get(bkey)
        if not b:
            await query.answer("Unknown building.", show_alert=True); return
        bld, res, lc = _get_empire(p)
        cur_lvl = bld.get(bkey, 0)
        if cur_lvl >= b["max_level"]:
            await query.answer("Already at max level!", show_alert=True); return
        req = b.get("requires")
        if req:
            req_key, req_lvl = req
            if bld.get(req_key, 0) < req_lvl:
                req_name = EMPIRE_BUILDINGS[req_key]["name"]
                await query.answer(f"Requires {req_name} Lv {req_lvl}!", show_alert=True); return
        cost = _empire_upgrade_cost(bkey, cur_lvl)
        for rtype, amt in cost.items():
            if rtype == "gold":
                if p.get("gold", 0) < amt:
                    await query.answer(f"Need {amt:,} gold!", show_alert=True); return
            else:
                if res.get(rtype, 0) < amt:
                    emoji = _EMPIRE_RES_EMOJI.get(rtype, rtype)
                    await query.answer(f"Need {amt:,} {emoji} {rtype}!", show_alert=True); return
        for rtype, amt in cost.items():
            if rtype == "gold":
                p["gold"] = p.get("gold", 0) - int(amt)
            else:
                res[rtype] = max(0, res.get(rtype, 0) - amt)
        bld[bkey] = cur_lvl + 1
        _save_empire(p, bld, res, lc)
        save_player(p)
        await query.answer(f"{b['name']} upgraded to Lv {cur_lvl + 1}! 🏗️", show_alert=True)
        text, markup = _build_empire_build(p, uid)
        try: await _q_edit(query, text, parse_mode="Markdown", reply_markup=markup)
        except Exception: pass
        return

    # ── Hub navigation (uid is parts[-1]) ──
    try: req_uid = int(parts[-1])
    except (IndexError, ValueError): req_uid = 0
    if uid != req_uid:
        await query.answer("Not your menu.", show_alert=True); return
    await query.answer()

    p   = get_player(uid)
    if not p: return

    if hub == "combat":
        try:
            await _q_edit(query, 
                f"⚔️ *{p['username']}'s Combat Hub*\n\nPage 1: Encounter & Combat  |  Page 2: War & Explore\nPage 3: Dungeons",
                parse_mode="Markdown", reply_markup=_combat_hub_markup(uid, page=1))
        except Exception: pass

    elif hub == "activities":
        try:
            await _q_edit(query, 
                f"🌍 *{p['username']}'s Activities Hub*\n\nPage 1: Daily  |  Page 2: Challenges\nPage 3: Character",
                parse_mode="Markdown", reply_markup=_activities_hub_markup(uid, page=1))
        except Exception: pass

    elif hub == "gear":
        try:
            await _q_edit(query, 
                f"⚙️ *{p['username']}'s Gear Hub*\n\nPage 1: Equipment  |  Page 2: Upgrades\nPage 3: Economy",
                parse_mode="Markdown", reply_markup=_gearhub_markup(uid, page=1))
        except Exception: pass

    elif hub == "social":
        marriages  = _get_marriages(p)
        hands_list = _get_holding_hands(p)
        partner_line = ""
        if marriages:
            partner_line = "💍 " + ", ".join(f"*{m['name']}*" for m in marriages[:2]) + "\n"
        if hands_list:
            partner_line += "🤝 " + ", ".join(f"*{h['name']}*" for h in hands_list[:2]) + "\n"
        text = (
            f"💬 *{p['username']}'s Social Hub*\n\n"
            f"{partner_line}"
            f"🌟 Influence: {safe_int(p.get('influence'))}\n\n"
            f"Page 1: Relationships  |  Page 2: Emotes\n"
            f"Page 3: Guilds & Alliances  |  Page 4: Recognition"
        )
        try:
            await _q_edit(query, text, parse_mode="Markdown",
                                          reply_markup=_social_hub_markup(uid, page=1))
        except Exception: pass

    elif hub == "pethub":
        try:
            pet = get_active_pet_record(uid)
            await _q_edit(query, 
                "🐾 *Pet Hub* — All things pets.\n_Page 1: Manage  |  Page 2: Care & Breeding  |  Page 3: Community_",
                parse_mode="Markdown", reply_markup=_pethub_markup(uid, pet, page=1))
        except Exception: pass

    elif hub == "home":
        try:
            await _q_edit(query, 
                f"🌌 *{p['username']}'s Empire*\n\nYour command center. Choose a hub:",
                parse_mode="Markdown", reply_markup=_empire_markup(uid))
        except Exception: pass


async def guide_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user
    try:
        await _send_guide_page(user.id, context.bot, page=1)
        if update.effective_chat.id != user.id:
            try: await update.message.delete()
            except: pass
            await context.bot.send_message(
                chat_id=update.effective_chat.id,
                text=f"📖 *{user.first_name}*, check your DMs for the guide!",
                parse_mode="Markdown")
    except Exception:
        await context.bot.send_message(
            chat_id=update.effective_chat.id,
            text=f"📖 *{user.first_name}*  -  start a DM with me first, then use /guide again!",
            parse_mode="Markdown")

