def roll_pool_shot():
    total_weight = sum(s["weight"] for s in POOL_SHOTS)
    roll = random.randint(0, total_weight - 1)
    cumulative = 0
    for shot in POOL_SHOTS:
        cumulative += shot["weight"]
        if roll < cumulative:
            return shot
    return POOL_SHOTS[0]

def roll_pool_shot_with_luk(p):
    shot = roll_pool_shot()
    luk = get_stat(p, "LUK")
    upgrade_chance = luk * 0.003
    if random.random() < upgrade_chance:
        tier_order = ["common","uncommon","rare","epic","legendary","mythic"]
        current_idx = tier_order.index(shot["rarity"])
        if current_idx < len(tier_order) - 1:
            next_rarity = tier_order[current_idx + 1]
            upgraded = [s for s in POOL_SHOTS if s["rarity"] == next_rarity]
            if upgraded:
                shot = random.choice(upgraded)
    return shot

async def pool_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user
    chat_id = update.effective_chat.id
    s = get_or_create_shadow(user.id, user.first_name)
    p = get_player(user.id) if s.get("ascended") else None

    last_pool = p.get("last_pool") if p else s.get("last_pool")
    if last_pool:
        try:
            elapsed = (datetime.now() - datetime.fromisoformat(last_pool)).total_seconds()
            if elapsed < 3:
                remaining = int(3 - elapsed)
                await send_group(update, f"🎱 Cooldown: {remaining}s", delay=5)
                return
        except Exception:
            pass

    shot = roll_pool_shot_with_luk(p) if p else roll_pool_shot()

    flavor = ""
    if p and random.random() < 0.25:
        line = get_class_line(p)
        options = POOL_CLASS_FLAVOR.get(line, [])
        if options:
            flavor = " " + random.choice(options)

    rarity_prefix = {
        "common":"🎱","uncommon":"🎯","rare":"🔵","epic":"🟣","legendary":"🟡","mythic":"🔴",
    }.get(shot["rarity"], "🎱")

    item_found = None
    if shot.get("loot") and p:
        item_found = roll_loot_table(shot["loot"])
        if item_found:
            add_item(p, item_found)

    gold_gain = shot["gold"]

    if p:
        # /pool is the flagship shot command — pays double the hub shot rate
        exp_gain  = _scaled_shot_exp(p["level"], shot["exp"]) * 2
        gold_bonus = max(1.0, 1.0 + (p["level"] - 1) * 0.12)
        gold_gain = int(gold_gain * gold_bonus)
        p["gold"] = p.get("gold", 0) + gold_gain
        p["last_pool"] = datetime.now().isoformat()
        lmsgs, leveled = add_exp(p, exp_gain)
        for _d, _e, _g in track_objective(p, "pool_run"):
            p["gold"] = p.get("gold",0) + _g; add_exp(p, _e)
        save_player(p)
        if leveled and p["level"] % 10 == 0:
            asyncio.create_task(announce(context.bot, chat_id,
                f"🎉 *{p['username']}* reached *Level {p['level']}*! 🎱",
                delay=60))
    else:
        s["last_pool"] = datetime.now().isoformat()
        exp_gain = _scaled_shot_exp(s["level"], shot["exp"]) * 2
        lmsgs, leveled = add_shadow_exp(s, exp_gain)
        save_shadow(s)

    flavor_suffix = f" {flavor.strip()}" if flavor else ""
    lines = [f"{rarity_prefix} *{user.first_name}* — _{shot['text']}{flavor_suffix}_"]
    reward_parts = []
    if exp_gain > 0:  reward_parts.append(f"✨ +{fmt_num(exp_gain)} EXP")
    if gold_gain > 0: reward_parts.append(f"💰 +{gold_gain}g")
    if reward_parts:  lines.append("  •  ".join(reward_parts))
    if item_found:
        rarity_tag = ""
        for pool3 in [WEAPONS, ARMORS, ACCESSORIES, CONSUMABLES]:
            if item_found in pool3:
                rarity_tag = RARITY_EMOJI.get(pool3[item_found].get("rarity", ""), "")
                break
        lines.append(f"🎒 {rarity_tag} *{item_found}*")

    # Secondary item roll from global pool
    if p:
        bonus_item = _roll_pool_bonus(p)
        if bonus_item:
            add_item(p, bonus_item)
            save_player(p)
            bi_rarity = ""
            for pool_check in [WEAPONS, ARMORS, ACCESSORIES, SHIELDS, HATS, GLOVES, BOOTS, MASKS]:
                if bonus_item in pool_check:
                    bi_rarity = RARITY_EMOJI.get(pool_check[bonus_item].get("rarity",""), "")
                    break
            lines.append(f"🎁 {bi_rarity} *{bonus_item}*")

    key = (chat_id, user.id)
    old_id = last_bot_message.get(key)
    if old_id:
        try:
            await update.get_bot().delete_message(chat_id=chat_id, message_id=old_id)
        except Exception:
            pass

    msg_obj = await update.get_bot().send_message(
        chat_id=chat_id, text="\n".join(lines), parse_mode="Markdown")
    last_bot_message[key] = msg_obj.message_id
    asyncio.create_task(_auto_delete(update.get_bot(), chat_id, msg_obj.message_id, 9))
    try:
        await update.message.delete()
    except Exception:
        pass

# ── HUSTLE ────────────────────────────────────────────────────────────────────
async def hustle_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Run all ready activities (daily, train, quest, pool, claim, explore) in one shot."""
    user = update.effective_user; p = get_player(user.id)
    if not p:
        await reply_to_dm(update, context, "Use /ascend first!"); return
    if is_defeated(p):
        await reply_to_dm(update, context, "💀 Too beaten up to hustle right now."); return

    now    = datetime.now()
    lines  = []
    ran    = []
    skipped = []
    w      = get_weather()

    # ── Daily ──────────────────────────────────────────────────────────────────
    if check_cooldown(p.get("last_daily"), 86400):
        p["last_daily"] = now.isoformat()
        gold = scaled_gold(p["level"], 100); p["gold"] = p.get("gold",0) + gold
        item = None
        if random.random() < 0.10:
            item = random.choice(["Health Potion","Greater Health Potion","Grand Restorative Flask"])
            add_item(p, item)
        daily_exp = exp_share(p["level"], 0.10)
        lmsgs, _ = add_exp(p, daily_exp)
        entry = f"🎁 *Daily:* +{fmt_num(daily_exp)} EXP, +{gold}g"
        if item: entry += f", *{item}*!"
        ran.append(entry)
        if lmsgs: ran.extend(f"  {m}" for m in lmsgs)
    else:
        skipped.append(f"🎁 Daily  -  {time_remaining(p.get('last_daily'), 86400)}")

    # ── Train ──────────────────────────────────────────────────────────────────
    if check_cooldown(p.get("last_train"), 1800):
        p["last_train"] = now.isoformat()
        base = exp_share(p["level"], 0.04)
        cls  = get_player_class(p)
        if cls:
            pk = cls.get("passive_key","")
            if pk in ("arcane_mind","spell_surge","arcane_mastery","mana_overload","eternal_wisdom"):
                base = round(base * 1.30)
            elif pk in ("iron_will","holy_stance","devotion","bulwark","divine_judgment"):
                base = round(base * 1.20)
            elif pk in ("quick_hands","evasion","shadowstep","ghost_form","deaths_shadow",
                        "eagle_eye","trailblazer","natures_bond","guardian_stance","pathfinder"):
                base = round(base * 1.35)
            elif pk in ("mending_aura","divine_grace","sacred_ground","resurrection","divine_presence",
                        "dark_sense","purge","judgement","wrath_of_the_righteous"):
                base = round(base * 1.15)
        lmsgs, _ = add_exp(p, base)
        ran.append(f"🏋️ *Train:* +{fmt_num(base)} EXP")
        if lmsgs: ran.extend(f"  {m}" for m in lmsgs)
    else:
        skipped.append(f"🏋️ Train  -  {time_remaining(p.get('last_train'), 1800)}")

    # ── Quest ──────────────────────────────────────────────────────────────────
    if check_cooldown(p.get("last_quest"), 3600):
        p["last_quest"] = now.isoformat()
        if p["level"] <= 3:   qpool = [q for q in SOLO_QUESTS if q["tier"]=="Easy"]
        elif p["level"] <= 7: qpool = [q for q in SOLO_QUESTS if q["tier"] in ["Easy","Medium"]]
        else:                 qpool = SOLO_QUESTS
        q  = random.choice(qpool or SOLO_QUESTS)
        item_found = roll_loot_table(q.get("loot_table",[]))
        if item_found: add_item(p, item_found)
        luk_val = get_stat(p, "LUK")
        gold    = round(q["gold"] * (1 + luk_val * 0.002))
        p["gold"] = p.get("gold",0) + gold
        p["quests_done"] = p.get("quests_done",0) + 1
        _q_exp = exp_share(p["level"], {"Easy": 0.03, "Medium": 0.05, "Hard": 0.08}.get(q["tier"], 0.03))
        lmsgs, _ = add_exp(p, _q_exp, w)
        check_titles(p)
        entry = f"🗺️ *Quest:* +{fmt_num(_q_exp)} EXP, +{gold}g"
        if item_found: entry += f", *{item_found}*!"
        ran.append(entry)
        if lmsgs: ran.extend(f"  {m}" for m in lmsgs)
    else:
        skipped.append(f"🗺️ Quest  -  {time_remaining(p.get('last_quest'), 3600)}")

    # ── Pool shot ──────────────────────────────────────────────────────────────
    last_pool = p.get("last_pool")
    pool_ready = True
    if last_pool:
        try:
            elapsed = (now - datetime.fromisoformat(last_pool)).total_seconds()
            if elapsed < 3:
                pool_ready = False
                skipped.append(f"🎱 Pool  -  {int(3 - elapsed)}s")
        except: pass
    if pool_ready:
        p["last_pool"] = now.isoformat()
        shot      = roll_pool_shot_with_luk(p)
        exp_gain  = _scaled_shot_exp(p["level"], shot["exp"])
        gold_gain = (max(5 + p["level"], int(shot["gold"] * max(1.0, 1.0 + (p["level"] - 1) * 0.12))) if shot["gold"] > 0 else 0)
        p["gold"] = p.get("gold",0) + gold_gain
        item_found = None
        if shot.get("loot"):
            item_found = roll_loot_table(shot["loot"])
            if item_found: add_item(p, item_found)
        bonus_item = _roll_pool_bonus(p)
        if bonus_item: add_item(p, bonus_item)
        lmsgs, _ = add_exp(p, exp_gain)
        rarity_prefix = {"common":"🎱","uncommon":"🎯","rare":"🔵","epic":"🟣","legendary":"🟡","mythic":"🔴"}.get(shot["rarity"],"🎱")
        entry = f"{rarity_prefix} *Pool:* +{fmt_num(exp_gain)} EXP"
        if gold_gain: entry += f", +{gold_gain}g"
        if item_found: entry += f", *{item_found}*!"
        if bonus_item: entry += f"\n  🎱 Table drop: *{bonus_item}*!"
        ran.append(entry)
        if lmsgs: ran.extend(f"  {m}" for m in lmsgs)

    # ── Claim ─────────────────────────────────────────────────────────────────
    today_str     = now.strftime("%Y-%m-%d")
    yesterday_str = (now - timedelta(days=1)).strftime("%Y-%m-%d")
    last_claim    = p.get("last_claim")
    if last_claim == today_str:
        skipped.append("🎁 Claim  -  already claimed today")
    else:
        streak = safe_int(p.get("claim_streak"))
        streak = streak + 1 if last_claim == yesterday_str else 1
        gold_reward  = 50 + min(streak * 10, 200)
        slate_count  = 1 if streak >= 3 else 0
        scale_count  = 1 if streak >= 7 else 0
        bonus_scroll = streak >= 14
        inv = sjl(p.get("inventory"), [])
        if slate_count: inv.extend(["Iron Shard"] * slate_count)
        if scale_count: inv.extend(["Iron Shard"] * scale_count)
        if bonus_scroll: inv.append("Enchanting Scroll")
        p["inventory"] = json.dumps(inv)
        p["gold"] = p.get("gold", 0) + gold_reward
        p["last_claim"] = today_str
        p["claim_streak"] = streak
        streak_emojis = "🔥" * min(streak, 7)
        claim_entry = f"🎁 *Claim Day {streak}* {streak_emojis}: +{gold_reward}g"
        if slate_count or scale_count:
            claim_entry += f", +{slate_count + scale_count} Iron Shard"
        if bonus_scroll:
            claim_entry += ", +1 Enchanting Scroll"
        ran.append(claim_entry)

    # ── Explore ────────────────────────────────────────────────────────────────
    if p.get("explore_date") == today_str and safe_int(p.get("explore_count_today")) >= 2:
        skipped.append("🗺️ Explore  -  2/2 used today")
    elif user.id in explore_timers and not explore_timers[user.id].done():
        skipped.append("🗺️ Explore  -  expedition in progress")
    else:
        if p["level"] <= 5:     _elig = [z for z in EXPLORE_ZONES if z["tier"]=="Easy"]
        elif p["level"] <= 15:  _elig = [z for z in EXPLORE_ZONES if z["tier"] in ["Easy","Medium"]]
        elif p["level"] <= 30:  _elig = [z for z in EXPLORE_ZONES if z["tier"] in ["Easy","Medium","Hard"]]
        elif p["level"] <= 60:  _elig = [z for z in EXPLORE_ZONES if z["tier"] != "Legendary"]
        else:                   _elig = EXPLORE_ZONES
        _zone = random.choice(_elig)
        if p.get("explore_date") != today_str:
            p["explore_count_today"] = 0
            p["explore_date"] = today_str
        p["explore_count_today"] = safe_int(p.get("explore_count_today")) + 1
        p["last_explore"] = now.isoformat()
        _remaining = 2 - safe_int(p.get("explore_count_today"))
        ran.append(f"🗺️ *Explore:* Expedition to *{_zone['name']}* started — results in 1 hour! ({_remaining} left today)")
        chat_id   = update.effective_chat.id
        _bot      = update.get_bot()
        _uid      = user.id
        _uname    = p.get("username", user.first_name)
        _zone_ref = _zone

        async def _hustle_explore():
            await asyncio.sleep(3600)
            pp = get_player(_uid)
            if not pp: return
            w2 = get_weather()
            success = random.random() < 0.70
            if success:
                _zone_pct = 0.08 + 0.17 * min(1.0, _zone_ref["exp"] / 28000)
                exp  = round(exp_share(pp["level"], _zone_pct) * w2.get("exp_mod", 1.0))
                gold = _zone_ref["gold"]
                pp["gold"] = pp.get("gold", 0) + gold
                item_found = roll_loot_table(_zone_ref.get("loot_table", []))
                if item_found: add_item(pp, item_found)
                lmsgs, leveled = add_exp(pp, exp)
                save_player(pp)
                rarity = ""
                if item_found:
                    for _pool in [WEAPONS, ARMORS, ACCESSORIES, CONSUMABLES]:
                        if item_found in _pool:
                            rarity = RARITY_EMOJI.get(_pool[item_found].get("rarity", ""), "")
                            break
                msg = (f"🗺️ *{pp['username']}* returns from *{_zone_ref['name']}*!\n\n"
                       f"✅ Expedition successful!\n"
                       f"✨ +{fmt_num(exp)} EXP | 💰 +{gold} Gold")
                if item_found: msg += f"\n🎒 Found: {rarity} *{item_found}*!"
                if lmsgs: msg += "\n\n" + "\n".join(lmsgs)
            else:
                save_player(pp)
                msg = (f"🗺️ *{pp['username']}* returns from *{_zone_ref['name']}*!\n\n"
                       f"❌ The expedition failed — nothing to show for it.")
            try:
                await _bot.send_message(chat_id=_uid, text=msg, parse_mode="Markdown")
            except Exception:
                try: await _bot.send_message(chat_id=chat_id, text=msg, parse_mode="Markdown")
                except Exception: pass

        _task = asyncio.create_task(_hustle_explore())
        explore_timers[_uid] = _task

    if not ran:
        cd_list = "\n".join(f"  {s}" for s in skipped)
        await reply_to_dm(update, context,
            f"🎱 *{user.first_name}*  -  nothing ready yet.\n\n{cd_list}"); return

    save_player(p)

    out = [f"🎱 *{user.first_name}* runs the table!\n"]
    out += ran
    if skipped:
        out += ["", "⏳ *Still cooling down:*"] + [f"  {s}" for s in skipped]
    await reply_to_dm(update, context, "\n".join(out))


# ── RESETSTATS ────────────────────────────────────────────────────────────────
def _do_resetstats(p):
    """Execute the stat reset and return (new_stats, refunded)."""
    sd = safe_stats(p)
    # Only the 6 allocatable stats are refunded — DEF is not allocatable (comes from gear/cores only)
    alloc_defaults = {"STR":5,"AGI":5,"INT":5,"WIS":5,"DEX":5,"LUK":5}
    # Get actual class bonuses so we don't count them as user-allocated points
    class_bonuses = _calc_applied_class_bonuses(p)
    total_allocated = 0
    for stat, base in alloc_defaults.items():
        bonus = class_bonuses.get(stat, 0)
        current = sd.get(stat, base)
        user_pts = current - base - bonus
        if user_pts > 0:
            total_allocated += user_pts
    # Reset only allocatable stats; preserve DEF (Monster Core Earth bonus)
    core_def = sd.get("DEF", 0)
    new_stats = {"STR":5,"AGI":5,"INT":5,"WIS":5,"DEX":5,"LUK":5,"DEF":core_def}
    for stat, bonus in class_bonuses.items():
        if stat in new_stats and stat != "DEF":
            new_stats[stat] = new_stats.get(stat, 5) + bonus
    refunded = total_allocated + safe_int(p.get("stat_points"))
    p["stats"] = json.dumps(new_stats)
    p["stat_points"] = refunded
    save_player(p)
    return new_stats, refunded

async def resetstats_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user; p = get_player(user.id)
    if not p:
        await send_group(update, "Use /ascend first!", delay=9); return

    _rss_cost = 1_000_000
    if not context.args or context.args[0].lower() != "confirm":
        rsstat_markup = InlineKeyboardMarkup([[
            InlineKeyboardButton("✅ Confirm Reset", callback_data=f"rsstat_confirm_{user.id}"),
            InlineKeyboardButton("❌ Cancel",        callback_data=f"rsstat_cancel_{user.id}"),
        ]])
        sd = safe_stats(p)
        await send_group(update,
            f"⚠️ *Stat Reset*\n\n"
            f"This will refund ALL allocated stat points back to your pool.\n"
            f"Your class stat bonuses will be preserved.\n\n"
            f"Current stats: STR:{sd.get('STR',5)} AGI:{sd.get('AGI',5)} "
            f"INT:{sd.get('INT',5)} WIS:{sd.get('WIS',5)} "
            f"DEX:{sd.get('DEX',5)} LUK:{sd.get('LUK',5)}\n\n"
            f"Cost: *{_rss_cost:,}g*\n\n"
            f"Tap Confirm or type /resetstats confirm to proceed.",
            delay=20, reply_markup=rsstat_markup); return

    if safe_int(p.get("gold")) < _rss_cost:
        await send_group(update,
            f"Not enough gold! Need {_rss_cost:,}g, you have {p.get('gold',0):,}g.", delay=9); return
    p["gold"] = safe_int(p.get("gold")) - _rss_cost
    new_stats, refunded = _do_resetstats(p)
    await send_group(update,
        f"🔄 *Stat Reset Complete!*\n\n"
        f"All allocated stat points have been refunded.\n"
        f"💡 *{refunded} points* returned to your pool.\n\n"
        f"DEF is now gear-only  -  armor and shields provide your defense.\n\n"
        f"Use `/allocate` to redistribute your points.\n"
        f"Current stats after class bonuses:\n"
        f"STR:{new_stats['STR']} AGI:{new_stats['AGI']} "
        f"INT:{new_stats['INT']} WIS:{new_stats['WIS']} "
        f"DEX:{new_stats['DEX']} LUK:{new_stats['LUK']}",
        delay=60)

async def resetstats_callback(update, context):
    """Handle resetstats confirm/cancel buttons."""
    query = update.callback_query
    caller_id = query.from_user.id
    _tok = _cb_lock(caller_id)
    if not _tok:
        await query.answer("Processing — please wait.", show_alert=False); return
    try:
        await query.answer()
        data = query.data
        parts = data.split("_")
        if len(parts) < 3:
            return
        action = parts[1]
        try:
            uid = int(parts[2])
        except (ValueError, IndexError):
            return
        if caller_id != uid:
            await query.answer("This isn't your reset button!", show_alert=True); return
        if action == "cancel":
            try:
                await _q_edit(query, "❌ Stat reset cancelled.", parse_mode="Markdown")
            except Exception:
                pass
            return
        p = get_player(uid)
        if not p:
            await query.answer("Player not found!", show_alert=True); return
        _rss_cost = 1_000_000
        if safe_int(p.get("gold")) < _rss_cost:
            await query.answer(f"Not enough gold! Need {_rss_cost:,}g.", show_alert=True); return
        p["gold"] = safe_int(p.get("gold")) - _rss_cost
        new_stats, refunded = _do_resetstats(p)
        result = (f"🔄 *Stat Reset Complete!*\n\n"
                  f"All allocated stat points have been refunded.\n"
                  f"💡 *{refunded} points* returned to your pool.\n\n"
                  f"DEF is now gear-only  -  armor and shields provide your defense.\n\n"
                  f"Use `/allocate` to redistribute your points.\n"
                  f"Current stats after class bonuses:\n"
                  f"STR:{new_stats['STR']} AGI:{new_stats['AGI']} "
                  f"INT:{new_stats['INT']} WIS:{new_stats['WIS']} "
                  f"DEX:{new_stats['DEX']} LUK:{new_stats['LUK']}")
        try:
            await _q_edit(query, result, parse_mode="Markdown")
        except Exception:
            pass
    finally:
        _cb_unlock(caller_id, _tok)

# ── BROADCAST (admin only) ────────────────────────────────────────────────────
async def broadcast_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user
    if user.id != ADMIN_ID:
        return
    if update.effective_chat.type != "private":
        try: await update.message.delete()
        except: pass
        return

    text = " ".join(context.args).strip() if context.args else ""
    if not text:
        await update.message.reply_text(
            "Usage: /broadcast <message>\n\n"
            "Sends a DM to every player in the database."
        )
        return

    c = _db().cursor()
    c.execute("SELECT DISTINCT user_id FROM players")
    user_ids = [row[0] for row in c.fetchall()]

    sent = 0; failed = 0
    status_msg = await update.message.reply_text(f"📡 Broadcasting to {len(user_ids)} players...")

    for uid in user_ids:
        try:
            await context.bot.send_message(chat_id=uid, text=text)
            sent += 1
        except Exception:
            failed += 1

    try:
        await status_msg.edit_text(
            f"📣 *Broadcast complete.*\n"
            f"✅ Delivered: *{sent}*\n"
            f"❌ Failed: *{failed}* _(blocked or never DM'd bot)_",
            parse_mode="Markdown"
        )
    except Exception:
        pass


# ── SEND QUEST (admin only) ───────────────────────────────────────────────────
async def sendquest_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    global _broadcast_quest, _broadcast_claims
    user = update.effective_user
    if user.id != ADMIN_ID:
        return
    if update.effective_chat.type != "private":
        try: await update.message.delete()
        except: pass
        return

    # Format: /sendquest <exp> <phrase…>
    if not context.args or len(context.args) < 2:
        await update.message.reply_text(
            "Usage: /sendquest <exp> <phrase>\n\n"
            "Example: /sendquest 500 Lets go team!\n\n"
            "Players earn the EXP by saying the exact phrase in the group.\n"
            "Use /cancelquest to end it early."
        )
        return

    try:
        exp = int(context.args[0])
    except ValueError:
        await update.message.reply_text("First argument must be a number (EXP amount).\nExample: /sendquest 500 Lets go team!")
        return

    phrase = " ".join(context.args[1:]).strip()
    quest_id = str(int(time.time()))
    _broadcast_quest  = {"id": quest_id, "phrase": phrase, "exp": exp, "expires": time.time() + 86400}
    _broadcast_claims = set()

    c = _db().cursor()
    c.execute("SELECT DISTINCT user_id FROM players")
    user_ids = [row[0] for row in c.fetchall()]

    dm_text = (
        f"📜 *Special Quest*\n\n"
        f"Say this phrase in the group chat to earn your reward:\n\n"
        f"*\"{phrase}\"*\n\n"
        f"💫 Reward: *{fmt_num(exp)} EXP*\n"
        f"⏳ Expires in 24 hours"
    )

    sent = 0; failed = 0
    status_msg = await update.message.reply_text(f"📡 Sending quest to {len(user_ids)} players...")
    for uid in user_ids:
        try:
            await context.bot.send_message(chat_id=uid, text=dm_text, parse_mode="Markdown")
            sent += 1
        except Exception:
            failed += 1

    try:
        await status_msg.edit_text(
            f"✅ *Quest sent!*\n\n"
            f"Phrase: *\"{phrase}\"*\n"
            f"Reward: *{fmt_num(exp)} EXP*\n\n"
            f"📨 Delivered: *{sent}* | ❌ Failed: *{failed}*\n"
            f"_Use /cancelquest to end it early._",
            parse_mode="Markdown"
        )
    except Exception:
        pass


async def cancelquest_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    global _broadcast_quest, _broadcast_claims
    if update.effective_user.id != ADMIN_ID:
        return
    if _broadcast_quest is None:
        await update.message.reply_text("No active broadcast quest.")
        return
    phrase = _broadcast_quest["phrase"]
    claimed = len(_broadcast_claims)
    _broadcast_quest  = None
    _broadcast_claims = set()
    await update.message.reply_text(
        f"🚫 Quest cancelled.\n\nPhrase: *\"{phrase}\"*\n{claimed} player(s) had already claimed it.",
        parse_mode="Markdown"
    )


# ── WIPE (admin only) ─────────────────────────────────────────────────────────
async def wipe_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user
    if user.id != ADMIN_ID:
        await send_group(update, "❌ Admin only.", delay=9); return

    last = _wipe_confirm.get(user.id)
    if not last or (datetime.now() - datetime.fromisoformat(last)).total_seconds() > 30:
        _wipe_confirm[user.id] = datetime.now().isoformat()
        await send_group(update,
            "⚠️ *Are you sure?* This wipes ALL player data.\n"
            "Type /wipe again within 30 seconds to confirm.", delay=30)
        return

    _wipe_confirm.pop(user.id, None)
    conn = _connect_db(); c = conn.cursor()
    c.execute("DROP TABLE IF EXISTS shadow_profiles")
    c.execute("DROP TABLE IF EXISTS players")
    c.execute("DROP TABLE IF EXISTS guilds")
    c.execute("DROP TABLE IF EXISTS bounties")
    conn.commit(); conn.close()
    init_db()
    # Clear memory state
    active_bosses.clear(); secret_boss_active.clear()
    active_events.clear(); active_raids.clear(); active_soloraids.clear()
    last_event_times.clear()
    message_counters.clear()
    pending_trades.clear(); pending_guild_reqs.clear()
    await send_group(update,
        "🗑️ *Database wiped and reset.*\n"
        "All players, guilds, and data cleared.\n"
        "Fresh start!", delay=30)

def is_banned(user_id: int) -> bool:
    try:
        conn = _connect_db(); c = conn.cursor()
        c.execute("SELECT 1 FROM banned_users WHERE user_id=?", (user_id,))
        row = c.fetchone(); conn.close()
        return row is not None
    except Exception:
        return False  # table missing or DB error — treat as not banned

def _do_ban_wipe(tid: int, tname: str):
    """Record ban in banned_users. Remove from guild and clear relationship bonds."""
    conn = _connect_db(); c = conn.cursor()
    c.execute("INSERT OR REPLACE INTO banned_users (user_id, username, banned_at) VALUES (?,?,?)",
              (tid, tname, datetime.now().isoformat()))
    conn.commit(); conn.close()

    p = get_player(tid)
    if not p:
        return

    # Remove from guild members list
    gid = p.get("guild_id")
    if gid and str(gid) != "None":
        try:
            g = get_guild(gid)
            if g:
                members = sjl(g.get("members"), [])
                if tid in members:
                    members.remove(tid)
                g["members"] = json.dumps(members)
                save_guild(g)
        except Exception:
            pass
    p["guild_id"] = None

    # Clear marriages on both sides
    m_list = sjl(p.get("marriages"), [])
    if not m_list and p.get("married_to_id"):
        m_list = [{"id": int(p["married_to_id"]), "name": p.get("married_to_name", "")}]
    for m in m_list:
        try:
            partner = get_player(m["id"])
            if partner:
                pm = sjl(partner.get("marriages"), [])
                pm = [x for x in pm if x.get("id") != tid]
                partner["marriages"] = json.dumps(pm) if pm else None
                if not pm:
                    partner["married_to_id"] = None
                    partner["married_to_name"] = None
                    partner["married_at"] = None
                else:
                    partner["married_to_id"] = pm[0]["id"]
                    partner["married_to_name"] = pm[0]["name"]
                save_player(partner)
        except Exception:
            pass
    p["marriages"] = None
    p["married_to_id"] = None
    p["married_to_name"] = None
    p["married_at"] = None

    # Clear holding hands on both sides
    try:
        h_list = _get_holding_hands(p)
        for h in h_list:
            try:
                partner = get_player(h["id"])
                if partner:
                    ph = _get_holding_hands(partner)
                    ph = [x for x in ph if x.get("id") != tid]
                    _save_holding_hands(partner, ph)
                    save_player(partner)
            except Exception:
                pass
        _save_holding_hands(p, [])
    except Exception:
        pass

    save_player(p)

_BAN_PAGE_SIZE = 10

def _build_ban_picker(page: int = 0):
    """Return (text, InlineKeyboardMarkup) for the ban player-picker."""
    conn = _connect_db(); c = conn.cursor()
    c.execute("""
        SELECT user_id, username, level FROM players
        WHERE user_id NOT IN (SELECT user_id FROM banned_users)
        ORDER BY level DESC
    """)
    rows = c.fetchall(); conn.close()
    total = len(rows)
    start = page * _BAN_PAGE_SIZE
    page_rows = rows[start:start + _BAN_PAGE_SIZE]

    text = f"🔨 *Ban Player — Select a target* (page {page+1})\n_Tap a name to get a confirmation button._\n"
    buttons = []
    for uid, uname, lvl in page_rows:
        buttons.append([InlineKeyboardButton(
            f"Lv{lvl} {uname}", callback_data=f"banpick_sel_{uid}")])

    nav = []
    if page > 0:
        nav.append(InlineKeyboardButton("◀️ Prev", callback_data=f"banpick_pg_{page-1}"))
    if start + _BAN_PAGE_SIZE < total:
        nav.append(InlineKeyboardButton("Next ▶️", callback_data=f"banpick_pg_{page+1}"))
    if nav:
        buttons.append(nav)
    buttons.append([InlineKeyboardButton("❌ Cancel", callback_data="banpick_cancel")])
    return text, InlineKeyboardMarkup(buttons)

async def ban_picker_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    if not query: return
    if query.from_user.id != ADMIN_ID:
        await query.answer("Admin only.", show_alert=True); return

    data = query.data

    # ── Cancel ────────────────────────────────────────────────────────────────
    if data == "banpick_cancel":
        await query.answer()
        try: await _q_edit(query, "Cancelled.")
        except Exception: pass
        return

    # ── Page navigation ───────────────────────────────────────────────────────
    if data.startswith("banpick_pg_"):
        await query.answer()
        page = int(data.split("_")[2])
        text, markup = _build_ban_picker(page)
        try: await _q_edit(query, text, parse_mode="Markdown", reply_markup=markup)
        except Exception: pass
        return

    # ── Select player → show confirmation ─────────────────────────────────────
    if data.startswith("banpick_sel_"):
        await query.answer()
        tid = int(data.split("_")[2])
        conn = _connect_db(); c = conn.cursor()
        c.execute("SELECT username, level FROM players WHERE user_id=?", (tid,))
        row = c.fetchone(); conn.close()
        if not row:
            try: await _q_edit(query, "❌ Player not found.")
            except Exception: pass
            return
        tname, lvl = row
        markup = InlineKeyboardMarkup([
            [InlineKeyboardButton("✅ Yes, ban them", callback_data=f"banpick_confirm_{tid}")],
            [InlineKeyboardButton("◀️ Back",          callback_data="banpick_pg_0")],
        ])
        try:
            await _q_edit(query, 
                f"Ban <b>{tname}</b>  |  Lv {lvl}  |  ID <code>{tid}</code>\n\n"
                f"This wipes all their data and blocks them permanently.",
                parse_mode="HTML", reply_markup=markup)
        except Exception as e:
            try: await context.bot.send_message(ADMIN_ID, f"[ban sel error] {e}")
            except Exception: pass
        return

    # ── Confirm ban ───────────────────────────────────────────────────────────
    if data.startswith("banpick_confirm_"):
        await query.answer("Banning...", show_alert=False)
        tid = int(data.split("_")[2])
        conn = _connect_db(); c = conn.cursor()
        c.execute("SELECT username FROM players WHERE user_id=?", (tid,))
        row = c.fetchone(); conn.close()
        tname = row[0] if row else f"User#{tid}"
        try:
            _do_ban_wipe(tid, tname)
        except Exception as e:
            try: await context.bot.send_message(ADMIN_ID, f"[ban wipe error] {e}")
            except Exception: pass
            return
        try:
            await context.bot.send_message(chat_id=tid,
                text="🚫 You have been banned from 8ball World.")
        except Exception:
            pass
        try:
            await _q_edit(query, 
                f"🔨 <b>{tname}</b> (ID <code>{tid}</code>) banned and wiped.",
                parse_mode="HTML")
        except Exception as e:
            try: await context.bot.send_message(ADMIN_ID, f"[ban confirm edit error] {e}")
            except Exception: pass
        return

    await query.answer()

async def ban_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user
    if user.id != ADMIN_ID:
        await send_group(update, "❌ Admin only.", delay=9); return

    tid = None; tname = None

    # Priority 1: reply to their message
    if update.message and update.message.reply_to_message:
        ru = update.message.reply_to_message.from_user
        tid = ru.id
        tname = ru.first_name
    # Priority 2: numeric user ID
    elif context.args and context.args[0].lstrip("-").isdigit():
        tid = int(context.args[0])
        conn = _connect_db(); c = conn.cursor()
        c.execute("SELECT username FROM players WHERE user_id=?", (tid,))
        row = c.fetchone()
        if not row:
            c.execute("SELECT username FROM shadow_profiles WHERE user_id=?", (tid,))
            row = c.fetchone()
        conn.close()
        tname = row[0] if row else f"User#{tid}"
    # Priority 3: display name or @handle
    elif context.args:
        target = get_player_by_username(context.args[0])
        if not target:
            await send_group(update, "❌ No player found with that name or ID.", delay=9); return
        tid = target["user_id"]; tname = target["username"]
    else:
        # No args — show interactive player picker (highest level first)
        text, markup = _build_ban_picker(0)
        await update.message.reply_text(text, parse_mode="Markdown", reply_markup=markup)
        return

    _do_ban_wipe(tid, tname)
    try:
        await context.bot.send_message(chat_id=tid, text="🚫 You have been banned from 8ball World.")
    except Exception:
        pass
    await send_group(update,
        f"🔨 *{tname}* (ID: `{tid}`) has been banned and wiped from the game.\n"
        f"They can no longer use any bot commands.", delay=30)

def _build_unban_picker():
    conn = _connect_db(); c = conn.cursor()
    c.execute("SELECT user_id, username, banned_at FROM banned_users ORDER BY banned_at DESC")
    rows = c.fetchall(); conn.close()
    return rows

def _build_unban_markup(rows):
    buttons = []
    for uid, uname, banned_at in rows:
        try:
            dt = datetime.fromisoformat(banned_at).strftime("%m/%d/%y")
        except Exception:
            dt = "?"
        buttons.append([InlineKeyboardButton(
            f"{uname}  (banned {dt})", callback_data=f"unbanpick_sel_{uid}")])
    buttons.append([InlineKeyboardButton("❌ Cancel", callback_data="unbanpick_cancel")])
    return InlineKeyboardMarkup(buttons)

async def unban_picker_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    if not query: return
    if query.from_user.id != ADMIN_ID:
        await query.answer("Admin only.", show_alert=True); return

    data = query.data

    if data == "unbanpick_cancel":
        await query.answer()
        try: await _q_edit(query, "Cancelled.")
        except Exception: pass
        return

    if data.startswith("unbanpick_sel_"):
        await query.answer()
        tid = int(data.split("_")[2])
        conn = _connect_db(); c = conn.cursor()
        c.execute("SELECT username, banned_at FROM banned_users WHERE user_id=?", (tid,))
        row = c.fetchone(); conn.close()
        if not row:
            try: await _q_edit(query, "❌ User not found in ban list.")
            except Exception: pass
            return
        uname, banned_at = row
        try:
            dt = datetime.fromisoformat(banned_at).strftime("%Y-%m-%d")
        except Exception:
            dt = "?"
        markup = InlineKeyboardMarkup([
            [InlineKeyboardButton("✅ Yes, unban them", callback_data=f"unbanpick_confirm_{tid}")],
            [InlineKeyboardButton("◀️ Back",            callback_data="unbanpick_back")],
        ])
        try:
            await _q_edit(query, 
                f"Unban <b>{uname}</b>?\nBanned on: {dt}\n\n"
                f"Their stats and progress are fully restored.",
                parse_mode="HTML", reply_markup=markup)
        except Exception as e:
            try: await context.bot.send_message(ADMIN_ID, f"[unban sel error] {e}")
            except Exception: pass
        return

    if data == "unbanpick_back":
        await query.answer()
        rows = _build_unban_picker()
        if not rows:
            try: await _q_edit(query, "No banned players.")
            except Exception: pass
            return
        try:
            await _q_edit(query, 
                "🔓 *Unban Player — Select a player to unban*",
                parse_mode="Markdown", reply_markup=_build_unban_markup(rows))
        except Exception: pass
        return

    if data.startswith("unbanpick_confirm_"):
        await query.answer()
        tid = int(data.split("_")[2])
        conn = _connect_db(); c = conn.cursor()
        c.execute("SELECT username FROM banned_users WHERE user_id=?", (tid,))
        row = c.fetchone()
        if not row:
            conn.close()
            try: await _q_edit(query, "❌ Already unbanned or not found.")
            except Exception: pass
            return
        uname = row[0]
        c.execute("DELETE FROM banned_users WHERE user_id=?", (tid,))
        conn.commit(); conn.close()
        try:
            await context.bot.send_message(chat_id=tid,
                text="✅ You have been unbanned from 8ball World. Your account has been fully restored.")
        except Exception:
            pass
        try:
            await _q_edit(query, 
                f"✅ <b>{uname}</b> has been unbanned.",
                parse_mode="HTML")
        except Exception as e:
            try: await context.bot.send_message(ADMIN_ID, f"[unban confirm error] {e}")
            except Exception: pass
        return

    await query.answer()

async def unban_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user
    if user.id != ADMIN_ID:
        await send_group(update, "❌ Admin only.", delay=9); return

    # No args — show interactive picker
    if not context.args:
        rows = _build_unban_picker()
        if not rows:
            await send_group(update, "No banned players.", delay=15); return
