def _calc_max_stat_points(p):
    lvl = safe_int(p.get("level", 1))
    prestige = safe_int(p.get("prestige_count", 0))
    base_pts = (lvl * 3 + lvl // 5) if lvl <= 20 else (20 * 3 + 20 // 5 + (lvl - 20) * 6)
    return base_pts + prestige * 10

async def fixstats_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Admin: inspect and correct stat points.
    /fixstats                       — scan all, list high pools
    /fixstats <name or id>          — full inspection
    /fixstats <name or id> setpool <n> — set pool directly to n
    /fixstats <name or id> fix      — auto-reduce pool by formula"""
    user = update.effective_user
    if user.id != ADMIN_ID:
        await send_group(update, "❌ Admin only.", delay=9); return

    def _inspect(p):
        class_bonuses = _calc_applied_class_bonuses(p)
        sd = safe_stats(p)
        base = {"STR":5,"AGI":5,"INT":5,"WIS":5,"DEX":5,"LUK":5}
        allocated = sum(max(0, sd.get(s, b) - b - class_bonuses.get(s, 0)) for s, b in base.items())
        pool      = safe_int(p.get("stat_points"))
        max_pts   = _calc_max_stat_points(p)
        return allocated, pool, max_pts

    if not context.args:
        conn_s = _connect_db(); conn_s.row_factory = sqlite3.Row; c_s = conn_s.cursor()
        c_s.execute("SELECT user_id, username, level, prestige_count, stat_points, "
                    "stats, class_id, class_path FROM players")
        rows = [dict(r) for r in c_s.fetchall()]; conn_s.close()
        flagged = []
        for row in rows:
            pool = safe_int(row.get("stat_points"))
            max_pts = _calc_max_stat_points(row)
            if pool > max_pts + 10:
                flagged.append(f"• *{row['username']}* (id `{row['user_id']}`) "
                               f"lv{row['level']} p{row.get('prestige_count',0)}: "
                               f"pool={pool} max={max_pts} excess≈{pool-max_pts}")
        if not flagged:
            await send_group(update, "✅ No stat pool anomalies found.", delay=15); return
        await send_group(update,
            f"⚠️ *High Pools ({len(flagged)}):*\n\n" + "\n".join(flagged[:20]) +
            f"\n\nUse `/fixstats <name> setpool 0` to zero, or inspect first.", delay=60); return

    query_str = context.args[0]
    rest = context.args[1:]

    target_id = None
    try:
        target_id = int(query_str)
    except ValueError:
        search = query_str.lower()
        conn_n = _connect_db(); conn_n.row_factory = sqlite3.Row; c_n = conn_n.cursor()
        c_n.execute("SELECT user_id, username FROM players WHERE LOWER(username) LIKE ?",
                    (f"%{search}%",))
        matches = [dict(r) for r in c_n.fetchall()]; conn_n.close()
        if not matches:
            await send_group(update, f"No player found matching '{query_str}'.", delay=9); return
        if len(matches) > 1:
            names = "\n".join(f"• *{m['username']}* — id `{m['user_id']}`" for m in matches[:10])
            await send_group(update,
                f"Multiple matches:\n\n{names}\n\nUse the id.", delay=20); return
        target_id = matches[0]["user_id"]

    p = get_player(target_id)
    if not p:
        await send_group(update, f"Player not found.", delay=9); return

    allocated, current_pool, max_pts = _inspect(p)
    prestige = safe_int(p.get("prestige_count", 0))

    # setpool — direct override
    if rest and rest[0].lower() == "setpool":
        try:
            new_val = int(rest[1]) if len(rest) > 1 else 0
        except (ValueError, IndexError):
            await send_group(update, "Usage: /fixstats <name> setpool <number>", delay=9); return
        p["stat_points"] = new_val
        save_player(p)
        p2 = get_player(target_id)
        saved = safe_int(p2.get("stat_points")) if p2 else new_val
        await send_group(update,
            f"✅ *{p['username']}* pool set: {current_pool} → {saved}", delay=15); return

    # fix — formula auto-reduce (only safe when player hasn't prestiged with class baked in)
    if rest and rest[0].lower() == "fix":
        total = allocated + current_pool
        if total <= max_pts:
            await send_group(update,
                f"✅ *{p['username']}* is within bounds. No fix needed.\n"
                f"pool={current_pool} allocated={allocated} max={max_pts}", delay=15); return
        excess = total - max_pts
        new_pool = max(0, current_pool - excess)
        p["stat_points"] = new_pool
        save_player(p)
        p2 = get_player(target_id)
        saved = safe_int(p2.get("stat_points")) if p2 else new_pool
        await send_group(update,
            f"✅ Fixed *{p['username']}*\n"
            f"Pool: {current_pool} → {saved} (removed {excess})\n"
            f"_If still flagged, use `setpool` to override directly._", delay=15); return

    # inspect
    sd = safe_stats(p)
    stats_line = " ".join(f"{s}:{sd.get(s,b)}" for s,b in
                          [("STR",5),("AGI",5),("INT",5),("WIS",5),("DEX",5),("LUK",5)])
    cls_name = (get_player_class(p) or {}).get("name", "none")
    await send_group(update,
        f"🔍 *{p['username']}* — id `{target_id}`\n"
        f"Level: {p['level']}  |  Prestige: {prestige}  |  Class: {cls_name}\n"
        f"Stats: {stats_line}\n"
        f"Allocated (est): {allocated}  |  Pool: {current_pool}\n"
        f"Formula max: {max_pts}  |  Pool excess: {max(0, current_pool - max_pts)}\n\n"
        f"`/fixstats {target_id} fix` — auto reduce pool\n"
        f"`/fixstats {target_id} setpool 0` — zero the pool directly", delay=30)


async def fixgear_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Admin: strip class-restricted gear from a player (or scan all).
    Usage: /fixgear               — list all players wearing invalid gear
           /fixgear <name or id>  — strip invalid gear for that player"""
    user = update.effective_user
    if user.id != ADMIN_ID:
        await send_group(update, "❌ Admin only.", delay=9); return

    def _invalid_gear(p):
        cls_line = get_class_line(p)
        path = p.get("class_path")
        bad = []
        for slot, pool in [("equipped_weapon", WEAPONS), ("equipped_armor", ARMORS),
                            ("equipped_hat", HATS), ("equipped_gloves", GLOVES),
                            ("equipped_boots", BOOTS), ("equipped_mask", MASKS)]:
            name = p.get(slot)
            if not name: continue
            d = pool.get(name, {})
            item_class = d.get("class") or d.get("line")
            if item_class and (not cls_line or item_class != cls_line):
                bad.append(name)
        s_name = p.get("equipped_shield")
        if s_name:
            s_data = SHIELDS.get(s_name, {})
            if s_data.get("type") == "claw":
                if cls_line != "thief" or path != "B": bad.append(s_name)
            else:
                if cls_line != "warrior" or path != "A": bad.append(s_name)
        return bad

    if not context.args:
        conn_fg = _connect_db(); conn_fg.row_factory = sqlite3.Row; c_fg = conn_fg.cursor()
        c_fg.execute("SELECT user_id, username, class_id, class_path, equipped_weapon, equipped_armor, "
                     "equipped_shield, equipped_hat, equipped_gloves, equipped_boots, equipped_mask FROM players")
        rows = [dict(r) for r in c_fg.fetchall()]; conn_fg.close()
        flagged = []
        for row in rows:
            bad = _invalid_gear(row)
            if bad:
                flagged.append(f"• *{row['username']}* (id `{row['user_id']}`): {', '.join(bad)}")
        if not flagged:
            await send_group(update, "✅ No invalid gear found.", delay=15); return
        await send_group(update,
            f"⚠️ *Invalid Gear Found ({len(flagged)}):*\n\n" + "\n".join(flagged[:20]) +
            f"\n\nUse `/fixgear <name or id>` to strip.", delay=60); return

    query_str = context.args[0]
    target_id = None
    try:
        target_id = int(query_str)
    except ValueError:
        conn_fg2 = _connect_db(); conn_fg2.row_factory = sqlite3.Row; c_fg2 = conn_fg2.cursor()
        c_fg2.execute("SELECT user_id, username FROM players WHERE LOWER(username) LIKE ?",
                      (f"%{query_str.lower()}%",))
        matches = [dict(r) for r in c_fg2.fetchall()]; conn_fg2.close()
        if not matches:
            await send_group(update, f"No player found matching '{query_str}'.", delay=9); return
        if len(matches) > 1:
            names = "\n".join(f"• *{m['username']}* — id `{m['user_id']}`" for m in matches[:10])
            await send_group(update,
                f"Multiple matches:\n\n{names}\n\nUse the id.", delay=20); return
        target_id = matches[0]["user_id"]

    p = get_player(target_id)
    if not p:
        await send_group(update, f"Player not found.", delay=9); return

    unequipped = _unequip_class_gear(p)
    if not unequipped:
        await send_group(update, f"✅ *{p['username']}* has no invalid gear equipped.", delay=15); return
    save_player(p)
    await send_group(update,
        f"✅ Stripped *{p['username']}*'s invalid gear:\n" +
        "\n".join(f"• {item}" for item in unequipped) +
        "\n\nItems returned to their inventory.", delay=15)


async def admingivexp_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if update.effective_user.id != ADMIN_ID:
        return
    if update.effective_chat.type != "private":
        try: await update.message.delete()
        except: pass
        return

    args = context.args
    if not args:
        await update.message.reply_text(
            "Usage: /admingivexp <name/id/search> <amount>\n\n"
            "If multiple players match the search, you'll get a picker.\n"
            "Examples:\n"
            "  /admingivexp john 900000\n"
            "  /admingivexp 123456789 50000\n"
            "  /admingivexp @john 200000"
        )
        return

    # If last arg is a number it's the amount; otherwise no amount given yet
    try:
        exp_amount = int(args[-1])
        query_parts = args[:-1]
    except ValueError:
        await update.message.reply_text("Last argument must be the EXP amount.\nExample: /admingivexp john 900000")
        return

    if not query_parts:
        await update.message.reply_text("Provide a name, @username, or user ID before the amount.")
        return

    search = " ".join(query_parts).strip().lower().lstrip("@")
    c = _db().cursor()

    # Collect all matches: exact user_id, exact tg_username, partial username/display
    matches = []
    seen = set()

    def _add(row):
        if row and row["user_id"] not in seen:
            seen.add(row["user_id"])
            matches.append(dict(row))

    # 1. Exact user_id
    try:
        uid_int = int(search)
        row = c.execute("SELECT user_id, username, level, tg_username FROM players WHERE user_id=?", (uid_int,)).fetchone()
        _add(row)
    except ValueError:
        pass

    # 2. Exact @handle
    c.execute("SELECT user_id, username, level, tg_username FROM players WHERE LOWER(tg_username)=?", (search,))
    for row in c.fetchall(): _add(row)

    # 3. Exact display name
    c.execute("SELECT user_id, username, level, tg_username FROM players WHERE LOWER(username)=?", (search,))
    for row in c.fetchall(): _add(row)

    # 4. Partial match on either field (up to 20 results)
    c.execute("""SELECT user_id, username, level, tg_username FROM players
                 WHERE LOWER(username) LIKE ? OR LOWER(tg_username) LIKE ?
                 ORDER BY level DESC LIMIT 20""", (f"%{search}%", f"%{search}%"))
    for row in c.fetchall(): _add(row)

    if not matches:
        await update.message.reply_text(f"No players found matching '{search}'.")
        return

    if len(matches) == 1:
        # Single match — apply directly
        p = get_player(matches[0]["user_id"])
        if not p:
            await update.message.reply_text("Player found but data missing."); return
        old_level = p["level"]
        add_exp(p, exp_amount)
        save_player(p)
        new_level = p["level"]
        level_note = f" _(levelled up: {old_level} → {new_level})_" if new_level != old_level else ""
        handle = f" (@{matches[0]['tg_username']})" if matches[0].get("tg_username") else ""
        await update.message.reply_text(
            f"✅ Gave *{fmt_num(exp_amount)} EXP* to *{p['username']}*{handle}{level_note}\n"
            f"New level: *{new_level}*  |  EXP: *{fmt_num(p['exp'])}*",
            parse_mode="Markdown"
        )
        return

    # Multiple matches — show picker (store exp in callback data)
    rows = []
    for m in matches[:20]:
        handle = f"@{m['tg_username']} · " if m.get("tg_username") else ""
        label = f"{m['username']} ({handle}Lv {m['level']}  |  id:{m['user_id']})"
        rows.append([InlineKeyboardButton(label,
            callback_data=f"agivexp_{m['user_id']}_{exp_amount}")])
    rows.append([InlineKeyboardButton("❌ Cancel", callback_data="agivexp_cancel")])
    await update.message.reply_text(
        f"Found *{len(matches)}* players matching *'{search}'*.\n"
        f"Select who should receive *{fmt_num(exp_amount)} EXP*:",
        parse_mode="Markdown",
        reply_markup=InlineKeyboardMarkup(rows)
    )


async def admingivexp_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    if update.effective_user.id != ADMIN_ID:
        await query.answer("Not authorised.", show_alert=True); return
    await query.answer()
    data = query.data

    if data == "agivexp_cancel":
        try: await _q_edit(query, "_Cancelled._", parse_mode="Markdown")
        except: pass
        return

    parts = data.split("_")   # agivexp_<uid>_<exp>
    try:
        target_uid = int(parts[1])
        exp_amount = int(parts[2])
    except (IndexError, ValueError):
        await _q_edit(query, "Invalid callback data."); return

    p = get_player(target_uid)
    if not p:
        await _q_edit(query, "Player not found."); return

    old_level = p["level"]
    add_exp(p, exp_amount)
    save_player(p)
    new_level = p["level"]
    level_note = f" _(levelled up: {old_level} → {new_level})_" if new_level != old_level else ""

    try:
        await _q_edit(query, 
            f"✅ Gave *{fmt_num(exp_amount)} EXP* to *{p['username']}*{level_note}\n"
            f"New level: *{new_level}*  |  EXP: *{fmt_num(p['exp'])}*",
            parse_mode="Markdown"
        )
    except Exception: pass


async def adminresetclass_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Admin-only: reset a player's class so they can re-choose. For testing purposes."""
    if update.effective_user.id != ADMIN_ID:
        return
    if not context.args:
        await update.message.reply_text(
            "Usage: /adminresetclass <@username or user_id>\n"
            "Clears class_id, class_path, and all_skills so the player can pick again.")
        return
    target = context.args[0].lstrip("@")
    p = get_player_by_username(target)
    if not p:
        try:
            p = get_player(int(target))
        except ValueError:
            p = None
    if not p:
        await update.message.reply_text(f"Player '{target}' not found."); return
    old_class = p.get("class_id") or "none"
    old_cls   = CLASS_TREE.get(old_class, {})
    old_name  = old_cls.get("name", old_class)

    # Reverse all class stat bonuses (same logic as /resetclass)
    bonuses = _calc_applied_class_bonuses(p)
    sd = safe_stats(p)
    for stat, val in bonuses.items():
        sd[stat] = max(0, sd.get(stat, 0) - val)
    p["stats"] = json.dumps(sd)

    p["class_id"]   = None
    p["class_path"] = None
    p["all_skills"] = json.dumps([])

    # Clear class-specific combat state
    for _f in ("charging_killshot", "steady_aim_target", "steady_aim_stacks",
               "mark_first_hit", "deadeye_kill_bonus", "spell_cast_count",
               "holy_field_until", "devotion_charge",
               "contract_target", "contract_until",
               "serpent_revive_used", "cure_priority"):
        p.pop(_f, None)
    for _f in ("charging_killshot", "steady_aim_stacks", "mark_first_hit",
               "deadeye_kill_bonus", "spell_cast_count", "devotion_charge"):
        p[_f] = 0  # integer fields need a default, not absent

    # Strip class-restricted gear
    unequipped = _unequip_class_gear(p)
    new_max_hp = calc_max_hp(p)
    p["hp"] = min(safe_int(p.get("hp", new_max_hp)), new_max_hp)

    save_player(p)
    gear_note = f"\n⚠️ Class gear unequipped: {', '.join(unequipped)}" if unequipped else ""
    bonus_note = (f"\n📉 Stat bonuses reversed: " +
                  ", ".join(f"{s} -{v}" for s, v in bonuses.items())) if bonuses else ""
    await update.message.reply_text(
        f"✅ *{p['username']}*'s class reset.\n"
        f"Old class: *{old_name}*{bonus_note}{gear_note}\n"
        f"They can now use /class to choose a new one.",
        parse_mode="Markdown")


async def fixbounties_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Admin: inspect and fix stuck bounties.
    /fixbounties              — list ALL unclaimed bounties (including expired)
    /fixbounties wipe         — delete all expired+unclaimed bounties
    /fixbounties wipe <name>  — delete all unclaimed bounties on that player
    /fixbounties claim <name> — force-claim all unclaimed bounties on that player (gold goes to admin)
    """
    user = update.effective_user
    if user.id != ADMIN_ID:
        await send_group(update, "❌ Admin only.", delay=9); return

    conn = _db(); c = conn.cursor()
    now_iso = datetime.now().isoformat()

    args = context.args or []
    action = args[0].lower() if args else "list"
    target_name = " ".join(args[1:]) if len(args) > 1 else None

    # ── Resolve target player ──────────────────────────────────────────────────
    target_uid = None
    if target_name:
        tp = get_player_by_username(target_name)
        if not tp:
            tp_c = c.execute("SELECT user_id, username FROM players WHERE username LIKE ?",
                             (f"%{target_name}%",)).fetchone()
            tp = dict(tp_c) if tp_c else None
        if not tp:
            await send_group(update, f"❌ Player *{target_name}* not found.", delay=9); return
        target_uid = tp["user_id"]

    if action == "list":
        rows = c.execute(
            "SELECT b.bounty_id, b.target_id, b.placer_id, b.reward, b.expires_at, b.claimed_by, "
            "p.username as target_name, p2.username as placer_name "
            "FROM bounties b "
            "LEFT JOIN players p  ON b.target_id  = p.user_id "
            "LEFT JOIN players p2 ON b.placer_id = p2.user_id "
            "WHERE b.claimed_by IS NULL "
            "ORDER BY b.expires_at DESC LIMIT 20"
        ).fetchall()
        if not rows:
            await send_group(update, "✅ No unclaimed bounties in the database.", delay=15); return
        lines = [f"🎯 *Unclaimed Bounties* ({len(rows)} shown)\n"]
        for r in rows:
            exp = r["expires_at"] or "?"
            expired = exp < now_iso if exp != "?" else False
            status = "💀 EXPIRED" if expired else "✅ LIVE"
            lines.append(
                f"ID `{r['bounty_id']}` | {status}\n"
                f"  Target: *{r['target_name'] or r['target_id']}*  "
                f"Placer: *{r['placer_name'] or r['placer_id']}*  "
                f"Reward: *{r['reward']}g*\n"
                f"  Expires: {exp[:16]}"
            )
        lines.append("\n`/fixbounties wipe` — delete expired\n"
                     "`/fixbounties wipe <name>` — delete all on player\n"
                     "`/fixbounties claim <name>` — force-claim all on player")
        await send_group(update, "\n".join(lines), permanent=True, delay=120); return

    if action == "wipe":
        if target_uid:
            deleted = c.execute(
                "DELETE FROM bounties WHERE target_id=? AND claimed_by IS NULL",
                (target_uid,)).rowcount
            conn.commit()
            await send_group(update,
                f"🗑️ Wiped *{deleted}* unclaimed bounty(s) on *{tp['username']}*.", delay=15)
        else:
            deleted = c.execute(
                "DELETE FROM bounties WHERE claimed_by IS NULL AND expires_at < ?",
                (now_iso,)).rowcount
            conn.commit()
            await send_group(update,
                f"🗑️ Deleted *{deleted}* expired unclaimed bounty(s).", delay=15)
        return

    if action == "claim":
        if not target_uid:
            await send_group(update, "Usage: /fixbounties claim <playername>", delay=9); return
        rows = c.execute(
            "SELECT * FROM bounties WHERE target_id=? AND claimed_by IS NULL",
            (target_uid,)).fetchall()
        if not rows:
            await send_group(update, f"No unclaimed bounties on that player.", delay=9); return
        total = sum(r["reward"] for r in rows)
        c.execute("UPDATE bounties SET claimed_by=? WHERE target_id=? AND claimed_by IS NULL",
                  (ADMIN_ID, target_uid))
        conn.commit()
        await send_group(update,
            f"✅ Force-claimed *{len(rows)}* bounty(s) on *{tp['username']}* "
            f"totaling *{total}g*. (Gold not awarded — use this to unstick the board.)", delay=15)
        return

    await send_group(update, "Unknown action. Use: list | wipe | wipe <name> | claim <name>", delay=9)


# ── IDLE REWARD SYSTEM ────────────────────────────────────────────────────────
def _calc_idle_exp(idle_secs: float, player_level: int = 1) -> int:
    """EXP for being offline. 0 if < 30 min. Grows EXPONENTIALLY with idle time for the
    first 10 hours (so checking back after a few hours feels meaningfully better than
    checking back after 30 min), then tapers to a slow linear rate beyond that to avoid
    rewarding multi-day AFK abandonment disproportionately."""
    if idle_secs < 1800:
        return 0
    idle_hours = idle_secs / 3600
    # Calibrated so a full 10h idle ramp pays ~15% of the current level requirement
    # (the exponential sum below multiplies base_rate by ~6.5x at 10 hours)
    base_rate = exp_share(player_level, 0.023)
    growth = 1.22
    capped_h = min(idle_hours, 10)
    # Geometric-sum style exponential ramp over the capped window
    exp_exponential = base_rate * (growth ** capped_h - 1) / (growth - 1) / 5
    overflow_h = max(0, idle_hours - 10)
    exp_overflow = base_rate * overflow_h * 0.15
    exp = int(exp_exponential + exp_overflow)
    return max(50, exp)

async def _try_idle_reward(uid: int, bot, prev_seen_iso: str):
    """Award idle EXP to shadow + RPG player, send DM. Call before updating last_seen."""
    global _idle_last_awarded
    now_ts = time.time()
    if _idle_last_awarded.get(uid, 0) > now_ts - 60:
        return  # already awarded within last 60 s (rapid messages)
    try:
        idle_secs = (datetime.now() - datetime.fromisoformat(prev_seen_iso)).total_seconds()
        p = get_player(uid)
        plvl = p["level"] if p else 1
        idle_exp = _calc_idle_exp(idle_secs, plvl)
        # Empire: point at pending resources instead of silently banking them —
        # collection belongs to the /empire Collect button. STRICTLY in tandem
        # with the idle reward (30+ min away): the pending peek accrues within
        # a minute, so letting it trigger the welcome-back alone spammed the
        # message on every short gap between messages.
        empire_notes = []
        if idle_secs >= 1800 and p and not is_defeated(p):
            if sjl(p.get("empire_buildings"), {}) and not p.get("empire_last_collect"):
                p["empire_last_collect"] = (datetime.now() - timedelta(hours=8)).isoformat()
                save_player(p)
            _pend = _empire_pending(p)
            if _pend:
                _pend_str = "  ".join(f"{_EMPIRE_RES_EMOJI.get(r,'📦')} +{v:,.1f}" if isinstance(v, float)
                                      else f"{_EMPIRE_RES_EMOJI.get(r,'📦')} +{v:,}" for r, v in _pend.items())
                empire_notes = [f"{_pend_str}\n  _Tap Collect in /empire to claim!_"]
        if idle_exp <= 0:
            return  # welcome-back only fires when the idle reward itself fires
        _idle_last_awarded[uid] = now_ts
        ih = idle_secs / 3600
        away_str = (f"{int(ih)}h {int((idle_secs % 3600) / 60)}m"
                    if ih >= 1 else f"{int(idle_secs / 60)}m")
        if idle_exp > 0:
            s = get_shadow(uid)
            if s:
                add_shadow_exp(s, idle_exp)
                save_shadow(s)
            if p and not is_defeated(p):
                add_exp(p, idle_exp)
        if p:
            save_player(p)
        emp_line = ""
        if empire_notes:
            emp_line = "\n\n🏰 *Empire production waiting:*\n" + "\n".join(f"  {n}" for n in empire_notes[:6])
        exp_line = (f"💫 Idle reward: *+{fmt_num(idle_exp)} EXP*\n"
                    f"_(Scales with your level — the higher your level, the more you earn)_"
                    if idle_exp > 0 else "")
        try:
            await bot.send_message(
                uid,
                f"🎱 *Welcome back!*\n\n"
                f"You were away for *{away_str}*.\n"
                f"{exp_line}"
                f"{emp_line}",
                parse_mode="Markdown")
        except Exception:
            pass
    except Exception:
        pass

# ── PASSIVE MESSAGE HANDLER ───────────────────────────────────────────────────
async def handle_message(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if not update.message: return
    user = update.effective_user
    if not user or user.is_bot: return
    if is_banned(user.id): return
    if not _chat_rate_ok(user.id):
        return  # silently drop — no response, no feedback loop
    chat_id = update.effective_chat.id
    text    = (update.message.text or "").lower()

    # Word scramble: exact item-name answers win the prize
    if text and chat_id in _scrambles:
        try:
            await _check_scramble_answer(update, context, chat_id, text)
        except Exception:
            pass

    # Alliance name creation: leader typed the name after clicking "Found an Order"
    if context.user_data.get("awaiting_alliance_name") is not None:
        raw_name = (update.message.text or "").strip()
        if raw_name and not raw_name.startswith("/") and 2 <= len(raw_name) <= 20:
            p_create = get_player(user.id)
            if p_create and not p_create.get("alliance_id"):
                if not get_alliance_by_name(raw_name):
                    new_aid = f"{user.id}_{int(time.time())}"
                    new_a = {
                        "id": new_aid, "name": raw_name, "leader_id": user.id,
                        "members": json.dumps([user.id]),
                        "influence_pool": 0, "created": int(time.time()),
                    }
                    save_alliance(new_a)
                    p_create["alliance_id"] = new_aid; save_player(p_create)
                    del context.user_data["awaiting_alliance_name"]
                    try: await update.message.reply_text(
                        f"⚔️ *Secret Order Founded!*\n\n*{raw_name}* is now bound to the void.\nUse /alliance to manage your order.",
                        parse_mode="Markdown")
                    except: pass
                    return
                else:
                    try: await update.message.reply_text(
                        f"❌ An order named *{raw_name}* already exists. Try another name.",
                        parse_mode="Markdown")
                    except: pass
                    return
            else:
                del context.user_data["awaiting_alliance_name"]

    # Silent influence: social greetings
    _p_msg = get_player(user.id)
    # Keep tg_username fresh on every message so /attack @handle always works
    if getattr(user, "username", None):
        try:
            _tgu_c = _connect_db()
            _tgu_c.execute("UPDATE players SET tg_username=? WHERE user_id=?", (user.username, user.id))
            _tgu_c.commit(); _tgu_c.close()
        except Exception:
            pass
        if _p_msg:
            _p_msg["tg_username"] = user.username
    # Also capture tg_username for anyone being replied to
    if update.message.reply_to_message and update.message.reply_to_message.from_user:
        _ru = update.message.reply_to_message.from_user
        if getattr(_ru, "username", None):
            try:
                _tgr_c = _connect_db()
                _tgr_c.execute("UPDATE players SET tg_username=? WHERE user_id=?", (_ru.username, _ru.id))
                _tgr_c.commit(); _tgr_c.close()
            except Exception:
                pass
    if _p_msg and update.message.reply_to_message:
        _txt = (update.message.text or "").lower().strip()
        _greets_pos = ["thank you", "thanks", "ty ", "ty!", "thx", " ty"]
        _greets_wel  = ["you're welcome", "youre welcome", "welcome", " np ", "no problem", "anytime"]
        if any(g in _txt for g in _greets_pos):
            _add_influence(_p_msg, 1); save_player(_p_msg)
        elif any(g in _txt for g in _greets_wel):
            _add_influence(_p_msg, 1); save_player(_p_msg)
    # Secret quest: phrase completion
    if _p_msg and update.message.text and not update.message.text.startswith("/"):
        _reply_uid = (update.message.reply_to_message.from_user.id
                      if update.message.reply_to_message and update.message.reply_to_message.from_user
                      else None)
        await _try_complete_quest_phrase(_p_msg, update.message.text, _reply_uid, context.bot)
    # Admin broadcast quest: phrase completion check
    if _p_msg and update.message.text and _broadcast_quest:
        await _try_complete_broadcast_quest(_p_msg, update.message.text, context.bot)
    # Quest dispatch trigger (20% chance if no active quest, 8h+ since last)
    if _p_msg and random.random() < 0.20:
        await _dispatch_secret_quest(user.id, context.bot)

    # Non-text messages (stickers, photos, etc.)  -  track shadow profile but skip keyword triggers
    if not update.message.text:
        s = get_or_create_shadow(user.id, user.first_name)
        s["username"]      = user.first_name
        s["message_count"] = s.get("message_count", 0) + 1
        s["last_seen"]     = datetime.now().isoformat()
        save_shadow(s)
        return

    # Railrunner target-spotted notification (rate-limited: once per 10 min per target)
    _bounty_spot_cache = context.bot_data.setdefault("bounty_spot_cache", {})
    cache_key = (user.id, chat_id)
    last_spot = _bounty_spot_cache.get(cache_key, 0)
    if (datetime.now().timestamp() - last_spot) > 600:
        try:
            bconn = _connect_db(); bconn.row_factory = sqlite3.Row
            rows = bconn.execute(
                "SELECT b.placer_id FROM bounties b "
                "JOIN players rp ON rp.user_id = b.placer_id AND rp.class_id = 'bounty_hunter' "
                "WHERE b.target_id=? AND b.claimed_by IS NULL AND b.expires_at > ?",
                (user.id, datetime.now().isoformat())).fetchall()
            bconn.close()
            for row in rows:
                if row["placer_id"] != user.id:
                    asyncio.create_task(context.bot.send_message(
                        chat_id=row["placer_id"],
                        text=f"🔭 *Target spotted!* Your bounty target *{user.first_name}* "
                             f"just sent a message in the group.",
                        parse_mode="Markdown"))
            if rows:
                _bounty_spot_cache[cache_key] = datetime.now().timestamp()
        except Exception: pass

    # Random events  -  every ~100 messages, minimum 30 min between events
    message_counters[chat_id] = message_counters.get(chat_id, 0) + 1
    cnt = message_counters[chat_id]

    # Periodic cleanup every 500 messages
    if cnt % 500 == 0:
        now_iso = datetime.now().isoformat()
        expired_trades = [uid for uid, t in pending_trades.items()
                          if t.get("expires", now_iso) < now_iso]
        for uid in expired_trades:
            pending_trades.pop(uid, None)
        expired_raids = [cid for cid, r in active_raids.items()
                         if not r.get("in_progress")
                         and r.get("expires", now_iso) < now_iso]
        for cid in expired_raids:
            active_raids.pop(cid, None)

    # Wild pet spawns: chat activity summons creatures (Pokétwo-style race)
    if (cnt % 45 == 20 and chat_id not in _wild_spawns
            and time.time() - _wild_last.get(chat_id, 0) >= 1500):
        _wild_last[chat_id] = time.time()
        _wt = asyncio.create_task(_spawn_wild_pet(context.bot, chat_id))
        _bg_tasks.add(_wt); _wt.add_done_callback(_bg_tasks.discard)

    _last_ev = last_event_times.get(chat_id)
    _ev_ok = _last_ev is None or (datetime.now() - _last_ev).total_seconds() >= 1800
    if cnt % 100 == 0 and chat_id not in active_events and _ev_ok:
        roll = random.random()
        if roll < 0.70:   freq = "common"
        elif roll < 0.90: freq = "uncommon"
        else:             freq = "rare"
        pool = [e for e in RANDOM_EVENTS if e["freq"]==freq]
        if pool:
            event = random.choice(pool).copy()
            active_events[chat_id] = event
            last_event_times[chat_id] = datetime.now()
            if event["key"] == "legendary_merchant":
                legend_shop_expiry[chat_id] = datetime.now() + timedelta(minutes=event.get("duration_min", 10))
            # One-tap action buttons — same events, zero typing
            _WEV_BTN = {"bandit":  ("⚔️ Fight!",  "fight"),
                        "ghost":   ("🔫 Shoot!",  "shoot"),
                        "rival":   ("⚔️ Fight!",  "fight"),
                        "traveler":("👋 Greet",   "greet"),
                        "merchant":("👋 Greet",   "greet"),
                        "cache":   ("🫳 Claim!",  "claim"),
                        "shrine":  ("🙏 Pray",    "pray"),
                        "drake":   ("⚔️ Strike!", "strike")}
            _wev = _WEV_BTN.get(event["key"])
            _wev_markup = (InlineKeyboardMarkup([[InlineKeyboardButton(
                _wev[0], callback_data=f"wev_{_wev[1]}_{chat_id}")]]) if _wev else None)
            msg = await update.message.reply_text(event["msg"], parse_mode="Markdown",
                                                  reply_markup=_wev_markup)
            # Store drake message id for reply detection
            if event["key"] == "drake":
                active_drakes[chat_id] = {
                    "msg_id": msg.message_id,
                    "hp": event["enemy_hp"],
                    "max_hp": event["enemy_hp"],
                    "fighters": {},
                    "loot_table": event.get("loot_table",[]),
                    "exp_reward": event["exp_reward"],
                }
                active_events.pop(chat_id, None)

    # Shadow profile
    s = get_or_create_shadow(user.id, user.first_name)
    s["username"] = user.first_name

    _is_group = update.effective_chat.type in ("group", "supergroup")

    if _is_group:
        _megaphone_state["group"] = update.effective_chat.id
        s["home_group"] = update.effective_chat.id

    p = get_player(user.id) if s.get("ascended") else None
    asyncio.create_task(check_pet_notifications(p, context.bot))

    # Idle reward — fire before updating last_seen. Not gated to group context:
    # last_seen advances in DMs too, so DM-only players must be able to collect.
    _prev_seen = s.get("last_seen")
    if _prev_seen:
        asyncio.create_task(_try_idle_reward(user.id, context.bot, _prev_seen))

    # Update last_seen regardless of context so DM-only players build and consume the timer
    s["message_count"] = s.get("message_count",0) + 1
    s["last_seen"] = datetime.now().isoformat()

    if p and s: sync_levels(p, s)

    cds_s = safe_cds(s)
    cds_p = safe_cds(p) if p else {}

    shadow_exp = 0; rpg_exp = 0; rpg_gold = 0

    # Bleed tick
    if p and is_bleeding(p):
        tick_dmg = check_bleed_tick(p)
        if tick_dmg:
            if p["hp"] <= 0:
                p["hp"] = 0
                p["defeated_until"] = (datetime.now()+timedelta(minutes=6)).isoformat()
                p["last_defeated_by"] = "Bleed damage (DoT)"
                p["losses"] = p.get("losses", 0) + 1
                p["kill_streak"] = 0
                asyncio.create_task(_notify_defeat(context.bot, p, "Bleed damage (you bled out)"))
                asyncio.create_task(announce(context.bot, chat_id,
                    f"🩸 *{p['username']}* bled out and is defeated for 6m!",
                    delay=30))
                _bleed_atk_ids = get_recent_attackers(p)
                if _bleed_atk_ids:
                    _bleed_atk = get_player(_bleed_atk_ids[-1])
                    if _bleed_atk:
                        _bleed_atk["wins"] = _bleed_atk.get("wins", 0) + 1
                        _bleed_atk["kill_streak"] = safe_int(_bleed_atk.get("kill_streak")) + 1
                        if _bleed_atk["kill_streak"] > safe_int(_bleed_atk.get("max_kill_streak")):
                            _bleed_atk["max_kill_streak"] = _bleed_atk["kill_streak"]
                        _today = datetime.now().strftime("%Y-%m-%d")
                        if _bleed_atk.get("kills_today_date") != _today:
                            _bleed_atk["kills_today"] = 0; _bleed_atk["kills_today_date"] = _today
                        _bleed_atk["kills_today"] = safe_int(_bleed_atk.get("kills_today")) + 1
                        if _bleed_atk["kills_today"] >= 5: _bleed_atk["is_wanted"] = 1
                        save_player(_bleed_atk)
                        _fire(check_and_claim_bounty(context.bot, _bleed_atk, p, chat_id))
            save_player(p)

    # Cannot earn EXP while defeated
    defeated_no_exp = p and is_defeated(p)

    # Easter eggs
    for egg in EASTER_EGGS:
        if re.search(egg["pattern"], text, re.IGNORECASE):
            if egg.get("secret_boss"):
                w = get_weather()
                if w.get("secret_eligible") and \
                   chat_id not in secret_boss_active and \
                   chat_id not in active_bosses:
                    bd = BOSSES["void"]
                    secret_boss_active[chat_id] = {
                        "data":bd.copy(),"hp":bd["max_hp"],
                        "participants":[{"id":user.id,"name":user.first_name,"dmg":0}]}
                    await update.message.reply_text(
                        f"🌑 *THE VOID BALL AWAKENS!*\n_{bd['desc']}_\n\n"
                        f"❤️ HP: {bd['max_hp']}\n*{user.first_name}* called it forth! /strike!",
                        parse_mode="Markdown")
            break

    # Keyword triggers
    if not defeated_no_exp:
        for trigger in KEYWORD_TRIGGERS:
            if re.search(trigger["pattern"], text, re.IGNORECASE):
                key = trigger["key"]
                if not cds_s.get(key) or \
                   datetime.now() > datetime.fromisoformat(cds_s[key]) + timedelta(seconds=trigger["cooldown"]):
                    cds_s[key] = datetime.now().isoformat()
                    if trigger["exp"] > 0:
                        # Table values are weights: 1M of table value = 0.2% of
                        # the current level requirement (so 1.5M→0.3%, 8M→1.6%)
                        _trig_pct = (trigger["exp"] / 1_000_000) * 0.002
                        shadow_exp += exp_share(s["level"], _trig_pct)
                        if p: rpg_exp += exp_share(p["level"], _trig_pct)
                    elif trigger["exp"] < 0:
                        s["exp"] = max(0, s["exp"]+trigger["exp"])
                        if p: p["exp"] = max(0, p.get("exp",0)+trigger["exp"])
                    if trigger.get("gold_chance") and random.random() < trigger["gold_chance"]:
                        rpg_gold += max(10, safe_int((p or s).get("level"), 1) * 2)
                break

        # Daily first message bonus
        today = datetime.now().strftime("%Y-%m-%d")
        if cds_s.get("daily_date") != today:
            cds_s.update({"daily_date":today,"daily_messages":0,
                          "daily_bonus_given":False,
                          "streak_50":False,"streak_100":False,"streak_500":False})
        # Chat EXP scales with level so it stays meaningful without
        # trivializing progression (was flat 10M/500M/2B/10B).
        if not cds_s.get("daily_bonus_given"):
            cds_s["daily_bonus_given"] = True
            shadow_exp += exp_share(s["level"], 0.25)
            if p: rpg_exp += exp_share(p["level"], 0.25)

        cds_s["daily_messages"] = cds_s.get("daily_messages",0) + 1
        dm = cds_s["daily_messages"]
        if dm >= 50 and not cds_s.get("streak_50"):
            cds_s["streak_50"] = True
            _stk_exp = exp_share(s["level"], 0.10)
            shadow_exp += _stk_exp
            if p:
                _stk_exp = exp_share(p["level"], 0.10)
                rpg_exp += _stk_exp
            asyncio.create_task(announce(context.bot, chat_id,
                f"🔥 *{user.first_name}* hit a *50 message streak!* +{fmt_num(_stk_exp)} EXP!",
                delay=8))
        if dm >= 100 and not cds_s.get("streak_100"):
            cds_s["streak_100"] = True; rpg_gold += 100
            _stk_exp = exp_share(s["level"], 0.25)
            shadow_exp += _stk_exp
            if p:
                _stk_exp = exp_share(p["level"], 0.25)
                rpg_exp += _stk_exp
            asyncio.create_task(announce(context.bot, chat_id,
                f"🔥 *{user.first_name}* hit a *100 message streak!* +{fmt_num(_stk_exp)} EXP!",
                delay=8))
        if dm >= 500 and not cds_s.get("streak_500"):
            cds_s["streak_500"] = True
            _stk_exp = exp_share(s["level"], 1.00)
            shadow_exp += _stk_exp
            if p:
                _stk_exp = exp_share(p["level"], 1.00)
                rpg_exp += _stk_exp
            asyncio.create_task(announce(context.bot, chat_id,
                f"🏆 *{user.first_name}* hit a *500 message streak!* +{fmt_num(_stk_exp)} EXP! 🎱",
                delay=8))

    # Apply shadow EXP
    s["passive_cooldowns"] = json.dumps(cds_s)
    if shadow_exp > 0 and not defeated_no_exp:
        lmsgs, did_level = add_shadow_exp(s, shadow_exp)
        save_shadow(s)
        if did_level:
            tier = get_tier(s["level"])
            hint = ""
            if not s.get("ascended") and s["level"] >= 5:
                hint = "\n_💡 Type /ascend in a private chat to enter the RPG!_"
            # Announce every level-up, not just multiples of 10
            asyncio.create_task(announce(context.bot, chat_id,
                f"{tier['emoji']} *{s['username']}* reached *Level {s['level']}*!{hint}",
                delay=60))
    else:
        save_shadow(s)

    # Apply RPG EXP
    if p and not defeated_no_exp:
        p["gold"] = p.get("gold",0) + rpg_gold
        p["passive_cooldowns"] = json.dumps(cds_p)
        if rpg_exp > 0:
            lmsgs, did_level = add_exp(p, rpg_exp)
            if did_level and p["level"] > s["level"]:
                s["level"] = p["level"]; s["exp"] = 0; save_shadow(s)
            save_player(p)
            if did_level and p["level"] % 10 == 0:
                cls = get_player_class(p)
                cnote = f" the *{cls['name']}*" if cls else ""
                ann = [f"🎉 *{p['username']}*{cnote} reached *Level {p['level']}*! 🎱"]
                for msg in lmsgs:
                    if any(x in msg for x in ["choose a class","Choose your path","LEVEL 100"]):
                        ann.append(msg)
                asyncio.create_task(announce(context.bot, chat_id,
                    "\n".join(ann), delay=60))
        else:
            save_player(p)

    # Drake reply detection  -  if message is a reply to drake message
    if chat_id in active_drakes:
        drake = active_drakes[chat_id]
        if (update.message.reply_to_message and
                update.message.reply_to_message.message_id == drake["msg_id"] and
                p and not is_defeated(p)):
            lines = _drake_hit(context.bot, chat_id, p, user.first_name)
            try:
                await update.message.reply_text("\n".join(lines), parse_mode="Markdown")
            except Exception:
                pass

def _drake_hit(bot, chat_id, p, display_name):
    """One strike against the group drake — shared by reply-strikes and the
    event card's Strike button. Returns response lines; handles the payout."""
    drake = active_drakes.get(chat_id)
    if not drake:
        return ["🐉 The drake is gone."]
    dmg = random.randint(10, 30) + p["level"] // 2
    drake["hp"] = max(0, drake["hp"] - dmg)
    uid = p["user_id"]
    drake.setdefault("fighters", {})
    drake["fighters"][uid] = drake["fighters"].get(uid, 0) + dmg
    lines = [f"🐉 *{display_name}* strikes the Wild Drake for *{dmg}*!\n"
             f"❤️ Drake HP: {drake['hp']}/{drake['max_hp']}"]
    if drake["hp"] <= 0:
        active_drakes.pop(chat_id, None)
        lines.append("\n🏆 *Wild Drake defeated!*\n")
        total_dmg = sum(drake["fighters"].values())
        for fid, fdmg in drake["fighters"].items():
            fp = get_player(fid)
            if not fp: continue
            share = fdmg / max(1, total_dmg)
            _drake_exp = round(exp_share(fp["level"], 0.30) * share)
            loot = roll_loot_table(drake.get("loot_table", []))
            if loot: add_item(fp, loot)
            lmsgs, leveled = add_exp(fp, _drake_exp)
            save_player(fp)
            lines.append(f"✅ *{fp['username']}*  -  +{fmt_num(_drake_exp)} EXP"
                         + (f" | 🎒 *{loot}*!" if loot else ""))
            if leveled and fp["level"] % 10 == 0:
                asyncio.create_task(announce(bot, chat_id,
                    f"🎉 *{fp['username']}* reached *Level {fp['level']}* from the Drake! 🐉",
                    delay=60))
    return lines

# ── EVENT HANDLERS ────────────────────────────────────────────────────────────
async def world_event_button_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """One-tap action buttons on world-event cards (wev_{action}_{chat_id}).
    Reuses the existing command handlers — send_group and the event handlers
    only touch effective_chat/effective_user/get_bot, all present on callback
    updates. Drake strikes go through the shared _drake_hit."""
    query = update.callback_query
    parts = query.data.split("_")
    try:
        action = parts[1]; ev_chat = int(parts[2])
    except (IndexError, ValueError):
        await query.answer(); return
    uid = query.from_user.id
    if action == "strike":
        p = get_player(uid)
        if not p:
            await query.answer("Use /ascend first!", show_alert=True); return
        if is_defeated(p):
            await query.answer("☠️ You're defeated!", show_alert=True); return
        if ev_chat not in active_drakes:
            await query.answer("The drake is gone!", show_alert=True)
            try: await query.edit_message_reply_markup(reply_markup=None)
            except Exception: pass
            return
        await query.answer("⚔️ Striking!")
        lines = _drake_hit(context.bot, ev_chat, p, query.from_user.first_name)
        try:
            await context.bot.send_message(ev_chat, "\n".join(lines), parse_mode="Markdown")
        except Exception:
            pass
        if ev_chat not in active_drakes:
            try: await query.edit_message_reply_markup(reply_markup=None)
            except Exception: pass
        return
    _handlers = {"fight": fight_event, "shoot": shoot_event, "greet": greet_event,
                 "claim": claim_event, "pray": pray_event}
    handler = _handlers.get(action)
    if not handler:
        await query.answer(); return
    ev = active_events.get(ev_chat)
    if not ev:
        await query.answer("This event has ended!", show_alert=True)
        try: await query.edit_message_reply_markup(reply_markup=None)
        except Exception: pass
        return
    await query.answer("🎯 On it!")
    try:
        await handler(update, context)
    except Exception:
        logger.exception("world event button failed")
    # If the event resolved, disarm the card's button
    if ev_chat not in active_events:
        try: await query.edit_message_reply_markup(reply_markup=None)
        except Exception: pass

async def greet_event(update: Update, context: ContextTypes.DEFAULT_TYPE):
    chat_id = update.effective_chat.id; user = update.effective_user
    event = active_events.get(chat_id)
    if not event or event["key"] not in ("traveler","merchant","shrine"): return
    s = get_or_create_shadow(user.id, user.first_name)
    p = get_player(user.id)
    active_events.pop(chat_id, None)
    if event["key"] == "traveler":
        loot = roll_loot_table(event.get("loot_table",[]))
        if p and not is_defeated(p):
            if loot: add_item(p, loot)
            _trav_exp = exp_share(p["level"], 0.05)
            lmsgs, leveled = add_exp(p, _trav_exp); save_player(p)
            msg = f"🧙 *{user.first_name}* greets the traveler! +{fmt_num(_trav_exp)} EXP"
            if loot: msg += f" | 🎒 *{loot}*!"
        else:
            lmsgs, leveled = add_shadow_exp(s, event["exp"]); save_shadow(s)
            msg = f"🧙 *{user.first_name}* greets the traveler! +{fmt_num(event['exp'])} EXP"
        await send_group(update, msg, delay=15)
    elif event["key"] == "merchant":
        if p:
            set_status(p, "shop_discount_until", event["duration_min"]*60)
            save_player(p)
        await send_group(update,
            f"🛍️ *{user.first_name}* greeted the merchant!\n"
            f"*20% shop discount* for {event['duration_min']}m! Use /shop", delay=15)
    elif event["key"] == "shrine":
        if p:
            stat = random.choice(["STR","DEF","AGI","INT","WIS"])
            sd = safe_stats(p); sd[stat] = sd.get(stat,5)+5; p["stats"] = json.dumps(sd)
            save_player(p)
            await send_group(update,
                f"🔮 *{user.first_name}* prays at the shrine!\n*+5 {stat}* for 2 hours!", delay=15)

async def fight_event(update: Update, context: ContextTypes.DEFAULT_TYPE):
    chat_id = update.effective_chat.id; user = update.effective_user
    event = active_events.get(chat_id)
    if not event or event["key"] not in ("bandit", "rival"):
        await send_group(update, "⚔️ Nothing to fight here right now.", delay=5)
        return
    p = get_player(user.id); s = get_or_create_shadow(user.id, user.first_name)

    # ── Rival event: first player to /fight claims it ────────────────────────
    if event["key"] == "rival":
        active_events.pop(chat_id, None)
        gold_prize = random.randint(400, 1000)
        _prize_pct = random.uniform(0.08, 0.12)
        lines = [f"⚔️ *{user.first_name}* steps up first and claims the table!"]
        if p and not is_defeated(p):
            exp_prize = exp_share(p["level"], _prize_pct)
            p["gold"] = p.get("gold", 0) + gold_prize
            add_exp(p, exp_prize); save_player(p)
            lines.append(f"💰 +{gold_prize} gold | ✨ +{fmt_num(exp_prize)} EXP")
        elif s:
            exp_prize = exp_share(s["level"], _prize_pct)
            add_shadow_exp(s, exp_prize); save_shadow(s)
            lines.append(f"✨ +{fmt_num(exp_prize)} EXP")
        await send_group(update, "\n".join(lines), delay=20)
        return

    # ── Bandit event ──────────────────────────────────────────────────────────
    dmg = random.randint(10, 30)
    event["enemy_hp"] = event.get("enemy_hp", 150) - dmg
    event.setdefault("fighters", [])
    if user.id not in event["fighters"]: event["fighters"].append(user.id)
    lines = [f"🗡️ *{user.first_name}* strikes the bandit for {dmg}! "
             f"(HP: {max(0, event['enemy_hp'])}/150)"]
    if event["enemy_hp"] <= 0:
        active_events.pop(chat_id, None)
        lines.append("💀 *Bandit defeated!* +12% of a level each!")
        for fid in event["fighters"]:
            fp = get_player(fid); fs = get_shadow(fid)
            if fp and not is_defeated(fp):
                loot = roll_loot_table(event.get("loot_table", []))
                if loot: add_item(fp, loot)
                # Bonus roll: 10% chance at a random rare/epic weapon
                if random.random() < 0.10:
                    _bonus_pool = [n for n, d in WEAPONS.items() if d.get("rarity") in ("rare", "epic")]
                    if _bonus_pool:
                        _bw = random.choice(_bonus_pool)
                        add_item(fp, _bw)
                        lines.append(f"✨ *{fp['username']}* looted a {RARITY_EMOJI.get(WEAPONS[_bw].get('rarity',''),'')} *{_bw}* from the bandit!")
                lmsgs, leveled = add_exp(fp, exp_share(fp["level"], 0.12)); save_player(fp)
                if loot: lines.append(f"🎒 *{fp['username']}* found *{loot}*!")
                if leveled and fp["level"] % 10 == 0:
                    asyncio.create_task(announce(context.bot, chat_id,
                        f"🎉 *{fp['username']}* reached *Level {fp['level']}* from battle! ⚔️",
                        delay=60))
            elif fs:
                lmsgs, leveled = add_shadow_exp(fs, exp_share(fs["level"], 0.12)); save_shadow(fs)
    await send_group(update, "\n".join(lines), delay=15)

async def shoot_event(update: Update, context: ContextTypes.DEFAULT_TYPE):
    chat_id = update.effective_chat.id; user = update.effective_user
    event = active_events.get(chat_id)
    if not event or event["key"] != "ghost": return
    p = get_player(user.id); s = get_or_create_shadow(user.id, user.first_name)
    dmg = random.randint(15,35)
    event["enemy_hp"] = event.get("enemy_hp",200) - dmg
    event.setdefault("fighters",[])
    if user.id not in event["fighters"]: event["fighters"].append(user.id)
    lines = [f"👻 *{user.first_name}* shoots the spirit for {dmg}! "
             f"(HP: {max(0,event['enemy_hp'])}/200)"]
    if event["enemy_hp"] <= 0:
        active_events.pop(chat_id, None)
        lines.append("✨ *Spirit banished!* +12% of a level each!")
        for fid in event["fighters"]:
            fp = get_player(fid); fs = get_shadow(fid)
            if fp and not is_defeated(fp):
                loot = roll_loot_table(event.get("loot_table",[]))
                if loot: add_item(fp, loot)
                lmsgs, leveled = add_exp(fp, exp_share(fp["level"], 0.12)); save_player(fp)
                if loot: lines.append(f"🎒 *{fp['username']}* found *{loot}*!")
                if leveled and fp["level"] % 10 == 0:
                    asyncio.create_task(announce(context.bot, chat_id,
                        f"🎉 *{fp['username']}* reached *Level {fp['level']}* from the ghost! 👻",
                        delay=60))
            elif fs:
                lmsgs, leveled = add_shadow_exp(fs, exp_share(fs["level"], 0.12)); save_shadow(fs)
    await send_group(update, "\n".join(lines), delay=15)

async def claim_event(update: Update, context: ContextTypes.DEFAULT_TYPE):
    chat_id = update.effective_chat.id; user = update.effective_user
    event = active_events.get(chat_id)
    if not event or event["key"] != "cache": return
    active_events.pop(chat_id, None)
    p = get_player(user.id)
    loot = roll_loot_table(event.get("loot_table",[]))
    gold = random.randint(250,1000)
    if p:
        if loot: add_item(p, loot)
        p["gold"] = p.get("gold",0) + gold; save_player(p)
    await send_group(update,
        f"💰 *{user.first_name}* claims the abandoned cache!\n"
        f"💰 +{gold} gold" + (f" | 🎒 *{loot}*!" if loot else ""), delay=15)

async def pray_event(update: Update, context: ContextTypes.DEFAULT_TYPE):
    await greet_event(update, context)  # shrine handled in greet

# ── INLINE CALLBACKS ──────────────────────────────────────────────────────────

# ── Solo Raid Attack/Skill callback ──
async def soloraid_act_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    await query.answer()
    parts = query.data.split("_")
    # format: sr_act_{uid}_{action}
    if len(parts) < 4:
        return
    try:
        uid = int(parts[2])
        action = parts[3]
    except (ValueError, IndexError):
        return
    if query.from_user.id != uid:
        await query.answer("This isn't your raid!", show_alert=True)
        return

    user = query.from_user
    p = get_player(uid)
    if not p:
        await query.answer("Use /ascend first!", show_alert=True); return
    if uid not in active_soloraids:
        await query.answer("No active solo raid! Use /soloraid.", show_alert=True); return
    if is_defeated(p):
        await query.answer("You're defeated — can't act!", show_alert=True); return
    _cc = _consume_cc(p)
    if _cc:
        await query.answer(_cc, show_alert=True); return

    chat_id = query.message.chat.id

    if action == "skl":
        # Trigger skill against solo raid enemy
        all_skills = sjl(p.get("all_skills"), [])
        if not all_skills:
            await query.answer("No skills unlocked yet!", show_alert=True); return
        sr = active_soloraids[uid]
        if len(all_skills) > 1:
            markup = _build_skill_picker_keyboard(all_skills, uid, 0, show_close=False)
            await _q_edit(query, 
                f"🔮 *vs {sr['enemy']['name']}* — choose a skill:",
                parse_mode="Markdown", reply_markup=markup)
            return
        sk = all_skills[0]
        w = get_weather()
        sk_lines, sk_dmg = apply_skill_to_raid_enemy(p, sk, sr, w)
        enemy = sr["enemy"]
        out = [f"⚡ *{user.first_name}* uses *{sk['name']}* on *{enemy['name']}*!"]
        out.extend(sk_lines)
        if sk_dmg > 0:
            out.append(f"💥 *{sk_dmg} damage!* Enemy HP: {sr['enemy_hp']}/{sr['enemy_max_hp']}")

        if sr["enemy_hp"] <= 0:
            out.append(f"\n✅ *{enemy['name']}* destroyed!")
            tier = sr["tier"]; wave_enemies = tier["wave_enemies"]; cw = sr["wave"]
            if cw < len(wave_enemies):
                sr["wave"] += 1; ne = wave_enemies[cw].copy()
                sr["enemy"] = ne; sr["enemy_hp"] = ne["hp"]; sr["enemy_max_hp"] = ne["hp"]
                sr.pop("enemy_statuses", None)
                out.append(f"\n🌊 *Wave {sr['wave']}  -  {ne['name']}*")
                out.append(f"❤️ HP: {ne['hp']} | 💀 {ne['dmg_min']}–{ne['dmg_max']}")
            elif cw == len(wave_enemies):
                bd = BOSSES[tier["wave_boss_key"]]; boss_hp = bd["max_hp"] // 2
                sr["wave"] = len(wave_enemies) + 1
                sr["enemy"] = {"name": bd["name"] + " ⚡","dmg_min": round(bd["dmg_min"]*0.6),"dmg_max": round(bd["dmg_max"]*0.6)}
                sr["enemy_hp"] = boss_hp; sr["enemy_max_hp"] = boss_hp
                sr.pop("enemy_statuses", None)
                out.append(f"\n🎱 *FINAL BOSS  -  {bd['name']}!* ❤️ HP: {boss_hp}")
            else:
                active_soloraids.pop(uid, None)
                exp_r = _scaled_raid_exp(p["level"], tier["exp_reward"]); gold_r = tier["gold_reward"]
                p["gold"] = p.get("gold", 0) + gold_r; p["quests_done"] = p.get("quests_done", 0) + 1
                for _d, _e, _g in track_objective(p, "solo_win"):
                    p["gold"] = p.get("gold",0) + _g; add_exp(p, _e)
                loot = roll_loot_table(tier.get("loot_table", []), p)
                if loot:
                    add_item(p, loot)
                    r = ""
                    for pool in [WEAPONS, ARMORS, ACCESSORIES]:
                        if loot in pool: r = RARITY_EMOJI.get(pool[loot].get("rarity", ""), ""); break
                    out.append(f"🎒 Found: {r} *{loot}*!")
                add_exp(p, exp_r, get_weather())
                out.append(f"\n🏆 *SOLO RAID COMPLETE!* +{fmt_num(exp_r)} EXP | +{gold_r}g")
                save_player(p)
                try:
                    await _q_edit(query, text="\n".join(out)[:4096], parse_mode="Markdown")
                except Exception: pass
                return
        else:
            killed = raid_enemy_counter(p, sr, out)
            if killed:
                active_soloraids.pop(uid, None)
                save_player(p)
                try:
                    await _q_edit(query, text="\n".join(out)[:4096], parse_mode="Markdown")
                except Exception:
                    pass
                return

        save_player(p)
        try:
            await _q_edit(query, text="\n".join(out)[:4096], parse_mode="Markdown", reply_markup=_build_sr_markup(uid))
        except Exception: pass
        return

    if action == "heal":
        sr = active_soloraids[uid]
        heal_amt = round(sr["player_max_hp"] * 0.25)
        sr["player_hp"] = min(sr["player_max_hp"], sr["player_hp"] + heal_amt)
        save_player(p)
        try:
            await _q_edit(query, 
                f"🩺 *{user.first_name}* rests and recovers *{heal_amt} HP!*\n"
                f"❤️ HP: {sr['player_hp']}/{sr['player_max_hp']} | "
                f"Enemy HP: {sr['enemy_hp']}/{sr['enemy_max_hp']}",
                parse_mode="Markdown", reply_markup=_build_sr_markup(uid))
        except Exception: pass
        return

    if action == "flee":
        active_soloraids.pop(uid, None)
        save_player(p)
        try:
            await _q_edit(query, "🏃 *You fled from the solo raid!*", parse_mode="Markdown")
        except Exception: pass
        return

    # action == "atk" — standard attack
    sr = active_soloraids[uid]
    enemy = sr["enemy"]
    w = get_weather()
    dmg = calc_attack_damage(p, w)
    is_crit = check_crit(p)
    if is_crit: dmg = apply_crit(p, dmg)
    if safe_int(p.get("charging_killshot")):
        p["charging_killshot"] = 0; dmg = get_stat(p, "AGI") * 4; is_crit = False

    sr["enemy_hp"] = max(0, sr["enemy_hp"] - dmg)
    sr["total_dmg"] = sr.get("total_dmg", 0) + dmg

    lines = [
        f"⚔️ *{user.first_name}* strikes *{enemy['name']}* for *{dmg}{'💥' if is_crit else ''}!*",
        f"❤️ Enemy HP: {sr['enemy_hp']}/{sr['enemy_max_hp']}  |  Your HP: {sr['player_hp']}/{sr['player_max_hp']}",
    ]
    bleed_dmg = tick_enemy_bleed(sr)
    if bleed_dmg:
        lines.append(f"🩸 *{enemy['name']}* bleeds for {bleed_dmg}! HP: {sr['enemy_hp']}/{sr['enemy_max_hp']}")

    if sr["enemy_hp"] <= 0:
        tier = sr["tier"]; wave_enemies = tier["wave_enemies"]; cw = sr["wave"]
        lines.append(f"\n✅ *Wave {cw} cleared!*")
        sr.pop("enemy_statuses", None)
        if cw < len(wave_enemies):
            sr["wave"] += 1; ne = wave_enemies[cw].copy()
            sr["enemy"] = ne; sr["enemy_hp"] = ne["hp"]; sr["enemy_max_hp"] = ne["hp"]
            lines.append(f"\n🌊 *Wave {sr['wave']}  -  {ne['name']}*")
            lines.append(f"❤️ HP: {ne['hp']} | 💀 {ne['dmg_min']}–{ne['dmg_max']}")
        elif cw == len(wave_enemies):
            bd = BOSSES[tier["wave_boss_key"]]; boss_hp = bd["max_hp"] // 2
            sr["wave"] = len(wave_enemies) + 1
            sr["enemy"] = {"name": bd["name"] + " ⚡","dmg_min": round(bd["dmg_min"]*0.6),"dmg_max": round(bd["dmg_max"]*0.6)}
            sr["enemy_hp"] = boss_hp; sr["enemy_max_hp"] = boss_hp
            lines.append(f"\n🎱 *FINAL BOSS  -  {bd['name']}!* ❤️ HP: {boss_hp}")
        else:
            active_soloraids.pop(uid, None)
            exp_r = _scaled_raid_exp(p["level"], tier["exp_reward"]); gold_r = tier["gold_reward"]
            p["gold"] = p.get("gold", 0) + gold_r; p["quests_done"] = p.get("quests_done", 0) + 1
            for _d, _e, _g in track_objective(p, "solo_win"):
                p["gold"] = p.get("gold",0) + _g; add_exp(p, _e)
            loot = roll_loot_table(tier.get("loot_table", []), p)
            loot_line = ""
            if loot:
                add_item(p, loot); r = ""
                for pool in [WEAPONS, ARMORS, ACCESSORIES]:
                    if loot in pool: r = RARITY_EMOJI.get(pool[loot].get("rarity", ""), ""); break
                loot_line = f"\n🎒 Found: {r} *{loot}*!"
            add_exp(p, exp_r, get_weather())
            lines.append(f"\n🏆 *SOLO RAID COMPLETE  -  {tier['name']}!*")
            lines.append(f"✅ +{fmt_num(exp_r)} EXP | +{gold_r}g{loot_line}")
            save_player(p)
            try:
                await _q_edit(query, text="\n".join(lines)[:4096], parse_mode="Markdown")
            except Exception: pass
            return
    else:
        enemy = sr["enemy"]
        if enemy_status_active(sr, "stunned_until"):
            lines.append(f"⚡ *{enemy['name']}* is stunned  -  no counter!")
        elif enemy_status_active(sr, "frozen_until"):
            lines.append(f"❄️ *{enemy['name']}* is frozen  -  no counter!")
        else:
            raw = random.randint(enemy["dmg_min"], enemy["dmg_max"])
            if enemy_status_active(sr, "weakened_until") or enemy_status_active(sr, "hexed_until"):
                raw = round(raw * 0.75)
            dodge = get_accessory_bonus(p, "dodge_bonus") + get_enchant_bonus(p, "dodge_bonus")
            cls_p = get_player_class(p)
            if cls_p and cls_p.get("passive_key") == "evasion": dodge += 0.10
            if dodge > 0 and random.random() < dodge:
                lines.append(f"💨 *{p['username']}* dodges!")
            else:
                edm = calc_defense(p, raw)
                sr["player_hp"] = max(0, sr["player_hp"] - edm)
                if sr["player_hp"] == 0:
                    exp_loss = apply_pvp_death(p, killer_name=enemy["name"], cause="Solo Raid")
                    asyncio.create_task(_notify_defeat(context.bot, p, enemy["name"] + " (Solo Raid)"))
                    active_soloraids.pop(uid, None)
                    save_player(p)
                    lines.append(f"💀 *{enemy['name']}* kills *{p['username']}*! 6min defeat. -{fmt_num(exp_loss)} EXP.")
                    try:
                        await _q_edit(query, text="\n".join(lines)[:4096], parse_mode="Markdown")
                    except Exception: pass
                    return
                else:
                    lines.append(f"🩸 *{enemy['name']}* hits *{p['username']}* for *{edm}!* "
                                 f"({sr['player_hp']}/{sr['player_max_hp']} raid HP)")
                    if sr["player_hp"] <= round(sr["player_max_hp"] * 0.30):
                        lines.append(f"⚠️ *Critically low HP!* Use /skill or a vial!")

    save_player(p)
    try:
        await _q_edit(query, text="\n".join(lines)[:4096], parse_mode="Markdown", reply_markup=_build_sr_markup(uid))
    except Exception: pass


# ── Boss Attack/Skill callback ──
async def boss_act_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    await query.answer()
    # format: boss_act_{uid}_{action}
    parts = query.data.split("_", 3)
    if len(parts) < 4:
        return
    try:
        uid = int(parts[2]); action = parts[3]
    except (ValueError, IndexError):
        return
    if query.from_user.id != uid:
        await query.answer("These buttons are for the summoner only!", show_alert=True); return

    user = query.from_user
    p = get_player(uid)
    chat_id = query.message.chat.id

    if not p:
        await query.answer("Use /ascend first!", show_alert=True); return
    if is_defeated(p):
        await query.answer("You're defeated!", show_alert=True); return
    _cc = _consume_cc(p)
    if _cc:
        await query.answer(_cc, show_alert=True); return

    boss_dict = active_bosses.get(chat_id) or secret_boss_active.get(chat_id)
    if not boss_dict:
        await query.answer("No active boss in this chat!", show_alert=True); return

    is_secret = chat_id in secret_boss_active

    if action == "skl":
        all_skills = sjl(p.get("all_skills"), [])
        if not all_skills:
            await query.answer("No skills unlocked yet!", show_alert=True); return
        # Ensure player is a participant before picker so skill_pick_callback can find them
        if uid not in [u["id"] for u in boss_dict["participants"]]:
            boss_dict["participants"].append({"id": uid, "name": user.first_name, "dmg": 0})
            if "player_hp" not in boss_dict:
                boss_dict["player_hp"] = {}; boss_dict["player_max_hp"] = {}
            mhp = calc_max_hp(p)
            boss_dict["player_hp"][uid] = min(mhp, max(1, safe_int(p.get("hp")) or mhp))
            boss_dict["player_max_hp"][uid] = mhp
        if len(all_skills) > 1:
            markup = _build_skill_picker_keyboard(all_skills, uid, 0, show_close=False)
            await _q_edit(query, 
                f"🔮 *vs {boss_dict['data']['name']}* — choose a skill:",
                parse_mode="Markdown", reply_markup=markup)
            return
        sk = all_skills[0]

        if uid not in [u["id"] for u in boss_dict["participants"]]:
            boss_dict["participants"].append({"id": uid, "name": user.first_name, "dmg": 0})
        participant = next(u for u in boss_dict["participants"] if u["id"] == uid)

        w = get_weather()
        stype = sk.get("type", "damage")
        lines = [f"⚡ *{user.first_name}* uses *{sk['name']}* on *{boss_dict['data']['name']}*!"]

        if stype in ("self_heal", "group_heal", "mass_cleanse",
                     "dmg_reduction_buff", "self_heal_buff", "revive_heal"):
            if stype == "self_heal":
                heal = round(get_stat(p, "WIS") * sk.get("mult", 3.0))
                p["hp"] = min(p["max_hp"], p["hp"] + heal)
                lines.append(f"💚 Healed self for *{heal} HP*!")
            elif stype == "self_heal_buff":
                heal = round(p["max_hp"] * 0.30)
                p["hp"] = min(p["max_hp"], p["hp"] + heal)
                lines.append(f"💚 *Rally!* +{heal} HP restored.")
            dmg = 0
        else:
            mult = sk.get("mult", 1.0) or 1.0
            hits = sk.get("hits", 1)
            if hits and hits > 1:
                total = 0; hit_log = []
                for _ in range(hits):
                    h = round(calc_attack_damage(p, w) * mult)
                    if check_crit(p): h = apply_crit(p, h); hit_log.append(f"💥{h}")
                    else: hit_log.append(str(h))
                    total += h
                dmg = total
                lines.append(f"⚡ {hits}-hit combo! [{' + '.join(hit_log)}] = {dmg}")
            elif stype in ("freeze_nuke", "execute_nuke", "holy_nuke", "fear_kill"):
                stat_key = sk.get("stat", get_primary_stat(p))
                dmg = round(get_stat(p, stat_key) * sk.get("mult", 3.0))
                lines.append(f"💥 *{sk['name']}!* {dmg} damage!")
            elif stype in ("drain", "drain_kill", "hp_drain"):
                drain_pct = min(sk.get("drain_pct", 0.25), 0.25)
                dmg = round(boss_dict["hp"] * drain_pct)
                heal = round(dmg * 0.50)
                p["hp"] = min(p["max_hp"], p["hp"] + heal)
                lines.append(f"🩸 *{sk['name']}!* Drained {dmg} HP! Healed {heal}.")
            else:
                dmg = round(calc_attack_damage(p, w) * mult)
            if stype not in ("multihit", "multi_hit") and hits == 1 and check_crit(p):
                dmg = apply_crit(p, dmg)
                lines.append("💥 *CRITICAL HIT!*")
            boss_dict["hp"] = max(0, boss_dict["hp"] - dmg)
            participant["dmg"] += dmg
            lines.append(f"❤️ Boss HP: {boss_dict['hp']}/{boss_dict['data']['max_hp']}")

        # Counter-attack
        alive = [u for u in boss_dict["participants"]
                 if not is_defeated(get_player(u["id"])) and boss_dict.get("player_hp",{}).get(u["id"],1) > 0]
        if alive and boss_dict["hp"] > 0 and random.random() < 0.90:
            target = random.choice(alive)
            tp = get_player(target["id"])
            if tp:
                if "player_hp" not in boss_dict:
                    boss_dict["player_hp"] = {}; boss_dict["player_max_hp"] = {}
                    for u in boss_dict["participants"]:
                        pp2 = get_player(u["id"])
                        if pp2:
                            mhp2 = calc_max_hp(pp2)
                            boss_dict["player_hp"][u["id"]] = mhp2
                            boss_dict["player_max_hp"][u["id"]] = mhp2
                bdmg = calc_defense(tp, random.randint(
                    boss_dict["data"]["dmg_min"], boss_dict["data"]["dmg_max"]))
                boss_dict["player_hp"][target["id"]] = max(0,
                    boss_dict["player_hp"].get(target["id"], calc_max_hp(tp)) - bdmg)
                php  = boss_dict["player_hp"][target["id"]]
                pmhp = boss_dict["player_max_hp"].get(target["id"], calc_max_hp(tp))
                if php == 0:
                    exp_loss = apply_pvp_death(tp, killer_name=boss_dict['data']['name'], cause="Boss")
                    asyncio.create_task(_notify_defeat(context.bot, tp, boss_dict['data']['name'] + " (Boss)"))
                    save_player(tp)
                    lines.append(f"💀 *{boss_dict['data']['name']}* KILLS *{target['name']}*! 30min defeat. -{fmt_num(exp_loss)} EXP.")
                else:
                    lines.append(f"💥 Boss hits *{target['name']}* for *{bdmg}!* ({php}/{pmhp} HP)")
                save_player(tp)

        if boss_dict["hp"] <= 0:
            data = boss_dict["data"]
            if is_secret: secret_boss_active.pop(chat_id, None)
            else: active_bosses.pop(chat_id, None)
            lines.append(f"\n🏆 *{data['name']} DEFEATED by {sk['name']}!*\n")
            w2 = get_weather()
            for u in boss_dict["participants"]:
                pp = get_player(u["id"])
                if not pp: continue
                pp["gold"] = pp.get("gold", 0) + data["gold"]
                for loot in _boss_guaranteed_loot(pp):
                    add_item(pp, loot); r = ""
                    for pool in [WEAPONS, ARMORS, ACCESSORIES, HATS, GLOVES, BOOTS, MASKS]:
                        if loot in pool: r = RARITY_EMOJI.get(pool[loot].get("rarity",""),""); break
                    lines.append(f"🎒 *{pp['username']}* found: {r} *{loot}*!")
                if award_title(pp, data["title"]):
                    lines.append(f"🏅 *{pp['username']}* earned: *{data['title']}*!")
                _braid_exp = exp_share(pp["level"], 0.10)
                add_exp(pp, _braid_exp, w2)
                save_player(pp)
                lines.append(f"✅ *{pp['username']}*  -  +{fmt_num(_braid_exp)} EXP | +{data['gold']} Gold")
            try:
                await _q_edit(query, text="\n".join(lines)[:4096], parse_mode="Markdown")
            except Exception: pass
            return

        save_player(p)
        try:
            await _q_edit(query, text="\n".join(lines)[:4096], parse_mode="Markdown", reply_markup=_build_boss_markup(uid))
        except Exception: pass
        return

    if action == "heal":
        if "player_hp" not in boss_dict:
            boss_dict["player_hp"] = {}; boss_dict["player_max_hp"] = {}
            for u in boss_dict["participants"]:
                pp2 = get_player(u["id"])
                if pp2:
                    mhp2 = calc_max_hp(pp2)
                    boss_dict["player_hp"][u["id"]] = mhp2
                    boss_dict["player_max_hp"][u["id"]] = mhp2
        max_hp = boss_dict["player_max_hp"].get(uid, calc_max_hp(p))
        cur_hp = boss_dict["player_hp"].get(uid, max_hp)
        heal_amt = round(max_hp * 0.25)
        boss_dict["player_hp"][uid] = min(max_hp, cur_hp + heal_amt)
        try:
            await _q_edit(query, 
                f"🩺 *{user.first_name}* recovers *{heal_amt} HP!*\n"
                f"❤️ Your HP: {boss_dict['player_hp'][uid]}/{max_hp}\n"
                f"💀 Boss HP: {boss_dict['hp']}/{boss_dict['data']['max_hp']}",
                parse_mode="Markdown", reply_markup=_build_boss_markup(uid))
        except Exception: pass
        return

    if action == "flee":
        boss_dict["participants"] = [u for u in boss_dict["participants"] if u["id"] != uid]
        boss_dict.get("player_hp", {}).pop(uid, None)
        boss_dict.get("player_max_hp", {}).pop(uid, None)
        if not boss_dict["participants"]:
            active_bosses.pop(chat_id, None); secret_boss_active.pop(chat_id, None)
            try:
                await _q_edit(query, "🏃 *All players fled! The boss vanishes.*", parse_mode="Markdown")
            except Exception: pass
        else:
            try:
                await _q_edit(query, 
                    f"🏃 *{user.first_name}* fled!\n"
                    f"💀 Boss HP: {boss_dict['hp']}/{boss_dict['data']['max_hp']}",
                    parse_mode="Markdown", reply_markup=_build_boss_markup(uid))
            except Exception: pass
        return

    # action == "atk"
    if uid not in [u["id"] for u in boss_dict["participants"]]:
        boss_dict["participants"].append({"id": uid, "name": user.first_name, "dmg": 0})
        if "player_hp" not in boss_dict:
            boss_dict["player_hp"] = {}; boss_dict["player_max_hp"] = {}
        mhp = calc_max_hp(p)
        boss_dict["player_hp"][uid] = mhp; boss_dict["player_max_hp"][uid] = mhp
    elif "player_hp" not in boss_dict:
        boss_dict["player_hp"] = {}; boss_dict["player_max_hp"] = {}
        for u in boss_dict["participants"]:
            pp = get_player(u["id"])
            if pp:
                mhp = calc_max_hp(pp)
                boss_dict["player_hp"][u["id"]] = mhp; boss_dict["player_max_hp"][u["id"]] = mhp
    participant = next(u for u in boss_dict["participants"] if u["id"] == uid)

    w = get_weather()
    dmg = calc_attack_damage(p, w)
    if check_crit(p): dmg = apply_crit(p, dmg)
    if safe_int(p.get("charging_killshot")):
        p["charging_killshot"] = 0; dmg = get_stat(p, "AGI") * 4

    boss_dict["hp"] = max(0, boss_dict["hp"] - dmg)
    participant["dmg"] += dmg

    lines = [
        f"⚔️ *{user.first_name}* strikes *{boss_dict['data']['name']}* for *{dmg}!*",
        f"❤️ Boss HP: {boss_dict['hp']}/{boss_dict['data']['max_hp']}"
    ]

    alive = [u for u in boss_dict["participants"]
             if not is_defeated(get_player(u["id"])) and boss_dict.get("player_hp", {}).get(u["id"], 1) > 0]
    if alive and boss_dict["hp"] > 0 and random.random() < 0.90:
        hit_count = 2 if random.random() < 0.30 else 1
        targets = random.sample(alive, min(hit_count, len(alive)))
        for target in targets:
            tp = get_player(target["id"])
            if tp and not is_defeated(tp):
                raw = random.randint(boss_dict["data"]["dmg_min"], boss_dict["data"]["dmg_max"])
                edm = calc_defense(tp, raw)
                boss_dict["player_hp"][target["id"]] = max(0,
                    boss_dict["player_hp"].get(target["id"], calc_max_hp(tp)) - edm)
                php = boss_dict["player_hp"][target["id"]]
                pmhp = boss_dict["player_max_hp"].get(target["id"], calc_max_hp(tp))
                if php == 0:
                    exp_loss = apply_pvp_death(tp, killer_name=boss_dict['data']['name'], cause="Boss")
                    asyncio.create_task(_notify_defeat(context.bot, tp, boss_dict['data']['name'] + " (Boss)"))
                    save_player(tp)
                    lines.append(f"💀 *{boss_dict['data']['name']}* KILLS *{target['name']}*! 30min defeat. -{fmt_num(exp_loss)} EXP.")
                else:
                    lines.append(f"💥 *{boss_dict['data']['name']}* hits *{target['name']}* for *{edm}!* ({php}/{pmhp} HP)")
                save_player(tp)

    alive_after = [u for u in boss_dict["participants"]
                   if not is_defeated(get_player(u["id"])) and boss_dict.get("player_hp", {}).get(u["id"], 1) > 0]
    if not alive_after and boss_dict["hp"] > 0:
        if is_secret: secret_boss_active.pop(chat_id, None)
        else: active_bosses.pop(chat_id, None)
        lines.append("💀 *ALL PLAYERS DEFEATED!* The boss wins...")
        save_player(p)
        try:
            await _q_edit(query, text="\n".join(lines)[:4096], parse_mode="Markdown")
        except Exception: pass
        return

    if boss_dict["hp"] <= 0:
        data = boss_dict["data"]
        if is_secret: secret_boss_active.pop(chat_id, None)
        else: active_bosses.pop(chat_id, None)
        lines.append(f"\n🏆 *{data['name']} DEFEATED!*\n")
        w2 = get_weather()
        for u in boss_dict["participants"]:
            pp = get_player(u["id"])
            if not pp: continue
            pp["gold"] = pp.get("gold", 0) + data["gold"]
            for loot in _boss_guaranteed_loot(pp):
                add_item(pp, loot); r = ""
                for pool in [WEAPONS, ARMORS, ACCESSORIES, HATS, GLOVES, BOOTS, MASKS]:
                    if loot in pool: r = RARITY_EMOJI.get(pool[loot].get("rarity",""),""); break
                lines.append(f"🎒 *{pp['username']}* found: {r} *{loot}*!")
            if award_title(pp, data["title"]):
                lines.append(f"🏅 *{pp['username']}* earned: *{data['title']}*!")
            _braid_exp = exp_share(pp["level"], 0.10)
            add_exp(pp, _braid_exp, w2); save_player(pp)
            lines.append(f"✅ *{pp['username']}*  -  +{fmt_num(_braid_exp)} EXP | +{data['gold']} Gold")
        try:
            await _q_edit(query, text="\n".join(lines)[:4096], parse_mode="Markdown")
        except Exception: pass
        return

    save_player(p)
    try:
        await _q_edit(query, text="\n".join(lines)[:4096], parse_mode="Markdown", reply_markup=_build_boss_markup(uid))
    except Exception: pass


# ── Prestige Path callback ──
async def prestige_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    await query.answer()
    parts = query.data.split("_")
    # format: prestige_{uid}_{path}
    if len(parts) < 3:
        return
    try:
        uid = int(parts[1])
        path = parts[2].upper()
    except (ValueError, IndexError):
        return
    if query.from_user.id != uid:
        await query.answer("This isn't your prestige menu!", show_alert=True)
        return

    user = query.from_user
    p = get_player(uid)
    if not p:
        await query.answer("Use /ascend first!", show_alert=True); return

    cid = p.get("class_id")
    if not cid:
        await query.answer("Choose a class first with /class.", show_alert=True); return
    cls = CLASS_TREE.get(cid, {})
    line = cls.get("line")
    existing_path = p.get("class_path")
    if existing_path:
        await query.answer("You already chose a path!", show_alert=True); return
    if p["level"] < 10:
        await query.answer("Path selection requires Level 10!", show_alert=True); return
    if path not in ("A", "B"):
        await query.answer("Invalid path.", show_alert=True); return

    paths = CLASS_PATHS.get(line, {})
    first_class = paths.get(path, [])[0] if paths.get(path) else None
    if not first_class:
        await query.answer("Invalid path for your class.", show_alert=True); return

    p["class_path"] = path
    p["class_id"] = first_class
    new_cls = CLASS_TREE.get(first_class, {})
    sd = safe_stats(p)
    for stat, bonus in new_cls.get("stat_bonus", {}).items():
        sd[stat] = sd.get(stat, 5) + bonus
    p["stats"] = json.dumps(sd)
    existing_skills = sjl(p.get("all_skills"), [])
    for sk in new_cls.get("skills", []):
        if sk["name"] not in [s["name"] for s in existing_skills]:
            existing_skills.append(sk)
    p["all_skills"] = json.dumps(existing_skills)
    # Catch-up: apply any tier advancements the player already qualifies for
    for _thresh in (30, 60, 100):
        if p["level"] >= _thresh:
            _auto_advance_class(p, _thresh)
    save_player(p)

    asyncio.create_task(announce(context.bot, query.message.chat.id,
        f"🌟 *{p['username']}* chose *Path {path}*  -  *{new_cls['name']}*!"))
    full_path = paths.get(path, [])
    path_names = " → ".join(CLASS_TREE.get(k, {}).get("name", "?") for k in full_path)
    msg = (f"🌟 *Path {path} chosen!* You are now a *{new_cls['name']}*!\n\n"
           f"_{new_cls['desc']}_\n\n"
           f"📜 Your journey: {path_names}\n\n"
           f"_Your class evolves automatically at Levels 30, 60, and 100. Level cap: 250._")
    try:
        await _q_edit(query, msg, parse_mode="Markdown")
    except Exception:
        pass


