async def shop_buy_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    # format: shopbuy_{uid}_{tab}_{idx}
    parts = query.data.split("_")
    if len(parts) < 4:
        await query.answer(); return
    try:
        uid = int(parts[1])
        tab = parts[2]
        idx = int(parts[3])
    except (ValueError, IndexError):
        await query.answer(); return
    if query.from_user.id != uid:
        await query.answer("This isn't your shop!", show_alert=True); return
    p = get_player(uid)
    if not p:
        await query.answer("Use /ascend first!", show_alert=True); return
    discount = _shop_discount(p)
    items = get_shop_tab_for_player(tab, p)
    if idx < 0 or idx >= len(items):
        await query.answer("Item no longer available.", show_alert=True); return
    entry = items[idx]
    price = round(entry["price"] * (1 - discount))
    if p["gold"] < price:
        await query.answer(f"Need {price:,}g — you have {p['gold']:,}g.", show_alert=True); return
    p["gold"] -= price
    add_item(p, entry["item"])
    save_player(p)
    await query.answer(f"✅ Bought {entry['item']} for {price:,}g!")
    # Rebuild the tab view with updated gold
    text, markup = _build_shop_view(p, tab, uid, discount)
    try:
        await _q_edit(query, text[:4096], parse_mode="Markdown", reply_markup=markup)
    except Exception:
        pass

async def shopbulk_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    # format: shopbulk_{uid}_{tab}_{idx}_{qty}
    parts = query.data.split("_")
    if len(parts) < 5:
        await query.answer(); return
    try:
        uid = int(parts[1])
        tab = parts[2]
        idx = int(parts[3])
        qty = int(parts[4])
    except (ValueError, IndexError):
        await query.answer(); return
    if query.from_user.id != uid:
        await query.answer("This isn't your shop!", show_alert=True); return
    p = get_player(uid)
    if not p:
        await query.answer("Use /ascend first!", show_alert=True); return
    discount = _shop_discount(p)
    items = get_shop_tab_for_player(tab, p)
    if idx < 0 or idx >= len(items):
        await query.answer("Item no longer available.", show_alert=True); return
    entry = items[idx]
    unit_price = round(entry["price"] * (1 - discount))
    total_price = unit_price * qty
    if p["gold"] < total_price:
        await query.answer(f"Need {total_price:,}g for {qty}× — you have {p['gold']:,}g.", show_alert=True); return
    p["gold"] -= total_price
    for _ in range(qty):
        add_item(p, entry["item"])
    save_player(p)
    await query.answer(f"✅ Bought {qty}× {entry['item']} for {total_price:,}g!")
    text, markup = _build_shop_view(p, tab, uid, discount)
    try:
        await _q_edit(query, text[:4096], parse_mode="Markdown", reply_markup=markup)
    except Exception:
        pass

async def shopreroll_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    parts = query.data.split("_")
    try:
        uid = int(parts[1])
        tab = parts[2]
    except (IndexError, ValueError):
        await query.answer(); return
    if query.from_user.id != uid:
        await query.answer("Not your shop!", show_alert=True); return
    p = get_player(uid)
    if not p:
        await query.answer("Use /ascend first!", show_alert=True); return

    today = datetime.now().strftime("%Y-%m-%d")
    reroll_count = safe_int(p.get("shop_reroll_count", 0)) if p.get("shop_reroll_date") == today else 0

    if reroll_count >= 3:
        await query.answer("Already rerolled 3 times today!", show_alert=True); return
    if safe_int(p.get("gold", 0)) < 1000:
        await query.answer("Need 1,000g to reroll!", show_alert=True); return

    p["gold"] = safe_int(p.get("gold", 0)) - 1000
    p["shop_reroll_date"] = today
    p["shop_reroll_count"] = reroll_count + 1
    save_player(p)

    discount = _shop_discount(p)
    text, markup = _build_shop_view(p, tab, uid, discount)
    await query.answer(f"Shop rerolled! ({reroll_count + 1}/3 today)")
    try:
        await _q_edit(query, text, parse_mode="Markdown", reply_markup=markup)
    except Exception:
        pass


# ── Allocate Stats callback ──
async def allocate_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    parts = query.data.split("_")
    # format: alloc_{uid}_{stat}_{amt}
    if len(parts) < 4:
        await query.answer(); return
    try:
        uid  = int(parts[1])
        stat = parts[2].upper()
        amt  = int(parts[3])
    except (ValueError, IndexError):
        await query.answer(); return
    if query.from_user.id != uid:
        await query.answer("This isn't your stat screen!", show_alert=True)
        return

    p = get_player(uid)
    if not p:
        await query.answer("Use /ascend first!", show_alert=True); return

    STAT_NAMES = ["STR","AGI","INT","WIS","DEX","LUK"]
    if stat not in STAT_NAMES:
        await query.answer("Invalid stat.", show_alert=True); return

    sp = safe_int(p.get("stat_points"))
    if amt > sp:
        await query.answer("Not enough stat points!", show_alert=True); return

    sd = safe_stats(p)
    sd[stat] = sd.get(stat, 5) + amt
    p["stats"] = json.dumps(sd)
    p["stat_points"] = sp - amt
    save_player(p)
    sp = p["stat_points"]

    await query.answer(f"+{amt} {stat}! {sp} points left.")

    # Rebuild the allocate message with updated stats and buttons
    cls = get_player_class(p)
    rec = cls["primary_stat"] + " recommended" if cls else "Free to allocate"
    max_hp = calc_max_hp(p)
    text = (f"📊 *Stat Allocation*  -  *{sp}* points available\n\n"
            f"❤️ Max HP: {max_hp}\n"
            f"STR:{get_stat(p,'STR')} AGI:{get_stat(p,'AGI')} INT:{get_stat(p,'INT')} "
            f"WIS:{get_stat(p,'WIS')} DEX:{get_stat(p,'DEX')} LUK:{get_stat(p,'LUK')}\n\n"
            f"📌 STR  -  Attack damage (Warrior)\n"
            f"📌 AGI  -  Dodge & crit\n"
            f"📌 INT  -  Spell damage (Mage)\n"
            f"📌 WIS  -  Heal power (Priest)\n"
            f"📌 DEX  -  Accuracy & crit (Archer)\n"
            f"📌 LUK  -  Crit & gold bonus (Thief)\n"
            f"📌 DEF  -  From gear only (cannot allocate)\n\n"
            f"🧭 {rec}")
    rows = []
    if sp > 0:
        for s in STAT_NAMES:
            row = [InlineKeyboardButton(f"{s} +1", callback_data=f"alloc_{uid}_{s}_1")]
            if sp >= 5:
                row.append(InlineKeyboardButton(f"{s} +5", callback_data=f"alloc_{uid}_{s}_5"))
            rows.append(row)
    markup = InlineKeyboardMarkup(rows) if rows else None
    try:
        await _q_edit(query, text[:4096], parse_mode="Markdown", reply_markup=markup)
    except Exception:
        pass


# ── MAIN ──────────────────────────────────────────────────────────────────────
# ── RANDOM WORLD EVENTS (ambient DMs throughout the day) ──────────────────────
async def _send_ambush_event(bot, uid, p):
    """Spawns a tough, fully-interactive battle encounter directly in the player's DM,
    using the same combat UI as /encounter, but harder and with extreme rewards."""
    if uid in active_encounters or uid in active_dungeons:
        return  # don't stomp an existing session
    p_level = p.get("level", 1)
    npc = _pick_random_npc(p_level)
    # Ambush enemies are meaningfully tougher than a normal encounter
    n_level = min(p_level + random.randint(8, 15), p_level + max(8, p_level // 3))
    n_hp, n_atk, reward_mult, num_gear, num_pots, gear_rarities = _enc_level_stats(n_level, p_level)
    n_hp  = round(n_hp * random.uniform(1.5, 1.9))
    n_atk = round(n_atk * random.uniform(1.3, 1.6))
    reward_mult = round(reward_mult * random.uniform(3.0, 4.5), 2)  # extreme EXP/gold on a win
    p_mhp = calc_max_hp(p)
    p_hp  = min(p_mhp, max(1, safe_int(p.get("hp")) or p_mhp))
    p_max_mp = calc_max_mp(p); p_mp = max(0, min(p_max_mp, safe_int(p.get("mp")) or p_max_mp))
    cls_name = CLASS_TREE.get(npc[1], {}).get("name", npc[1].replace("_", " ").title())
    _amb_pet = get_active_pet_record(uid)
    _pet_info = None
    if _amb_pet and not _pet_is_on_adventure(_amb_pet):
        _sp = PET_SPECIES.get(_amb_pet.get("species"), {})
        _, _bond_label = _get_bond_tier(_amb_pet.get("bond_score", 0))
        _pet_info = {
            "pet_id": _amb_pet["pet_id"],
            "name": _amb_pet.get("nickname") or _sp.get("name", "Pet"),
            "level": _amb_pet.get("level", 1),
            "atk": _pet_combat_atk(_amb_pet, p),
            "bond_label": _bond_label,
            "species": _amb_pet.get("species"),
            "def_ability": _sp.get("def_ability"),
        }
    enc = {
        "uid": uid, "mode": "battle", "p_name": p.get("username", "You"),
        "p_hp": p_hp, "p_max_hp": p_mhp, "p_mp": p_mp, "p_max_mp": p_max_mp,
        "e_name": npc[0], "e_class": npc[1],
        "e_hp": n_hp, "e_max_hp": n_hp, "e_atk": n_atk, "e_level": n_level,
        "e_gold_range": npc[6], "e_exp_range": npc[7], "e_loot_key": npc[8],
        "action_log": [f"⚠️ *{npc[0]}* [{cls_name}] Lv.{n_level} ambushes you from the shadows!"],
        "pet_info": _pet_info,
        "pet_ability_used": False,
        "reward_mult": reward_mult, "num_gear": num_gear,
        "num_pots": num_pots, "gear_rarities": gear_rarities,
        "is_ambush": True,
    }
    _enc_set(uid, enc)
    _enc_sessions.setdefault(uid, {"gold": 0, "exp": 0, "wins": 0, "losses": 0, "items": []})["mode"] = "battle"
    card = ("🚨 *AMBUSH!* A dangerous foe blocks your path — beat it for extreme rewards!\n\n"
            + _encounter_battle_card(enc))
    markup = _encounter_battle_markup(enc, p)
    try:
        await bot.send_message(uid, card, parse_mode="Markdown", reply_markup=markup)
    except Exception:
        active_encounters.pop(uid, None)
        _enc_sessions.pop(uid, None)

_CHEST_FLAVORS = [
    "🎁 *A mysterious chest appears in your path!*",
    "💰 *You spot a glint in the rubble — buried treasure!*",
    "📦 *A courier drops a package at your feet and vanishes.*",
    "🗝️ *An old lockbox finally gives up its secret.*",
    "⛏️ *You strike something metal while digging around.*",
]
_QUEST_FLAVORS = [
    "📜 *A traveling merchant rewards you for a good deed!*",
    "🧙 *A grateful stranger presses knowledge into your hands.*",
    "🕯️ *An oracle's blessing settles over you.*",
    "🍺 *A tavern tale teaches you something worth knowing.*",
    "🗺️ *You retrace an old map and learn from the journey.*",
]

async def _send_random_dm_event(bot, uid, p):
    kind = random.choices(["chest", "quest", "gift", "ambush"], weights=[35, 30, 15, 20])[0]
    try:
        if kind == "chest":
            gold = scaled_gold(p.get("level", 1), random.randint(150, 450))
            p["gold"] = safe_int(p.get("gold")) + gold
            save_player(p)
            await bot.send_message(uid,
                f"{random.choice(_CHEST_FLAVORS)}\nYou find *{fmt_num(gold)} gold*.",
                parse_mode="Markdown")
        elif kind == "quest":
            exp = exp_share(p.get("level", 1), random.uniform(0.03, 0.08))
            add_exp(p, exp)
            save_player(p)
            await bot.send_message(uid,
                f"{random.choice(_QUEST_FLAVORS)}\n+*{fmt_num(exp)} EXP*",
                parse_mode="Markdown")
        elif kind == "gift":
            reward = _grant_gift(uid)
            if reward:
                await bot.send_message(uid,
                    f"🍀 *A stroke of good fortune finds you!*\nYou received {reward}.",
                    parse_mode="Markdown")
        else:  # ambush — tough, interactive fight with extreme rewards on a win
            await _send_ambush_event(bot, uid, p)
    except Exception:
        pass

async def _fire_random_world_events(bot):
    try:
        c = _db().cursor()
        # 7-day window so semi-away players get pulled back too, not only
        # players who were already active yesterday
        cutoff = (datetime.now() - timedelta(days=7)).isoformat()
        c.execute("SELECT user_id FROM shadow_profiles WHERE last_seen >= ?", (cutoff,))
        candidates = [r[0] for r in c.fetchall()]
    except Exception:
        return
    if not candidates:
        return
    random.shuffle(candidates)
    picks = candidates[: max(1, len(candidates) // 4)]  # ~25% of the window per cycle
    for uid in picks:
        if random.random() > 0.50:
            continue
        try:
            if is_banned(uid):
                continue
            p = get_player(uid)
            if not p or is_defeated(p):
                continue
            await _send_random_dm_event(bot, uid, p)
            await asyncio.sleep(0.3)  # spread sends out to avoid flood limits
        except Exception:
            continue

async def _pet_care_sweep(bot, max_sends=30):
    """Proactively DM owners whose active pet is hungry/sad/done adventuring —
    even if they haven't messaged in days. check_pet_notifications is already
    rate-limited per condition (4-8h, persisted), so this can run often."""
    try:
        c = _db().cursor()
        c.execute("SELECT DISTINCT owner_id FROM pets WHERE is_active=1")
        owners = [r[0] for r in c.fetchall()]
    except Exception:
        return
    random.shuffle(owners)
    sent = 0
    for uid in owners:
        if sent >= max_sends:
            break
        try:
            if is_banned(uid):
                continue
            p = get_player(uid)
            if not p:
                continue
            pet = get_active_pet_record(uid)
            if not pet:
                continue
            _needy = (pet.get("hunger", 100) < 30 or pet.get("mood", 100) < 30
                      or pet.get("adventure_ends_at"))
            if not _needy:
                continue
            await check_pet_notifications(p, bot)
            sent += 1
            await asyncio.sleep(0.3)
        except Exception:
            continue

async def _winback_sweep(bot, max_sends=20):
    """DM players who've been away 24h-14d with a personalized reason to
    return (idle EXP waiting, empire stockpiles, lonely pet, /daily ready).
    At most one win-back per player per 48h (persisted in pet_notify_ts)."""
    now = datetime.now()
    try:
        c = _db().cursor()
        lo = (now - timedelta(days=14)).isoformat()
        hi = (now - timedelta(hours=24)).isoformat()
        c.execute("""SELECT user_id, username, last_seen, pet_notify_ts
                     FROM shadow_profiles WHERE last_seen BETWEEN ? AND ?""", (lo, hi))
        rows = c.fetchall()
    except Exception:
        return
    rows = list(rows)
    random.shuffle(rows)
    sent = 0
    for row in rows:
        if sent >= max_sends:
            break
        uid = row["user_id"]
        try:
            if is_banned(uid):
                continue
            # 48h per-player cooldown, persisted alongside pet notify stamps
            try:
                cache = json.loads(row["pet_notify_ts"] or "{}")
            except Exception:
                cache = {}
            last_wb = cache.get("winback")
            if last_wb:
                try:
                    if (now - datetime.fromisoformat(last_wb)).total_seconds() < 48 * 3600:
                        continue
                except Exception:
                    pass
            p = get_player(uid)
            hooks = []
            if p:
                try:
                    idle_secs = (now - datetime.fromisoformat(row["last_seen"])).total_seconds()
                    idle_exp = _calc_idle_exp(idle_secs, p.get("level", 1))
                    if idle_exp > 0:
                        hooks.append(f"✨ *{fmt_num(idle_exp)} idle EXP* is waiting for you")
                except Exception:
                    pass
                try:
                    bld, _, lc = _get_empire(p)
                    if bld and p.get("empire_last_collect"):
                        _emp_h = min(_EMPIRE_MAX_HOURS,
                                     (now - datetime.fromisoformat(lc)).total_seconds() / 3600)
                        if _emp_h >= 4:
                            hooks.append(f"🏰 Your empire has *{_emp_h:.0f}h* of resources stockpiled")
                except Exception:
                    pass
                if check_cooldown(p.get("last_daily"), 86400):
                    hooks.append("🎁 Your */daily* reward is ready")
            pet = get_active_pet_record(uid)
            if pet:
                _pname = pet.get("nickname") or PET_SPECIES.get(pet.get("species"), {}).get("name", "Your pet")
                if pet.get("hunger", 100) < 50:
                    hooks.append(f"🍖 *{_pname}* is getting hungry without you")
                else:
                    hooks.append(f"🐾 *{_pname}* misses you")
            if not hooks:
                continue  # nothing personal to say — don't send generic spam
            random.shuffle(hooks)
            msg = ("🎱 *The table's been quiet without you...*\n\n"
                   + "\n".join(f"• {h}" for h in hooks[:3])
                   + "\n\n_Come say something in the group — everything picks up where you left it._")
            await bot.send_message(uid, msg, parse_mode="Markdown")
            cache["winback"] = now.isoformat()
            s = get_shadow(uid)
            if s:
                s["pet_notify_ts"] = json.dumps(cache)
                save_shadow(s)
            sent += 1
            await asyncio.sleep(0.3)
        except Exception:
            continue

async def _post_daily_digest(bot):
    """Evening group digest: top EXP grinders, PvP standout, kill-streak
    leader, weather — social proof that pulls lurkers back into the game.
    Gains are measured against the digest_snap table refreshed each post."""
    c = _db().cursor()
    week_ago = (datetime.now() - timedelta(days=7)).isoformat()
    try:
        c.execute("""SELECT DISTINCT home_group FROM shadow_profiles
                     WHERE home_group IS NOT NULL AND last_seen >= ?""", (week_ago,))
        groups = [r[0] for r in c.fetchall()]
    except Exception:
        return
    if not groups:
        return
    conn = _db()
    conn.execute("""CREATE TABLE IF NOT EXISTS digest_snap
                    (user_id INTEGER PRIMARY KEY, total_exp INTEGER, wins INTEGER)""")
    conn.commit()
    c.execute("""SELECT p.user_id, p.username, p.total_exp, p.wins, p.kill_streak,
                        p.level, s.home_group
                 FROM players p JOIN shadow_profiles s ON s.user_id = p.user_id
                 WHERE s.last_seen >= ?""", (week_ago,))
    rows = [dict(r) for r in c.fetchall()]
    c.execute("SELECT user_id, total_exp, wins FROM digest_snap")
    snap = {r["user_id"]: (safe_int(r["total_exp"]), safe_int(r["wins"])) for r in c.fetchall()}
    per_group = {}
    for r in rows:
        old = snap.get(r["user_id"])
        exp_gain = max(0, safe_int(r["total_exp"]) - old[0]) if old else 0
        win_gain = max(0, safe_int(r["wins"]) - old[1]) if old else 0
        per_group.setdefault(r["home_group"], []).append((r, exp_gain, win_gain))
    w = get_weather()
    # ── WEEKLY PVP CHAMPION ──────────────────────────────────────────────────
    # Once every 7 days, crown the highest-rated fighter: title + gold prize,
    # announced in every group's digest. Rating itself is never reset.
    _champ_line = ""
    try:
        _last_crown = _ws_get("pvp_champion_ts", 0)
        if time.time() - safe_int(_last_crown) >= 7 * 86400:
            _tc = _db().cursor()
            _top = _tc.execute("SELECT user_id, username, pvp_rating FROM players "
                               "WHERE pvp_rating IS NOT NULL AND pvp_rating > 1000 "
                               "ORDER BY pvp_rating DESC LIMIT 1").fetchone()
            if _top:
                _champ_p = get_player(_top["user_id"])
                if _champ_p:
                    _prize = 100000
                    _champ_p["gold"] = safe_int(_champ_p.get("gold")) + _prize
                    award_title(_champ_p, "PvP Champion")
                    save_player(_champ_p)
                    _ws_set("pvp_champion", {"uid": _top["user_id"], "name": _top["username"],
                                            "rating": safe_int(_top["pvp_rating"]), "ts": time.time()})
                    _ws_set("pvp_champion_ts", time.time())
                    _champ_line = (f"👑🏆 *WEEKLY PVP CHAMPION: {_top['username']}!*\n"
                                   f"Rating {safe_int(_top['pvp_rating'])} {_pvp_rank_name(safe_int(_top['pvp_rating']))} "
                                   f"— awarded the *PvP Champion* title + {fmt_num(_prize)}g!")
                    try:
                        await bot.send_message(_top["user_id"],
                            f"👑 *You are this week's PvP Champion!*\n\n"
                            f"Top rating at *{safe_int(_top['pvp_rating'])}*. Prize: *{fmt_num(_prize)}g* "
                            f"and the *PvP Champion* title. Defend your throne!",
                            parse_mode="Markdown")
                    except Exception:
                        pass
    except Exception:
        logger.error("weekly champion crown failed", exc_info=True)
    for g in groups:
        entries = per_group.get(g, [])
        gainers  = sorted([e for e in entries if e[1] > 0], key=lambda e: -e[1])[:3]
        fighters = sorted([e for e in entries if e[2] > 0], key=lambda e: -e[2])[:1]
        streaker = None
        if entries:
            _cand = max(entries, key=lambda e: safe_int(e[0].get("kill_streak")))
            if safe_int(_cand[0].get("kill_streak")) >= 3:
                streaker = _cand[0]
        lines = ["🎱 *DAILY DIGEST*", ""]
        if gainers:
            lines.append("🏆 *Top grinders today:*")
            medals = ["🥇", "🥈", "🥉"]
            for i, (r, eg, _) in enumerate(gainers):
                lines.append(f"{medals[i]} *{r['username']}* (Lv {r['level']}) — +{fmt_num(eg)} EXP")
            lines.append("")
        if fighters:
            r, _, wg = fighters[0]
            lines.append(f"⚔️ *PvP standout:* {r['username']} — {wg} win{'s' if wg != 1 else ''} today")
            lines.append("")
        if streaker:
            lines.append(f"🔥 *Kill streak:* {streaker['username']} ×{streaker['kill_streak']} — someone stop them!")
            lines.append("")
        if _champ_line:
            lines.append(_champ_line)
            lines.append("")
        _king = _get_king()
        if _king:
            lines.append(f"👑 *King of the Table:* {_king['name']} — dethrone them in PvP!")
            lines.append("")
        try:
            lines.append(await _goal_check_reward(bot))
            lines.append("")
        except Exception:
            pass
        try:
            _lot_line = await _lottery_draw(bot)
            if _lot_line:
                lines.append(_lot_line)
                lines.append("")
        except Exception:
            pass
        lines.append(f"🌍 *{w['name']}* — EXP ×{w['exp_mod']} | DMG ×{w['dmg_mod']}")
        lines.append("")
        lines.append("_Think you can top tomorrow's board? /daily · /dungeon · /attack_")
        try:
            await bot.send_message(g, "\n".join(lines), parse_mode="Markdown")
        except Exception:
            pass
        await asyncio.sleep(0.5)
    # Refresh the snapshot so tomorrow's digest measures the next 24h
    try:
        conn.execute("DELETE FROM digest_snap")
        conn.execute("""INSERT INTO digest_snap
                        SELECT user_id, COALESCE(total_exp,0), COALESCE(wins,0) FROM players""")
        conn.commit()
    except Exception:
        pass

async def _daily_digest_loop(bot):
    """Posts the digest every evening at 20:00 server time."""
    while True:
        try:
            now = datetime.now()
            target = now.replace(hour=20, minute=0, second=0, microsecond=0)
            if target <= now:
                target += timedelta(days=1)
            await asyncio.sleep((target - now).total_seconds())
            await _post_daily_digest(bot)
        except Exception:
            await asyncio.sleep(300)

# ══════════════════════════════════════════════════════════════════════════════
# GROUP INTERACTIVITY — king of the table, weekly goal, crates, fight bets,
# weather announcements. State lives in the world_state key/value table.
# ══════════════════════════════════════════════════════════════════════════════

def _ws_get(key, default=None):
    try:
        conn = _db()
        conn.execute("CREATE TABLE IF NOT EXISTS world_state (key TEXT PRIMARY KEY, value TEXT)")
        row = conn.execute("SELECT value FROM world_state WHERE key=?", (key,)).fetchone()
        return json.loads(row["value"]) if row else default
    except Exception:
        return default

def _ws_set(key, value):
    try:
        conn = _db()
        conn.execute("CREATE TABLE IF NOT EXISTS world_state (key TEXT PRIMARY KEY, value TEXT)")
        conn.execute("INSERT OR REPLACE INTO world_state (key, value) VALUES (?, ?)",
                     (key, json.dumps(value)))
        conn.commit()
    except Exception:
        pass

# ── KING OF THE TABLE ────────────────────────────────────────────────────────
def _get_king():
    return _ws_get("king")  # {"uid", "name", "since"} or None

def _is_king(p):
    k = _get_king()
    return bool(k and p and k.get("uid") == p.get("user_id"))

async def _update_king_on_kill(bot, winner, loser, chat_id=None):
    """Crown logic: beating the King takes the crown; if the throne is empty,
    the first PvP kill claims it. One announcement per crown change."""
    try:
        k = _get_king()
        w_uid = winner.get("user_id"); w_name = winner.get("username", "?")
        if k and k.get("uid") == w_uid:
            return  # king defended the crown — no spam
        took_crown = (k is None) or (k.get("uid") == loser.get("user_id"))
        if not took_crown:
            return
        _ws_set("king", {"uid": w_uid, "name": w_name, "since": datetime.now().isoformat()})
        grp = chat_id or _megaphone_state.get("group")
        if grp:
            if k:
                txt = (f"👑 *THE CROWN CHANGES HANDS!*\n\n"
                       f"*{w_name}* dethroned *{k.get('name','?')}* and is the new "
                       f"*King of the Table!*\n_+5% damage while holding the crown. "
                       f"Defeat them in PvP to take it._")
            else:
                txt = (f"👑 *A KING RISES!*\n\n*{w_name}* has claimed the empty throne — "
                       f"*King of the Table!*\n_+5% damage while holding the crown. "
                       f"Defeat them in PvP to take it._")
            try:
                await bot.send_message(grp, txt, parse_mode="Markdown")
            except Exception:
                pass
    except Exception:
        pass

# ── WEEKLY GROUP GOAL ────────────────────────────────────────────────────────
_GOAL_TYPES = [
    ("pvp_win",     "⚔️ Win {n} PvP fights together",      120),
    ("dungeon_run", "🏚️ Complete {n} dungeon runs together", 40),
    ("quest_run",   "🗺️ Complete {n} quests together",      150),
    ("pool_run",    "🎱 Finish {n} adventures together",     80),
]

def _goal_get():
    g = _ws_get("weekly_goal")
    wk = datetime.now().strftime("%Y-%W")
    if not g or g.get("week") != wk:
        key, desc, target = random.choice(_GOAL_TYPES)
        g = {"week": wk, "key": key, "desc": desc.format(n=target), "target": target,
             "progress": 0, "contributors": {}, "rewarded": False}
        _ws_set("weekly_goal", g)
    return g

def _goal_bump(p, obj_id, amount=1):
    """Called from track_objective — counts qualifying actions toward the goal."""
    try:
        g = _goal_get()
        if g.get("key") != obj_id or g.get("rewarded"):
            return
        g["progress"] = g.get("progress", 0) + amount
        cu = str(p.get("user_id"))
        g["contributors"][cu] = g["contributors"].get(cu, 0) + amount
        _ws_set("weekly_goal", g)
    except Exception:
        pass

async def _goal_check_reward(bot):
    """If the goal just completed, pay every contributor and announce. Returns
    a digest line describing current goal state."""
    g = _goal_get()
    bar_w = 12
    filled = min(bar_w, round(g["progress"] / max(1, g["target"]) * bar_w))
    bar = "█" * filled + "░" * (bar_w - filled)
    if g["progress"] >= g["target"] and not g.get("rewarded"):
        g["rewarded"] = True
        _ws_set("weekly_goal", g)
        paid = 0
        for cu, cnt in list(g.get("contributors", {}).items())[:100]:
            cp = get_player(int(cu))
            if cp:
                add_exp(cp, exp_share(cp["level"], 0.20))
                cp["gold"] = cp.get("gold", 0) + 400
                save_player(cp)
                paid += 1
                try:
                    await bot.send_message(int(cu),
                        f"🎉 *Group Quest complete!* {g['desc']} — done!\n"
                        f"Your share: *+20% of a level EXP + 400g*", parse_mode="Markdown")
                except Exception:
                    pass
                await asyncio.sleep(0.2)
        return f"🏁 *GROUP QUEST COMPLETE!* {g['desc']} — {paid} heroes rewarded!"
    return f"🤝 *Group Quest:* {g['desc']}\n`{bar}` {g['progress']}/{g['target']}"

# ── LOOT CRATES (first-come tap race) ────────────────────────────────────────
_active_crates = {}   # chat_id -> {"msg_id", "claimed": [(uid,name)], "expires"}
_CRATE_LOOT = ["Health Potion", "Greater Health Potion", "Iron Shard", "Enchanting Scroll",
               "MP Tonic", "Scroll of Revival"]

async def _spawn_crate(bot, chat_id):
    if chat_id in _active_crates:
        return
    try:
        msg = await bot.send_message(chat_id,
            "📦 *A supply crate crashes onto the table!*\n\n"
            "_First 3 to grab it get gold, EXP, and loot!_",
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup([[
                InlineKeyboardButton("🫳 GRAB IT!", callback_data=f"crate_{chat_id}")]]))
    except Exception:
        return
    _active_crates[chat_id] = {"msg_id": msg.message_id, "claimed": [], "expires": time.time() + 90}
    async def _crate_expire(cid=chat_id, mid=msg.message_id):
        await asyncio.sleep(95)
        st = _active_crates.get(cid)
        if st and st["msg_id"] == mid:
            _active_crates.pop(cid, None)
            try:
                if st["claimed"]:
                    names = ", ".join(n for _, n in st["claimed"])
                    await bot.edit_message_text(chat_id=cid, message_id=mid,
                        text=f"📦 *Crate emptied!* Grabbed by: {names}", parse_mode="Markdown")
                else:
                    await bot.delete_message(chat_id=cid, message_id=mid)
            except Exception:
                pass
    _t = asyncio.create_task(_crate_expire())
    _bg_tasks.add(_t); _t.add_done_callback(_bg_tasks.discard)

async def crate_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    try:
        chat_id = int(query.data.split("_")[1])
    except (IndexError, ValueError):
        await query.answer(); return
    st = _active_crates.get(chat_id)
    uid = query.from_user.id
    if not st or time.time() > st["expires"]:
        await query.answer("Too slow — the crate is gone!", show_alert=True); return
    if any(u == uid for u, _ in st["claimed"]):
        await query.answer("You already grabbed your share!"); return
    if len(st["claimed"]) >= 3:
        await query.answer("Too slow — all 3 shares are gone!", show_alert=True); return
    p = get_player(uid)
    if not p:
        await query.answer("Use /ascend first!", show_alert=True); return
    st["claimed"].append((uid, p["username"]))
    gold = 150 + p["level"] * 10
    exp = exp_share(p["level"], 0.03)
    item = random.choice(_CRATE_LOOT)
    p["gold"] = p.get("gold", 0) + gold
    add_item(p, item)
    add_exp(p, exp)
    save_player(p)
    await query.answer(f"📦 +{gold}g, +{fmt_num(exp)} EXP, {item}!")
    names = ", ".join(f"*{n}*" for _, n in st["claimed"])
    left = 3 - len(st["claimed"])
    try:
        await _q_edit(query, 
            f"📦 *A supply crate crashed onto the table!*\n\n"
            f"Grabbed by: {names}\n" +
            (f"_{left} share{'s' if left != 1 else ''} left — be quick!_" if left else "_Emptied!_"),
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup([[
                InlineKeyboardButton("🫳 GRAB IT!", callback_data=f"crate_{chat_id}")]]) if left else None)
    except Exception:
        pass
    if not left:
        _active_crates.pop(chat_id, None)

# ── FIGHT BETTING (spectators stake gold on PvP fights) ──────────────────────
_fight_bets = {}  # pair -> {"chat_id","msg_id","bets":{uid:(side_uid,amt,name)},"open_until","names":{uid:name}}
_BET_AMOUNT = 100

async def _open_fight_bets(bot, chat_id, pair, a, d):
    if pair in _fight_bets or not chat_id or chat_id in (a.get("user_id"), d.get("user_id")):
        return
    au, du = a.get("user_id"), d.get("user_id")
    try:
        msg = await bot.send_message(chat_id,
            f"⚔️ *FIGHT!*  *{a['username']}* (Lv {a.get('level',1)})  vs  "
            f"*{d['username']}* (Lv {d.get('level',1)})\n\n"
            f"💰 _Spectators: bet {_BET_AMOUNT}g on the winner — 60s window, 2x payout!_",
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup([[
                InlineKeyboardButton(f"💰 {a['username'][:12]}", callback_data=f"bet_{au}_{du}_{au}"),
                InlineKeyboardButton(f"💰 {d['username'][:12]}", callback_data=f"bet_{au}_{du}_{du}"),
            ]]))
        _fight_bets[pair] = {"chat_id": chat_id, "msg_id": msg.message_id, "bets": {},
                             "open_until": time.time() + 60,
                             "names": {au: a["username"], du: d["username"]}}
        # Watchdog: if the fight never finalizes (both players walk away),
        # refund every stake and close the card instead of leaking the escrow.
        _wt = asyncio.create_task(_bet_watchdog(bot, pair))
        _bg_tasks.add(_wt); _wt.add_done_callback(_bg_tasks.discard)
    except Exception:
        pass

async def _bet_watchdog(bot, pair, delay=900):
    await asyncio.sleep(delay)
    if pair in _fight_bets:
        try:
            await _resolve_fight_bets(bot, pair, None)
        except Exception:
            _fight_bets.pop(pair, None)

async def bet_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    parts = query.data.split("_")
    try:
        au, du, side = int(parts[1]), int(parts[2]), int(parts[3])
    except (IndexError, ValueError):
        await query.answer(); return
    pair = _pvp_pair_key(au, du)
    st = _fight_bets.get(pair)
    uid = query.from_user.id
    if not st:
        await query.answer("Betting is closed for this fight.", show_alert=True); return
    if time.time() > st["open_until"]:
        await query.answer("⏳ The betting window has closed!", show_alert=True); return
    if uid in (au, du):
        await query.answer("Fighters can't bet on their own match!", show_alert=True); return
    if uid in st["bets"]:
        await query.answer("You already placed your bet!"); return
    p = get_player(uid)
    if not p:
        await query.answer("Use /ascend first!", show_alert=True); return
    if p.get("gold", 0) < _BET_AMOUNT:
        await query.answer(f"Need {_BET_AMOUNT}g to bet!", show_alert=True); return
    p["gold"] -= _BET_AMOUNT
    save_player(p)
    st["bets"][uid] = (side, _BET_AMOUNT, p["username"])
    await query.answer(f"💰 {_BET_AMOUNT}g on {st['names'].get(side,'?')}!")
    n_bets = len(st["bets"])
    try:
        await _q_edit(query, 
            f"⚔️ *FIGHT!*  *{st['names'][au]}*  vs  *{st['names'][du]}*\n\n"
            f"💰 {n_bets} bet{'s' if n_bets != 1 else ''} placed — "
            f"_{_BET_AMOUNT}g a seat, 2x payout, window closes fast!_",
            parse_mode="Markdown", reply_markup=query.message.reply_markup)
    except Exception:
        pass

async def _resolve_fight_bets(bot, pair, winner_id, result_text=""):
    st = _fight_bets.pop(pair, None)
    if not st:
        return
    names = st["names"]
    if winner_id is None:
        lines = ["🏳️ *The fight fizzled out — no winner.*"]
        if st["bets"]:
            for uid, (side, amt, nm) in st["bets"].items():
                bp = get_player(uid)
                if bp:
                    bp["gold"] = bp.get("gold", 0) + amt
                    save_player(bp)
            lines.append("💰 *All bets refunded.*")
    else:
        lines = [f"🏁 *{names.get(winner_id, '?')} WINS!*"]
        w_names, l_names = [], []
        for uid, (side, amt, nm) in st["bets"].items():
            if side == winner_id:
                bp = get_player(uid)
                if bp:
                    bp["gold"] = bp.get("gold", 0) + amt * 2
                    save_player(bp)
                w_names.append(nm)
            else:
                l_names.append(nm)
        if w_names: lines.append(f"💰 *Paid 2x:* {', '.join(w_names)}")
        if l_names: lines.append(f"💸 *Lost the house's favor:* {', '.join(l_names)}")
    try:
        await bot.edit_message_text(chat_id=st["chat_id"], message_id=st["msg_id"],
            text="\n".join(lines), parse_mode="Markdown", reply_markup=None)
    except Exception:
        pass

# ── PVP GAME MODES: ROYALE / QUICKDRAW / RUSSIAN / STANDOFF ──────────────────
# Four consensual, wager-based PvP mini-modes. All state is per-chat and
# in-memory; stakes are deducted at accept time (gold is race-safe via the
# delta-merge) and refunded on cancel/expiry.

_royales    = {}   # chat_id -> {"players":{uid:name},"pot":int,"msg_id":int,"state":"join"}
_quickdraws = {}   # chat_id -> quickdraw state
_russians   = {}   # chat_id -> russian roulette state
_standoffs  = {}   # chat_id -> standoff state
_ROYALE_FEE = 100

def _wager_from_args(args, default=100, lo=10, hi=100000):
    for a in (args or []):
        try:
            return max(lo, min(hi, int(a)))
        except ValueError:
            continue
    return default

def _take_gold(uid, amount):
    """Deduct gold if the player can afford it. Returns the player dict or None."""
    p = get_player(uid)
    if not p or safe_int(p.get("gold")) < amount:
        return None
    p["gold"] -= amount
    save_player(p)
    return p

def _give_gold(uid, amount):
    p = get_player(uid)
    if p:
        p["gold"] = safe_int(p.get("gold")) + amount
        save_player(p)

# ── 1) BATTLE ROYALE ─────────────────────────────────────────────────────────
_BR_KILL_LINES = [
    "⚔️ *{k}* ambushes *{v}* behind the pool hall!",
    "🔪 *{v}* trusted *{k}*. Mistake.",
    "🏹 *{k}* snipes *{v}* clean off the fence!",
    "💥 *{v}* steps on a trap laid by *{k}*!",
    "🪓 *{k}* kicks *{v}* into the void pocket!",
    "🐍 *{k}* poisons *{v}*'s drink at the bar!",
    "🌩️ *{k}* calls down thunder on *{v}*!",
    "🕳️ *{v}* falls into a pit while running from *{k}*!",
    "🎱 *{k}* breaks the rack — *{v}* goes down with it!",
    "👻 *{v}* is never seen again. *{k}* whistles innocently.",
]

async def royale_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    chat = update.effective_chat
    user = update.effective_user
    if chat.type not in ("group", "supergroup"):
        await update.message.reply_text("⚔️ Battle Royale runs in the group chat!"); return
    if chat.id in _royales:
        await send_group(update, "⚔️ A Battle Royale is already forming/running here!", delay=9); return
    p = _take_gold(user.id, _ROYALE_FEE)
    if not p:
        await send_group(update, f"⚔️ Battle Royale entry costs *{_ROYALE_FEE}g* — you can't cover it!", delay=9); return
    st = {"players": {user.id: p["username"]}, "pot": _ROYALE_FEE, "msg_id": None, "state": "join"}
    _royales[chat.id] = st
    try:
        msg = await context.bot.send_message(chat.id,
            f"⚔️ *BATTLE ROYALE FORMING!*\n\n"
            f"*{p['username']}* threw down {_ROYALE_FEE}g!\n"
            f"💰 Pot: *{st['pot']}g*  •  👥 1 fighter\n\n"
            f"_60 seconds to join — {_ROYALE_FEE}g entry, winner takes ALL._",
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup([[InlineKeyboardButton(
                f"⚔️ JOIN ({_ROYALE_FEE}g)", callback_data=f"br_join_{chat.id}")]]))
        st["msg_id"] = msg.message_id
    except Exception:
        _royales.pop(chat.id, None); _give_gold(user.id, _ROYALE_FEE); return
    _t = asyncio.create_task(_royale_run(context.bot, chat.id))
    _bg_tasks.add(_t); _t.add_done_callback(_bg_tasks.discard)

async def royale_join_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    try:
        chat_id = int(query.data.split("_")[2])
    except (IndexError, ValueError):
        await query.answer(); return
    st = _royales.get(chat_id)
    if not st or st["state"] != "join":
        await query.answer("Too late — the royale already started!", show_alert=True); return
    uid = query.from_user.id
    if uid in st["players"]:
        await query.answer("You're already in!"); return
    p = _take_gold(uid, _ROYALE_FEE)
    if not p:
        await query.answer(f"Need {_ROYALE_FEE}g to enter (and an /ascend-ed character)!", show_alert=True); return
    st["players"][uid] = p["username"]
    st["pot"] += _ROYALE_FEE
    await query.answer(f"⚔️ You're in! Pot: {st['pot']}g")
    try:
        await context.bot.edit_message_text(chat_id=chat_id, message_id=st["msg_id"],
            text=(f"⚔️ *BATTLE ROYALE FORMING!*\n\n"
                  f"💰 Pot: *{st['pot']}g*  •  👥 {len(st['players'])} fighters\n"
                  f"{', '.join(list(st['players'].values())[:12])}\n\n"
                  f"_Join before the gate closes!_"),
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup([[InlineKeyboardButton(
                f"⚔️ JOIN ({_ROYALE_FEE}g)", callback_data=f"br_join_{chat_id}")]]))
    except Exception:
        pass

async def _royale_run(bot, chat_id):
    await asyncio.sleep(60)
    st = _royales.get(chat_id)
    if not st:
        return
    if len(st["players"]) < 2:
        # not enough fighters — refund
        for uid in st["players"]:
            _give_gold(uid, _ROYALE_FEE)
        try:
            await bot.edit_message_text(chat_id=chat_id, message_id=st["msg_id"],
                text="⚔️ *Battle Royale cancelled* — nobody else dared to enter. Entry refunded.",
                parse_mode="Markdown", reply_markup=None)
        except Exception:
            pass
        _royales.pop(chat_id, None)
        return
    st["state"] = "running"
    try:
        await bot.edit_message_text(chat_id=chat_id, message_id=st["msg_id"],
            text=f"⚔️ *THE GATES CLOSE!* {len(st['players'])} fighters — 💰 *{st['pot']}g* pot.\n_Last one standing takes it all…_",
            parse_mode="Markdown", reply_markup=None)
    except Exception:
        pass
    alive = dict(st["players"])
    # survival weight: level + stats give an edge, but anyone can win
    def _weight(uid):
        pl = get_player(uid)
        if not pl:
            return 100.0
        return 100.0 + safe_int(pl.get("level"), 1) + sum(safe_stats(pl).values()) / 5.0
    weights = {uid: _weight(uid) for uid in alive}
    try:
        while len(alive) > 1:
            await asyncio.sleep(10)
            kills_this_round = 2 if len(alive) > 8 else 1
            round_lines = []
            for _ in range(kills_this_round):
                if len(alive) <= 1:
                    break
                uids = list(alive.keys())
                inv_w = [1.0 / max(1.0, weights[u]) for u in uids]
                victim = random.choices(uids, weights=inv_w, k=1)[0]
                killers = [u for u in uids if u != victim]
                killer = random.choices(killers, weights=[weights[u] for u in killers], k=1)[0]
                line = random.choice(_BR_KILL_LINES).format(k=alive[killer], v=alive[victim])
                del alive[victim]
                round_lines.append(f"{line}\n☠️ *{len(alive)}* remain.")
            if round_lines:
                await announce(bot, chat_id, "\n\n".join(round_lines), delay=90)
        winner_uid, winner_name = next(iter(alive.items()))
        _give_gold(winner_uid, st["pot"])
        wp = get_player(winner_uid)
        _br_exp = 0
        if wp:
            _br_exp = exp_share(wp.get("level", 1), 0.10)
            add_exp(wp, _br_exp)
            save_player(wp)
        await announce(bot, chat_id,
            f"👑 *BATTLE ROYALE CHAMPION: {winner_name}!*\n"
            f"💰 Takes the *{st['pot']}g* pot" + (f"  •  ✨ +{fmt_num(_br_exp)} EXP" if _br_exp else "") + "\n"
            f"_{len(st['players'])} entered. One walked out._",
            permanent=True)
    except Exception:
        logger.error("royale error in chat %s", chat_id, exc_info=True)
    finally:
        _royales.pop(chat_id, None)

# ── 2) WILD WEST QUICKDRAW ───────────────────────────────────────────────────
async def quickdraw_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    chat = update.effective_chat
    user = update.effective_user
    if chat.type not in ("group", "supergroup"):
        await update.message.reply_text("🤠 Quickdraw duels happen in the group!"); return
    if chat.id in _quickdraws:
        await send_group(update, "🤠 A quickdraw is already underway here!", delay=9); return
    if not (update.message and update.message.reply_to_message):
        await send_group(update, "🤠 *Quickdraw*: reply to someone with `/quickdraw [wager]` to challenge them.\n"
                                 "First to tap 🔫 after the DRAW signal wins the pot. Tap early = misfire = lose.", delay=15); return
    tu = update.message.reply_to_message.from_user
    if tu.id == user.id or tu.is_bot:
        await send_group(update, "🤠 Pick a real opponent.", delay=9); return
    if not get_player(tu.id):
        await send_group(update, f"🤠 *{tu.first_name}* hasn't ascended yet!", delay=9); return
    wager = _wager_from_args(context.args, default=50)
    st = {"a": user.id, "a_name": user.first_name, "b": tu.id, "b_name": tu.first_name,
          "wager": wager, "state": "challenge", "msg_id": None, "armed_at": None}
    _quickdraws[chat.id] = st
    try:
        msg = await context.bot.send_message(chat.id,
            f"🤠 *QUICKDRAW!*  *{user.first_name}* challenges *{tu.first_name}* — 💰 {wager}g each.\n"
            f"_Wait for 🔫 DRAW! First shot wins. Shoot early and you lose._",
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup([[InlineKeyboardButton(
                "🎯 Accept the duel", callback_data=f"qd_accept_{chat.id}")]]))
        st["msg_id"] = msg.message_id
    except Exception:
        _quickdraws.pop(chat.id, None); return
    async def _qd_expire(cid=chat.id, mid=st["msg_id"]):
        await asyncio.sleep(90)
        s2 = _quickdraws.get(cid)
        if s2 and s2["state"] == "challenge" and s2["msg_id"] == mid:
            _quickdraws.pop(cid, None)
            try:
                await bot_edit_challenge_expired(context.bot, cid, mid)
            except Exception:
                pass
    _t = asyncio.create_task(_qd_expire())
    _bg_tasks.add(_t); _t.add_done_callback(_bg_tasks.discard)

async def bot_edit_challenge_expired(bot, chat_id, msg_id):
    try:
        await bot.edit_message_text(chat_id=chat_id, message_id=msg_id,
            text="⌛ _The challenge expired unanswered._", parse_mode="Markdown", reply_markup=None)
    except Exception:
        pass

async def quickdraw_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    parts = query.data.split("_")
    action, chat_id = parts[1], int(parts[2])
    st = _quickdraws.get(chat_id)
    uid = query.from_user.id
    if not st:
        await query.answer("This duel is over.", show_alert=True); return
    if action == "accept":
        if uid != st["b"]:
            await query.answer("This challenge isn't for you!", show_alert=True); return
        if st["state"] != "challenge":
            await query.answer(); return
        pa = _take_gold(st["a"], st["wager"])
        if not pa:
            _quickdraws.pop(chat_id, None)
            await query.answer(f"{st['a_name']} can't cover the wager — duel off!", show_alert=True); return
        pb = _take_gold(st["b"], st["wager"])
        if not pb:
            _give_gold(st["a"], st["wager"])
            _quickdraws.pop(chat_id, None)
            await query.answer(f"You can't cover the {st['wager']}g wager!", show_alert=True); return
        st["state"] = "steady"
        await query.answer("🤠 Duel on!")
        await _q_edit(query,
            f"🌵 *{st['a_name']}* vs *{st['b_name']}* — 💰 {st['wager'] * 2}g pot\n\n"
            f"*Steady…* wait for the signal.\n_Shooting early is an instant loss._",
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup([[InlineKeyboardButton(
                "🔫 FIRE", callback_data=f"qd_fire_{chat_id}")]]))
        async def _arm(cid=chat_id):
            await asyncio.sleep(random.uniform(3.0, 8.0))
            s2 = _quickdraws.get(cid)
            if not s2 or s2["state"] != "steady":
                return
            s2["state"] = "armed"; s2["armed_at"] = time.time()
            try:
                await context.bot.edit_message_text(chat_id=cid, message_id=s2["msg_id"],
                    text=f"🔫 *DRAW!!!*  — 💰 {s2['wager'] * 2}g pot\n_FIRST SHOT WINS!_",
                    parse_mode="Markdown",
                    reply_markup=InlineKeyboardMarkup([[InlineKeyboardButton(
                        "🔫 FIRE", callback_data=f"qd_fire_{cid}")]]))
            except Exception:
                pass
            await asyncio.sleep(30)
            s3 = _quickdraws.get(cid)
            if s3 and s3["state"] == "armed":
                _quickdraws.pop(cid, None)
                _give_gold(s3["a"], s3["wager"]); _give_gold(s3["b"], s3["wager"])
                try:
                    await context.bot.edit_message_text(chat_id=cid, message_id=s3["msg_id"],
                        text="🌵 _Neither gunslinger fired. Wagers returned. The tumbleweed wins._",
                        parse_mode="Markdown", reply_markup=None)
                except Exception:
                    pass
        _t = asyncio.create_task(_arm())
        _bg_tasks.add(_t); _t.add_done_callback(_bg_tasks.discard)
        return
    if action == "fire":
        if uid not in (st["a"], st["b"]):
            await query.answer("You're a spectator — enjoy the show!", show_alert=True); return
        me = st["a_name"] if uid == st["a"] else st["b_name"]
        opp_uid = st["b"] if uid == st["a"] else st["a"]
        opp = st["b_name"] if uid == st["a"] else st["a_name"]
        if st["state"] == "steady":
            # misfire — instant loss
            _quickdraws.pop(chat_id, None)
            _give_gold(opp_uid, st["wager"] * 2)
            await query.answer("💥 You fired EARLY!", show_alert=True)
            await _q_edit(query,
                f"💥 *MISFIRE!* *{me}* shot before the signal!\n"
                f"🏆 *{opp}* wins the *{st['wager'] * 2}g* pot without drawing.",
                parse_mode="Markdown")
            return
        if st["state"] == "armed":
            _quickdraws.pop(chat_id, None)
            reaction_ms = int((time.time() - st["armed_at"]) * 1000)
            _give_gold(uid, st["wager"] * 2)
            wp = get_player(uid)
            if wp:
                add_exp(wp, exp_share(wp.get("level", 1), 0.03)); save_player(wp)
            await query.answer(f"🔫 {reaction_ms}ms — you win!")
            await _q_edit(query,
                f"🔫 *BANG!* *{me}* draws in *{reaction_ms}ms*!\n"
                f"🏆 Takes the *{st['wager'] * 2}g* pot. *{opp}* eats dust.",
                parse_mode="Markdown")
            return
        await query.answer()

# ── 3) RUSSIAN ROULETTE (VERSUS) ─────────────────────────────────────────────
async def russian_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    chat = update.effective_chat
    user = update.effective_user
    if chat.type not in ("group", "supergroup"):
        await update.message.reply_text("🔫 Russian Roulette is played in the group!"); return
    if chat.id in _russians:
        await send_group(update, "🔫 A game is already in progress here!", delay=9); return
    if not (update.message and update.message.reply_to_message):
        await send_group(update, "🔫 *Russian Roulette*: reply to someone with `/russian [wager]`.\n"
                                 "Six chambers, one bullet, alternating pulls. Loser pays.", delay=15); return
    tu = update.message.reply_to_message.from_user
    if tu.id == user.id or tu.is_bot:
        await send_group(update, "🔫 You need a living opponent.", delay=9); return
    if not get_player(tu.id):
        await send_group(update, f"🔫 *{tu.first_name}* hasn't ascended yet!", delay=9); return
    wager = _wager_from_args(context.args, default=100)
    st = {"a": user.id, "a_name": user.first_name, "b": tu.id, "b_name": tu.first_name,
          "wager": wager, "state": "challenge", "msg_id": None,
          "chambers": 6, "turn": None, "deadline": None}
    _russians[chat.id] = st
    try:
        msg = await context.bot.send_message(chat.id,
            f"🔫 *RUSSIAN ROULETTE*  —  *{user.first_name}* challenges *{tu.first_name}*\n"
            f"💰 {wager}g each  •  6 chambers  •  1 bullet\n_Winner takes the pot. Loser is defeated 3 minutes._",
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup([[InlineKeyboardButton(
                "😤 Accept", callback_data=f"rr2_accept_{chat.id}")]]))
        st["msg_id"] = msg.message_id
    except Exception:
        _russians.pop(chat.id, None); return
    async def _rr_expire(cid=chat.id, mid=st["msg_id"]):
        await asyncio.sleep(90)
        s2 = _russians.get(cid)
        if s2 and s2["state"] == "challenge" and s2["msg_id"] == mid:
            _russians.pop(cid, None)
            await bot_edit_challenge_expired(context.bot, cid, mid)
    _t = asyncio.create_task(_rr_expire())
    _bg_tasks.add(_t); _t.add_done_callback(_bg_tasks.discard)

def _rr_card(st):
    turn_name = st["a_name"] if st["turn"] == st["a"] else st["b_name"]
    fired = 6 - st["chambers"]
    dots = "⚫" * fired + "🔘" * st["chambers"]
    return (f"🔫 *RUSSIAN ROULETTE* — 💰 {st['wager'] * 2}g pot\n"
            f"{dots}  _({st['chambers']} chambers left)_\n\n"
            f"👉 *{turn_name}*, the revolver is in your hand.")

async def russian_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    parts = query.data.split("_")
    action, chat_id = parts[1], int(parts[2])
    st = _russians.get(chat_id)
    uid = query.from_user.id
    if not st:
        await query.answer("This game is over.", show_alert=True); return
    if action == "accept":
        if uid != st["b"]:
            await query.answer("This challenge isn't for you!", show_alert=True); return
        if st["state"] != "challenge":
            await query.answer(); return
        pa = _take_gold(st["a"], st["wager"])
        if not pa:
            _russians.pop(chat_id, None)
            await query.answer(f"{st['a_name']} can't cover the wager — game off!", show_alert=True); return
        pb = _take_gold(st["b"], st["wager"])
        if not pb:
            _give_gold(st["a"], st["wager"])
            _russians.pop(chat_id, None)
            await query.answer(f"You can't cover the {st['wager']}g wager!", show_alert=True); return
        st["state"] = "playing"
        st["turn"] = random.choice([st["a"], st["b"]])
        st["deadline"] = time.time() + 60
        await query.answer("🔫 The cylinder spins...")
        await _q_edit(query, _rr_card(st), parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup([[InlineKeyboardButton(
                "🔫 Pull the trigger", callback_data=f"rr2_pull_{chat_id}")]]))
        async def _rr_watch(cid=chat_id):
            while True:
                await asyncio.sleep(15)
                s2 = _russians.get(cid)
                if not s2 or s2["state"] != "playing":
                    return
                if time.time() > s2["deadline"]:
                    # turn holder chickened out — forfeits
                    loser = s2["turn"]
                    winner = s2["b"] if loser == s2["a"] else s2["a"]
                    l_name = s2["a_name"] if loser == s2["a"] else s2["b_name"]
                    w_name = s2["b_name"] if loser == s2["a"] else s2["a_name"]
                    _russians.pop(cid, None)
                    _give_gold(winner, s2["wager"] * 2)
                    try:
                        await context.bot.edit_message_text(chat_id=cid, message_id=s2["msg_id"],
                            text=f"🐔 *{l_name}* couldn't pull the trigger — *forfeits!*\n"
                                 f"🏆 *{w_name}* takes the {s2['wager'] * 2}g pot.",
                            parse_mode="Markdown", reply_markup=None)
                    except Exception:
                        pass
                    return
        _t = asyncio.create_task(_rr_watch())
        _bg_tasks.add(_t); _t.add_done_callback(_bg_tasks.discard)
        return
    if action == "pull":
        if st["state"] != "playing":
            await query.answer(); return
        if uid != st["turn"]:
            await query.answer("Not your turn — or not your game!", show_alert=True); return
        me = st["a_name"] if uid == st["a"] else st["b_name"]
        opp_uid = st["b"] if uid == st["a"] else st["a"]
        opp_name = st["b_name"] if uid == st["a"] else st["a_name"]
        bang = random.randint(1, st["chambers"]) == 1
        if bang:
            _russians.pop(chat_id, None)
            _give_gold(opp_uid, st["wager"] * 2)
            lp = get_player(uid)
            if lp:
                lp["hp"] = 0
                lp["defeated_until"] = (datetime.now() + timedelta(minutes=3)).isoformat()
                lp["last_defeated_by"] = "Russian Roulette"
                save_player(lp)
            wp = get_player(opp_uid)
            if wp:
                add_exp(wp, exp_share(wp.get("level", 1), 0.04)); save_player(wp)
            await query.answer("💥 BANG.", show_alert=True)
            await _q_edit(query,
                f"💥 *BANG!* The chamber wasn't empty.\n"
                f"☠️ *{me}* hits the floor — defeated for 3 minutes.\n"
                f"🏆 *{opp_name}* takes the *{st['wager'] * 2}g* pot.",
                parse_mode="Markdown")
            return
        st["chambers"] -= 1
        st["turn"] = opp_uid
        st["deadline"] = time.time() + 60
        await query.answer("…click.")
        await _q_edit(query, _rr_card(st) + "\n\n_…click. Nothing. The revolver changes hands._",
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup([[InlineKeyboardButton(
                "🔫 Pull the trigger", callback_data=f"rr2_pull_{chat_id}")]]))
        return

# ── 4) GOLD STANDOFF (split-or-steal) ────────────────────────────────────────
async def standoff_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    chat = update.effective_chat
    user = update.effective_user
    if chat.type not in ("group", "supergroup"):
        await update.message.reply_text("🤝 Standoffs happen in the group!"); return
    if chat.id in _standoffs:
        await send_group(update, "🤝 A standoff is already underway here!", delay=9); return
    if not (update.message and update.message.reply_to_message):
        await send_group(update, "🤝 *Gold Standoff*: reply to someone with `/standoff [wager]`.\n"
                                 "Both secretly pick 🤝 SPLIT or 🗡️ STEAL.\n"
                                 "Split/Split: both profit +25%. Steal/Split: thief takes all. Steal/Steal: pot burns.", delay=20); return
    tu = update.message.reply_to_message.from_user
    if tu.id == user.id or tu.is_bot:
        await send_group(update, "🤝 Find a real partner-in-crime.", delay=9); return
    if not get_player(tu.id):
        await send_group(update, f"🤝 *{tu.first_name}* hasn't ascended yet!", delay=9); return
    wager = _wager_from_args(context.args, default=100)
    st = {"a": user.id, "a_name": user.first_name, "b": tu.id, "b_name": tu.first_name,
          "wager": wager, "state": "challenge", "msg_id": None, "picks": {}}
    _standoffs[chat.id] = st
    try:
        msg = await context.bot.send_message(chat.id,
            f"🤝 *GOLD STANDOFF*  —  *{user.first_name}* ⚡ *{tu.first_name}*\n"
            f"💰 {wager}g each on the table.\n"
            f"_Split/Split: +25% each  •  Steal/Split: thief takes all  •  Steal/Steal: pot BURNS_",
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup([[InlineKeyboardButton(
                "⚡ Accept the standoff", callback_data=f"so_accept_{chat.id}")]]))
        st["msg_id"] = msg.message_id
    except Exception:
        _standoffs.pop(chat.id, None); return
    async def _so_expire(cid=chat.id, mid=st["msg_id"]):
        await asyncio.sleep(90)
        s2 = _standoffs.get(cid)
        if s2 and s2["state"] == "challenge" and s2["msg_id"] == mid:
            _standoffs.pop(cid, None)
            await bot_edit_challenge_expired(context.bot, cid, mid)
    _t = asyncio.create_task(_so_expire())
    _bg_tasks.add(_t); _t.add_done_callback(_bg_tasks.discard)

async def _standoff_resolve(bot, chat_id):
    st = _standoffs.pop(chat_id, None)
    if not st:
        return
    w = st["wager"]
    pa = st["picks"].get(st["a"], "split")
    pb = st["picks"].get(st["b"], "split")
    an, bn = st["a_name"], st["b_name"]
    _ic = {"split": "🤝 SPLIT", "steal": "🗡️ STEAL"}
    if pa == "split" and pb == "split":
        bonus = round(w * 0.25)
        _give_gold(st["a"], w + bonus); _give_gold(st["b"], w + bonus)
        result = (f"🤝🤝 *HONOR AMONG THIEVES!* Both chose SPLIT.\n"
                  f"💰 Each walks away with *{w + bonus}g* (+{bonus} bonus).")
    elif pa == "steal" and pb == "steal":
        result = (f"🗡️🗡️ *DOUBLE CROSS!* Both tried to STEAL.\n"
                  f"🔥 The *{w * 2}g* pot burns in the crossfire. Nobody gets anything.")
    else:
        thief = st["a"] if pa == "steal" else st["b"]
        thief_name = an if pa == "steal" else bn
        mark_name = bn if pa == "steal" else an
        _give_gold(thief, w * 2)
        result = (f"🗡️ *BETRAYAL!* *{thief_name}* stole the pot while *{mark_name}* offered the split.\n"
                  f"💰 *{thief_name}* rides off with *{w * 2}g*.")
    try:
        await bot.edit_message_text(chat_id=chat_id, message_id=st["msg_id"],
            text=(f"🤝 *STANDOFF RESOLVED*\n"
                  f"*{an}*: {_ic[pa]}   •   *{bn}*: {_ic[pb]}\n\n{result}"),
            parse_mode="Markdown", reply_markup=None)
    except Exception:
        pass

async def standoff_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    parts = query.data.split("_")
    action, chat_id = parts[1], int(parts[2])
    st = _standoffs.get(chat_id)
    uid = query.from_user.id
    if not st:
        await query.answer("This standoff is over.", show_alert=True); return
    if action == "accept":
        if uid != st["b"]:
            await query.answer("This challenge isn't for you!", show_alert=True); return
        if st["state"] != "challenge":
            await query.answer(); return
        pa = _take_gold(st["a"], st["wager"])
        if not pa:
            _standoffs.pop(chat_id, None)
            await query.answer(f"{st['a_name']} can't cover the wager!", show_alert=True); return
        pb = _take_gold(st["b"], st["wager"])
        if not pb:
            _give_gold(st["a"], st["wager"])
            _standoffs.pop(chat_id, None)
            await query.answer(f"You can't cover the {st['wager']}g wager!", show_alert=True); return
        st["state"] = "picking"
        # secret pick buttons via DM — if either DM fails, cancel and refund
        _pick_kb = InlineKeyboardMarkup([[
            InlineKeyboardButton("🤝 SPLIT", callback_data=f"so_pick-split_{chat_id}"),
            InlineKeyboardButton("🗡️ STEAL", callback_data=f"so_pick-steal_{chat_id}"),
        ]])
        try:
            for _uid, _opp in ((st["a"], st["b_name"]), (st["b"], st["a_name"])):
                await context.bot.send_message(_uid,
                    f"🤝 *Standoff vs {_opp}* — {st['wager']}g on the table.\n"
                    f"Choose in secret. 45 seconds. No pick = SPLIT.",
                    parse_mode="Markdown", reply_markup=_pick_kb)
        except Exception:
            _give_gold(st["a"], st["wager"]); _give_gold(st["b"], st["wager"])
            _standoffs.pop(chat_id, None)
            await query.answer("Couldn't DM both players (start a chat with the bot first). Refunded.", show_alert=True)
            return
        await query.answer("⚡ Standoff on — check your DMs!")
        await _q_edit(query,
            f"🤝 *STANDOFF!*  *{st['a_name']}* ⚡ *{st['b_name']}* — 💰 {st['wager'] * 2}g\n\n"
            f"🕶️ _Both are choosing in secret… 45 seconds._",
            parse_mode="Markdown")
        async def _so_timer(cid=chat_id):
            await asyncio.sleep(45)
            s2 = _standoffs.get(cid)
            if s2 and s2["state"] == "picking":
                await _standoff_resolve(context.bot, cid)
        _t = asyncio.create_task(_so_timer())
        _bg_tasks.add(_t); _t.add_done_callback(_bg_tasks.discard)
        return
    if action.startswith("pick-"):
        choice = action.split("-")[1]
        if st["state"] != "picking" or uid not in (st["a"], st["b"]):
            await query.answer("Not your standoff!", show_alert=True); return
        if uid in st["picks"]:
            await query.answer("You already chose — no take-backs."); return
        st["picks"][uid] = choice
        await query.answer("🕶️ Choice locked.")
        try:
            await _q_edit(query, f"🕶️ *Choice locked in: {'🤝 SPLIT' if choice == 'split' else '🗡️ STEAL'}*\n_Now we wait…_",
                          parse_mode="Markdown")
        except Exception:
            pass
        if len(st["picks"]) == 2:
            await _standoff_resolve(context.bot, chat_id)
        return

# ── WEATHER CHANGE ANNOUNCEMENTS ─────────────────────────────────────────────
_last_weather_announced = {"name": None}

def _recent_group_players(group_id, hours=6, limit=25):
    """(uid, name) of players recently active in a specific group."""
    try:
        cutoff = (datetime.now() - timedelta(hours=hours)).isoformat()
        c = _db().cursor()
        rows = c.execute(
            """SELECT s.user_id, COALESCE(p.username, s.username) AS name
               FROM shadow_profiles s LEFT JOIN players p ON p.user_id = s.user_id
               WHERE s.home_group = ? AND s.last_seen >= ?
               ORDER BY s.last_seen DESC LIMIT ?""",
            (group_id, cutoff, limit)).fetchall()
        return [(r["user_id"], r["name"] or "someone") for r in rows]
    except Exception:
        return []

# Gift pool for blessings/fortune drops. Each returns (apply_fn, describe).
_GIFT_ITEMS = ["Greater Health Potion", "Grand Restorative Flask", "MP Tonic",
               "Iron Shard", "Enchanting Scroll", "Common Egg", "Rare Egg",
               "Pet Snack", "Scroll of Revival"]

def _grant_gift(uid):
    """Give a recently-active player a random gift. Returns a short reward
    string ('+2.4K gold', '🥚 Rare Egg', ...) or None if the player is gone."""
    p = get_player(uid)
    if not p:
        return None
    lvl = safe_int(p.get("level"), 1)
    roll = random.random()
    if roll < 0.45:
        amt = scaled_gold(lvl, random.randint(200, 600))
        p["gold"] = safe_int(p.get("gold")) + amt
        save_player(p)
        return f"💰 +{fmt_num(amt)} gold"
    elif roll < 0.75:
        xp = exp_share(lvl, random.uniform(0.05, 0.13))
        add_exp(p, xp); save_player(p)
        return f"✨ +{fmt_num(xp)} EXP"
    else:
        item = random.choice(_GIFT_ITEMS)
        add_item(p, item); save_player(p)
        return f"🎁 {item}"

_WEATHER_WITNESS = [
    "{names} feel the shift in the air.",
    "{names} pause mid-shot as the world turns.",
    "The change isn't lost on {names}.",
    "{names} look up as the atmosphere bends.",
    "Somewhere, {names} sense it too.",
]

async def _weather_watch(bot):
    """Announce weather CHANGES with variety: a random flavor line, a shout-out
    to recent players, and an occasional 'blessing' gift to a random active
    player — named publicly to pull the group's attention back in."""
    w = get_weather()
    if w["name"] == _last_weather_announced["name"]:
        return
    first_run = _last_weather_announced["name"] is None
    _last_weather_announced["name"] = w["name"]
    if first_run:
        return  # don't announce on boot — only on actual changes
    emoji = w.get("emoji", "🌦️")
    flavor = random.choice(w.get("flavors", [w.get("desc", "The world shifts.")]))
    hint = "\n🌑 _Something ancient stirs... it can be summoned tonight._" if w.get("secret_eligible") else ""
    try:
        c = _db().cursor()
        week_ago = (datetime.now() - timedelta(days=7)).isoformat()
        c.execute("""SELECT DISTINCT home_group FROM shadow_profiles
                     WHERE home_group IS NOT NULL AND last_seen >= ?""", (week_ago,))
        groups = [r[0] for r in c.fetchall()]
    except Exception:
        return
    for g in groups:
        recent = _recent_group_players(g, hours=6)
        witness = ""
        if len(recent) >= 1:
            names = [f"*{n}*" for _, n in recent[:2]]
            _joined = " & ".join(names)
            witness = "\n_" + random.choice(_WEATHER_WITNESS).format(names=_joined) + "_"
        # Blessing: ~40% of weather changes gift a random recent player, by name
        blessing = ""
        if recent and random.random() < 0.40:
            _buid, _bname = random.choice(recent)
            reward = _grant_gift(_buid)
            if reward:
                blessing = f"\n\n🎁 *The {w['name']} blesses {_bname}!*  {reward}"
                try:
                    await bot.send_message(_buid,
                        f"🎁 *The {w['name']} smiles on you!*\nYou received {reward}. "
                        f"_Being active in the group has its rewards._",
                        parse_mode="Markdown")
                except Exception:
                    pass
        try:
            await bot.send_message(g,
                f"{emoji} *The conditions have changed: {w['name']}*\n"
                f"_{flavor}_{witness}\n\n"
                f"📈 EXP ×{w['exp_mod']}  |  ⚔️ DMG ×{w['dmg_mod']}{hint}{blessing}",
                parse_mode="Markdown")
        except Exception:
            pass
        await asyncio.sleep(0.3)

# ── FORTUNE DROPS — random surprise gifts to active players ───────────────────
_FORTUNE_LINES = [
    "🍀 *Fortune smiles!* A stray pouch of luck lands on *{name}*.",
    "🎰 *The 8-Ball rolls in {name}'s favor!*",
    "✨ *A gift from the void* finds its way to *{name}*.",
    "🪙 *{name}* reaches into their pocket and finds something new.",
    "🌟 *The table honors {name}* for keeping the game alive.",
    "🎁 *A wandering merchant tosses {name} a parting gift.*",
]
_fortune_last = {}  # chat_id -> last fortune drop ts

async def _fortune_drop_scheduler(bot):
    """A few times a day per group, surprise a random recently-active player
    with a gift — named in the group. Pure 'come back and see what you got'."""
    try:
        c = _db().cursor()
        day_ago = (datetime.now() - timedelta(days=1)).isoformat()
        c.execute("""SELECT DISTINCT home_group FROM shadow_profiles
                     WHERE home_group IS NOT NULL AND last_seen >= ?""", (day_ago,))
        groups = [r[0] for r in c.fetchall()]
    except Exception:
        return
    now_ts = time.time()
    for g in groups:
        if now_ts - _fortune_last.get(g, 0) < 5 * 3600:  # at most ~1 per 5h/group
            continue
        if random.random() >= 0.15:   # ~2-3 per day across eligible cycles
            continue
        recent = _recent_group_players(g, hours=4)
        if not recent:
            continue
        _fortune_last[g] = now_ts
        uid, name = random.choice(recent)
        reward = _grant_gift(uid)
        if not reward:
            continue
        line = random.choice(_FORTUNE_LINES).format(name=name)
        try:
            await bot.send_message(g, f"{line}\n{reward}", parse_mode="Markdown")
        except Exception:
            pass
        try:
            await bot.send_message(uid,
                f"🍀 *A little fortune found you in the group!*\nYou received {reward}.",
                parse_mode="Markdown")
        except Exception:
            pass
        await asyncio.sleep(0.3)

_crate_last = {}  # chat_id -> last crate spawn ts

async def _crate_scheduler(bot):
    """Give each active group a crate race a few times a day, at random."""
    try:
        c = _db().cursor()
        day_ago = (datetime.now() - timedelta(days=1)).isoformat()
        c.execute("""SELECT DISTINCT home_group FROM shadow_profiles
                     WHERE home_group IS NOT NULL AND last_seen >= ?""", (day_ago,))
        groups = [r[0] for r in c.fetchall()]
    except Exception:
        return
    now_ts = time.time()
    for g in groups:
        if now_ts - _crate_last.get(g, 0) < 6 * 3600:
            continue  # at most one crate per ~6h per group
        if random.random() < 0.12:  # ~once per 2h of eligible cycles → 2-3/day
            _crate_last[g] = now_ts
            await _spawn_crate(bot, g)
            await asyncio.sleep(0.3)

