def _menu_markup(uid, p=None):
    rows = [
        [InlineKeyboardButton("👤 Profile", callback_data=f"menu_stats_{uid}"),
         InlineKeyboardButton("🏚️ Dungeon", callback_data=f"menu_dungeon_{uid}")],
        [InlineKeyboardButton("🐾 Pets",    callback_data=f"menu_pets_{uid}"),
         InlineKeyboardButton("🏰 Empire",  callback_data=f"menu_empire_{uid}")],
        [InlineKeyboardButton("🛒 Shop",    callback_data=f"menu_shop_{uid}"),
         InlineKeyboardButton("⚔️ Battle",  callback_data=f"menu_battle_{uid}")],
    ]
    if p is not None and not _first_steps_complete(p):
        rows.insert(0, [InlineKeyboardButton("🚀 First Steps — rewards inside!",
                                             callback_data=f"menu_fsteps_{uid}")])
    rows.append([InlineKeyboardButton("❌ Close", callback_data=f"close_msg_{uid}")])
    return InlineKeyboardMarkup(rows)

async def menu_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user
    p = get_player(user.id)
    try: await update.message.delete()
    except Exception: pass
    if not p:
        await send_group(update, "Use /ascend first to enter the world!", delay=9); return
    w = get_weather()
    text = (f"🎱 *{WORLD_NAME}*\n\n"
            f"👤 *{p['username']}* — Lv {p['level']}  |  ❤️ {p['hp']}/{p['max_hp']}\n"
            f"💰 {p.get('gold',0):,}g  |  🌍 {w['name']}\n\n"
            f"_Where to?_")
    await context.bot.send_message(chat_id=update.effective_chat.id, text=text,
                                   parse_mode="Markdown", reply_markup=_menu_markup(user.id, p))

async def menu_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    parts = query.data.split("_")
    try:
        section = parts[1]; uid = int(parts[2])
    except (IndexError, ValueError):
        await query.answer(); return
    if query.from_user.id != uid:
        await query.answer("This isn't your menu!", show_alert=True); return
    p = get_player(uid)
    if not p:
        await query.answer("Use /ascend first!", show_alert=True); return
    await query.answer()

    back_row = [InlineKeyboardButton("« Menu", callback_data=f"menu_home_{uid}")]

    async def _show(text, markup_rows):
        try:
            await _q_edit(query, text[:4096], parse_mode="Markdown",
                                          reply_markup=InlineKeyboardMarkup(markup_rows))
        except Exception:
            pass

    if section == "home":
        w = get_weather()
        text = (f"🎱 *{WORLD_NAME}*\n\n"
                f"👤 *{p['username']}* — Lv {p['level']}  |  ❤️ {p['hp']}/{p['max_hp']}\n"
                f"💰 {p.get('gold',0):,}g  |  🌍 {w['name']}\n\n"
                f"_Where to?_")
        try:
            await _q_edit(query, text, parse_mode="Markdown", reply_markup=_menu_markup(uid, p))
        except Exception:
            pass
        return

    if section == "stats":
        await _send_stats_page(query, uid, page=1, edit=True, back_rows=[back_row])
        return

    if section == "dungeon":
        if uid in active_dungeons:
            await _show("🏚️ *The Dungeon*\n\nYou're mid-run! Use /dungeon to resume your current card.",
                        [back_row])
            return
        p_level = p.get("level", 1)
        rows = []
        for dk, dc in DNG_DIFF.items():
            if p_level < dc["min_level"]:
                rows.append([InlineKeyboardButton(
                    f"{dc['emoji']} {dc['label']} (Lv{dc['min_level']}+) — 🔒",
                    callback_data=f"dng_locked_{uid}")])
            else:
                rows.append([InlineKeyboardButton(
                    f"{dc['emoji']} {dc['label']} — {dc['desc']}",
                    callback_data=f"dng_diff_{uid}_{dk}")])
        rows.append(back_row)
        await _show(f"🏚️ *The Dungeon*\n\nChoose your difficulty. Die and you lose everything. "
                    f"Extract to keep rewards.\n\n❤️ {p['hp']}/{calc_max_hp(p)} HP", rows)
        return

    if section == "pets":
        text, markup = _build_pet_home(uid, p)
        rows = list(markup.inline_keyboard) + [back_row]
        await _show(text, rows)
        return

    if section == "empire":
        if sjl(p.get("empire_buildings"), {}) and not p.get("empire_last_collect"):
            p["empire_last_collect"] = (datetime.now() - timedelta(hours=8)).isoformat()
            save_player(p)
        text, markup = _build_empire_overview(p, uid)
        rows = list(markup.inline_keyboard) + [back_row]
        await _show(text, rows)
        return

    if section == "shop":
        text, markup = _build_shop_view(p, "daily", uid, _shop_discount(p))
        rows = list(markup.inline_keyboard) + [back_row]
        await _show(text, rows)
        return

    if section == "fsteps":
        text, markup = _build_first_steps(p, uid)
        rows = list(markup.inline_keyboard)
        rows.insert(-1, back_row)
        await _show(text, rows)
        return

    if section == "battle":
        await _show(
            "⚔️ *Battle Guide*\n\n"
            "• *PvP:* reply to any player's message with /attack — the fight card "
            "lands in your DMs with attack/skill/potion buttons\n"
            "• *Skills:* reply with /skill to open your skill picker\n"
            "• *Monsters:* /encounter for wild battles and hunts\n"
            "• *Dungeon:* /dungeon for the roguelike tower\n"
            "• *Shield:* /defend raises a damage-absorbing shield\n\n"
            "_Defeated players revive after 6 minutes — revenge within 24h pays +15% damage._",
            [back_row])
        return
    await query.answer("Unknown menu option.")

async def ping_cmd(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Instant health check: confirms the bot is alive and WHICH build is live."""
    try:
        build = datetime.fromtimestamp(os.path.getmtime(__file__)).strftime("%m/%d %H:%M")
    except Exception:
        build = "?"
    up = datetime.now() - _BOOT_TIME
    up_str = f"{int(up.total_seconds()//3600)}h {int(up.total_seconds()%3600//60)}m"
    await update.message.reply_text(
        f"🏓 Pong! {WORLD_NAME} {CURRENT_VERSION}\n"
        f"🧱 Build: {build}  •  ⏱️ Up: {up_str}")

async def _global_error_handler(update, context):
    """Log every handler exception (they were previously invisible), and DM the
    admin when Telegram reports a Conflict — the classic 'two bot instances are
    polling the same token' failure after an overlapping deploy, which makes
    every command look dead."""
    err = context.error
    try:
        logger.error("Handler error: %s", err, exc_info=err)
    except Exception:
        pass
    if err.__class__.__name__ == "Conflict":
        now_ts = time.time()
        if now_ts - _conflict_alert_ts["t"] > 3600:  # alert at most hourly
            _conflict_alert_ts["t"] = now_ts
            try:
                await context.bot.send_message(ADMIN_ID,
                    "⚠️ *Bot conflict detected!*\n\n"
                    "Another instance is polling this bot token — commands will "
                    "look dead until only one instance runs. Check Railway for "
                    "a stuck/duplicate deployment and restart the service.",
                    parse_mode="Markdown")
            except Exception:
                pass
        return
    # Any other handler crash: DM the admin a short diagnostic (throttled to
    # one per 5 min) so a command that dies silently in production is visible
    # without digging through Railway logs.
    now_ts = time.time()
    if now_ts - _err_alert_ts["t"] > 300:
        _err_alert_ts["t"] = now_ts
        _src = ""
        try:
            if update is not None and getattr(update, "message", None) and update.message and update.message.text:
                _src = update.message.text.split()[0][:32]
            elif update is not None and getattr(update, "callback_query", None) and update.callback_query:
                _src = "button " + str(update.callback_query.data)[:32]
        except Exception:
            pass
        try:
            await context.bot.send_message(ADMIN_ID,
                f"🐞 Handler error{(' on ' + _src) if _src else ''}: "
                f"{err.__class__.__name__}: {str(err)[:300]}")
        except Exception:
            pass

async def _post_init(application):
    """On startup: launch background loops, register the command menu,
    DM admin if version changed."""
    asyncio.create_task(_engagement_loop(application.bot))
    asyncio.create_task(_revive_watch_loop(application.bot))
    asyncio.create_task(_daily_digest_loop(application.bot))
    asyncio.create_task(_pvp_idle_watch_loop(application.bot))
    # Telegram "/" command menu — discoverability for every command that matters
    try:
        from telegram import BotCommand
        await application.bot.set_my_commands([
            BotCommand("menu",      "🏠 Main menu — everything in one place"),
            BotCommand("firststeps","🚀 New player? Start here"),
            BotCommand("stats",     "👤 Your profile & stats"),
            BotCommand("daily",     "🎁 Claim your daily reward"),
            BotCommand("quest",     "🗺️ Run an hourly quest"),
            BotCommand("train",     "🏋️ Train for EXP (30m)"),
            BotCommand("pool",      "🎱 Shoot pool for EXP & loot"),
            BotCommand("dungeon",   "🏚️ Enter the dungeon"),
            BotCommand("encounter", "🐉 Fight wild monsters"),
            BotCommand("attack",    "⚔️ Attack a player (reply to them)"),
            BotCommand("skill",     "✨ Use a skill (reply to target)"),
            BotCommand("heal",      "💚 Heal an ally (reply to them)"),
            BotCommand("defend",    "🛡️ Raise your shield"),
            BotCommand("pet",       "🐾 Your pets"),
            BotCommand("empire",    "🏰 Your empire & resources"),
            BotCommand("shop",      "🛒 Item shop"),
            BotCommand("inventory", "🎒 Your items"),
            BotCommand("explore",   "🧭 Send an expedition (1h)"),
            BotCommand("rank",      "🏆 Leaderboards"),
            BotCommand("guild",     "🏰 Guild hub"),
            BotCommand("party",     "👥 Party up"),
            BotCommand("objectives","📋 Daily objectives"),
            BotCommand("collection","📖 Your collection log"),
            BotCommand("bestiary",  "🐾 Pet bestiary — collect all 85 species"),
            BotCommand("pvp",       "⚔️ Your PvP hub — rating, record, streak, bounties"),
            BotCommand("pvptop",    "🏆 PvP rating leaderboard"),
            BotCommand("slots",     "🎰 Spin the slots"),
            BotCommand("coinflip",  "🪙 Wager vs a player (reply)"),
            BotCommand("lottery",   "🎟️ Buy a lottery ticket"),
            BotCommand("roulette",  "💀 Russian roulette lobby"),
            BotCommand("royale",    "⚔️ Battle Royale — group deathmatch, winner takes the pot"),
            BotCommand("quickdraw", "🤠 Reaction duel — reply to challenge, first shot wins"),
            BotCommand("russian",   "🔫 1v1 Russian roulette — reply to challenge"),
            BotCommand("standoff",  "🤝 Split-or-steal showdown — reply to challenge"),
            BotCommand("rob",       "🕶️ Rob a player (reply, risky)"),
            BotCommand("help",      "❓ How to play"),
            BotCommand("ping",      "🏓 Bot health check"),
        ])
    except Exception:
        pass
    version_file = "/data/bot_version.txt"
    try:
        with open(version_file) as f:
            last_version = f.read().strip()
    except Exception:
        last_version = None
    if last_version == CURRENT_VERSION:
        return
    try:
        with open(version_file, "w") as f:
            f.write(CURRENT_VERSION)
    except Exception: pass
    entry = next((e for e in reversed(CHANGELOG) if e["version"] == CURRENT_VERSION), None)
    if not entry: return
    changes_text = "\n".join(f"• {c}" for c in entry["changes"])
    msg = (f"🎱 *Bot Updated to {CURRENT_VERSION}*\n"
           f"_{entry['date']}_\n\n"
           f"{changes_text}")
    try:
        await application.bot.send_message(
            chat_id=ADMIN_ID, text=msg, parse_mode="Markdown")
    except Exception: pass

def main():
    init_db()
    # concurrent_updates: PTB's default processes ONE update at a time for the
    # whole bot — any handler that awaits (PvP card pacing, dungeon turns, a
    # slow Telegram call) stalls EVERY other player's commands, and during
    # active play the update queue backs up until the bot looks dead and needs
    # a restart. Handlers are already concurrency-safe (per-user _cb_lock,
    # per-pair PvP locks, save_player's stale-snapshot guard), so let them run
    # in parallel.
    app = (Application.builder().token(BOT_TOKEN).post_init(_post_init)
           .concurrent_updates(32).build())
    app.add_error_handler(_global_error_handler)

    # Universal
    app.add_handler(CommandHandler("ping",         ping_cmd))
    app.add_handler(CommandHandler("menu",         menu_cmd))
